}

local function LeafVECallSkin(methodName, ...)
  local args = arg
  local argCount = args and (args.n or table.getn(args)) or 0
  if FrameSkins and type(FrameSkins[methodName]) == "function" then
    local ok
    local result
    if argCount > 0 then
      ok, result = pcall(FrameSkins[methodName], FrameSkins, unpack(args, 1, argCount))
    else
      ok, result = pcall(FrameSkins[methodName], FrameSkins)
    end
    if ok then
      return result
    end
    if argCount > 0 then
      return FrameSkins[methodName](unpack(args, 1, argCount))
    end
    return FrameSkins[methodName]()
  end
  local skinFn = _G[methodName]
  if type(skinFn) == "function" then
    if argCount > 0 then
      return skinFn(unpack(args, 1, argCount))
    end
    return skinFn()
  end
end

local function LeafVEApplyFont(fontString, styleKey, flags)
  if Fonts and type(Fonts.Apply) == "function" then
    local ok = pcall(Fonts.Apply, Fonts, fontString, styleKey, flags)
    if ok then
      return true
    end
  end
  return false
end

local function LeafVEGetTextHeight(fontString, minimumHeight)
  local fallbackHeight = tonumber(minimumHeight) or 0
  if not fontString then
    return fallbackHeight
  end

  local height = nil
  if fontString.GetStringHeight then
    height = fontString:GetStringHeight()
  end
  if (not height or height <= 0) and fontString.GetHeight then
    height = fontString:GetHeight()
  end
  if not height or height <= 0 then
    height = fallbackHeight
  end
  if height < fallbackHeight then
    height = fallbackHeight
  end
  return height
end

