  for k, v in pairs(LeafVE_DB.lboard.updatedAt) do
    if type(v) == "number" then LeafVE_DB.lboard.updatedAt[k] = { lifetime = v } end
  end
  -- Migrate: ensure weekly[wk] entries are tables, not numbers
