    LeafVE_DB.pendingAllianceRequests = nil
    LeafVE_DB.allianceChatLog = nil
  end
  if LeafVE_DB.ui.welcomeSection == nil or LeafVE_DB.ui.welcomeSection == "" then LeafVE_DB.ui.welcomeSection = "guide" end
