  if not LeafVE_GlobalDB.workOrderCrafterSignupMeta then LeafVE_GlobalDB.workOrderCrafterSignupMeta = {} end
  if not LeafVE_GlobalDB.workOrderIdentityLinks then LeafVE_GlobalDB.workOrderIdentityLinks = {} end
  if LeafVE.allianceEnabled == true then
    if type(LeafVE_GlobalDB.allianceRosters) ~= "table" then LeafVE_GlobalDB.allianceRosters = {} end
    if type(LeafVE_GlobalDB.allianceAccessSnapshot) ~= "table" then LeafVE_GlobalDB.allianceAccessSnapshot = { updatedAt = 0, guilds = {} } end
    if type(LeafVE_GlobalDB.allianceAccessSnapshot.guilds) ~= "table" then LeafVE_GlobalDB.allianceAccessSnapshot.guilds = {} end
  else
    LeafVE_GlobalDB.allianceRosters = nil
    LeafVE_GlobalDB.allianceAccessSnapshot = nil
  end
  if LeafVE.guildBankEnabled == true then
    if not LeafVE_GlobalDB.guildBankConfig then LeafVE_GlobalDB.guildBankConfig = { owner = LeafVE.guildBankOwner, updatedAt = 0, updatedBy = "" } end
    if not LeafVE_GlobalDB.guildBankCache then LeafVE_GlobalDB.guildBankCache = { owner = LeafVE.guildBankOwner, updatedAt = 0, counts = {}, goldCopper = 0 } end
    if not LeafVE_GlobalDB.guildBankRequests then LeafVE_GlobalDB.guildBankRequests = {} end
    if not LeafVE_GlobalDB.guildBankHighValueItems then LeafVE_GlobalDB.guildBankHighValueItems = {} end
    if not LeafVE_GlobalDB.guildBankCategoryOverrides then LeafVE_GlobalDB.guildBankCategoryOverrides = {} end
  else
    LeafVE_GlobalDB.guildBankConfig = nil
    LeafVE_GlobalDB.guildBankCache = nil
    LeafVE_GlobalDB.guildBankRequests = nil
    LeafVE_GlobalDB.guildBankHighValueItems = nil
    LeafVE_GlobalDB.guildBankCategoryOverrides = nil
  end
  if not LeafVE_GlobalDB.guildEvents then LeafVE_GlobalDB.guildEvents = {} end
  if not LeafVE_GlobalDB.guildEventRSVPs then LeafVE_GlobalDB.guildEventRSVPs = {} end
  if LeafVE.raidSignupsEnabled == true then
    if not LeafVE_GlobalDB.raidEvents then LeafVE_GlobalDB.raidEvents = {} end
    if not LeafVE_GlobalDB.raidSignups then LeafVE_GlobalDB.raidSignups = {} end
  else
    LeafVE_GlobalDB.raidEvents = nil
    LeafVE_GlobalDB.raidSignups = nil
  end
  if not LeafVE_GlobalDB.fullWipeVersion then LeafVE_GlobalDB.fullWipeVersion = 0 end
  if not LeafVE_DB.badgesArchive then LeafVE_DB.badgesArchive = {} end
  -- Badge bucket follows full-wipe version so manual resets start a fresh badge season.
  local currentBadgeBucket = tonumber(LeafVE_GlobalDB.fullWipeVersion) or 0
  local storedBadgeBucket = tonumber(LeafVE_DB.badgeBucketVersion)
  if LeafVE_DB.badgeBucketMigrated ~= true then
    -- One-time migration for clients that had pre-bucket badge data.
    if currentBadgeBucket > 0 and type(LeafVE_DB.badges) == "table" and next(LeafVE_DB.badges) then
      LeafVE_DB.badgesArchive["legacy"] = LeafVE_DB.badges
      LeafVE_DB.badges = {}
      LeafVE_DB.badgesAnnounced = {}
    end
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
    LeafVE_DB.badgeBucketMigrated = true
  elseif storedBadgeBucket == nil then
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
  elseif storedBadgeBucket ~= currentBadgeBucket then
    if type(LeafVE_DB.badges) == "table" and next(LeafVE_DB.badges) then
      LeafVE_DB.badgesArchive[tostring(storedBadgeBucket)] = LeafVE_DB.badges
    end
    LeafVE_DB.badges = {}
    LeafVE_DB.badgesAnnounced = {}
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
  end
  -- Migration/safety: "__fw" is a transport marker, never a real badge entry.
  for _, badgeMap in pairs(LeafVE_DB.badges or {}) do
    if type(badgeMap) == "table" then
      badgeMap["__fw"] = nil
    end
  end
  PurgeRemovedBadgesFromContainer(LeafVE_DB.badges)
  for _, archivedSeason in pairs(LeafVE_DB.badgesArchive or {}) do
    PurgeRemovedBadgesFromContainer(archivedSeason)
  end
  for announcedKey in pairs(LeafVE_DB.badgesAnnounced or {}) do
    if announcedKey == "first_login" or (type(announcedKey) == "string" and string.sub(announcedKey, -12) == ":first_login") then
      LeafVE_DB.badgesAnnounced[announcedKey] = nil
    end
  end
  if LeafVE_DB.options.groupPoints == nil then LeafVE_DB.options.groupPoints = GROUP_POINTS end
  if LeafVE_DB.options.loginPoints == nil then LeafVE_DB.options.loginPoints = 20 end
  if not LeafVE_DB.raidProfile then LeafVE_DB.raidProfile = {} end
  if LeafVE_DB.raidProfile.defaultRole == nil then LeafVE_DB.raidProfile.defaultRole = "" end
end

local function LboardEntryTotal(entry)
  return entry and ((entry.L or 0) + (entry.G or 0) + (entry.S or 0)) or 0
end

local function SamePlayerName(a, b)
  local an = ShortName(a)
  local bn = ShortName(b)
  if not an or not bn then return false end
  return Lower(an) == Lower(bn)
end

function LeafVE:GetPlayerGuildName(unitToken)
  local guildName = nil
  if _G.GetGuildInfo then
    guildName = _G.GetGuildInfo(unitToken or "player")
  end
  return Trim(guildName or "")
end

function LeafVE:GetAllianceGuildList()
  EnsureDB()
  if self.allianceEnabled ~= true then
    return {}
  end

  local guilds = {}
  local seen = {}
  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild ~= "" then
    local lowerHome = Lower(homeGuild)
    seen[lowerHome] = true
    table.insert(guilds, {
      name = homeGuild,
      lowerName = lowerHome,
      isHomeGuild = true,
    })
  end

  for lowerName, entry in pairs(LeafVE_DB.allianceGuilds or {}) do
    local guildName = Trim((type(entry) == "table" and entry.name) or lowerName or "")
    local normalizedLower = Lower(guildName)
    if guildName ~= "" and not seen[normalizedLower] then
      seen[normalizedLower] = true
      table.insert(guilds, {
        name = guildName,
        lowerName = normalizedLower,
        isHomeGuild = false,
      })
    end
  end

  table.sort(guilds, function(a, b)
    if a.isHomeGuild ~= b.isHomeGuild then
      return a.isHomeGuild and true or false
    end
    return Lower(a.name or "") < Lower(b.name or "")
  end)

  return guilds
end

function LeafVE:GetAllianceBroadcastGuildList()
  EnsureDB()

  local guilds = {}
  local seen = {}

  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild ~= "" then
    local lowerHome = Lower(homeGuild)
    seen[lowerHome] = true
    table.insert(guilds, homeGuild)
  end

  for _, entry in pairs(LeafVE_DB.allianceGuilds or {}) do
    local guildName = Trim((type(entry) == "table" and entry.name) or entry or "")
    local lowerName = Lower(guildName)
    if guildName ~= "" and not seen[lowerName] then
      seen[lowerName] = true
      table.insert(guilds, guildName)
    end
  end

  table.sort(guilds, function(a, b)
    if homeGuild ~= "" then
      local aIsHome = Lower(a or "") == Lower(homeGuild)
      local bIsHome = Lower(b or "") == Lower(homeGuild)
      if aIsHome ~= bIsHome then
        return aIsHome and true or false
      end
    end
    return Lower(a or "") < Lower(b or "")
  end)

  return guilds
end

function LeafVE:SetAllianceAccessSnapshot(updatedAt, guildNames)
  EnsureDB()

  local snapshotAt = tonumber(updatedAt) or Now()
  local existing = LeafVE_GlobalDB.allianceAccessSnapshot
  if type(existing) == "table" and tonumber(existing.updatedAt or 0) > snapshotAt then
    return false
  end

  local normalized = {}
  local seen = {}
  for i = 1, table.getn(guildNames or {}) do
    local guildName = Trim(guildNames[i] or "")
    local lowerName = Lower(guildName)
    if guildName ~= "" and not seen[lowerName] then
      seen[lowerName] = true
      table.insert(normalized, guildName)
    end
  end
  table.sort(normalized, function(a, b) return Lower(a or "") < Lower(b or "") end)

  LeafVE_GlobalDB.allianceAccessSnapshot = {
    updatedAt = snapshotAt,
    guilds = normalized,
  }
  return true
end

function LeafVE:GetAllianceAccessSnapshot()
  EnsureDB()
  if type(LeafVE_GlobalDB.allianceAccessSnapshot) ~= "table" then
    LeafVE_GlobalDB.allianceAccessSnapshot = { updatedAt = 0, guilds = {} }
  end
  if type(LeafVE_GlobalDB.allianceAccessSnapshot.guilds) ~= "table" then
    LeafVE_GlobalDB.allianceAccessSnapshot.guilds = {}
  end
  return LeafVE_GlobalDB.allianceAccessSnapshot
end

function LeafVE:IsAllianceGuildAuthorized(guildName)
  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false
  end

  if not self.isAllianceStandalone then
    local homeGuild = self:GetPlayerGuildName("player")
    if homeGuild ~= "" and Lower(homeGuild) == Lower(trimmedGuild) then
      return true
    end

    for _, allowedGuild in ipairs(self:GetAllianceBroadcastGuildList()) do
      if Lower(allowedGuild or "") == Lower(trimmedGuild) then
        return true
      end
    end
  end

  local snapshot = self:GetAllianceAccessSnapshot()
  for i = 1, table.getn(snapshot.guilds or {}) do
    if Lower(snapshot.guilds[i] or "") == Lower(trimmedGuild) then
      return true
    end
  end

  return false
end

function LeafVE:BroadcastAllianceAccessSnapshot(force)
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 then
    if force then
      self:JoinAllianceChannel(false, false)
      self:ScheduleDeferred("leafve_alliance_access_retry", 1.0, function()
        LeafVE:BroadcastAllianceAccessSnapshot(false)
      end)
    end
    return false
  end

  local now = Now()
  self.lastAllianceAccessBroadcastAt = self.lastAllianceAccessBroadcastAt or 0
  if not force and (now - self.lastAllianceAccessBroadcastAt) < 10 then
    return false
  end

  local guilds = self:GetAllianceBroadcastGuildList()
  self:SetAllianceAccessSnapshot(now, guilds)

  local fields = { tostring(now) }
  for i = 1, table.getn(guilds) do
    table.insert(fields, EncodeTalentField(guilds[i] or ""))
  end

  self.lastAllianceAccessBroadcastAt = now
  self:SendAllianceControlMessage("CFGSYNC:", fields)
  return true
end

function LeafVE:RequestAllianceAccessSnapshot()
  return false
end

function LeafVE:BroadcastAllianceAccessDecision(guildName, decision)
  local trimmedGuild = Trim(guildName or "")
  local trimmedDecision = Lower(Trim(decision or ""))
  if trimmedGuild == "" or trimmedDecision == "" then
    return false
  end

  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 then
    self:JoinAllianceChannel(false, false)
    self:ScheduleDeferred("leafve_alliance_access_decision_" .. Lower(trimmedGuild), 1.0, function()
      LeafVE:BroadcastAllianceAccessDecision(trimmedGuild, trimmedDecision)
    end)
    return false
  end

  return self:SendAllianceControlMessage("ACCESSRESP:", {
    EncodeTalentField(trimmedGuild),
    EncodeTalentField(trimmedDecision),
    tostring(Now()),
  })
end

function LeafVE:GetAllianceAccessAddonChatType()
  local raidCount = type(GetNumRaidMembers) == "function" and tonumber(GetNumRaidMembers()) or 0
  if raidCount and raidCount > 0 then
    return "RAID"
  end

  local partyCount = type(GetNumPartyMembers) == "function" and tonumber(GetNumPartyMembers()) or 0
  if partyCount and partyCount > 0 then
    return "PARTY"
  end

  return nil
end

function LeafVE:SendAllianceAccessGroupDecision(targetPlayer, guildName, decision)
  local trimmedGuild = Trim(guildName or "")
  local trimmedDecision = Lower(Trim(decision or ""))
  local chatType = self:GetAllianceAccessAddonChatType()
  if trimmedGuild == "" or trimmedDecision == "" or chatType == nil or type(SendAddonMessage) ~= "function" then
    return false
  end

  local fieldSep = (self.allianceChat and self.allianceChat.fieldSep) or TALENT_RECORD_SEP
  local payload = "ACCESSRESP:" .. table.concat({
    EncodeTalentField(trimmedGuild),
    EncodeTalentField(trimmedDecision),
    tostring(Now()),
  }, fieldSep)
  SendAddonMessage(self.prefix, payload, chatType)
  return true
end

function LeafVE:SendAllianceGroupAddonMessage(payload)
  local chatType = self:GetAllianceAccessAddonChatType()
  if chatType == nil or type(SendAddonMessage) ~= "function" then
    return false
  end

  local maxPayloadLength = math.max(1, 254 - string.len(tostring(self.prefix or "")))
  if string.len(tostring(payload or "")) > maxPayloadLength then
    Print("Alliance addon payload was too large for 3.3.5 and was skipped.")
    return false
  end

  SendAddonMessage(self.prefix, payload, chatType)
  return true
end

function LeafVE:RunAllianceSafe(label, callback)
  if type(callback) ~= "function" then
    return false, "missing callback"
  end

  local ok, result = pcall(callback)
  if not ok then
    Print("Alliance " .. tostring(label or "operation") .. " error: " .. tostring(result))
    return false, tostring(result)
  end
  return true, result
end

function LeafVE:AddAllianceGuild(guildName)
  EnsureDB()

  if not self:IsAdminRank() then
    return false, "Only Kage and Hokage can manage alliances."
  end

  local trimmed = Trim(guildName or "")
  if trimmed == "" then
    return false, "Enter a guild name first."
  end

  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild ~= "" and Lower(homeGuild) == Lower(trimmed) then
    return false, "Your guild is already on the alliance board."
  end

  local lowerName = Lower(trimmed)
  local requestEntry = LeafVE_DB.pendingAllianceRequests[lowerName]
  local requestTarget = requestEntry and requestEntry.requestedBy or nil
  LeafVE_DB.allianceGuilds[lowerName] = {
    name = trimmed,
    addedAt = Now(),
    addedBy = ShortName(UnitName("player")) or "",
  }
  LeafVE_DB.pendingAllianceRequests[lowerName] = nil
  local okSnapshot, errSnapshot = self:RunAllianceSafe("access snapshot", function()
    LeafVE:SetAllianceAccessSnapshot(Now(), LeafVE:GetAllianceBroadcastGuildList())
  end)
  if not okSnapshot then
    return false, errSnapshot or "Unable to update alliance access snapshot."
  end

  self:RunAllianceSafe("access channel snapshot", function()
    LeafVE:BroadcastAllianceAccessSnapshot(true)
  end)
  if requestTarget and requestTarget ~= "" then
    self:RunAllianceSafe("group approval decision", function()
      LeafVE:SendAllianceAccessGroupDecision(requestTarget, trimmed, "approved")
    end)
  end
  self:RunAllianceSafe("group initial roster sync", function()
    LeafVE:BroadcastAllianceRosterSnapshot(true)
  end)
  self:RunAllianceSafe("channel approval decision", function()
    LeafVE:BroadcastAllianceAccessDecision(trimmed, "approved")
  end)
  return true
end

function LeafVE:RemoveAllianceGuild(guildName)
  EnsureDB()

  if not self:IsAdminRank() then
    return false, "Only Kage and Hokage can manage alliances."
  end

  local trimmed = Trim(guildName or "")
  if trimmed == "" then
    return false, "Select an alliance guild first."
  end

  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild ~= "" and Lower(homeGuild) == Lower(trimmed) then
    return false, "Your home guild cannot be removed from the alliance board."
  end

  LeafVE_DB.allianceGuilds[Lower(trimmed)] = nil
  LeafVE_DB.pendingAllianceRequests[Lower(trimmed)] = nil
  local okSnapshot, errSnapshot = self:RunAllianceSafe("access snapshot", function()
    LeafVE:SetAllianceAccessSnapshot(Now(), LeafVE:GetAllianceBroadcastGuildList())
  end)
  if not okSnapshot then
    return false, errSnapshot or "Unable to update alliance access snapshot."
  end

  self:RunAllianceSafe("access channel snapshot", function()
    LeafVE:BroadcastAllianceAccessSnapshot(true)
  end)
  self:RunAllianceSafe("channel remove decision", function()
    LeafVE:BroadcastAllianceAccessDecision(trimmed, "removed")
  end)
  return true
end

function LeafVE:GetPendingAllianceAccessRequests()
  EnsureDB()

  local requests = {}
  for lowerGuild, entry in pairs(LeafVE_DB.pendingAllianceRequests or {}) do
    if type(entry) == "table" then
      local guildName = Trim(entry.guildName or entry.name or lowerGuild or "")
      if guildName ~= "" then
        table.insert(requests, {
          guildName = guildName,
          lowerGuild = Lower(guildName),
          requestedBy = ShortName(entry.requestedBy) or Trim(entry.requestedBy or ""),
          requestedAt = tonumber(entry.requestedAt) or 0,
        })
      end
    end
  end

  table.sort(requests, function(a, b)
    local at = tonumber(a.requestedAt or 0)
    local bt = tonumber(b.requestedAt or 0)
    if at == bt then
      return Lower(a.guildName or "") < Lower(b.guildName or "")
    end
    return at > bt
  end)

  return requests
end

function LeafVE:QueueAllianceAccessRequest(guildName, requestedBy, requestedAt)
  EnsureDB()

  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false, "Missing guild name."
  end

  local lowerGuild = Lower(trimmedGuild)
  if self:IsAllianceGuildAuthorized(trimmedGuild) then
    self:BroadcastAllianceAccessSnapshot(true)
    if requestedBy and requestedBy ~= "" then
      self:SendAllianceAccessGroupDecision(requestedBy, trimmedGuild, "approved")
    end
    self:BroadcastAllianceAccessDecision(trimmedGuild, "approved")
    return false, "Guild already has alliance access."
  end

  local existing = LeafVE_DB.pendingAllianceRequests[lowerGuild]
  local isNew = type(existing) ~= "table"
  LeafVE_DB.pendingAllianceRequests[lowerGuild] = {
    guildName = trimmedGuild,
    requestedBy = ShortName(requestedBy) or Trim(requestedBy or ""),
    requestedAt = tonumber(requestedAt) or Now(),
  }
  return isNew, nil
end

function LeafVE:ClearAllianceAccessRequest(guildName)
  EnsureDB()

  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false
  end
  LeafVE_DB.pendingAllianceRequests[Lower(trimmedGuild)] = nil
  return true
end

function LeafVE:ApproveAllianceAccessRequest(guildName)
  local trimmedGuild = Trim(guildName or "")
  local requestEntry = LeafVE_DB and LeafVE_DB.pendingAllianceRequests and LeafVE_DB.pendingAllianceRequests[Lower(trimmedGuild)]
  local requestTarget = requestEntry and requestEntry.requestedBy or nil
  local ok, err = self:RunAllianceSafe("approve request", function()
    local approved, approveErr = LeafVE:AddAllianceGuild(trimmedGuild)
    if not approved then
      error(tostring(approveErr or "Unable to approve request."))
    end
    return true
  end)
  if ok then
    self:ClearAllianceAccessRequest(trimmedGuild)
  end
  return ok, err
end

function LeafVE:DenyAllianceAccessRequest(guildName)
  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false, "Select a pending request first."
  end
  local requestEntry = LeafVE_DB and LeafVE_DB.pendingAllianceRequests and LeafVE_DB.pendingAllianceRequests[Lower(trimmedGuild)]
  local requestTarget = requestEntry and requestEntry.requestedBy or nil
  self:ClearAllianceAccessRequest(trimmedGuild)
  if requestTarget and requestTarget ~= "" then
    self:RunAllianceSafe("group deny decision", function()
      LeafVE:SendAllianceAccessGroupDecision(requestTarget, trimmedGuild, "denied")
    end)
  end
  self:RunAllianceSafe("channel deny decision", function()
    LeafVE:BroadcastAllianceAccessDecision(trimmedGuild, "denied")
  end)
  return true
end

function LeafVE:ShowAllianceAccessApproval(guildName)
  if self.allianceEnabled ~= true then
    return false
  end
  if not self:IsAdminRank() or not self:HasLeafAccess() then
    return false
  end
  if not LeafVE.UI or not LeafVE.UI.Build then
    return false
  end

  if not LeafVE.UI.frame then
    LeafVE.UI:Build()
  end
  if not LeafVE.UI.frame then
    return false
  end

  LeafVE.UI.activeCategory = "welcome"
  LeafVE.UI.activeNavSubTab = nil
  LeafVE.UI.activeTab = "welcome"
  if LeafVE.UI.navLastTabByCategory then
    LeafVE.UI.navLastTabByCategory.welcome = "welcome"
  end

  if not LeafVE.UI.frame:IsVisible() then
    LeafVE.UI.frame:Show()
  end

  if LeafVE.UI.SetWelcomeSection then
    LeafVE.UI:SetWelcomeSection("alliance")
  end
  if LeafVE.UI.panels and LeafVE.UI.panels.welcome then
    LeafVE.UI.panels.welcome.selectedAllianceRequestGuild = Trim(guildName or "")
  end
  if LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
  if LeafVE.UI.RefreshAllianceWelcomePanel then
    LeafVE.UI:RefreshAllianceWelcomePanel()
  end
  return true
end

function LeafVE:SetAllianceRosterSnapshot(guildName, updatedAt, members, sourcePlayer)
  EnsureDB()

  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false
  end

  local lowerGuild = Lower(trimmedGuild)
  local existing = LeafVE_GlobalDB.allianceRosters and LeafVE_GlobalDB.allianceRosters[lowerGuild]
  updatedAt = tonumber(updatedAt) or Now()
  if existing and tonumber(existing.updatedAt or 0) > updatedAt then
    return false
  end

  local normalizedMembers = {}
  for i = 1, table.getn(members or {}) do
    local member = members[i]
    if type(member) == "table" and Trim(member.name or "") ~= "" then
      table.insert(normalizedMembers, {
        name = self:GetStoredDisplayPlayerName(member.name),
        rank = Trim(member.rank or ""),
        level = tonumber(member.level) or 0,
        classTag = string.upper(Trim(member.classTag or "UNKNOWN")),
        online = member.online == nil and true or (member.online and true or false),
      })
    end
  end

  table.sort(normalizedMembers, function(a, b)
    return Lower(a.name or "") < Lower(b.name or "")
  end)

  LeafVE_GlobalDB.allianceRosters[lowerGuild] = {
    guildName = trimmedGuild,
    updatedAt = updatedAt,
    sourcePlayer = ShortName(sourcePlayer) or "",
    members = normalizedMembers,
    onlineCount = table.getn(normalizedMembers),
  }
  return true
end

function LeafVE:ReceiveAllianceRosterChunk(sourcePlayer, guildName, updatedAt, chunkIndex, totalChunks, payloadChunk)
  local lowerGuild = Lower(guildName or "")
  if lowerGuild == "" then
    return false
  end

  updatedAt = tonumber(updatedAt) or 0
  chunkIndex = tonumber(chunkIndex) or 1
  totalChunks = math.max(1, tonumber(totalChunks) or 1)
  payloadChunk = payloadChunk or ""

  self.pendingAllianceRosterSyncs = self.pendingAllianceRosterSyncs or {}
  local pending = self.pendingAllianceRosterSyncs[lowerGuild]
  if type(pending) ~= "table" or tonumber(pending.updatedAt or 0) ~= updatedAt then
    pending = {
      guildName = guildName,
      updatedAt = updatedAt,
      sourcePlayer = ShortName(sourcePlayer) or "",
      totalChunks = totalChunks,
      chunks = {},
    }
    self.pendingAllianceRosterSyncs[lowerGuild] = pending
  end

  pending.totalChunks = totalChunks
  pending.chunks[chunkIndex] = payloadChunk

  local receivedCount = 0
  for i = 1, totalChunks do
    if pending.chunks[i] ~= nil then
      receivedCount = receivedCount + 1
    end
  end

  if receivedCount < totalChunks then
    return false
  end

  local members = {}
  local fieldSep = (self.allianceChat and self.allianceChat.fieldSep) or TALENT_RECORD_SEP
  local memberSep = (self.allianceChat and self.allianceChat.rosterMemberSep) or "<#>"
  for i = 1, totalChunks do
    local chunkText = pending.chunks[i] or ""
    if chunkText ~= "" then
      local memberEntries = SplitByLiteralSep(chunkText, memberSep)
      for entryIndex = 1, table.getn(memberEntries) do
        local memberFields = SplitByLiteralSep(memberEntries[entryIndex] or "", fieldSep)
        if Trim(memberFields[1] or "") ~= "" then
          table.insert(members, {
            name = DecodeTalentField(memberFields[1] or ""),
            rank = DecodeTalentField(memberFields[2] or ""),
            level = tonumber(memberFields[3]) or 0,
            classTag = DecodeTalentField(memberFields[4] or "UNKNOWN"),
            online = true,
          })
        end
      end
    end
  end

  self:SetAllianceRosterSnapshot(pending.guildName, pending.updatedAt, members, pending.sourcePlayer)
  self.pendingAllianceRosterSyncs[lowerGuild] = nil
  if LeafVE.UI and LeafVE.UI.RefreshAllianceWelcomePanel then
    LeafVE.UI:RefreshAllianceWelcomePanel()
  end
  return true
end

function LeafVE:BuildLocalAllianceRosterSnapshot()
  local guildName = self:GetPlayerGuildName("player")
  if guildName == "" then
    return nil
  end

  self:UpdateGuildRosterCache()

  local members = {}
  for _, info in pairs(self.guildRosterCache or {}) do
    if type(info) == "table" and info.online then
      table.insert(members, {
        name = self:GetStoredDisplayPlayerName(info.name or ""),
        rank = info.rank or "",
        level = tonumber(info.level) or 0,
        classTag = string.upper(Trim(info.class or "UNKNOWN")),
        online = true,
      })
    end
  end

  table.sort(members, function(a, b)
    local aRank = tostring(a.rank or "")
    local bRank = tostring(b.rank or "")
    if aRank == bRank then
      return Lower(a.name or "") < Lower(b.name or "")
    end
    return aRank < bRank
  end)

  return {
    guildName = guildName,
    updatedAt = Now(),
    members = members,
    onlineCount = table.getn(members),
  }
end

function LeafVE:CacheLocalAllianceRoster()
  local snapshot = self:BuildLocalAllianceRosterSnapshot()
  if not snapshot then
    return nil
  end
  self:SetAllianceRosterSnapshot(snapshot.guildName, snapshot.updatedAt, snapshot.members, UnitName("player"))
  return snapshot
end

function LeafVE:GetAllianceRosterSnapshot(guildName)
  EnsureDB()

  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return nil
  end

  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild ~= "" and Lower(homeGuild) == Lower(trimmedGuild) then
    return self:CacheLocalAllianceRoster()
  end

  return LeafVE_GlobalDB.allianceRosters and LeafVE_GlobalDB.allianceRosters[Lower(trimmedGuild)] or nil
end

function LeafVE:ResolveAllianceGuildForPlayer(playerName)
  local shortName = ShortName(playerName)
  if not shortName then
    return nil
  end

  local homeGuild = self:GetPlayerGuildName("player")
  local guildInfo = self:GetGuildInfo(shortName)
  if guildInfo and homeGuild ~= "" then
    return homeGuild
  end

  for _, snapshot in pairs(LeafVE_GlobalDB.allianceRosters or {}) do
    if type(snapshot) == "table" and type(snapshot.members) == "table" then
      for i = 1, table.getn(snapshot.members) do
        local member = snapshot.members[i]
        if member and SamePlayerName(member.name, shortName) then
          return snapshot.guildName
        end
      end
    end
  end

  return nil
end

function LeafVE:RecordAllianceChatMessage(author, message, timestamp, eventToken)
  EnsureDB()

  local cleaned = self:StripAllianceChatDecorators(message)
  cleaned = Trim(cleaned or "")
  if cleaned == "" then
    return false
  end

  local hiddenPrefix = self.allianceChat and self.allianceChat.hiddenPrefix or ""
  local controlPrefix = self.allianceChat and self.allianceChat.controlPrefix or ""
  if (hiddenPrefix ~= "" and string.sub(cleaned, 1, string.len(hiddenPrefix)) == hiddenPrefix)
    or (controlPrefix ~= "" and string.sub(cleaned, 1, string.len(controlPrefix)) == controlPrefix) then
    return false
  end

  if eventToken and eventToken ~= "" then
    local tokenAt = tonumber(self.lastAllianceChatLogTokenAt) or 0
    if self.lastAllianceChatLogToken == eventToken and (Now() - tokenAt) <= 2 then
      return false
    end
    self.lastAllianceChatLogToken = eventToken
    self.lastAllianceChatLogTokenAt = Now()
  end

  local record = {
    author = self:GetStoredDisplayPlayerName(author),
    guildName = self:ResolveAllianceGuildForPlayer(author) or "",
    message = cleaned,
    timestamp = tonumber(timestamp) or Now(),
  }

  table.insert(LeafVE_DB.allianceChatLog, record)
  while table.getn(LeafVE_DB.allianceChatLog) > 120 do
    table.remove(LeafVE_DB.allianceChatLog, 1)
  end

  if LeafVE.UI and LeafVE.UI.RefreshAllianceWelcomeChatHistory then
    LeafVE.UI:RefreshAllianceWelcomeChatHistory(true)
  elseif LeafVE.UI and LeafVE.UI.RefreshAllianceWelcomePanel then
    LeafVE.UI:RefreshAllianceWelcomePanel()
  end
  return true
end

function LeafVE:GetAllianceChatLog()
  EnsureDB()
  return LeafVE_DB.allianceChatLog or {}
end

function LeafVE:SendAllianceControlMessage(prefix, fields)
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 or type(SendChatMessage) ~= "function" then
    return false
  end

  local payload = tostring(prefix or "")
  if type(fields) == "table" and table.getn(fields) > 0 then
    payload = payload .. table.concat(fields, (self.allianceChat and self.allianceChat.fieldSep) or TALENT_RECORD_SEP)
  end

  local hiddenPrefix = (self.allianceChat and self.allianceChat.hiddenPrefix) or ""
  SendChatMessage(hiddenPrefix .. payload, "CHANNEL", nil, channelId)
  return true
end

function LeafVE:HandleAllianceControlMessage(author, message)
  local cleaned = self:StripAllianceChatDecorators(message)
  local hiddenPrefix = self.allianceChat and self.allianceChat.hiddenPrefix or ""
  local controlPrefix = self.allianceChat and self.allianceChat.controlPrefix or ""
  local fieldSep = (self.allianceChat and self.allianceChat.fieldSep) or TALENT_RECORD_SEP
  local payload = nil
  if hiddenPrefix ~= "" and string.sub(cleaned or "", 1, string.len(hiddenPrefix)) == hiddenPrefix then
    payload = string.sub(cleaned, string.len(hiddenPrefix) + 1)
  elseif controlPrefix ~= "" and string.sub(cleaned or "", 1, string.len(controlPrefix)) == controlPrefix then
    payload = string.sub(cleaned, string.len(controlPrefix) + 1)
  else
    return false
  end
  if string.sub(payload, 1, 10) == "ROSTERREQ:" then
    local fields = SplitByLiteralSep(string.sub(payload, 11), fieldSep)
    local requestedGuild = DecodeTalentField(fields[1] or "")
    local homeGuild = self:GetPlayerGuildName("player")
    if requestedGuild ~= "" and homeGuild ~= "" and Lower(requestedGuild) == Lower(homeGuild) and self:IsAllianceGuildAuthorized(homeGuild) and self:IsAllianceRosterBroadcaster() then
      self:ScheduleDeferred("alliance_roster_request_" .. Lower(homeGuild), 1.0, function()
        LeafVE:MaybeBroadcastAllianceRosterSnapshot(true)
      end)
    end
    return true
  end

  if string.sub(payload, 1, 11) == "ROSTERDATA:" then
    local fields = SplitByLiteralSep(string.sub(payload, 12), fieldSep)
    local payloadChunk = ""
    if table.getn(fields) >= 5 then
      payloadChunk = table.concat(fields, fieldSep, 5)
    end
    self:ReceiveAllianceRosterChunk(
      author,
      DecodeTalentField(fields[1] or ""),
      tonumber(fields[2]) or 0,
      tonumber(fields[3]) or 1,
      tonumber(fields[4]) or 1,
      payloadChunk
    )
    return true
  end

  if string.sub(payload, 1, 10) == "ACCESSREQ:" then
    local fields = SplitByLiteralSep(string.sub(payload, 11), fieldSep)
    local requestedGuild = DecodeTalentField(fields[1] or "")
    local requestedBy = ShortName(DecodeTalentField(fields[2] or "")) or ShortName(author) or ""
    local requestedAt = tonumber(fields[3]) or Now()
    local isNewRequest = self:QueueAllianceAccessRequest(requestedGuild, requestedBy, requestedAt)
    if requestedGuild ~= "" then
      self:ShowAllianceAccessApproval(requestedGuild)
    end
    if isNewRequest and requestedGuild ~= "" then
      Print("|cFFFFD700Alliance access request received:|r " .. tostring(requestedGuild) .. " |cFF888888(" .. tostring(requestedBy ~= "" and requestedBy or "Unknown") .. ")|r")
    end
    if LeafVE.UI and LeafVE.UI.RefreshAllianceWelcomePanel then
      LeafVE.UI:RefreshAllianceWelcomePanel()
    end
    return true
  end

  if string.sub(payload, 1, 8) == "CFGSYNC:" then
    local fields = SplitByLiteralSep(string.sub(payload, 9), fieldSep)
    local updatedAt = tonumber(fields[1]) or Now()
    local guilds = {}
    for i = 2, table.getn(fields) do
      table.insert(guilds, DecodeTalentField(fields[i] or ""))
    end
    self:SetAllianceAccessSnapshot(updatedAt, guilds)
    if LeafVE.UI and LeafVE.UI.RefreshAllianceWelcomePanel then
      LeafVE.UI:RefreshAllianceWelcomePanel()
    end
    return true
  end

  if string.sub(payload, 1, 7) == "CFGREQ:" then
    if not self.isAllianceStandalone and self:IsAdminRank() then
      self:BroadcastAllianceAccessSnapshot(true)
    end
    return true
  end

  return true
end

function LeafVE:BroadcastAllianceRosterSnapshot(force)
  local snapshot = self:CacheLocalAllianceRoster()
  if not snapshot then
    return false
  end

  local now = Now()
  self.lastAllianceRosterBroadcastAt = self.lastAllianceRosterBroadcastAt or 0
  if not force and (now - self.lastAllianceRosterBroadcastAt) < 30 then
    return false
  end

  local useGroupTransport = self:GetAllianceAccessAddonChatType() ~= nil
  local channelId = self:GetAllianceChannelId()
  if not useGroupTransport and channelId <= 0 then
    return false
  end

  self.lastAllianceRosterBroadcastAt = now
  local fieldSep = (self.allianceChat and self.allianceChat.fieldSep) or TALENT_RECORD_SEP
  local memberSep = (self.allianceChat and self.allianceChat.rosterMemberSep) or "<#>"
  local maxPayloadLength = math.max(1, 254 - string.len(tostring(self.prefix or "")))
  local headerReserve = string.len("ROSTERDATA:")
    + string.len(EncodeTalentField(snapshot.guildName or ""))
    + string.len(tostring(snapshot.updatedAt or now))
    + 20
  local chunks = {}
  local currentChunk = ""
  local maxChunkPayload = math.max(60, maxPayloadLength - headerReserve)
  for i = 1, table.getn(snapshot.members or {}) do
    local member = snapshot.members[i]
    local memberPayload = table.concat({
      EncodeTalentField(member.name or ""),
      EncodeTalentField(member.rank or ""),
      tostring(member.level or 0),
      EncodeTalentField(member.classTag or "UNKNOWN"),
    }, fieldSep)
    local combined = currentChunk
    if combined ~= "" then
      combined = combined .. memberSep .. memberPayload
    else
      combined = memberPayload
    end
    if currentChunk ~= "" and string.len(combined) > maxChunkPayload then
      table.insert(chunks, currentChunk)
      currentChunk = memberPayload
    else
      currentChunk = combined
    end
  end
  if currentChunk ~= "" then
    table.insert(chunks, currentChunk)
  end
  if table.getn(chunks) < 1 then
    table.insert(chunks, "")
  end

  local totalChunks = table.getn(chunks)
  for i = 1, totalChunks do
    local fields = {
      EncodeTalentField(snapshot.guildName or ""),
      tostring(snapshot.updatedAt or now),
      tostring(i),
      tostring(totalChunks),
      chunks[i] or "",
    }
    if useGroupTransport then
      self:SendAllianceGroupAddonMessage("ROSTERDATA:" .. table.concat(fields, fieldSep))
    else
      self:SendAllianceControlMessage("ROSTERDATA:", fields)
    end
  end
  return true
end

function LeafVE:RequestAllianceRosterSnapshot(guildName, force)
  local trimmedGuild = Trim(guildName or "")
  if trimmedGuild == "" then
    return false
  end

  local lowerGuild = Lower(trimmedGuild)
  local now = Now()
  self.lastAllianceRosterRequestAt = self.lastAllianceRosterRequestAt or {}
  if not force and (now - tonumber(self.lastAllianceRosterRequestAt[lowerGuild] or 0)) < 20 then
    return false
  end

  self.lastAllianceRosterRequestAt[lowerGuild] = now
  return self:SendAllianceControlMessage("ROSTERREQ:", {
    EncodeTalentField(trimmedGuild),
    tostring(now),
  })
end

function LeafVE:PruneAllianceRosterBroadcasterPeers()
  local now = Now()
  self.allianceRosterBroadcasterPeers = self.allianceRosterBroadcasterPeers or {}
  for lowerName, entry in pairs(self.allianceRosterBroadcasterPeers) do
    local seenAt = type(entry) == "table" and tonumber(entry.seenAt or 0) or tonumber(entry) or 0
    if seenAt <= 0 or (now - seenAt) > (LeafVE.allianceRosterBroadcasterTTL or 90) then
      self.allianceRosterBroadcasterPeers[lowerName] = nil
    end
  end
end

function LeafVE:RecordAllianceRosterBroadcasterPeer(playerName, seenAt)
  local shortName = ShortName(playerName)
  if not shortName then
    return false
  end

  self.allianceRosterBroadcasterPeers = self.allianceRosterBroadcasterPeers or {}
  self.allianceRosterBroadcasterPeers[Lower(shortName)] = {
    name = shortName,
    seenAt = tonumber(seenAt) or Now(),
  }
  self:PruneAllianceRosterBroadcasterPeers()
  return true
end

function LeafVE:BroadcastAllianceRosterPresence(force)
  if not InGuild() then
    return false
  end

  local me = ShortName(UnitName("player"))
  if not me then
    return false
  end

  local now = Now()
  self.lastAllianceRosterPresenceAt = self.lastAllianceRosterPresenceAt or 0
  if not force and (now - self.lastAllianceRosterPresenceAt) < 20 then
    return false
  end

  self.lastAllianceRosterPresenceAt = now
  self:RecordAllianceRosterBroadcasterPeer(me, now)
  SendAddonMessage("LeafVE", "ALLYPRES:" .. tostring(now), "GUILD")
  return true
end

function LeafVE:GetAllianceRosterBroadcasterName()
  self:PruneAllianceRosterBroadcasterPeers()

  local candidates = {}
  local me = ShortName(UnitName("player"))
  if me then
    table.insert(candidates, me)
  end

  for _, entry in pairs(self.allianceRosterBroadcasterPeers or {}) do
    local name = type(entry) == "table" and entry.name or nil
    if name and (not me or Lower(name) ~= Lower(me)) then
      table.insert(candidates, name)
    end
  end

  if table.getn(candidates) == 0 then
    return me
  end

  table.sort(candidates, function(a, b) return Lower(a or "") < Lower(b or "") end)
  return candidates[1]
end

function LeafVE:IsAllianceRosterBroadcaster()
  local me = ShortName(UnitName("player"))
  local broadcaster = self:GetAllianceRosterBroadcasterName()
  if not me or not broadcaster then
    return false
  end
  return Lower(me) == Lower(broadcaster)
end

function LeafVE:BuildAllianceRosterSnapshotHash(snapshot)
  if type(snapshot) ~= "table" then
    return ""
  end

  local parts = {
    tostring(snapshot.guildName or ""),
    tostring(snapshot.onlineCount or 0),
  }

  for i = 1, table.getn(snapshot.members or {}) do
    local member = snapshot.members[i]
    table.insert(parts, table.concat({
      tostring(member.name or ""),
      tostring(member.rank or ""),
      tostring(member.level or 0),
      tostring(member.classTag or ""),
    }, ":"))
  end

  return table.concat(parts, "|")
end

function LeafVE:MaybeBroadcastAllianceRosterSnapshot(force)
  local homeGuild = self:GetPlayerGuildName("player")
  if homeGuild == "" or not self:IsAllianceGuildAuthorized(homeGuild) then
    return false
  end

  if not force and not self:IsAllianceRosterBroadcaster() then
    return false
  end

  local snapshot = self:CacheLocalAllianceRoster()
  if not snapshot then
    return false
  end

  local snapshotHash = self:BuildAllianceRosterSnapshotHash(snapshot)
  if not force and snapshotHash ~= "" and snapshotHash == (self.lastAllianceRosterBroadcastHash or "") then
    return false
  end

  local broadcasted = self:BroadcastAllianceRosterSnapshot(force)
  if broadcasted then
    self.lastAllianceRosterBroadcastHash = snapshotHash
  end
  return broadcasted
end

function LeafVE:SendAllianceChatMessage(text, retryCount)
  if self.allianceEnabled ~= true then
    return false, "This channel has been removed from this version."
  end
  local outgoing = Trim(text or "")
  if outgoing == "" then
    return false, "Type a message first."
  end

  retryCount = tonumber(retryCount) or 0
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 then
    self:JoinAllianceChannel(false, true)
    if retryCount < 1 then
      self:ScheduleDeferred("alliance_chat_send_retry", 1.0, function()
        LeafVE:SendAllianceChatMessage(outgoing, retryCount + 1)
      end)
    end
    return false, "Joining channel..."
  end

  SendChatMessage(outgoing, "CHANNEL", nil, channelId)
  return true
end

function LeafVE:GetAllianceChannelName()
  return LeafVE.allianceChat.name
end

function LeafVE:GetAllianceChannelPassword()
  return LeafVE.allianceChat.password
end

function LeafVE:GetAllianceDisplayLabel()
  return LeafVE.allianceChat.label
end

function LeafVE:GetAllianceChannelId()
  if self.allianceEnabled ~= true then
    return 0
  end
  local channelId = 0
  if type(GetChannelName) == "function" then
    local lookupId = GetChannelName(self:GetAllianceChannelName())
    channelId = tonumber(lookupId) or 0
  end
  if channelId > 0 then
    self.allianceChannelId = channelId
  end
  return channelId
end

function LeafVE:IsAllianceMessageChannel(channelString, channelName, channelNumber)
  local desiredName = Lower(self:GetAllianceChannelName())
  local normalizedString = Lower(Trim(channelString or ""))
  local normalizedName = Lower(Trim(channelName or ""))
  local activeChannelId = self:GetAllianceChannelId()

  if normalizedName ~= "" then
    if normalizedName == desiredName then
      return true
    end
    if string.find(normalizedName, desiredName, 1, true) then
      return true
    end
  end

  if normalizedString ~= "" and string.find(normalizedString, desiredName, 1, true) then
    return true
  end

  if activeChannelId > 0 and tonumber(channelNumber) == activeChannelId then
    return true
  end

  return false
end

function LeafVE:IsAllianceOutgoingChannel(channelTarget)
  local activeChannelId = self:GetAllianceChannelId()
  local desiredName = Lower(self:GetAllianceChannelName())
  local normalizedTarget = Lower(Trim(tostring(channelTarget or "")))

  if normalizedTarget == "" then
    return false
  end
  if normalizedTarget == desiredName then
    return true
  end
  if string.find(normalizedTarget, desiredName, 1, true) then
    return true
  end
  if activeChannelId > 0 and tonumber(channelTarget) == activeChannelId then
    return true
  end

  return false
end

function LeafVE:BuildAllianceOutgoingPrefix()
  return LeafVE.allianceChat.prefixColor .. "[" .. self:GetAllianceDisplayLabel() .. "]|r " .. LeafVE.allianceChat.messageColor
end

function LeafVE:BuildAlliancePlainOutgoingPrefix()
  return "[" .. self:GetAllianceDisplayLabel() .. "] "
end

function LeafVE:StripAllianceChatDecorators(message)
  local text = tostring(message or "")
  local prefix = self:BuildAllianceOutgoingPrefix()
  local plainPrefix = self:BuildAlliancePlainOutgoingPrefix()
  local legacyPlainPrefix = "[Alliance] "

  if string.sub(text, 1, string.len(prefix)) == prefix then
    text = string.sub(text, string.len(prefix) + 1)
    if string.sub(text, -2) == "|r" then
      text = string.sub(text, 1, -3)
    end
  end

  if string.sub(text, 1, string.len(plainPrefix)) == plainPrefix then
    text = string.sub(text, string.len(plainPrefix) + 1)
  end

  if string.sub(text, 1, string.len(legacyPlainPrefix)) == legacyPlainPrefix then
    text = string.sub(text, string.len(legacyPlainPrefix) + 1)
  end

  text = string.gsub(text, "^%[" .. EscapePattern(self:GetAllianceDisplayLabel()) .. "%]%s*", "")
  text = string.gsub(text, "^%[Alliance%]%s*", "")
  return text
end

function LeafVE:BuildAllianceFormattedLine(author, message)
  local displayAuthor = ShortName(author) or Trim(author or "")
  local displayMessage = self:StripAllianceChatDecorators(message)

  if displayAuthor == nil or displayAuthor == "" then
    displayAuthor = "Unknown"
  end

  return LeafVE.allianceChat.prefixColor .. "[" .. self:GetAllianceDisplayLabel() .. "]|r [" .. displayAuthor .. "]: " .. LeafVE.allianceChat.messageColor .. displayMessage .. "|r"
end

function LeafVE:BuildAlliancePanelLine(author, message, timestamp, guildName)
  local displayAuthor = Trim(author or "")
  local displayMessage = Trim(self:StripAllianceChatDecorators(message) or "")
  local displayGuild = Trim(guildName or "")
  local timeText = date("%H:%M", tonumber(timestamp) or Now())

  if displayAuthor == "" then
    displayAuthor = "Unknown"
  end
  if displayGuild == "" then
    displayGuild = self:ResolveAllianceGuildForPlayer(displayAuthor) or ""
  end
  if displayGuild == "" then
    displayGuild = "Unknown Guild"
  end

  return "|cFF888888[" .. timeText .. "]|r: |cFFFFD700" .. displayAuthor .. "|r: |cFF88CC88" .. displayGuild .. "|r: "
    .. LeafVE.allianceChat.messageColor .. displayMessage .. "|r"
end

function LeafVE:IsAllianceSystemNoticeText(text)
  text = Lower(Trim(text or ""))
  if text == "" then
    return false
  end

  return string.find(text, "owner changed to", 1, true) ~= nil
    or string.find(text, "changed owner to", 1, true) ~= nil
    or string.find(text, "channel owner", 1, true) ~= nil
    or string.find(text, "joined channel", 1, true) ~= nil
    or string.find(text, "left channel", 1, true) ~= nil
end

function LeafVE:MessageTargetsAllianceChannel(text)
  text = Lower(Trim(text or ""))
  local desiredName = Lower(self:GetAllianceChannelName() or "")
  local channelId = tonumber(self:GetAllianceChannelId()) or 0

  if text == "" then
    return false
  end
  if desiredName ~= "" and string.find(text, desiredName, 1, true) ~= nil then
    return true
  end
  if channelId > 0 then
    local channelToken = "[" .. tostring(channelId) .. "]"
    if string.find(text, Lower(channelToken), 1, true) ~= nil
      or string.find(text, tostring(channelId) .. ".", 1, true) ~= nil then
      return true
    end
  end
  return false
end

function LeafVE:ShouldSuppressAllianceSystemMessage(message)
  local text = Lower(Trim(message or ""))
  if not self:IsAllianceSystemNoticeText(text) then
    return false
  end
  return self:MessageTargetsAllianceChannel(text)
end

function LeafVE:ShouldSuppressAllianceNoticeEvent(...)
  local args = arg or {}
  local argCount = args.n or table.getn(args)
  local parts = {}
  for i = 1, argCount do
    local value = args[i]
    if value ~= nil and value ~= "" then
      table.insert(parts, Lower(tostring(value)))
    end
  end

  local combined = table.concat(parts, " ")
  if combined == "" then
    return false
  end
  if not (
    string.find(combined, "joined", 1, true) ~= nil
    or string.find(combined, "left", 1, true) ~= nil
    or string.find(combined, "owner", 1, true) ~= nil
  ) then
    return false
  end
  return self:MessageTargetsAllianceChannel(combined)
end

function LeafVE:ShouldSuppressAllianceRenderedText(text)
  local rendered = tostring(text or "")
  local hiddenPrefix = LeafVE.allianceChat and LeafVE.allianceChat.hiddenPrefix or ""
  if hiddenPrefix ~= "" and string.find(rendered, hiddenPrefix, 1, true) ~= nil then
    return true
  end
  local controlPrefix = LeafVE.allianceChat and LeafVE.allianceChat.controlPrefix or ""
  if controlPrefix ~= "" and string.find(rendered, controlPrefix, 1, true) ~= nil then
    return true
  end
  return self:ShouldSuppressAllianceSystemMessage(rendered)
end

function LeafVE:StripAllianceRenderedMarkup(text)
  local cleaned = tostring(text or "")
  cleaned = string.gsub(cleaned, "|c%x%x%x%x%x%x%x%x", "")
  cleaned = string.gsub(cleaned, "|r", "")
  cleaned = string.gsub(cleaned, "|H.-|h", "")
  cleaned = string.gsub(cleaned, "|h", "")
  return cleaned
end

function LeafVE:TryFormatAllianceRenderedText(text)
  local rendered = tostring(text or "")
  if rendered == "" then
    return nil
  end
  if string.find(rendered, LeafVE.allianceChat.prefixColor, 1, true) ~= nil
    and string.find(rendered, "[" .. self:GetAllianceDisplayLabel() .. "]", 1, true) ~= nil then
    return nil
  end

  local renderedPlain = self:StripAllianceRenderedMarkup(rendered)
  local channelTag, author = string.match(renderedPlain, "^%[([^%]]+)%]%s*%[([^%]]+)%]:")
  if not channelTag then
    channelTag, author = string.match(renderedPlain, "^%[([^%]]+)%]%s*([^:]+):")
  end
  if not channelTag or not author then
    return nil
  end
  if string.find(Lower(channelTag), Lower(self:GetAllianceChannelName()), 1, true) == nil then
    return nil
  end

  local separatorStart, separatorEnd = string.find(rendered, ": ", 1, true)
  local message = ""
  if separatorEnd then
    message = string.sub(rendered, separatorEnd + 1)
  end

  author = Trim(string.gsub(author, "^%[", ""))
  author = Trim(string.gsub(author, "%]$", ""))

  return self:BuildAllianceFormattedLine(author, message)
end

function LeafVE:IsRenderedGuildChannelTag(channelTag)
  local normalized = Lower(Trim(channelTag or ""))
  return normalized == "g"
    or normalized == "guild"
    or string.find(normalized, "guild", 1, true) ~= nil
end

function LeafVE:TryFormatGuildMessagePayload(eventName, message)
  if string.upper(tostring(eventName or "")) ~= "CHAT_MSG_GUILD" then
    return nil
  end

  local formatted = tostring(message or "")
  if formatted == "" then
    return nil
  end

  local changed = false
  local recoloredLinks = self:ApplyGuildAnnouncementLinkColors(formatted)
  if recoloredLinks ~= formatted then
    formatted = recoloredLinks
    changed = true
  end

  if string.find(formatted, "|Hleafve_title:", 1, true) == nil then
    for i = 1, table.getn(self.titleDefinitions or {}) do
      local titleDef = self.titleDefinitions[i]
      local titleText = titleDef and tostring(titleDef.title or "") or ""
      if titleText ~= "" then
        local bracketedPrefix = "[" .. titleText .. "] "
        local plainPrefix = titleText .. " "
        local matchedPrefix = nil
        local includeBrackets = false
        if string.sub(formatted, 1, string.len(bracketedPrefix)) == bracketedPrefix then
          matchedPrefix = bracketedPrefix
          includeBrackets = true
        elseif string.sub(formatted, 1, string.len(plainPrefix)) == plainPrefix then
          matchedPrefix = plainPrefix
        end

        if matchedPrefix then
          local titleLink = self:GetChatTitleLink(titleDef, includeBrackets)
          if titleLink then
            formatted = titleLink .. " " .. string.sub(formatted, string.len(matchedPrefix) + 1)
            changed = true
          end
          break
        end
      end
    end
  end

  local titleToken = string.match(formatted, "^(%[?[^%]]+%])%s+")
  if titleToken and string.sub(formatted, 1, 4) ~= "|cFF" then
    local titleName = string.gsub(titleToken, "^%[", "")
    titleName = string.gsub(titleName, "%]$", "")
    if titleName ~= "" then
      local titleDef = nil
      for i = 1, table.getn(self.titleDefinitions or {}) do
        local entry = self.titleDefinitions[i]
        if entry and entry.title == titleName then
          titleDef = entry
          break
        end
      end
      if titleDef then
        local sourceBadge = GetBadgeDefinition(titleDef.badgeId)
        local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
        local coloredTitle = "|cFF" .. RGBToHex(tr, tg, tb) .. "[" .. tostring(titleDef.title or titleName) .. "]|r"
        local plainPrefix = titleToken .. " "
        formatted = coloredTitle .. " " .. string.sub(formatted, string.len(plainPrefix) + 1)
        changed = true
      end
    end
  end

  if string.find(formatted, "|cFF", 1, true) == nil or string.find(formatted, "|r", 1, true) == nil then
    local plainMessage = self:StripAllianceRenderedMarkup(formatted)
    local badgeName = string.match(plainMessage, "^earned %[(.-)%]")
    if badgeName and badgeName ~= "" then
      local badge = nil
      for i = 1, table.getn(BADGES) do
        if BADGES[i] and BADGES[i].name == badgeName then
          badge = BADGES[i]
          break
        end
      end

      if badge then
        local qr, qg, qb = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
        local linkedBadgeName = "|cFF" .. RGBToHex(qr, qg, qb) .. "[" .. badgeName .. "]|r"
        local plainBadgeText = "[" .. badgeName .. "]"
        local badgeStart, badgeEnd = string.find(formatted, plainBadgeText, 1, true)
        if badgeStart and badgeEnd then
          formatted = string.sub(formatted, 1, badgeStart - 1) .. linkedBadgeName .. string.sub(formatted, badgeEnd + 1)
          changed = true
        end

        local unlockedTitle = self:GetTitleDefinition(badge.id)
        if unlockedTitle and unlockedTitle.title and unlockedTitle.title ~= "" then
          local bracketedTitle = "[" .. tostring(unlockedTitle.title) .. "]"
          local titleStart, titleEnd = string.find(formatted, bracketedTitle, 1, true)
          if titleStart and titleEnd then
            local coloredTitle = "|cFF" .. RGBToHex(qr, qg, qb) .. bracketedTitle .. "|r"
            formatted = string.sub(formatted, 1, titleStart - 1) .. coloredTitle .. string.sub(formatted, titleEnd + 1)
            changed = true
          end
        end
      end
    end
  end

  if changed and formatted ~= tostring(message or "") then
    return formatted
  end
  return nil
end

function LeafVE:ApplyGuildAnnouncementLinkColors(text)
  local formatted = tostring(text or "")
  if formatted == "" then
    return formatted
  end
  if string.find(formatted, "|Hleafve_", 1, true) == nil then
    return formatted
  end
  if string.find(formatted, "|c%x%x%x%x%x%x%x%x|Hleafve_badge:") or string.find(formatted, "|c%x%x%x%x%x%x%x%x|Hleafve_title:") then
    return formatted
  end

  formatted = string.gsub(formatted, "(|Hleafve_badge:([^|]+)|h.-|h)", function(linkMarkup, badgeId)
    local badge = GetBadgeDefinition(badgeId)
    if not badge then
      return linkMarkup
    end
    local qr, qg, qb = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
    return "|cFF" .. RGBToHex(qr, qg, qb) .. linkMarkup .. "|r"
  end)

  formatted = string.gsub(formatted, "(|Hleafve_title:([^|]+)|h.-|h)", function(linkMarkup, titleId)
    local titleDef = self:GetTitleDefinition(titleId)
    if not titleDef then
      return linkMarkup
    end
    local sourceBadge = GetBadgeDefinition(titleDef.badgeId)
    local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
    return "|cFF" .. RGBToHex(tr, tg, tb) .. linkMarkup .. "|r"
  end)

  if string.find(formatted, "|Hleafve_title:", 1, true) == nil then
    local linkedBadgeId = string.match(formatted, "|Hleafve_badge:([^|]+)|h")
    if linkedBadgeId then
      local unlockedTitle = self:GetTitleDefinition(linkedBadgeId)
      if unlockedTitle and unlockedTitle.title and unlockedTitle.title ~= "" then
        local bracketedTitle = "[" .. tostring(unlockedTitle.title) .. "]"
        local titleLink = self:GetChatTitleLink(unlockedTitle, true)
        local titleStart, titleEnd = string.find(formatted, bracketedTitle, 1, true)
        if titleLink and titleStart and titleEnd then
          formatted = string.sub(formatted, 1, titleStart - 1) .. titleLink .. string.sub(formatted, titleEnd + 1)
        end
      end
    end
  end

  return formatted
end

function LeafVE:TryFormatGuildTitleRenderedText(text)
  local rendered = tostring(text or "")
  if rendered == "" then
    return nil
  end

  local separatorStart, separatorEnd = string.find(rendered, ": ", 1, true)
  if separatorEnd then
    local messageRendered = string.sub(rendered, separatorEnd + 1)
    if string.sub(messageRendered, 1, 4) == "|cFF" then
      return nil
    end
  end

  local renderedPlain = self:StripAllianceRenderedMarkup(rendered)
  local channelTag, author, messagePlain = string.match(renderedPlain, "^%[([^%]]+)%]%s*%[([^%]]+)%]:%s*(.+)$")
  if not channelTag then
    channelTag, author, messagePlain = string.match(renderedPlain, "^%[([^%]]+)%]%s*([^:]+):%s*(.+)$")
  end
  if not channelTag or not author or not messagePlain then
    return nil
  end
  if not self:IsRenderedGuildChannelTag(channelTag) then
    return nil
  end

  local shortAuthor = ShortName(author)
  if not shortAuthor then
    return nil
  end

  local titleToken = string.match(messagePlain, "^(%[?[^%]]+%])%s+")
  if not titleToken or titleToken == "" then
    return nil
  end

  local plainPrefix = titleToken .. " "
  if string.sub(messagePlain, 1, string.len(plainPrefix)) ~= plainPrefix then
    return nil
  end

  local titleName = string.gsub(titleToken, "^%[", "")
  titleName = string.gsub(titleName, "%]$", "")
  if titleName == "" then
    return nil
  end

  local titleDef = nil
  for i = 1, table.getn(self.titleDefinitions or {}) do
    local entry = self.titleDefinitions[i]
    if entry and entry.title == titleName then
      titleDef = entry
      break
    end
  end
  if not titleDef then
    return nil
  end
  local sourceBadge = nil
  for i = 1, table.getn(BADGES) do
    local badge = BADGES[i]
    if badge and badge.id == titleDef.badgeId then
      sourceBadge = badge
      break
    end
  end
  local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
  local coloredPrefix = "|cFF" .. RGBToHex(tr, tg, tb) .. "[" .. tostring(titleDef.title or "") .. "]|r"

  separatorStart, separatorEnd = string.find(rendered, ": ", 1, true)
  if not separatorEnd then
    return nil
  end

  local messageRendered = string.sub(rendered, separatorEnd + 1)
  if string.sub(messageRendered, 1, string.len(plainPrefix)) ~= plainPrefix then
    return nil
  end

  return string.sub(rendered, 1, separatorEnd) .. coloredPrefix .. " " .. string.sub(messageRendered, string.len(plainPrefix) + 1)
end

function LeafVE:TryFormatGuildBadgeAnnouncementRenderedText(text)
  local rendered = tostring(text or "")
  if rendered == "" then
    return nil
  end

  local renderedPlain = self:StripAllianceRenderedMarkup(rendered)
  local channelTag, author, messagePlain = string.match(renderedPlain, "^%[([^%]]+)%]%s*%[([^%]]+)%]:%s*(.+)$")
  if not channelTag then
    channelTag, author, messagePlain = string.match(renderedPlain, "^%[([^%]]+)%]%s*([^:]+):%s*(.+)$")
  end
  if not channelTag or not author or not messagePlain then
    return nil
  end
  if not self:IsRenderedGuildChannelTag(channelTag) then
    return nil
  end

  local badgeName = string.match(messagePlain, "^earned %[(.-)%]")
  if not badgeName or badgeName == "" then
    return nil
  end

  local badge
  for i = 1, table.getn(BADGES) do
    if BADGES[i] and BADGES[i].name == badgeName then
      badge = BADGES[i]
      break
    end
  end
  if not badge then
    return nil
  end

  local qr, qg, qb = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
  local linkedBadgeName = "|cFF" .. RGBToHex(qr, qg, qb) .. "[" .. badgeName .. "]|r"

  local separatorStart, separatorEnd = string.find(rendered, ": ", 1, true)
  if not separatorEnd then
    return nil
  end
  local messageRendered = string.sub(rendered, separatorEnd + 1)
  if string.find(messageRendered, "|cFF", 1, true) ~= nil and string.find(messageRendered, "|r", 1, true) ~= nil then
    return nil
  end

  local prefix = string.sub(rendered, 1, separatorEnd)
  local suffix = messageRendered
  local plainBadgeText = "[" .. badgeName .. "]"
  local badgeStart, badgeEnd = string.find(suffix, plainBadgeText, 1, true)
  if not badgeStart or not badgeEnd then
    return nil
  end

  local formatted = prefix .. string.sub(suffix, 1, badgeStart - 1) .. linkedBadgeName .. string.sub(suffix, badgeEnd + 1)

  local unlockedTitle = self:GetTitleDefinition(badge.id)
  if unlockedTitle and unlockedTitle.title and unlockedTitle.title ~= "" then
    local bracketedTitle = "[" .. tostring(unlockedTitle.title) .. "]"
    local titleStart, titleEnd = string.find(formatted, bracketedTitle, 1, true)
    if titleStart and titleEnd then
      local coloredTitle = "|cFF" .. RGBToHex(qr, qg, qb) .. bracketedTitle .. "|r"
      formatted = string.sub(formatted, 1, titleStart - 1) .. coloredTitle .. string.sub(formatted, titleEnd + 1)
    else
      local plainTitleText = tostring(unlockedTitle.title) .. "]"
      local fallbackStart, fallbackEnd = string.find(formatted, plainTitleText, 1, true)
      if fallbackStart and fallbackEnd then
        local coloredFallback = "|cFF" .. RGBToHex(qr, qg, qb) .. tostring(unlockedTitle.title) .. "]|r"
        formatted = string.sub(formatted, 1, fallbackStart - 1) .. coloredFallback .. string.sub(formatted, fallbackEnd + 1)
      end
    end
  end

  return formatted
end

function LeafVE:WrapAllianceChatFrame(frame)
  if not frame or type(frame.AddMessage) ~= "function" then
    return false
  end
  if frame.leafVEAllianceWrapped and frame.AddMessage == frame.leafVEAllianceWrappedAddMessage then
    return false
  end

  frame.leafVEAllianceOriginalAddMessage = frame.AddMessage
  frame.leafVEAllianceWrappedAddMessage = function(selfFrame, text, r, g, b, chatTypeID, holdTime, accessID, lineID)
    if LeafVE and LeafVE.ShouldSuppressAllianceRenderedText and LeafVE:ShouldSuppressAllianceRenderedText(text) then
      return
    end
    if LeafVE and LeafVE.TryFormatAllianceRenderedText then
      local formatted = LeafVE:TryFormatAllianceRenderedText(text)
      if formatted then
        return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, formatted, r, g, b, chatTypeID, holdTime, accessID, lineID)
      end
    end
    if LeafVE and LeafVE.ApplyGuildAnnouncementLinkColors then
      local linkedFormatted = LeafVE:ApplyGuildAnnouncementLinkColors(text)
      if linkedFormatted and linkedFormatted ~= text then
        return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, linkedFormatted, r, g, b, chatTypeID, holdTime, accessID, lineID)
      end
    end
    if LeafVE and LeafVE.TryFormatGuildTitleRenderedText then
      local titleFormatted = LeafVE:TryFormatGuildTitleRenderedText(text)
      if titleFormatted then
        return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, titleFormatted, r, g, b, chatTypeID, holdTime, accessID, lineID)
      end
    end
    if LeafVE and LeafVE.TryFormatGuildBadgeAnnouncementRenderedText then
      local badgeFormatted = LeafVE:TryFormatGuildBadgeAnnouncementRenderedText(text)
      if badgeFormatted then
        return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, badgeFormatted, r, g, b, chatTypeID, holdTime, accessID, lineID)
      end
    end
    return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, text, r, g, b, chatTypeID, holdTime, accessID, lineID)
  end
  frame.AddMessage = frame.leafVEAllianceWrappedAddMessage

  frame.leafVEAllianceWrapped = true
  return true
end

function LeafVE:InstallAllianceRenderedMessageSuppression()
  if self.allianceRenderedSuppressionInstalled then
    return
  end

  self.allianceRenderedSuppressionInstalled = true

  local totalFrames = tonumber(NUM_CHAT_WINDOWS) or 7
  for i = 1, totalFrames do
    self:WrapAllianceChatFrame(_G["ChatFrame" .. tostring(i)])
  end
  self:WrapAllianceChatFrame(DEFAULT_CHAT_FRAME)
  self:WrapAllianceChatFrame(SELECTED_CHAT_FRAME)
end

function LeafVE:HandleAllianceChatFrameMessage(chatFrame, eventName, message, author, languageName, channelString, target, flags, unknown1, channelNumber, channelName, unknown2, counter)
  if eventName == "CHAT_MSG_CHANNEL_NOTICE" or eventName == "CHAT_MSG_CHANNEL_NOTICE_USER" then
    if self:ShouldSuppressAllianceNoticeEvent(message, author, languageName, channelString, target, flags, unknown1, channelNumber, channelName, unknown2, counter) then
      return true
    end
  end

  if eventName == "CHAT_MSG_SYSTEM" and self:ShouldSuppressAllianceSystemMessage(message) then
    return true
  end

  if eventName == "CHAT_MSG_CHANNEL" and self:IsAllianceMessageChannel(channelString, channelName, channelNumber) then
    if self:HandleAllianceControlMessage(author, message) then
      return true
    end
    local cleaned = Trim(self:StripAllianceChatDecorators(message) or "")
    local eventToken = table.concat({
      tostring(channelNumber or channelName or ""),
      tostring(counter or ""),
      Lower(ShortName(author) or author or ""),
      cleaned,
    }, "|")
    self:RecordAllianceChatMessage(author, message, Now(), eventToken)
    return false
  end

  return false
end

function LeafVE:InstallAllianceChatHandler()
  if self.allianceChatHandlerInstalled and ChatFrame_MessageEventHandler == self.wrappedAllianceMessageEventHandler then
    return
  end
  if type(ChatFrame_MessageEventHandler) ~= "function" then
    return
  end

  self.allianceChatHandlerInstalled = true
  self.originalAllianceMessageEventHandler = ChatFrame_MessageEventHandler
  self.wrappedAllianceMessageEventHandler = function(...)
    local args = arg or {}
    args.n = args.n or table.getn(args)
    local chatFrame
    local eventName
    local message
    local author
    local languageName
    local channelString
    local target
    local flags
    local unknown1
    local channelNumber
    local channelName
    local unknown2
    local counter

    if type(args[1]) == "table" and args[1].AddMessage then
      chatFrame = args[1]
      eventName = args[2]
      message = args[3]
      author = args[4]
      languageName = args[5]
      channelString = args[6]
      target = args[7]
      flags = args[8]
      unknown1 = args[9]
      channelNumber = args[10]
      channelName = args[11]
      unknown2 = args[12]
      counter = args[13]
    else
      chatFrame = (type(this) == "table" and this.AddMessage and this) or DEFAULT_CHAT_FRAME
      eventName = args[1]
      message = args[2]
      author = args[3]
      languageName = args[4]
      channelString = args[5]
      target = args[6]
      flags = args[7]
      unknown1 = args[8]
      channelNumber = args[9]
      channelName = args[10]
      unknown2 = args[11]
      counter = args[12]
    end

    if LeafVE and LeafVE.HandleAllianceChatFrameMessage then
      local ok, handled = pcall(
        LeafVE.HandleAllianceChatFrameMessage,
        LeafVE,
        chatFrame,
        eventName,
        message,
        author,
        languageName,
        channelString,
        target,
        flags,
        unknown1,
        channelNumber,
        channelName,
        unknown2,
        counter
      )
      if ok and handled then
        return
      end
      if not ok then
        Print("Alliance chat handler error: " .. tostring(handled))
      end
    end

    if LeafVE and LeafVE.TryFormatGuildMessagePayload then
      local ok, formattedMessage = pcall(LeafVE.TryFormatGuildMessagePayload, LeafVE, eventName, message)
      if ok and formattedMessage and formattedMessage ~= "" then
        message = formattedMessage
        if type(args[1]) == "table" and args[1].AddMessage then
          args[3] = formattedMessage
        else
          args[2] = formattedMessage
        end
      elseif not ok then
        Print("Guild chat formatter error: " .. tostring(formattedMessage))
      end
    end

    if LeafVE and LeafVE.WrapAllianceChatFrame and chatFrame then
      pcall(LeafVE.WrapAllianceChatFrame, LeafVE, chatFrame)
    end

    local originalArg1 = _G and _G.arg1 or nil
    if message ~= nil and _G then
      _G.arg1 = message
    end

    local result = { LeafVE.originalAllianceMessageEventHandler(unpack(args, 1, args.n)) }

    if _G then
      _G.arg1 = originalArg1
    end

    return unpack(result, 1, table.getn(result))
  end

  ChatFrame_MessageEventHandler = self.wrappedAllianceMessageEventHandler
end

function LeafVE:NormalizeMalformedAnnouncementLinks(message)
  local text = tostring(message or "")
  if text == "" then
    return text
  end

  text = string.gsub(text, "|H(leafve_[^:|]+:[^|]+)|h|c([0-9A-Fa-f]+)(.-)|r|h", function(linkTarget, colorHex, displayText)
    return "|c" .. tostring(colorHex or "") .. "|H" .. tostring(linkTarget or "") .. "|h" .. tostring(displayText or "") .. "|h|r"
  end)

  return text
end

function LeafVE:GetSafeAchievementAnnouncementLink(linkTarget, displayText, colorHex)
  local safeLink = tostring(linkTarget or "")
  local safeText = tostring(displayText or "")
  local safeColor = tostring(colorHex or "")
  if safeLink == "" or safeText == "" or safeColor == "" then
    return nil
  end
  return "|c" .. safeColor .. "|H" .. safeLink .. "|h" .. safeText .. "|h|r"
end

function LeafVE:BuildSafeAchievementGuildMessage(playerName, achievementID, achievementData)
  local achievementsAddon = LeafVillageAchievements or LeafVE_AchTest
  local shortPlayerName = ShortName(playerName) or tostring(playerName or "")
  local achievement = achievementData
  if not achievement and achievementsAddon and achievementsAddon.GetAchievementMeta then
    achievement = achievementsAddon.GetAchievementMeta(achievementID)
  end
  if shortPlayerName == "" or not achievement then
    return nil
  end

  local achId = tostring(achievement.id or achievementID or "")
  local achName = tostring(achievement.name or achievementID or "Achievement")
  local achLink = self:GetSafeAchievementAnnouncementLink("leafve_ach:" .. achId, "[" .. achName .. "]", "ffffd700")
    or ("[" .. achName .. "]")

  local titleLink = nil
  if achievementsAddon and achievementsAddon.GetCurrentTitle then
    local currentTitle = achievementsAddon:GetCurrentTitle(shortPlayerName)
    if currentTitle and currentTitle.id and currentTitle.name then
      local colorHex = "ffff7f00"
      if currentTitle.legendary then
        colorHex = "ffff0000"
      elseif currentTitle.guild then
        colorHex = "ff8b4513"
      end
      titleLink = self:GetSafeAchievementAnnouncementLink("leafve_title:" .. tostring(currentTitle.id or ""), tostring(currentTitle.name or ""), colorHex)
    end
  end

  local me = ShortName(UnitName("player"))
  local earnedByOtherPlayer = shortPlayerName ~= (me or "")
  if titleLink and earnedByOtherPlayer then
    return shortPlayerName .. " " .. titleLink .. " has earned the achievement " .. achLink
  end
  if titleLink then
    return titleLink .. " has earned the achievement " .. achLink
  end
  if earnedByOtherPlayer then
    return shortPlayerName .. " has earned the achievement " .. achLink
  end
  return "has earned the achievement " .. achLink
end

function LeafVE:InstallChatAnnouncementSendHook()
  if self.chatAnnouncementSendHookInstalled and SendChatMessage == self.wrappedChatAnnouncementSendChatMessage then
    return true
  end
  if type(SendChatMessage) ~= "function" then
    return false
  end

  self.chatAnnouncementSendHookInstalled = true
  self.originalChatAnnouncementSendChatMessage = SendChatMessage
  self.wrappedChatAnnouncementSendChatMessage = function(msg, chatType, language, channel)
    local outgoing = msg
    if type(outgoing) == "string" and outgoing ~= "" then
      outgoing = LeafVE:NormalizeMalformedAnnouncementLinks(outgoing)
    end
    return LeafVE.originalChatAnnouncementSendChatMessage(outgoing, chatType, language, channel)
  end

  SendChatMessage = self.wrappedChatAnnouncementSendChatMessage
  return true
end

function LeafVE:PatchAchievementsChatAnnouncements()
  local achievementsAddon = LeafVillageAchievements or LeafVE_AchTest
  if not achievementsAddon then
    return false
  end
  if achievementsAddon._leafveChatAnnouncementPatched then
    return true
  end

  if type(achievementsAddon.AwardAchievement) == "function" then
    achievementsAddon._leafveOriginalAwardAchievement = achievementsAddon.AwardAchievement
    achievementsAddon.AwardAchievement = function(this, achievementID, silent)
      local me = ShortName(UnitName("player"))
      local alreadyHad = me and this.HasAchievement and this:HasAchievement(me, achievementID)
      local originalIsInGuild = IsInGuild
      if type(originalIsInGuild) == "function" then
        IsInGuild = function()
          return false
        end
      end

      local ok, err = pcall(achievementsAddon._leafveOriginalAwardAchievement, this, achievementID, silent)

      if type(originalIsInGuild) == "function" then
        IsInGuild = originalIsInGuild
      end

      if not ok then
        error(err)
      end

      if not alreadyHad and not silent and type(originalIsInGuild) == "function" and originalIsInGuild() then
        local achievement = this.GetAchievementMeta and this.GetAchievementMeta(achievementID) or nil
        local guildMessage = LeafVE:BuildSafeAchievementGuildMessage(me, achievementID, achievement)
        if guildMessage and guildMessage ~= "" then
          LeafVE:SendSystemChatMessage(guildMessage, "GUILD")
        end
      end
    end
  end

  if type(achievementsAddon.AdminGrantAchievement) == "function" then
    achievementsAddon._leafveOriginalAdminGrantAchievement = achievementsAddon.AdminGrantAchievement
    achievementsAddon.AdminGrantAchievement = function(this, targetInput, achInput, requireGuildMember)
      local originalIsInGuild = IsInGuild
      if type(originalIsInGuild) == "function" then
        IsInGuild = function()
          return false
        end
      end

      local results = { pcall(achievementsAddon._leafveOriginalAdminGrantAchievement, this, targetInput, achInput, requireGuildMember) }

      if type(originalIsInGuild) == "function" then
        IsInGuild = originalIsInGuild
      end

      if not results[1] then
        error(results[2])
      end

      local granted = results[2]
      local targetName = results[3]
      local achievement = results[4]
      if granted and type(originalIsInGuild) == "function" and originalIsInGuild() then
        local guildMessage = LeafVE:BuildSafeAchievementGuildMessage(targetName, achievement and achievement.id or achInput, achievement)
        if guildMessage and guildMessage ~= "" then
          LeafVE:SendSystemChatMessage(guildMessage, "GUILD")
        end
      end

      return unpack(results, 2, table.getn(results))
    end
  end

  achievementsAddon._leafveChatAnnouncementPatched = true
  return true
end

function LeafVE:InstallAllianceSendHook()
  if self.allianceSendHookInstalled and SendChatMessage == self.wrappedAllianceSendChatMessage then
    return
  end
  if type(SendChatMessage) ~= "function" then
    return
  end

  self.allianceSendHookInstalled = true
  self.originalAllianceSendChatMessage = SendChatMessage
  self.wrappedAllianceSendChatMessage = function(msg, chatType, language, channel)
    local outgoing = msg
    local isAllianceChannelSend = chatType == "CHANNEL" and LeafVE:IsAllianceOutgoingChannel(channel)
    if LeafVE and type(msg) == "string" and msg ~= "" and string.sub(msg, 1, 1) ~= "/" then
      local suppressDecorators = (LeafVE.suppressOutgoingChatDecorators or 0) > 0
      if not suppressDecorators then
        local me = ShortName(UnitName("player"))
        if me and LeafVE:IsChatTitleEligibleType(chatType) then
          local titlePrefix = LeafVE:GetChatTitlePrefixForPlayer(me)
          if titlePrefix ~= "" then
            local rawMessage = outgoing
            local hasExistingTitle = false
            if isAllianceChannelSend then
              rawMessage = LeafVE:StripAllianceChatDecorators(rawMessage)
            end
            hasExistingTitle = LeafVE:HasChatAnnouncementLink(rawMessage)
            if not hasExistingTitle then
              local ownTitleName = LeafVE:GetEquippedTitleNameForPlayer(me)
              if ownTitleName and ownTitleName ~= "" then
                local ownPlainPrefix = tostring(ownTitleName) .. " "
                local ownBracketedPrefix = "[" .. tostring(ownTitleName) .. "] "
                hasExistingTitle = string.sub(rawMessage, 1, string.len(ownPlainPrefix)) == ownPlainPrefix
                  or string.sub(rawMessage, 1, string.len(ownBracketedPrefix)) == ownBracketedPrefix
              end
            end
            local achievementsAddon = LeafVillageAchievements or LeafVE_AchTest
            if not hasExistingTitle and achievementsAddon and achievementsAddon.GetCurrentTitle then
              local achTitle = achievementsAddon:GetCurrentTitle(me)
              local achTitleName = achTitle and achTitle.name or nil
              if achTitleName and achTitleName ~= "" then
                local achPlainPrefix = tostring(achTitleName) .. " "
                local achBracketedPrefix = "[" .. tostring(achTitleName) .. "] "
                hasExistingTitle = string.sub(rawMessage, 1, string.len(achPlainPrefix)) == achPlainPrefix
                  or string.sub(rawMessage, 1, string.len(achBracketedPrefix)) == achBracketedPrefix
              end
            end
            if not hasExistingTitle
              and string.sub(rawMessage, 1, string.len(titlePrefix)) ~= titlePrefix then
              outgoing = titlePrefix .. rawMessage
            else
              outgoing = rawMessage
            end
          end
        end
      end
      local hiddenPrefix = LeafVE.allianceChat and LeafVE.allianceChat.hiddenPrefix or ""
      local controlPrefix = LeafVE.allianceChat and LeafVE.allianceChat.controlPrefix or ""
      local isAllianceControlPayload = isAllianceChannelSend
        and type(outgoing) == "string"
        and (
          (hiddenPrefix ~= "" and string.sub(outgoing, 1, string.len(hiddenPrefix)) == hiddenPrefix)
          or
          (controlPrefix ~= "" and string.sub(outgoing, 1, string.len(controlPrefix)) == controlPrefix)
        )

      if isAllianceChannelSend and not isAllianceControlPayload then
        outgoing = LeafVE:BuildAlliancePlainOutgoingPrefix() .. LeafVE:StripAllianceChatDecorators(outgoing)
      end
    end
    outgoing = LeafVE:NormalizeMalformedAnnouncementLinks(outgoing)
    if isAllianceChannelSend then
      LeafVE.allianceChatStickyEnabled = true
    elseif chatType and chatType ~= "" and chatType ~= "AFK" and chatType ~= "DND" then
      LeafVE.allianceChatStickyEnabled = false
    end
    return LeafVE.originalAllianceSendChatMessage(outgoing, chatType, language, channel)
  end

  SendChatMessage = self.wrappedAllianceSendChatMessage
end

function LeafVE:SendSystemChatMessage(message, chatType, language, channel)
  local sender = SendChatMessage
  if self.originalAllianceSendChatMessage and SendChatMessage == self.wrappedAllianceSendChatMessage then
    sender = self.originalAllianceSendChatMessage
  end

  if type(sender) ~= "function" then
    return false
  end

  message = self:NormalizeMalformedAnnouncementLinks(message)
  self.suppressOutgoingChatDecorators = (self.suppressOutgoingChatDecorators or 0) + 1
  local ok, err = pcall(sender, message, chatType, language, channel)
  self.suppressOutgoingChatDecorators = math.max(0, (self.suppressOutgoingChatDecorators or 1) - 1)
  if not ok then
    Print("Chat send failed: " .. tostring(err))
    return false
  end
  return true
end

function LeafVE:InstallAllianceChatSupport()
  if self.allianceEnabled ~= true then
    return false
  end
  self:InstallAllianceSendHook()
  self:InstallAllianceRenderedMessageSuppression()
  self:InstallAllianceChatHandler()
  self:InstallAllianceStickyChatHook()
  return true
end

function LeafVE:ApplyAllianceChannelColor(channelId)
  channelId = tonumber(channelId) or self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end

  local channelKey = "CHANNEL" .. tostring(channelId)
  local color = LeafVE.allianceChat.color

  if ChatTypeInfo and ChatTypeInfo[channelKey] then
    ChatTypeInfo[channelKey].r = color[1]
    ChatTypeInfo[channelKey].g = color[2]
    ChatTypeInfo[channelKey].b = color[3]
  end

  if type(ChangeChatColor) == "function" then
    pcall(ChangeChatColor, channelKey, color[1], color[2], color[3])
  end
  if type(ChangeChatColorByID) == "function" then
    pcall(ChangeChatColorByID, channelId, color[1], color[2], color[3])
  end

  return true
end

function LeafVE:EnsureAllianceChannelVisible(channelName)
  channelName = channelName or self:GetAllianceChannelName()
  if type(ChatFrame_AddChannel) == "function" then
    local totalFrames = tonumber(NUM_CHAT_WINDOWS) or 7
    for i = 1, totalFrames do
      local frame = _G["ChatFrame" .. tostring(i)]
      if frame then
        pcall(ChatFrame_AddChannel, frame, channelName)
      end
    end
    if DEFAULT_CHAT_FRAME then
      pcall(ChatFrame_AddChannel, DEFAULT_CHAT_FRAME, channelName)
    end
    if SELECTED_CHAT_FRAME then
      pcall(ChatFrame_AddChannel, SELECTED_CHAT_FRAME, channelName)
    end
  end
end

function LeafVE:ApplyAllianceStickyToEditBox(editBox)
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 or not editBox then
    return false
  end
  if ChatTypeInfo and ChatTypeInfo["CHANNEL"] then
    ChatTypeInfo["CHANNEL"].sticky = 1
  end
  editBox.stickyType = "CHANNEL"
  editBox.chatType = "CHANNEL"
  editBox.channelTarget = channelId
  if type(editBox.SetAttribute) == "function" then
    pcall(editBox.SetAttribute, editBox, "stickyType", "CHANNEL")
    pcall(editBox.SetAttribute, editBox, "chatType", "CHANNEL")
    pcall(editBox.SetAttribute, editBox, "channelTarget", channelId)
  end
  if type(ChatEdit_UpdateHeader) == "function" then
    pcall(ChatEdit_UpdateHeader, editBox)
  end
  return true
end

function LeafVE:InstallAllianceStickyChatHook()
  if self.allianceStickyChatHookInstalled then
    return
  end

  if type(ChatFrame_OpenChat) == "function" then
    self.originalAllianceChatFrameOpenChat = self.originalAllianceChatFrameOpenChat or ChatFrame_OpenChat
    if ChatFrame_OpenChat ~= self.wrappedAllianceChatFrameOpenChat then
      self.wrappedAllianceChatFrameOpenChat = function(text, chatFrame)
        local result = { LeafVE.originalAllianceChatFrameOpenChat(text, chatFrame) }
        if LeafVE and LeafVE.allianceChatStickyEnabled and (text == nil or text == "") then
          local targetFrame = chatFrame or SELECTED_CHAT_FRAME or DEFAULT_CHAT_FRAME
          local editBox = targetFrame and targetFrame.editBox or nil
          if editBox then
            LeafVE:ApplyAllianceStickyToEditBox(editBox)
          end
        end
        return unpack(result)
      end
      ChatFrame_OpenChat = self.wrappedAllianceChatFrameOpenChat
    end
  end

  if type(ChatEdit_ActivateChat) == "function" then
    self.originalAllianceChatEditActivate = self.originalAllianceChatEditActivate or ChatEdit_ActivateChat
    if ChatEdit_ActivateChat ~= self.wrappedAllianceChatEditActivate then
      self.wrappedAllianceChatEditActivate = function(editBox)
        local result = { LeafVE.originalAllianceChatEditActivate(editBox) }
        if LeafVE and LeafVE.allianceChatStickyEnabled and editBox then
          local currentText = ""
          local currentType = string.upper(tostring(editBox.chatType or ""))
          if type(editBox.GetText) == "function" then
            currentText = tostring(editBox:GetText() or "")
          end
          if currentText == "" and (currentType == "" or currentType == "SAY" or currentType == "CHANNEL") then
            LeafVE:ApplyAllianceStickyToEditBox(editBox)
          end
        end
        return unpack(result)
      end
      ChatEdit_ActivateChat = self.wrappedAllianceChatEditActivate
    end
  end

  self.allianceStickyChatHookInstalled = true
end

function LeafVE:OpenAllianceChatInput()
  if self.allianceEnabled ~= true then
    return false
  end
  self:InstallAllianceStickyChatHook()
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end
  if ChatTypeInfo and ChatTypeInfo["CHANNEL"] then
    ChatTypeInfo["CHANNEL"].sticky = 1
  end
  local targetFrame = DEFAULT_CHAT_FRAME
  if SELECTED_CHAT_FRAME and SELECTED_CHAT_FRAME.editBox then
    targetFrame = SELECTED_CHAT_FRAME
  end
  local editBox = targetFrame and targetFrame.editBox or nil
  if not editBox then
    return false
  end
  if type(ChatFrame_OpenChat) == "function" then
    ChatFrame_OpenChat("", targetFrame)
  elseif type(ChatEdit_ActivateChat) == "function" then
    ChatEdit_ActivateChat(editBox)
  end
  self.allianceChatStickyEnabled = true
  self:ApplyAllianceStickyToEditBox(editBox)
  if type(editBox.SetText) == "function" then
    editBox:SetText("")
  end
  if type(editBox.SetFocus) == "function" then
    editBox:SetFocus()
  end
  return true
end

function LeafVE:FinalizeAllianceChannelJoin(channelId, announce, openInput)
  channelId = tonumber(channelId) or self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end

  self.allianceChannelId = channelId
  self.lastAllianceAutoJoinAttemptAt = Now()
  self:EnsureAllianceChannelVisible(self:GetAllianceChannelName())
  self:ApplyAllianceChannelColor(channelId)
  self:InstallAllianceChatSupport()

  if announce then
    Print("Joined " .. self:GetAllianceDisplayLabel() .. ": [" .. self:GetAllianceChannelName() .. "]")
  end

  if openInput then
    self:OpenAllianceChatInput()
  end

  return true
end

function LeafVE:JoinAllianceChannel(openInput, announce)
  if self.allianceEnabled ~= true then
    return false
  end
  EnsureDB()
  self:InstallAllianceChatSupport()

  local channelName = self:GetAllianceChannelName()
  local channelId = self:GetAllianceChannelId()
  if channelId > 0 then
    return self:FinalizeAllianceChannelJoin(channelId, announce, openInput)
  end

  if type(JoinChannelByName) ~= "function" then
    return false
  end

  JoinChannelByName(channelName, self:GetAllianceChannelPassword() ~= "" and self:GetAllianceChannelPassword() or nil)

  self.pendingAllianceOpenInput = openInput and true or false
  self.pendingAllianceAnnounceJoin = announce and true or false

  if announce then
    Print("Joining " .. self:GetAllianceDisplayLabel() .. " [" .. channelName .. "]...")
  end

  self:ScheduleDeferred("leafve_alliance_join_retry", 0.7, function()
    local retryChannelId = LeafVE:GetAllianceChannelId()
    local shouldOpenInput = LeafVE.pendingAllianceOpenInput and true or false
    local shouldAnnounce = LeafVE.pendingAllianceAnnounceJoin and true or false
    LeafVE.pendingAllianceOpenInput = nil
    LeafVE.pendingAllianceAnnounceJoin = nil

    if retryChannelId > 0 then
      LeafVE:FinalizeAllianceChannelJoin(retryChannelId, shouldAnnounce, shouldOpenInput)
    elseif shouldAnnounce then
      Print("Unable to join " .. LeafVE:GetAllianceDisplayLabel() .. " [" .. channelName .. "].")
    end
  end)

  return true
end

function LeafVE:MaybeAutoJoinAlliance(force)
  if self.allianceEnabled ~= true then
    return false
  end
  EnsureDB()

  if LeafVE_DB.options.allianceAutoJoin ~= true then
    return false
  end

  local guildName = GetGuildInfo and GetGuildInfo("player") or nil
  if Trim(guildName or "") == "" then
    return false
  end

  local now = Now()
  local channelId = self:GetAllianceChannelId()
  if channelId > 0 then
    self.allianceChannelId = channelId
    self.lastAllianceAutoJoinAttemptAt = now
    self:EnsureAllianceChannelVisible(self:GetAllianceChannelName())
    self:ApplyAllianceChannelColor(channelId)
    self:InstallAllianceChatSupport()
    return true
  end

  self.lastAllianceAutoJoinAttemptAt = now
  return self:JoinAllianceChannel(false, false)
end

local function CurrentWipeVersion()
  return (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or 0
end

local function PointBucketForEntry(entry)
  if type(entry) ~= "table" then return 0 end
  return tonumber(entry._b) or 0
end

local function IsPointEntryInCurrentBucket(entry)
  return PointBucketForEntry(entry) == CurrentWipeVersion()
end

local function EnsurePointEntryCurrentBucket(container, key)
  if type(container) ~= "table" then
    return {L = 0, G = 0, S = 0, _b = CurrentWipeVersion()}
  end
  local entry = container[key]
  local bucket = CurrentWipeVersion()
  if type(entry) ~= "table" or PointBucketForEntry(entry) ~= bucket then
    entry = {L = 0, G = 0, S = 0, _b = bucket}
    container[key] = entry
    return entry
  end
  if entry.L == nil then entry.L = 0 end
  if entry.G == nil then entry.G = 0 end
  if entry.S == nil then entry.S = 0 end
  entry._b = bucket
  return entry
end

local function SetWeeklyEntryWipeVersion(wk, name, wipeVersion)
  EnsureDB()
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return end
  if type(LeafVE_DB.lboard.weeklyVersion[wk]) ~= "table" then
    LeafVE_DB.lboard.weeklyVersion[wk] = {}
  end
  LeafVE_DB.lboard.weeklyVersion[wk][name] = tonumber(wipeVersion) or CurrentWipeVersion()
end

local function GetWeeklyEntryWipeVersion(wk, name)
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return nil end
  local wkMap = LeafVE_DB and LeafVE_DB.lboard and LeafVE_DB.lboard.weeklyVersion and LeafVE_DB.lboard.weeklyVersion[wk]
  if type(wkMap) ~= "table" then return nil end
  return tonumber(wkMap[name])
end

local function ClearWeeklyEntryWipeVersion(wk, name)
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return end
  local wkMap = LeafVE_DB and LeafVE_DB.lboard and LeafVE_DB.lboard.weeklyVersion and LeafVE_DB.lboard.weeklyVersion[wk]
  if type(wkMap) == "table" then
    wkMap[name] = nil
  end
end

local function PruneLeaderboardForCurrentWipe()
  EnsureDB()
  local currentVersion = CurrentWipeVersion()
  if currentVersion <= 0 then return end

  for name, _ in pairs(LeafVE_DB.lboard.alltime or {}) do
    local meta = LeafVE_DB.lboard.updatedAt[name]
    local entryVersion = type(meta) == "table" and tonumber(meta.lifetimeWipeVersion) or nil
    if entryVersion ~= currentVersion then
      LeafVE_DB.lboard.alltime[name] = nil
      if LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime then
        LeafVE_GlobalDB.lboardCache.alltime[name] = nil
      end
    end
  end

  for wk, wkData in pairs(LeafVE_DB.lboard.weekly or {}) do
    if type(wkData) == "table" then
      local wkVersions = type(LeafVE_DB.lboard.weeklyVersion[wk]) == "table" and LeafVE_DB.lboard.weeklyVersion[wk] or {}
      for name, _ in pairs(wkData) do
        local entryVersion = tonumber(wkVersions[name])
        if entryVersion ~= currentVersion then
          wkData[name] = nil
          wkVersions[name] = nil
        end
      end
    end
  end
end

local function StoreLifetimeSnapshot(name, L, G, S, sourceName, authoritative, overwriteSharedCache)
  EnsureDB()
  name = ShortName(name)
  if not name then return end

  L = tonumber(L) or 0
  G = tonumber(G) or 0
  S = tonumber(S) or 0
  if (L + G + S) <= 0 then return end

  LeafVE_DB.lboard.alltime[name] = {L = L, G = G, S = S}
  if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
    LeafVE_DB.lboard.updatedAt[name] = {}
  end
  LeafVE_DB.lboard.updatedAt[name].lifetime = Now()
  LeafVE_DB.lboard.updatedAt[name].lifetimeSource = ShortName(sourceName) or sourceName or name
  LeafVE_DB.lboard.updatedAt[name].lifetimeAuthoritative = authoritative and true or false
  LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()

  if overwriteSharedCache then
    if not LeafVE_GlobalDB.lboardCache then
      LeafVE_GlobalDB.lboardCache = { alltime = {}, weekly = {} }
    end
    if not LeafVE_GlobalDB.lboardCache.alltime then
      LeafVE_GlobalDB.lboardCache.alltime = {}
    end
    LeafVE_GlobalDB.lboardCache.alltime[name] = {L = L, G = G, S = S}
  end
end

local function ClearLifetimeSnapshot(name, sourceName, authoritative)
  EnsureDB()
  name = ShortName(name)
  if not name then return end

  LeafVE_DB.lboard.alltime[name] = nil
  if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
    LeafVE_DB.lboard.updatedAt[name] = {}
  end
  LeafVE_DB.lboard.updatedAt[name].lifetime = Now()
  LeafVE_DB.lboard.updatedAt[name].lifetimeSource = ShortName(sourceName) or sourceName or name
  LeafVE_DB.lboard.updatedAt[name].lifetimeAuthoritative = authoritative and true or false
  LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()

  if LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime then
    LeafVE_GlobalDB.lboardCache.alltime[name] = nil
  end
end

local function GetBadgeProgressCacheEntry(playerName, createIfMissing)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return nil, nil end

  if not LeafVE_GlobalDB.badgeProgressCache then
    LeafVE_GlobalDB.badgeProgressCache = {}
  end

  local entry = LeafVE_GlobalDB.badgeProgressCache[name]
  if type(entry) ~= "table" then
    if not createIfMissing then
      return name, nil
    end
    entry = {}
    LeafVE_GlobalDB.badgeProgressCache[name] = entry
  end

  return name, entry
end

local function GetCachedProgressNumber(playerName, field)
  local _, cache = GetBadgeProgressCacheEntry(playerName, false)
  if type(cache) ~= "table" then return 0 end
  if (tonumber(cache.bucket) or 0) ~= CurrentWipeVersion() then return 0 end
  return tonumber(cache[field]) or 0
end

local function GetBestLifetimeEntry(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local best = nil
  local function Consider(entry)
    if type(entry) ~= "table" then return end
    local normalized = {
      L = tonumber(entry.L) or 0,
      G = tonumber(entry.G) or 0,
      S = tonumber(entry.S) or 0,
    }
    if LboardEntryTotal(normalized) <= 0 then return end
    if not best or LboardEntryTotal(normalized) > LboardEntryTotal(best) then
      best = normalized
    end
  end

  local localAlltime = LeafVE_DB.alltime and LeafVE_DB.alltime[name]
  if IsPointEntryInCurrentBucket(localAlltime) then
    Consider(localAlltime)
  end
  Consider(LeafVE_DB.lboard and LeafVE_DB.lboard.alltime and LeafVE_DB.lboard.alltime[name])
  Consider(LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime and LeafVE_GlobalDB.lboardCache.alltime[name])
  local progressCache = LeafVE_GlobalDB.badgeProgressCache and LeafVE_GlobalDB.badgeProgressCache[name]
  if type(progressCache) == "table" and (tonumber(progressCache.bucket) or 0) == CurrentWipeVersion() then
    Consider(progressCache.alltime)
  end

  return best or {L = 0, G = 0, S = 0}
end

local function GetBestGuildieGroupHours(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localHours = (LeafVE_DB.guildieGroupHours and LeafVE_DB.guildieGroupHours[name]) or 0
  local cachedHours = GetCachedProgressNumber(name, "guildieGroupHours")
  if cachedHours > localHours then
    if not LeafVE_DB.guildieGroupHours then LeafVE_DB.guildieGroupHours = {} end
    LeafVE_DB.guildieGroupHours[name] = cachedHours
    return cachedHours
  end
  return localHours
end

local function GetBestGuildieHonorableKills(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localKills = (LeafVE_DB.guildieHonorableKills and LeafVE_DB.guildieHonorableKills[name]) or 0
  local cachedKills = GetCachedProgressNumber(name, "guildieHonorableKills")
  if cachedKills > localKills then
    if not LeafVE_DB.guildieHonorableKills then LeafVE_DB.guildieHonorableKills = {} end
    LeafVE_DB.guildieHonorableKills[name] = cachedKills
    return cachedKills
  end
  return localKills
end

local function GetBestAttendanceCount(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local attendance = (LeafVE_DB.attendance and LeafVE_DB.attendance[name]) or {}
  local localCount = table.getn(attendance)
  local cachedCount = GetCachedProgressNumber(name, "attendance")
  if cachedCount > localCount then
    if not LeafVE_DB.attendance then LeafVE_DB.attendance = {} end
    if not LeafVE_DB.attendance[name] then LeafVE_DB.attendance[name] = {} end
    while table.getn(LeafVE_DB.attendance[name]) < cachedCount do
      table.insert(LeafVE_DB.attendance[name], {})
    end
    return cachedCount
  end
  return localCount
end

local function GetBestLoginStreak(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localStreak = (LeafVE_DB.loginStreaks and LeafVE_DB.loginStreaks[name] and LeafVE_DB.loginStreaks[name].current) or 0
  local cachedStreak = GetCachedProgressNumber(name, "loginStreak")
  if cachedStreak > localStreak then
    if not LeafVE_DB.loginStreaks then LeafVE_DB.loginStreaks = {} end
    if not LeafVE_DB.loginStreaks[name] then
      LeafVE_DB.loginStreaks[name] = {current = 0}
    end
    LeafVE_DB.loginStreaks[name].current = cachedStreak
    return cachedStreak
  end
  return localStreak
end

local function GetBestGuildJoinDate(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localJoinDate = (LeafVE_DB.guildJoinDate and LeafVE_DB.guildJoinDate[name]) or 0
  local cachedJoinDate = GetCachedProgressNumber(name, "guildJoinDate")

  if localJoinDate > 0 and cachedJoinDate > 0 then
    local earliest = math.min(localJoinDate, cachedJoinDate)
    if not LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate = {} end
    LeafVE_DB.guildJoinDate[name] = earliest
    return earliest
  elseif cachedJoinDate > 0 then
    if not LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate = {} end
    LeafVE_DB.guildJoinDate[name] = cachedJoinDate
    return cachedJoinDate
  end

  return localJoinDate
end

local function AggregateGlobalTotalsForPlayer(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local totals = {L = 0, G = 0, S = 0}
  local bucket = CurrentWipeVersion()
  for _, dayData in pairs(LeafVE_DB.global or {}) do
    if type(dayData) == "table" then
      local entry = dayData[name]
      if type(entry) == "table" and PointBucketForEntry(entry) == bucket then
        totals.L = totals.L + (tonumber(entry.L) or 0)
        totals.G = totals.G + (tonumber(entry.G) or 0)
        totals.S = totals.S + (tonumber(entry.S) or 0)
      end
    end
  end

  return totals
end

local function ResolveLifetimeEntryForDisplay(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local me = ShortName(UnitName("player"))
  local wk = WeekKey()
  local syncedWeek = (type(LeafVE_DB.lboard.weekly[wk]) == "table") and LeafVE_DB.lboard.weekly[wk] or {}
  local localWeek = AggForThisWeek()

  local localPts  = LeafVE_DB.alltime[name]
  if not IsPointEntryInCurrentBucket(localPts) then
    localPts = nil
  end
  local syncedPts = LeafVE_DB.lboard.alltime[name]
  local lifeMeta = LeafVE_DB.lboard.updatedAt[name]
  local syncedIsAuthoritative = (type(lifeMeta) == "table" and lifeMeta.lifetimeAuthoritative == true)
  local pts = syncedIsAuthoritative and syncedPts or nil
  if not SamePlayerName(name, me) then
    localPts = nil
  end
  if LboardEntryTotal(localPts) > LboardEntryTotal(pts) then
    pts = localPts
  end
  local weekPts = syncedWeek[name] or localWeek[name]
  if LboardEntryTotal(weekPts) > LboardEntryTotal(pts) then
    pts = weekPts
  end

  return {
    L = pts and (pts.L or 0) or 0,
    G = pts and (pts.G or 0) or 0,
    S = pts and (pts.S or 0) or 0,
  }
end

-- Builds the exact snapshot used for leaderboard self-broadcasts.
-- This mirrors My Stats reconciliation so refresh requests pull the same totals.
local function BuildMyStatsSnapshotForPlayer(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then
    return {L = 0, G = 0, S = 0}, {L = 0, G = 0, S = 0}
  end

  local weekAgg = AggForThisWeek()
  local weekT = weekAgg[name] or {L = 0, G = 0, S = 0}

  local globalSum = AggregateGlobalTotalsForPlayer(name)
  local leaderboardAlltime = ResolveLifetimeEntryForDisplay(name)
  local bestAlltime = GetBestLifetimeEntry(name)
  local alltimeT = {
    L = math.max(leaderboardAlltime.L or 0, bestAlltime.L or 0, globalSum.L or 0),
    G = math.max(leaderboardAlltime.G or 0, bestAlltime.G or 0, globalSum.G or 0),
    S = math.max(leaderboardAlltime.S or 0, bestAlltime.S or 0, globalSum.S or 0),
  }

  return alltimeT, {
    L = weekT.L or 0,
    G = weekT.G or 0,
    S = weekT.S or 0,
  }
end

function LeafVE:CacheBadgeProgress(playerName)
  EnsureDB()
  local name, cache = GetBadgeProgressCacheEntry(playerName, true)
  if not name or type(cache) ~= "table" then return end
  cache.bucket = CurrentWipeVersion()

  local alltime = GetBestLifetimeEntry(name)
  cache.alltime = {
    L = alltime.L or 0,
    G = alltime.G or 0,
    S = alltime.S or 0,
  }

  local groupSessions = (LeafVE_DB.groupSessions and LeafVE_DB.groupSessions[name]) or 0
  if groupSessions > (cache.groupSessions or 0) then
    cache.groupSessions = groupSessions
  end

  local guildieHours = (LeafVE_DB.guildieGroupHours and LeafVE_DB.guildieGroupHours[name]) or 0
  if guildieHours > (cache.guildieGroupHours or 0) then
    cache.guildieGroupHours = guildieHours
  end

  local guildieHonorableKills = (LeafVE_DB.guildieHonorableKills and LeafVE_DB.guildieHonorableKills[name]) or 0
  if guildieHonorableKills > (cache.guildieHonorableKills or 0) then
    cache.guildieHonorableKills = guildieHonorableKills
  end

  local attendanceCount = table.getn((LeafVE_DB.attendance and LeafVE_DB.attendance[name]) or {})
  if attendanceCount > (cache.attendance or 0) then
    cache.attendance = attendanceCount
  end

  local streak = (LeafVE_DB.loginStreaks and LeafVE_DB.loginStreaks[name] and LeafVE_DB.loginStreaks[name].current) or 0
  if streak > (cache.loginStreak or 0) then
    cache.loginStreak = streak
  end

  local joinDate = (LeafVE_DB.guildJoinDate and LeafVE_DB.guildJoinDate[name]) or 0
  if joinDate > 0 then
    if not cache.guildJoinDate or cache.guildJoinDate <= 0 or joinDate < cache.guildJoinDate then
      cache.guildJoinDate = joinDate
    end
  end

  cache.updatedAt = Now()
end

function LeafVE:UpsertSharedLeaderboard(name, lifetimeEntry, weeklyEntry, wk, forceReplace)
  EnsureDB()
  name = ShortName(name)
  if not name then return end
  if not LeafVE_GlobalDB.lboardCache then
    LeafVE_GlobalDB.lboardCache = { alltime = {}, weekly = {} }
  end
  if not LeafVE_GlobalDB.lboardCache.alltime then LeafVE_GlobalDB.lboardCache.alltime = {} end
  if not LeafVE_GlobalDB.lboardCache.weekly then LeafVE_GlobalDB.lboardCache.weekly = {} end
  wk = wk or WeekKey()

  if lifetimeEntry then
    local existing = LeafVE_GlobalDB.lboardCache.alltime[name]
    if forceReplace or LboardEntryTotal(lifetimeEntry) > LboardEntryTotal(existing) then
      LeafVE_GlobalDB.lboardCache.alltime[name] = {
        L = lifetimeEntry.L or 0,
        G = lifetimeEntry.G or 0,
        S = lifetimeEntry.S or 0,
      }
    end
  end

  if weeklyEntry then
    if type(LeafVE_GlobalDB.lboardCache.weekly[wk]) ~= "table" then
      LeafVE_GlobalDB.lboardCache.weekly[wk] = {}
    end
    local existingW = LeafVE_GlobalDB.lboardCache.weekly[wk][name]
    if forceReplace or LboardEntryTotal(weeklyEntry) > LboardEntryTotal(existingW) then
      LeafVE_GlobalDB.lboardCache.weekly[wk][name] = {
        L = weeklyEntry.L or 0,
        G = weeklyEntry.G or 0,
        S = weeklyEntry.S or 0,
      }
    end
  end
end

function LeafVE:MergeSharedLeaderboardIntoLocal()
  EnsureDB()
  PruneLeaderboardForCurrentWipe()
  local cache = LeafVE_GlobalDB.lboardCache
  if not cache then return end
  local wk = WeekKey()

  for name, entry in pairs(cache.alltime or {}) do
    if LboardEntryTotal(entry) > LboardEntryTotal(LeafVE_DB.lboard.alltime[name]) then
      LeafVE_DB.lboard.alltime[name] = {
        L = entry.L or 0,
        G = entry.G or 0,
        S = entry.S or 0,
      }
      if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
        LeafVE_DB.lboard.updatedAt[name] = {}
      end
      LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()
    end
  end

  if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then
    LeafVE_DB.lboard.weekly[wk] = {}
  end
  local weekCache = type(cache.weekly[wk]) == "table" and cache.weekly[wk] or {}
  for name, entry in pairs(weekCache) do
    if LboardEntryTotal(entry) > LboardEntryTotal(LeafVE_DB.lboard.weekly[wk][name]) then
      LeafVE_DB.lboard.weekly[wk][name] = {
        L = entry.L or 0,
        G = entry.G or 0,
        S = entry.S or 0,
      }
      SetWeeklyEntryWipeVersion(wk, name, CurrentWipeVersion())
    end
  end
end

function LeafVE:AddToHistory(playerName, pointType, amount, reason)
  EnsureDB() playerName = ShortName(playerName) if not playerName then return end
  if not LeafVE_DB.pointHistory[playerName] then LeafVE_DB.pointHistory[playerName] = {} end
  local now = Now()
  local dateStr = date("%m/%d %H:%M", now)
  table.insert(LeafVE_DB.pointHistory[playerName], {timestamp = now, type = pointType, amount = amount, reason = reason or "Unknown", dateStr = dateStr})
  while table.getn(LeafVE_DB.pointHistory[playerName]) > 500 do table.remove(LeafVE_DB.pointHistory[playerName], 1) end

  -- Keep currently-visible history/leaderboard views up to date immediately.
  if LeafVE.UI and LeafVE.UI.panels then
    if LeafVE.UI.panels.liveHistory and LeafVE.UI.panels.liveHistory:IsVisible() and LeafVE.UI.RefreshLiveHistory then
      LeafVE.UI:RefreshLiveHistory()
    end
    if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() and LeafVE.UI.RefreshLeaderboard then
      LeafVE.UI:RefreshLeaderboard("leaderLife")
    end
    if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() and LeafVE.UI.RefreshLeaderboard then
      LeafVE.UI:RefreshLeaderboard("leaderWeek")
    end
  end

  -- Broadcast this transaction to all online guild members
  local me = ShortName(UnitName("player"))
  if me and playerName == me and InGuild() then
    local truncReason = reason or "Unknown"
    if string.len(truncReason) > 80 then truncReason = string.sub(truncReason, 1, 80) end
    SendAddonMessage("LeafVE", "PTXN:"..playerName..SEP..tostring(amount)..SEP..tostring(now)..SEP..(pointType or "")..SEP..truncReason, "GUILD")
  end
end

local function FindBadgeMapForPlayer(badgeTable, playerName)
  if type(badgeTable) ~= "table" then return nil end
  local shortName = ShortName(playerName)
  if not shortName then return nil end

  local direct = badgeTable[shortName]
  if type(direct) == "table" then
    return direct
  end

  local targetLower = Lower(shortName)
  for name, badgeMap in pairs(badgeTable) do
    if type(name) == "string" and type(badgeMap) == "table" then
      local short = ShortName(name)
      if short and Lower(short) == targetLower then
        return badgeMap
      end
    end
  end
  return nil
end

local function HadBadgeInArchivedSeason(playerName, badgeId)
  if type(LeafVE_DB) ~= "table" or type(LeafVE_DB.badgesArchive) ~= "table" then
    return false
  end
  for _, seasonBadges in pairs(LeafVE_DB.badgesArchive) do
    local playerBadges = FindBadgeMapForPlayer(seasonBadges, playerName)
    if type(playerBadges) == "table" and playerBadges[badgeId] then
      return true
    end
  end
  return false
end

local function GetBadgeDefinition(badgeId)
  if not badgeId or badgeId == "" then return nil end
  for i = 1, table.getn(BADGES) do
    if BADGES[i].id == badgeId then
      return BADGES[i]
    end
  end
  return nil
end

function LeafVE:GetTitleDefinition(titleId)
  if not titleId or titleId == "" then
    return nil
  end
  for i = 1, table.getn(self.titleDefinitions or {}) do
    local titleDef = self.titleDefinitions[i]
    if titleDef and titleDef.id == titleId then
      return titleDef
    end
  end
  return nil
end

LeafVE.chatTitleEligibleTypes = {
  GUILD = true,
}

function LeafVE:SetTitleCacheRecord(playerName, titleId, updatedAt)
  EnsureDB()
  local shortName = ShortName(playerName)
  if not shortName then
    return
  end
  if not LeafVE_GlobalDB.titleCache then
    LeafVE_GlobalDB.titleCache = {}
  end
  LeafVE_GlobalDB.titleCache[Lower(shortName)] = {
    player = shortName,
    titleId = titleId or "",
    updatedAt = tonumber(updatedAt) or Now(),
  }
end

function LeafVE:GetUnlockedTitlesForPlayer(playerName)
  EnsureDB()
  local shortName = ShortName(playerName)
  local unlocked = {}
  if not shortName then
    return unlocked
  end

  local badgeMap = LeafVE_DB.badges[shortName] or {}
  for i = 1, table.getn(self.titleDefinitions or {}) do
    local titleDef = self.titleDefinitions[i]
    if badgeMap[titleDef.badgeId] then
      table.insert(unlocked, titleDef)
    end
  end
  return unlocked
end

function LeafVE:IsTitleUnlockedForPlayer(playerName, titleId)
  EnsureDB()
  local shortName = ShortName(playerName)
  local titleDef = self:GetTitleDefinition(titleId)
  if not shortName or not titleDef then
    return false
  end

  local badgeMap = LeafVE_DB.badges[shortName] or {}
  return badgeMap[titleDef.badgeId] ~= nil
end

function LeafVE:GetEquippedTitleIdForPlayer(playerName)
  EnsureDB()
  local shortName = ShortName(playerName)
  if not shortName then
    return nil
  end

  local me = ShortName(UnitName("player"))
  if me and Lower(me) == Lower(shortName) then
    local selfTitleId = LeafVE_DB.equippedTitles[shortName]
    if selfTitleId and selfTitleId ~= "" then
      if self:IsTitleUnlockedForPlayer(shortName, selfTitleId) then
        return selfTitleId
      end
      LeafVE_DB.equippedTitles[shortName] = nil
      self:SetTitleCacheRecord(shortName, nil, Now())
    end
  end

  local titleCache = LeafVE_GlobalDB.titleCache and LeafVE_GlobalDB.titleCache[Lower(shortName)]
  local cachedId = titleCache and titleCache.titleId or nil
  if cachedId and cachedId ~= "" and self:GetTitleDefinition(cachedId) then
    return cachedId
  end

  local fallbackId = LeafVE_DB.equippedTitles and LeafVE_DB.equippedTitles[shortName]
  if fallbackId and fallbackId ~= "" and self:GetTitleDefinition(fallbackId) then
    return fallbackId
  end
  return nil
end

function LeafVE:GetEquippedTitleDefinitionForPlayer(playerName)
  local titleId = self:GetEquippedTitleIdForPlayer(playerName)
  return self:GetTitleDefinition(titleId)
end

function LeafVE:GetEquippedTitleNameForPlayer(playerName)
  local titleDef = self:GetEquippedTitleDefinitionForPlayer(playerName)
  if titleDef then
    return titleDef.title
  end
  return nil
end

function LeafVE:BuildPlayerTitleMarkup(playerName)
  local titleDef = self:GetEquippedTitleDefinitionForPlayer(playerName)
  if not titleDef then
    return nil
  end

  local sourceBadge = GetBadgeDefinition(titleDef.badgeId)
  local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
  return "|cFF" .. RGBToHex(tr, tg, tb) .. "[" .. tostring(titleDef.title or "") .. "]|r"
end

function LeafVE:GetChatAnnouncementLink(linkTarget, displayText, colorHex)
  local safeLink = tostring(linkTarget or "")
  local safeText = tostring(displayText or "")
  local safeColor = tostring(colorHex or "")
  if safeLink == "" or safeText == "" or safeColor == "" then
    return nil
  end
  return "|c" .. safeColor .. "|H" .. safeLink .. "|h" .. safeText .. "|h|r"
end

function LeafVE:HasChatAnnouncementLink(text)
  local message = tostring(text or "")
  return string.find(message, "|Hleafve_badge:", 1, true) ~= nil
    or string.find(message, "|Hleafve_title:", 1, true) ~= nil
    or string.find(message, "|Hitem:6948:0:0:0|h", 1, true) ~= nil
end

function LeafVE:GetChatTitleLink(titleDef, includeBrackets)
  if not titleDef or not titleDef.id or titleDef.id == "" or not titleDef.title or titleDef.title == "" then
    return nil
  end

  local sourceBadge = GetBadgeDefinition(titleDef.badgeId)
  local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
  local displayText = tostring(titleDef.title or "")
  if includeBrackets then
    displayText = "[" .. displayText .. "]"
  end
  return self:GetChatAnnouncementLink("leafve_title:" .. tostring(titleDef.id or ""), displayText, "FF" .. RGBToHex(tr, tg, tb))
end

function LeafVE:GetChatBadgeLink(badge)
  if not badge or not badge.id or badge.id == "" or not badge.name or badge.name == "" then
    return nil
  end

  local qr, qg, qb = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
  return self:GetChatAnnouncementLink("leafve_badge:" .. tostring(badge.id or ""), "[" .. tostring(badge.name or "") .. "]", "FF" .. RGBToHex(qr, qg, qb))
end

function LeafVE:GetStoredDisplayPlayerName(playerName)
  local shortName = ShortName(playerName) or tostring(playerName or "")
  if shortName == "" then
    return ""
  end

  local guildInfo = self:GetGuildInfo(shortName)
  if guildInfo and guildInfo.name and guildInfo.name ~= "" then
    return guildInfo.name
  end

  local persistent = LeafVE_DB and LeafVE_DB.persistentRoster and LeafVE_DB.persistentRoster[Lower(shortName)]
  if persistent and persistent.name and persistent.name ~= "" then
    return persistent.name
  end

  return shortName
end

function LeafVE:BuildPlayerCardNameMarkup(playerName, classTag)
  local shortName = self:GetStoredDisplayPlayerName(playerName)
  if shortName == "" then
    return ""
  end

  local classToken = string.upper(tostring(classTag or self:GetClassTagForPlayer(shortName) or "UNKNOWN"))
  local classColor = CLASS_COLORS[classToken] or {1, 1, 1}
  local nameMarkup = "|cFF" .. RGBToHex(classColor[1], classColor[2], classColor[3]) .. shortName .. "|r"
  local titleDef = self:GetEquippedTitleDefinitionForPlayer(shortName)
  if not titleDef then
    return nameMarkup
  end

  local sourceBadge = GetBadgeDefinition(titleDef.badgeId)
  local tr, tg, tb = GetBadgeQualityColor((sourceBadge and sourceBadge.quality) or BADGE_QUALITY.EPIC)
  return nameMarkup .. " |cFF" .. RGBToHex(tr, tg, tb) .. tostring(titleDef.title or "") .. "|r"
end

function LeafVE:BuildStyledPlayerName(playerName, classTag)
  local shortName = self:GetStoredDisplayPlayerName(playerName)
  if shortName == "" then
    return ""
  end

  local classToken = string.upper(tostring(classTag or self:GetClassTagForPlayer(shortName) or "UNKNOWN"))
  local classColor = CLASS_COLORS[classToken] or {1, 1, 1}
  local nameMarkup = "|cFF" .. RGBToHex(classColor[1], classColor[2], classColor[3]) .. shortName .. "|r"
  local titleMarkup = self:BuildPlayerTitleMarkup(shortName)
  if titleMarkup then
    return titleMarkup .. " " .. nameMarkup
  end
  return nameMarkup
end

function LeafVE:GetChatTitlePrefixForPlayer(playerName)
  local titleDef = self:GetEquippedTitleDefinitionForPlayer(playerName)
  local titleLink = self:GetChatTitleLink(titleDef, false)
  if titleLink then
    return titleLink .. " "
  end
  return ""
end

function LeafVE:IsChatTitleEligibleType(chatType)
  return self.chatTitleEligibleTypes[string.upper(tostring(chatType or ""))] == true
end

function LeafVE:SetEquippedTitleForSelf(titleId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return false, "Could not determine your character name."
  end

  if titleId == "" then
    titleId = nil
  end
  if titleId and not self:GetTitleDefinition(titleId) then
    return false, "That title does not exist."
  end
  if titleId and not self:IsTitleUnlockedForPlayer(me, titleId) then
    return false, "You have not unlocked that title yet."
  end

  LeafVE_DB.equippedTitles[me] = titleId or nil
  self:SetTitleCacheRecord(me, titleId, Now())
  self:BroadcastMyEquippedTitle(true)
  if self.UI and self.UI.Refresh then
    self.UI:Refresh()
  end
  return true
end

function LeafVE:BroadcastMyEquippedTitle(force)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me or not InGuild() then
    return
  end

  self.lastTitleBroadcastAt = self.lastTitleBroadcastAt or 0
  local now = Now()
  if not force and (now - self.lastTitleBroadcastAt) < 15 then
    return
  end

  local titleId = LeafVE_DB.equippedTitles[me]
  if titleId and not self:IsTitleUnlockedForPlayer(me, titleId) then
    titleId = nil
    LeafVE_DB.equippedTitles[me] = nil
  end

  self.lastTitleBroadcastAt = now
  self:SetTitleCacheRecord(me, titleId, now)
  SendAddonMessage("LeafVE", "TITLEEQ:" .. tostring(now) .. SEP .. EncodeTalentField(titleId or ""), "GUILD")
end

function LeafVE:RequestPlayerTitle(playerName, force)
  local shortName = ShortName(playerName)
  local me = ShortName(UnitName("player"))
  if not shortName or not me or Lower(shortName) == Lower(me) or not InGuild() then
    return
  end

  self.lastTitleRequestAt = self.lastTitleRequestAt or {}
  local key = Lower(shortName)
  local now = Now()
  if not force and self.lastTitleRequestAt[key] and (now - self.lastTitleRequestAt[key]) < 15 then
    return
  end

  self.lastTitleRequestAt[key] = now
  SendAddonMessage("LeafVE", "TITLEREQ:" .. shortName, "GUILD")
end

local function ShouldAnnounceBadgeInGuild(playerName, badgeId)
  if not InGuild() then return false end
  if not badgeId or badgeId == "" then return false end
  if not LeafVE_DB.badgesAnnounced then LeafVE_DB.badgesAnnounced = {} end

  local shortPlayerName = ShortName(playerName) or tostring(playerName or "")
  local bucketKey = tostring(CurrentWipeVersion()) .. ":" .. shortPlayerName .. ":" .. tostring(badgeId or "")
  if LeafVE_DB.badgesAnnounced[bucketKey] then
    return false
  end

  return true
end

local BADGE_ANNOUNCEMENT_FLAVORS = {
  ["Activity"] = {
    "showing relentless dedication to the Leaf",
    "keeping the village standard high day after day",
    "proving steady devotion to the Shinobi path",
  },
  ["Social"] = {
    "standing shoulder to shoulder with fellow Shinobis",
    "strengthening the village through teamwork",
    "building bonds that make the Leaf stronger",
  },
  ["Shinobi Combatant"] = {
    "defending the Leaf alongside other Shinobis",
    "holding the line with fellow Shinobis in battle",
    "bringing honor to the village on the battlefield",
  },
  ["Recognition"] = {
    "uplifting the village through respect and recognition",
    "showing that honor and gratitude still matter in the Leaf",
    "earning the trust and respect of fellow Shinobis",
  },
  ["Milestones"] = {
    "reaching another legendary milestone for the Leaf",
    "pushing their Shinobi legend even higher",
    "proving their name belongs among the village elite",
  },
  ["Raids"] = {
    "leading the charge through the village's fiercest battles",
    "standing strong in the Leaf's hardest encounters",
    "conquering dangerous missions for the village",
  },
  ["Loyalty"] = {
    "remaining steadfast in service to the Leaf",
    "showing unwavering loyalty to the village",
    "staying true to the village through every season",
  },
  ["Work Orders"] = {
    "keeping the village supplied and battle-ready",
    "supporting the Leaf through tireless craftsmanship",
    "answering the village's call with skilled hands",
  },
  default = {
    "bringing honor to the Leaf",
    "serving the village with distinction",
    "strengthening the Leaf through their efforts",
  },
}

local function GetBadgeAnnouncementFlavor(playerName, badge)
  local flavorList = BADGE_ANNOUNCEMENT_FLAVORS[(badge and badge.category) or "default"]
    or BADGE_ANNOUNCEMENT_FLAVORS.default
  local count = table.getn(flavorList)
  if count <= 0 then
    return "bringing honor to the Leaf"
  end

  local seedText = tostring(playerName or "") .. ":" .. tostring(badge and badge.id or "") .. ":" .. tostring(Now())
  local hash = 0
  for i = 1, string.len(seedText) do
    hash = PositiveModulo((hash * 33) + (string.byte(seedText, i) or 0), 2147483647)
  end
  return flavorList[PositiveModulo(hash, count) + 1]
end

local function AnnounceBadgeInGuild(playerName, badge)
  if not badge or not ShouldAnnounceBadgeInGuild(playerName, badge.id) then
    return
  end
  local flavor = GetBadgeAnnouncementFlavor(playerName, badge)
  local badgeName = tostring(badge.name or badge.id or "Unknown Badge")
  local badgeLink = LeafVE:GetChatBadgeLink(badge) or ("[" .. badgeName .. "]")
  local announceText = "earned " .. badgeLink .. " for " .. flavor
  local unlockedTitle = LeafVE:GetTitleDefinition(badge.id)
  if unlockedTitle and unlockedTitle.title and unlockedTitle.title ~= "" then
    local titleLink = LeafVE:GetChatTitleLink(unlockedTitle, true) or ("[" .. tostring(unlockedTitle.title) .. "]")
    announceText = announceText .. " and now shall be known as " .. titleLink
  end
  if LeafVE:SendSystemChatMessage(announceText .. "!", "GUILD") then
    if not LeafVE_DB.badgesAnnounced then LeafVE_DB.badgesAnnounced = {} end
    local legacyBucketKey = tostring(CurrentWipeVersion())..":"..badge.id
    local shortPlayerName = ShortName(playerName) or tostring(playerName or "")
    local bucketKey = tostring(CurrentWipeVersion()) .. ":" .. shortPlayerName .. ":" .. tostring(badge.id or "")

    -- Clear legacy unscoped keys so old seasons do not permanently suppress
    -- current guild announcements after the bucket-scoped migration.
    if LeafVE_DB.badgesAnnounced[badge.id] then
      LeafVE_DB.badgesAnnounced[badge.id] = nil
    end
    if LeafVE_DB.badgesAnnounced[legacyBucketKey] then
      LeafVE_DB.badgesAnnounced[legacyBucketKey] = nil
    end
    LeafVE_DB.badgesAnnounced[bucketKey] = true
  end
end

function LeafVE:AwardBadge(playerName, badgeId)
  EnsureDB()
  playerName = ShortName(playerName)
  
  if not playerName then
    Print("ERROR: Invalid player name")
    return
  end
  
  -- Check if badge exists
  local badge = GetBadgeDefinition(badgeId)

  if not badge then
    Print("ERROR: Badge '"..badgeId.."' does not exist")
    return
  end

  -- Initialize player badges table if needed
  if not LeafVE_DB.badges[playerName] then
    LeafVE_DB.badges[playerName] = {}
  end

  -- Check if already earned
  if LeafVE_DB.badges[playerName][badgeId] then
    Print(playerName.." already has badge: "..badgeId)
    return
  end

  -- Award the badge
  LeafVE_DB.badges[playerName][badgeId] = time()
  Print("Badge awarded to "..playerName..": "..badgeId)

  -- Show notification if this is the current player
  local me = ShortName(UnitName("player"))
  if me and playerName == me then
    local badgeQuality = badge.quality or BADGE_QUALITY.COMMON
    local qr, qg, qb = GetBadgeQualityColor(badgeQuality)
    local qualityLabel = GetBadgeQualityLabel(badgeQuality)
    if LeafVE_DB.options.enableNotifications ~= false and LeafVE_DB.options.enableBadgeNotifications ~= false then
      self:ShowNotification("Badge Earned! ["..qualityLabel.."]", badge.name..": "..badge.desc, badge.icon, {qr, qg, qb, 1})
    end
    Print("|cFF"..RGBToHex(qr, qg, qb).."["..qualityLabel.."] Badge Earned:|r "..badge.name.." - "..badge.desc)

    local unlockedTitle = self:GetTitleDefinition(badgeId)
    if unlockedTitle then
      local unlockedTitleMarkup = "|cFF" .. RGBToHex(qr, qg, qb) .. "[" .. tostring(unlockedTitle.title or "") .. "]|r"
      if LeafVE_DB.options.enableNotifications ~= false and LeafVE_DB.options.enableBadgeNotifications ~= false then
        self:ShowNotification("Title Unlocked", tostring(unlockedTitle.title or "New Title") .. " can now be equipped in Titles.", badge.icon, {qr, qg, qb, 1})
      end
      Print("|cFF2DD35CNew Title Unlocked:|r " .. unlockedTitleMarkup .. " |cFFAAAAAA(Character -> Titles)|r")
    end
  end

  -- Send guild chat announcement (only once per badge, never re-announce)
  AnnounceBadgeInGuild(playerName, badge)

  -- Broadcast badges immediately after awarding
  if me and playerName == me then
    self:BroadcastBadges()
  end
  
  -- Refresh UI if player card is showing this player
  if LeafVE.UI.cardCurrentPlayer == playerName then
    LeafVE.UI:UpdateCardRecentBadges(playerName)
  end
  
  -- Refresh badges tab if open
  if LeafVE.UI.panels and LeafVE.UI.panels.badges and LeafVE.UI.panels.badges:IsVisible() then
    LeafVE.UI:RefreshBadges()
  end
  if LeafVE.UI.panels and LeafVE.UI.panels.titles and LeafVE.UI.panels.titles:IsVisible() then
    LeafVE.UI:RefreshTitlesPanel()
  end
end

function LeafVE:AwardRandomBadge(playerName)
  EnsureDB()
  playerName = ShortName(playerName)
  if not playerName then
    Print("ERROR: Invalid player name")
    return
  end
  if not LeafVE_DB.badges[playerName] then LeafVE_DB.badges[playerName] = {} end
  local unearned = {}
  for i = 1, table.getn(BADGES) do
    if not LeafVE_DB.badges[playerName][BADGES[i].id] then
      table.insert(unearned, BADGES[i].id)
    end
  end
  if table.getn(unearned) == 0 then
    Print(playerName.." already has all badges.")
    return
  end
  local idx = math.random(1, table.getn(unearned))
  self:AwardBadge(playerName, unearned[idx])
end

function LeafVE:ResetMyBadges()
  EnsureDB()
  if not self:IsAdminRank() then
return false, "Only Kage / Hokage can reset badges from the admin panel."
  end

  local me = ShortName(UnitName("player"))
  if not me then
    return false, "Could not determine your character name."
  end

  LeafVE_DB.badges[me] = {}
  LeafVE_DB.equippedTitles[me] = nil
  self:SetTitleCacheRecord(me, nil, Now())

  if LeafVE_DB.badgesAnnounced then
    for key, _ in pairs(LeafVE_DB.badgesAnnounced) do
      if type(key) == "string" and string.find(key, ":" .. me .. ":", 1, true) then
        LeafVE_DB.badgesAnnounced[key] = nil
      end
    end
  end

  if self.BroadcastBadges then
    self:BroadcastBadges()
  end
  self:BroadcastMyEquippedTitle(true)

  if LeafVE.UI then
    if LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == Lower(me) and LeafVE.UI.UpdateCardRecentBadges then
      LeafVE.UI:UpdateCardRecentBadges(me)
    end
    if LeafVE.UI.panels and LeafVE.UI.panels.badges and LeafVE.UI.panels.badges:IsVisible() and LeafVE.UI.RefreshBadges then
      LeafVE.UI:RefreshBadges()
    end
    if LeafVE.UI.panels and LeafVE.UI.panels.titles and LeafVE.UI.panels.titles:IsVisible() and LeafVE.UI.RefreshTitlesPanel then
      LeafVE.UI:RefreshTitlesPanel()
    end
  end

  Print("|cFF88FF88Your current-season badges have been reset.|r")
  return true
end

-- Wipes all saved data for the current player (account-wide).
-- Clears both the per-character DB and all per-player entries in the shared DB,
-- then broadcasts a removal notice to online guild members so their caches are
-- also cleaned up, preventing polluted data from entering the leaderboards.
function LeafVE:ResetMyData()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    Print("|cFFFF4444Error: Could not determine your character name.|r")
    return
  end

  -- Clear all point and tracking data keyed by the player's name.
  LeafVE_DB.alltime[me]            = nil
  LeafVE_DB.season[me]             = nil
  LeafVE_DB.loginStreaks[me]       = nil
  LeafVE_DB.loginTracking[me]      = nil
  LeafVE_DB.groupSessions[me]      = nil
  LeafVE_DB.groupPointsToday[me]   = nil
  LeafVE_DB.guildieGroupHours[me]  = nil
  LeafVE_DB.guildieHonorableKills[me] = nil
  LeafVE_DB.pvpStats[me]           = nil
  if LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate[me] = nil end
  LeafVE_DB.attendance[me]         = nil
  LeafVE_DB.pointHistory[me]       = nil
  LeafVE_DB.instanceTracking[me]   = nil
  LeafVE_DB.questTracking[me]      = nil
  LeafVE_DB.questCompletions[me]   = nil
  LeafVE_DB.badges[me]             = nil
  LeafVE_DB.equippedTitles[me]     = nil
  LeafVE_DB.badgesAnnounced[me]    = nil
  for key, _ in pairs(LeafVE_DB.badgesAnnounced) do
    if type(key) == "string" and string.find(key, ":" .. me .. ":", 1, true) then
      LeafVE_DB.badgesAnnounced[key] = nil
    end
  end
  -- Remove from leaderboard caches.
  LeafVE_DB.lboard.alltime[me]     = nil
  LeafVE_DB.lboard.updatedAt[me]   = nil
  for _, wkData in pairs(LeafVE_DB.lboard.weekly) do
    if type(wkData) == "table" then wkData[me] = nil end
  end
  if LeafVE_DB.lboard.season then
    LeafVE_DB.lboard.season[me] = nil
  end
  -- Remove from daily global point tables.
  for _, dayData in pairs(LeafVE_DB.global) do
    if type(dayData) == "table" then dayData[me] = nil end
  end
  -- Remove shoutouts sent by this player and shoutouts targeting this player.
  LeafVE_DB.shoutouts[me] = nil
  for _, targets in pairs(LeafVE_DB.shoutouts) do
    if type(targets) == "table" then targets[me] = nil end
  end
  -- Clear account-wide (GlobalDB) entries for this player.
  if LeafVE_GlobalDB.achievementCache then
    LeafVE_GlobalDB.achievementCache[me] = nil
  end
  if LeafVE_GlobalDB.titleCache then
    LeafVE_GlobalDB.titleCache[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.lboardCache then
    if LeafVE_GlobalDB.lboardCache.alltime then
      LeafVE_GlobalDB.lboardCache.alltime[me] = nil
    end
    if LeafVE_GlobalDB.lboardCache.weekly then
      for _, wkData in pairs(LeafVE_GlobalDB.lboardCache.weekly) do
        if type(wkData) == "table" then wkData[me] = nil end
      end
    end
  end
  if LeafVE_GlobalDB.badgeProgressCache then
    LeafVE_GlobalDB.badgeProgressCache[me] = nil
  end
  if LeafVE_GlobalDB.gearCache then
    LeafVE_GlobalDB.gearCache[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.specCache then
    LeafVE_GlobalDB.specCache[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.talentCache then
    LeafVE_GlobalDB.talentCache[Lower(me)] = nil
  end
  if LeafVE.talentSyncBuffer then
    LeafVE.talentSyncBuffer[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.playerNotes then
    LeafVE_GlobalDB.playerNotes[me] = nil
  end
  if LeafVE_GlobalDB.professionDesignations then
    LeafVE_GlobalDB.professionDesignations[Lower(me)] = nil
  end

  -- Broadcast so online guild members remove this player from their caches.
  if InGuild() then
    SendAddonMessage("LeafVE", "LVE_PLAYER_DATA_RESET:"..me, "GUILD")
  end

  Print("|cFF2DD35CYour saved data has been reset. Guild members have been notified to remove your entries from their leaderboard caches.|r")
  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
end

-- Wipes ALL addon SavedVariables for this client (daily/weekly/season/lifetime
-- points, history, badges, leaderboard cache, gear cache, notes, etc.) and then
-- reloads the UI so the addon starts from a completely clean slate.
function LeafVE:ResetAllData_Local()
  LeafVE_DB       = {}
  LeafVE_GlobalDB = {}
  ReloadUI()
end

-- Resets point/history/leaderboard fields on the local player's LeafVE_DB while
-- preserving badge structures and lastWipeApplied so full-wipe bucket transitions
-- can rotate cleanly without losing archived badge seasons.
function LVE_ResetPlayerDB()
  local wipeApplied = (LeafVE_DB and LeafVE_DB.lastWipeApplied) or 0
  local preservedBadges = (LeafVE_DB and LeafVE_DB.badges) or nil
  local preservedBadgesAnnounced = (LeafVE_DB and LeafVE_DB.badgesAnnounced) or nil
  local preservedBadgeBucketVersion = (LeafVE_DB and LeafVE_DB.badgeBucketVersion) or nil
  local preservedBadgesArchive = (LeafVE_DB and LeafVE_DB.badgesArchive) or nil
  if LeafVE_DB then
    for k in pairs(LeafVE_DB) do
      LeafVE_DB[k] = nil
    end
  else
    LeafVE_DB = {}
  end
  LeafVE_DB.lastWipeApplied = wipeApplied
  if type(preservedBadges) == "table" then
    LeafVE_DB.badges = preservedBadges
  end
  if type(preservedBadgesAnnounced) == "table" then
    LeafVE_DB.badgesAnnounced = preservedBadgesAnnounced
  end
  if preservedBadgeBucketVersion ~= nil then
    LeafVE_DB.badgeBucketVersion = preservedBadgeBucketVersion
  end
  if type(preservedBadgesArchive) == "table" then
    LeafVE_DB.badgesArchive = preservedBadgesArchive
  end
  EnsureDB()
end

-- After a full wipe, prevent the same day's auto-login grant from immediately
-- repopulating all-time with +20 L points on the next login refresh.
local function LVE_StampTodayLoginAsHandled()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  local today = DayKey()
  if not LeafVE_DB.loginTracking[me] then
    LeafVE_DB.loginTracking[me] = {}
  end
  LeafVE_DB.loginTracking[me][today] = true
end

local function LVE_ApplyFullWipeVersion(wipeVersion, announceMessage)
  wipeVersion = tonumber(wipeVersion) or 0
  if wipeVersion <= 0 then return false end

  LVE_ResetGlobalDB(wipeVersion)
  local appliedVersion = (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or wipeVersion
  LVE_ResetPlayerDB()
  LeafVE_DB.lastWipeApplied = appliedVersion
  LVE_StampTodayLoginAsHandled()
  if announceMessage and announceMessage ~= "" then
    Print(announceMessage)
  end
  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
  return true
end

local function ShouldApplyIncomingWipeVersion(incomingVersion)
  incomingVersion = tonumber(incomingVersion) or 0
  if incomingVersion <= 0 then return false end
  local localVersion = (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or 0
  local lastApplied = (LeafVE_DB and tonumber(LeafVE_DB.lastWipeApplied)) or 0
  local effectiveLocalVersion = math.max(localVersion, lastApplied)
  return incomingVersion > effectiveLocalVersion
end

function LeafVE:BroadcastFullWipeVersion(wipeVersion)
  if not InGuild() then return end
  local version = tonumber(wipeVersion) or ((LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0)
  if version and version > 0 then
    SendAddonMessage("LeafVE", "FULL_WIPE:"..version, "GUILD")
  end
end

local function ParseGuildWipeMarkerVersion(infoText)
  if type(infoText) ~= "string" then return 0 end
  local markerVersion = string.match(infoText, FULL_WIPE_GUILD_MARKER_PATTERN)
  return tonumber(markerVersion) or 0
end

local function BuildGuildInfoTextWithWipeMarker(infoText, wipeVersion)
  local cleanInfo = string.gsub(tostring(infoText or ""), FULL_WIPE_GUILD_MARKER_STRIP_PATTERN, " ")
  cleanInfo = Trim(cleanInfo)
  local marker = "["..FULL_WIPE_GUILD_MARKER..":"..tostring(wipeVersion).."]"
  if cleanInfo == "" then
    return marker
  end
  return cleanInfo.." "..marker
end

function LeafVE:PublishGuildWipeMarker(wipeVersion)
  if not wipeVersion or wipeVersion <= 0 then return false, "invalid_version" end
  if not InGuild() then return false, "not_in_guild" end
  if not GetGuildInfoText or not SetGuildInfoText then
    return false, "guild_info_api_unavailable"
  end

  local currentInfo = GetGuildInfoText() or ""
  local currentMarkerVersion = ParseGuildWipeMarkerVersion(currentInfo)
  if currentMarkerVersion >= wipeVersion then
    return true, "already_current"
  end

  local updatedInfo = BuildGuildInfoTextWithWipeMarker(currentInfo, wipeVersion)
  SetGuildInfoText(updatedInfo)
  return true, "set_requested"
end

function LeafVE:ApplyGuildWipeMarkerIfNeeded()
  EnsureDB()
  if not InGuild() then return false end
  if not GetGuildInfoText then return false end

  local guildMarkerVersion = ParseGuildWipeMarkerVersion(GetGuildInfoText() or "")
  if guildMarkerVersion <= 0 then return false end

  local localVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
  local lastApplied = (LeafVE_DB and LeafVE_DB.lastWipeApplied) or 0
  local effectiveLocalVersion = math.max(localVersion, lastApplied)
  if guildMarkerVersion <= effectiveLocalVersion then
    return false
  end

  local applied = LVE_ApplyFullWipeVersion(
    guildMarkerVersion,
    "|cFFFFD700[LVL]|r Detected guild wipe marker; local data reset applied."
  )
  if applied then
    self:BroadcastFullWipeVersion(guildMarkerVersion)
  end
  return applied
end

-- Clears all account-wide caches and stamps fullWipeVersion.
-- When targetVersion is nil, this uses epoch seconds (monotonic fallback) and
-- returns the new version.
function LVE_ResetGlobalDB(targetVersion)
  local currentVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
  local newVersion = tonumber(targetVersion)
  if not newVersion or newVersion <= 0 then
    -- Use epoch seconds so each admin wipe is globally monotonic across clients.
    newVersion = Now()
    if newVersion <= currentVersion then
      newVersion = currentVersion + 1
    end
  elseif newVersion < currentVersion then
    -- Never move backward; older relays must not downgrade local wipe state.
    newVersion = currentVersion
  end
  if LeafVE_GlobalDB then
    for k in pairs(LeafVE_GlobalDB) do
      LeafVE_GlobalDB[k] = nil
    end
  else
    LeafVE_GlobalDB = {}
  end
  LeafVE_GlobalDB.fullWipeVersion = newVersion
  EnsureDB()
  return newVersion
end

-- Admin-only full wipe. This is the sole guild-wide reset path.
function LeafVE:ExecuteAdminFullDataWipe()
  if not self:IsAdminRank() then
Print("|cFFFF4444Access denied: only Kage / Hokage can perform a full data wipe.|r")
    return
  end

  EnsureDB()
  local wipeVersion = LVE_ResetGlobalDB()
  LVE_ResetPlayerDB()
  LeafVE_DB.lastWipeApplied = wipeVersion
  LVE_StampTodayLoginAsHandled()
  local markerPublished, markerReason = self:PublishGuildWipeMarker(wipeVersion)
  if not markerPublished then
    Print("|cFFFFAA00[LVL]|r Could not publish guild wipe marker ("..tostring(markerReason).."). Offline clients will reset once they receive live guild sync.")
  end

  self:BroadcastFullWipeVersion(wipeVersion)

  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
  Print("|cFFFF2222[LVL]|r Full data wipe complete for all guild members.")
end

