function LeafVE:GetConfiguredGroupInterval()
  -- Guildie-hour badges are standardized to one tick per 60 minutes for everyone.
  return GROUP_POINT_INTERVAL
end

function LeafVE:GetConfiguredGroupPoints()
  local configured = (LeafVE_DB and LeafVE_DB.options and tonumber(LeafVE_DB.options.groupPoints)) or GROUP_POINTS
  if not configured or configured < 1 then
    configured = GROUP_POINTS
  end
  return configured
end

function LeafVE:GetClassTagForPlayer(playerName)
  local info = self:GetGuildInfo(playerName)
  local class = info and info.class or nil
  if not class and playerName then
    local unit = FindUnitToken(playerName)
    if unit and UnitClass then
      local _, classTag = UnitClass(unit)
      class = classTag or class
    end
  end
  class = string.upper(Trim(class or ""))
  if class == "" then class = "UNKNOWN" end
  return class
end

function LeafVE:GetSpecIndexForClass(classTag)
  EnsureDB()
  classTag = string.upper(classTag or "")
  local specList = CLASS_SPEC_NAMES[classTag]
  if not specList then return 1 end
  local idx = tonumber(LeafVE_DB.specSelection[classTag]) or 1
  if idx < 1 then idx = 1 end
  if idx > table.getn(specList) then idx = table.getn(specList) end
  return idx
end

function LeafVE:GetSpecSnapshotForPlayer(playerName, classTag)
  EnsureDB()
  local cache = LeafVE_GlobalDB.specCache and LeafVE_GlobalDB.specCache[Lower(playerName or "")]
  classTag = string.upper(classTag or "")
  if classTag == "" or classTag == "UNKNOWN" then
    if cache and cache.class then
      classTag = string.upper(cache.class)
    else
      classTag = self:GetClassTagForPlayer(playerName)
    end
  end

  local idx = 1
  local me = ShortName(UnitName("player"))
  if me and playerName and Lower(me) == Lower(playerName) then
    idx = self:GetSpecIndexForClass(classTag)
  else
    if cache and cache.class and cache.index then
      if classTag == "" or classTag == "UNKNOWN" then
        classTag = string.upper(cache.class)
      end
      idx = tonumber(cache.index) or 1
    end
  end

  local names = CLASS_SPEC_NAMES[classTag]
  local icons = CLASS_SPEC_ICONS[classTag]
  local specName = (names and names[idx]) or classTag
  local specIcon = (icons and icons[idx]) or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark"
  return {
    class = classTag,
    index = idx,
    name = specName,
    icon = specIcon,
  }
end

function LeafVE:GetLiveTalentSnapshot()
  local me = ShortName(UnitName("player"))
  if not me then return nil end
  local treeSnapshot = self:GetTalentTreeSnapshotForPlayer(me, nil, false)

  local bestName, bestIcon = nil, nil
  local bestPoints = -1
  local totalSpent = 0
  local tabs = {}

  if treeSnapshot and treeSnapshot.tabs then
    local maxTab = 0
    for idx in pairs(treeSnapshot.tabs) do
      idx = tonumber(idx) or 0
      if idx > maxTab then maxTab = idx end
    end
    for i = 1, maxTab do
      local tab = treeSnapshot.tabs[i]
      if tab then
        local pointsSpent = tonumber(tab.points) or 0
        totalSpent = totalSpent + pointsSpent
        local row = {
          name = tab.name or ("Tree " .. tostring(i)),
          icon = tab.icon or "Interface\\Icons\\INV_Misc_QuestionMark",
          points = pointsSpent,
        }
        table.insert(tabs, row)
        if pointsSpent > bestPoints then
          bestPoints = pointsSpent
          bestName = row.name
          bestIcon = row.icon
        end
      end
    end
  else
    if not GetNumTalentTabs or not GetTalentTabInfo then return nil end
    local tabCount = GetNumTalentTabs()
    if not tabCount or tabCount < 1 then return nil end
    for i = 1, tabCount do
      local treeName, treeIcon, pointsSpent = GetTalentTabInfo(i)
      pointsSpent = tonumber(pointsSpent) or 0
      totalSpent = totalSpent + pointsSpent

      local row = {
        name = treeName or ("Tree " .. tostring(i)),
        icon = NormalizeIconPath(treeIcon) or "Interface\\Icons\\INV_Misc_QuestionMark",
        points = pointsSpent,
      }
      table.insert(tabs, row)

      if pointsSpent > bestPoints then
        bestPoints = pointsSpent
        bestName = row.name
        bestIcon = row.icon
      end
    end
  end

  return {
    name = bestName,
    icon = bestIcon,
    points = bestPoints,
    total = totalSpent,
    tabs = tabs,
  }
end

function LeafVE:GetTalentSpecForPlayer(playerName, classTag)
  playerName = ShortName(playerName)
  if not playerName then return nil end
  classTag = string.upper(classTag or "")
  if classTag == "" or classTag == "UNKNOWN" then
    classTag = self:GetClassTagForPlayer(playerName)
  end

  local me = ShortName(UnitName("player"))
  local isSelf = me and Lower(me) == Lower(playerName)

  local treeSnapshot = self:GetTalentTreeSnapshotForPlayer(playerName, classTag, false)
  if treeSnapshot and treeSnapshot.tabs then
    local bestIdx = tonumber(treeSnapshot.activeTab) or 1
    local bestName = nil
    local bestIcon = nil
    local bestPoints = -1
    local totalSpent = 0
    local tabs = {}
    local maxTab = 0
    for idx in pairs(treeSnapshot.tabs) do
      idx = tonumber(idx) or 0
      if idx > maxTab then maxTab = idx end
    end
    for idx = 1, maxTab do
      local tab = treeSnapshot.tabs[idx]
      if tab then
        local points = tonumber(tab.points) or 0
        totalSpent = totalSpent + points
        table.insert(tabs, {
          name = tab.name or ("Tree " .. tostring(idx)),
          icon = tab.icon or "Interface\\Icons\\INV_Misc_QuestionMark",
          points = points,
        })
        if points > bestPoints then
          bestPoints = points
          bestIdx = idx
          bestName = tab.name
          bestIcon = tab.icon
        end
      end
    end
    if bestName and totalSpent > 0 then
      return {
        class = classTag,
        index = bestIdx,
        name = bestName,
        icon = bestIcon or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark",
        source = isSelf and "live" or "broadcast",
        points = bestPoints,
        total = totalSpent,
        tabs = tabs,
      }
    end
  end

  local spec = self:GetSpecSnapshotForPlayer(playerName, classTag)
  if spec then
    spec.source = "cached"
    return spec
  end
  return nil
end

function LeafVE:CycleMySpec()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  local classTag = self:GetClassTagForPlayer(me)
  local names = CLASS_SPEC_NAMES[classTag]
  if not names or table.getn(names) == 0 then return end
  local cur = self:GetSpecIndexForClass(classTag)
  local nextIdx = cur + 1
  if nextIdx > table.getn(names) then nextIdx = 1 end
  LeafVE_DB.specSelection[classTag] = nextIdx
  self:BroadcastMyGear(true)
end

function LeafVE:RecordActivity()
  self.lastActivityTime = Now()
end

function LeafVE:IsPlayerInactive(useActivityTimeout)
  if UnitIsAFK and UnitIsAFK("player") then
    return true
  end
  if useActivityTimeout == nil then useActivityTimeout = true end
  if useActivityTimeout and self.lastActivityTime and (Now() - self.lastActivityTime) > AFK_TIMEOUT then
    return true
  end
  return false
end

-- Returns true if the current player holds an approved Leaf Village rank.
function LeafVE:HasLeafAccess()
