-- Returns true if `name` appears in the in-memory roster cache or the
-- persistent roster, covering the case where GetGuildInfo() returns nil.
function LeafVE:IsKnownGuildie(name)
  if not name then return false end
  local lname = Lower(name)
  return (self.guildRosterCache[lname] ~= nil)
    or (LeafVE_DB and LeafVE_DB.persistentRoster and LeafVE_DB.persistentRoster[lname] ~= nil)
end

function LeafVE:GetGroupGuildies()
  local me = ShortName(UnitName("player"))
  local myGuild = GetGuildInfo("player")  -- may be nil early in the session
  self:UpdateGuildRosterCache()
  local guildies = {} local numMembers = GetNumRaidMembers() local isRaid = numMembers > 0
  if not isRaid then numMembers = GetNumPartyMembers() end
  if numMembers == 0 then return {} end
  for i = 1, numMembers do
    local unit = isRaid and "raid"..i or "party"..i
    if UnitExists(unit) and UnitIsConnected(unit) then
      local name = UnitName(unit) name = ShortName(name)
      local unitGuild = GetGuildInfo(unit)
      local isGuildie = (myGuild and unitGuild and unitGuild == myGuild)
        or self:IsKnownGuildie(name)
      if name and isGuildie and (not me or Lower(name) ~= Lower(me)) then
        table.insert(guildies, name)
      end
    end
  end
  return guildies
end

function LeafVE:GetGroupHash(members) table.sort(members) return table.concat(members, ",") end

local function GetLifetimeHonorableKills()
  if type(GetPVPLifetimeStats) ~= "function" then
    return nil
  end
  local ok, honorableKills = pcall(GetPVPLifetimeStats)
  if not ok then
    return nil
  end
  honorableKills = tonumber(honorableKills)
  if honorableKills == nil or honorableKills < 0 then
    return nil
  end
  return honorableKills
end

function LeafVE:PrimeHonorableKillTracker()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  if not LeafVE_DB.pvpStats[me] then LeafVE_DB.pvpStats[me] = {} end

  local currentKills = GetLifetimeHonorableKills()
  if currentKills ~= nil then
    LeafVE_DB.pvpStats[me].lastLifetimeHonorableKills = currentKills
  end
end

function LeafVE:RecordGuildieHonorableKillProgress(playerName, killCount)
  EnsureDB()
  playerName = ShortName(playerName)
  killCount = tonumber(killCount) or 0
  if not playerName or killCount <= 0 then
    return 0
  end

  if not LeafVE_DB.guildieHonorableKills then LeafVE_DB.guildieHonorableKills = {} end
  LeafVE_DB.guildieHonorableKills[playerName] = (LeafVE_DB.guildieHonorableKills[playerName] or 0) + killCount
  self:AddShinobiDutyWeeklyStat(playerName, "guildieHonorableKills", killCount)
  self:CacheBadgeProgress(playerName)
  self:CheckBadgeMilestones(playerName)
  if InGuild() then
    self:BroadcastBadgeProgress()
  end
  self:RefreshShinobiDutyProgress(playerName)

  return LeafVE_DB.guildieHonorableKills[playerName]
end

function LeafVE:ApplyGuildieHonorableKillPointAward(playerName, killCount, guildieList)
  EnsureDB()
  playerName = ShortName(playerName)
  local requestedKills = tonumber(killCount) or 0
  if not playerName or requestedKills <= 0 then
    return 0
  end

  local today = DayKey()
  if not LeafVE_DB.groupPointsToday then LeafVE_DB.groupPointsToday = {} end
  if not LeafVE_DB.groupPointsToday[playerName] then LeafVE_DB.groupPointsToday[playerName] = {} end
  local todayData = LeafVE_DB.groupPointsToday[playerName]
  if todayData.date ~= today then
    todayData.date = today
    todayData.earned = 0
  end

  local pointsToAward = requestedKills * 0.5
  if GROUP_POINTS_DAILY_CAP ~= 0 then
    local earned = todayData.earned or 0
    if earned >= GROUP_POINTS_DAILY_CAP then
      return 0
    end
    local remaining = GROUP_POINTS_DAILY_CAP - earned
    if pointsToAward > remaining then
      pointsToAward = remaining
    end
  end

  if pointsToAward <= 0 then
    return 0
  end

  local awarded = self:AddPoints(playerName, "G", pointsToAward, true)
  if awarded and awarded > 0 then
    todayData.earned = (todayData.earned or 0) + awarded
    self:CacheBadgeProgress(playerName)
    local reason = "Honorable kill alongside guildies"
    if requestedKills > 1 then
      reason = "Honorable kills alongside guildies (" .. tostring(requestedKills) .. " HKs)"
    end
    if guildieList and guildieList ~= "" then
      reason = reason .. ": " .. tostring(guildieList)
    end
    self:AddToHistory(playerName, "G", awarded, reason)
    if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
    self:BroadcastLeaderboardData()
    return awarded
  end

  if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
  return 0
end

function LeafVE:HandleHonorableKillUpdate()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  if not LeafVE_DB.pvpStats then LeafVE_DB.pvpStats = {} end
  if not LeafVE_DB.pvpStats[me] then LeafVE_DB.pvpStats[me] = {} end

  local currentKills = GetLifetimeHonorableKills()
  if currentKills == nil then
    return
  end

  local previousKills = LeafVE_DB.pvpStats[me].lastLifetimeHonorableKills
  if previousKills == nil then
    LeafVE_DB.pvpStats[me].lastLifetimeHonorableKills = currentKills
    return
  end

  previousKills = tonumber(previousKills) or 0
  if currentKills <= previousKills then
    LeafVE_DB.pvpStats[me].lastLifetimeHonorableKills = currentKills
    return
  end

  LeafVE_DB.pvpStats[me].lastLifetimeHonorableKills = currentKills

  local killDelta = currentKills - previousKills
  if killDelta <= 0 then
    return
  end

  local guildies = self:GetGroupGuildies()
  if table.getn(guildies) <= 0 then
    return
  end

  local guildieList = table.concat(guildies, ", ")
  self:RecordGuildieHonorableKillProgress(me, killDelta)
  self:ApplyGuildieHonorableKillPointAward(me, killDelta, guildieList)
end

-- Shared helper: apply a group-point award for the local player.
-- Handles daily cap, AddPoints, history, badges, and chat feedback.
-- Returns the number of points actually awarded (0 if capped or ineligible).
function LeafVE:ApplyGroupPointAward(playerName, pointsPerGuildie, numGuildies, guildieList)
  EnsureDB()
  local today = DayKey()
  if not LeafVE_DB.groupPointsToday then LeafVE_DB.groupPointsToday = {} end
  if not LeafVE_DB.groupPointsToday[playerName] then LeafVE_DB.groupPointsToday[playerName] = {} end
  local todayData = LeafVE_DB.groupPointsToday[playerName]
  if todayData.date ~= today then
    todayData.date = today
    todayData.earned = 0
  end

  -- Each valid hourly tick always advances guildie-hour progress, even when LP is capped.
  LeafVE_DB.groupSessions[playerName] = (LeafVE_DB.groupSessions[playerName] or 0) + 1
  LeafVE_DB.guildieGroupHours[playerName] = (LeafVE_DB.guildieGroupHours[playerName] or 0) + 1
  self:AddShinobiDutyWeeklyStat(playerName, "groupHours", 1)
  self:CacheBadgeProgress(playerName)
  self:CheckBadgeMilestones(playerName)
  if InGuild() then self:BroadcastBadgeProgress() end
  self:RefreshShinobiDutyProgress(playerName)

  if GROUP_POINTS_DAILY_CAP ~= 0 then
    local earned = todayData.earned or 0
    if earned >= GROUP_POINTS_DAILY_CAP then
      Print(string.format("|cFFFF4444Group points skipped - daily group cap of %d LP reached!|r", GROUP_POINTS_DAILY_CAP))
      if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
      return 0
    end
  end

  local points = pointsPerGuildie * numGuildies
  if GROUP_POINTS_DAILY_CAP ~= 0 then
    local remaining = GROUP_POINTS_DAILY_CAP - (todayData.earned or 0)
    local now = Now()
    local projectedAward = ApplyPointMultiplier(points, now)
    if projectedAward > remaining then
      -- AddPoints may multiply weekend awards; trim the pre-multiplier input so
      -- the post-multiplier result does not overshoot the group-specific cap.
      if IsDoublePointsWeekend(now) then
        points = math.floor(remaining / WEEKEND_POINT_MULTIPLIER)
      else
        points = remaining
      end
    end
    if points <= 0 then
      Print(string.format("|cFFFF4444Group points skipped - daily group cap of %d LP reached!|r", GROUP_POINTS_DAILY_CAP))
      if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
      return 0
    end
  end

  local awarded = self:AddPoints(playerName, "G", points)
  if awarded and awarded > 0 then
    todayData.earned = (todayData.earned or 0) + awarded
    self:CacheBadgeProgress(playerName)
    self:AddToHistory(playerName, "G", awarded, "Grouped with "..numGuildies.." guildies: "..guildieList)
    Print(string.format("Group points awarded! +%d LP (%d per guildie x%d guildies)", awarded, pointsPerGuildie, numGuildies))
    if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
    self:BroadcastLeaderboardData()
  else
    if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
  end

  return awarded or 0
end
function LeafVE:OnGroupUpdate()
  local guildies = self:GetGroupGuildies()
  local numGuildies = table.getn(guildies)

  if numGuildies == 0 then
    self.currentGroupStart = nil
    self.currentGroupMembers = {}
    self.lastGroupAwardTick = nil
    self.lastGroupAwardTime = nil
    self.grpAwardFallbackAt = nil
    return
  end

  local groupHash = self:GetGroupHash(guildies)
  if not self.currentGroupStart or groupHash ~= self:GetGroupHash(self.currentGroupMembers) then
    self.currentGroupStart = Now()
    self.currentGroupMembers = guildies
    self.lastGroupAwardTick = nil
    self.lastGroupAwardTime = nil
    self.grpAwardFallbackAt = nil
    Print("Group leaf points are now active! (grouped with: "..table.concat(guildies, ", ")..")")
    return
  end

  EnsureDB()
  local isRaid = GetNumRaidMembers() > 0
  local groupInterval = self:GetConfiguredGroupInterval()
  local pointsPerGuildie = self:GetConfiguredGroupPoints()
  local now = Now()
  local currentTick = math.floor(now / groupInterval)
  local lastAwardedTick = self.lastGroupAwardTick or -1

  if currentTick > lastAwardedTick and self.currentGroupStart and (now - self.currentGroupStart) >= groupInterval then
    local playerName = ShortName(UnitName("player"))
    if not playerName then return end

    local broadcasterCandidates = {playerName}
    for _, g in ipairs(guildies) do
      table.insert(broadcasterCandidates, g)
    end
    table.sort(broadcasterCandidates)
    local amBroadcaster = (Lower(playerName) == Lower(broadcasterCandidates[1]))

    if amBroadcaster then
      if self:IsPlayerInactive(false) then
        self.lastGroupAwardTick = currentTick
        self.lastGroupAwardTime = now
        Print("|cFFFF4444Group points skipped - you appear to be AFK!|r")
        return
      end

      self:ApplyGroupPointAward(playerName, pointsPerGuildie, numGuildies, table.concat(guildies, ", "))
      self.lastGroupAwardTick = currentTick
      self.lastGroupAwardTime = now

      local channel = isRaid and "RAID" or "PARTY"
      SendAddonMessage("LeafVE", "GRPAWARD:"..pointsPerGuildie.."|"..numGuildies.."|"..table.concat(guildies, ","), channel)
    else
      if not self.grpAwardFallbackAt then
        self.grpAwardFallbackAt = now + GRPAWARD_GRACE_PERIOD
      elseif now >= self.grpAwardFallbackAt then
        self.grpAwardFallbackAt = nil
        local localPlayer = ShortName(UnitName("player"))
        if localPlayer then
          if self:IsPlayerInactive(false) then
            self.lastGroupAwardTick = currentTick
            self.lastGroupAwardTime = now
            Print("|cFFFF4444Group points skipped - you appear to be AFK!|r")
            return
          end
          self:ApplyGroupPointAward(localPlayer, pointsPerGuildie, numGuildies, table.concat(guildies, ", "))
          self.lastGroupAwardTick = currentTick
          self.lastGroupAwardTime = now
        end
      end
    end
  end
end
