-- INSTANCE / BOSS / QUEST TRACKING
-------------------------------------------------

-------------------------------------------------
-- pfDB INTEGRATION (pfQuest database)
-------------------------------------------------

-- Snapshot the current quest log: title -> {level, isComplete}
function LeafVE:CacheQuestLog()
  local newCache = {}
  local numEntries = GetNumQuestLogEntries and GetNumQuestLogEntries() or 0
  for i = 1, numEntries do
    local title, level, _, isHeader, isComplete = GetQuestLogTitle(i)
    if title and not isHeader then
      newCache[title] = { level = level, isComplete = isComplete or 0 }
    end
  end
  self.questLogCache = newCache
end

-- Diff the current quest log against the last snapshot to find the completed quest.
-- Returns the title of the quest that just disappeared, or nil.
function LeafVE:GetCompletedQuestTitle()
  local numEntries = GetNumQuestLogEntries and GetNumQuestLogEntries() or 0
  -- First pass: find a quest marked complete (isComplete ~= 0) that is still in the log.
  -- In 1.12, QUEST_TURNED_IN often fires before QUEST_LOG_UPDATE removes the quest,
  -- so the completed quest is still there with isComplete = 1.
  for i = 1, numEntries do
    local title, _, _, isHeader, isComplete = GetQuestLogTitle(i)
    if title and not isHeader and isComplete and isComplete ~= 0 then
      return title
    end
  end
  -- Second pass: if the quest is already gone (QUEST_LOG_UPDATE fired first),
  -- find it by diffing the cached log against what is currently in the log.
  -- Only count as a turn-in if it was marked complete before disappearing.
  -- Abandoned quests have isComplete = 0 and should not award points.
  local current = {}
  for i = 1, numEntries do
    local title, _, _, isHeader = GetQuestLogTitle(i)
    if title and not isHeader then current[title] = true end
  end
  for title, data in pairs(self.questLogCache) do
    if not current[title] then
      if data and data.isComplete and data.isComplete ~= 0 then
        return title
      end
    end
  end
  return nil
end

function LeafVE:OnZoneChanged()
  local wasInInstance = self.instanceJoinedAt ~= nil
  local inInstance, instanceType
  if IsInInstance then
    inInstance, instanceType = IsInInstance()
  else
    inInstance = false
    instanceType = "none"
  end
  local zone = GetRealZoneText and GetRealZoneText() or "Unknown"
  if inInstance then
    if not wasInInstance then
      self.instanceJoinedAt = Now()
      self.instanceZone = zone
      self.instanceHasGuildie = false
      self.instanceBossesKilledThisRun = 0
      self.instanceIsRaid = (instanceType == "raid")
      local guildies = self:GetGroupGuildies()
      if table.getn(guildies) > 0 then
        self.instanceHasGuildie = true
      end
    end
  else
    if wasInInstance then
      self:OnInstanceExit()
    end
  end
end

function LeafVE:OnInstanceExit()
  if not self.instanceJoinedAt then return end
  local runDuration = Now() - self.instanceJoinedAt
  local me = ShortName(UnitName("player"))
  if not me then
    self.instanceJoinedAt = nil
    return
  end
  -- Require the player to have been present for at least INSTANCE_MIN_PRESENCE_PCT of
  -- the minimum expected run length (GROUP_MIN_TIME). This gates out teleporting out
  -- immediately while still crediting fast dungeon clears.
  local minPresence = math.floor(GROUP_MIN_TIME * INSTANCE_MIN_PRESENCE_PCT)
  if self.instanceHasGuildie and runDuration >= minPresence then
    EnsureDB()
    local today = DayKey()
    if not LeafVE_DB.instanceTracking[me] then
      LeafVE_DB.instanceTracking[me] = {}
    end
    if not LeafVE_DB.instanceTracking[me][today] then
      LeafVE_DB.instanceTracking[me][today] = {completions = 0, bosses = 0}
    end
    local tracked = LeafVE_DB.instanceTracking[me][today]
    local instCap = (LeafVE_DB.options and LeafVE_DB.options.instanceMaxDaily) or INSTANCE_MAX_DAILY
    local instPts = self.instanceIsRaid and RAID_COMPLETION_POINTS or INSTANCE_COMPLETION_POINTS
    if instCap == 0 or tracked.completions < instCap then
      if self.instanceBossesKilledThisRun > 0 then
        local awarded = self:AddPoints(me, "G", instPts)
        if awarded and awarded > 0 then
          tracked.completions = tracked.completions + 1
          tracked.bosses = tracked.bosses + self.instanceBossesKilledThisRun
          self:AddToHistory(me, "G", awarded, "Instance completion: "..(self.instanceZone or "Unknown"))
          Print(string.format("Instance complete! +%d G (%d boss%s)", awarded, self.instanceBossesKilledThisRun, self.instanceBossesKilledThisRun ~= 1 and "es" or ""))
          if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
          self:BroadcastLeaderboardData()
        end
      else
        Print("Instance exited with no bosses slain. No completion points awarded.")
      end
    end
  end
  self.instanceJoinedAt = nil
  self.instanceZone = nil
  self.instanceHasGuildie = false
  self.instanceBossesKilledThisRun = 0
  self.instanceIsRaid = false
end

local function IsGUIDInPlayerGroup(sourceGUID)
  if not sourceGUID or not UnitGUID then return true end
  if UnitGUID("player") == sourceGUID then return true end
  for i = 1, 4 do
    local token = "party" .. i
    if UnitExists(token) and UnitGUID(token) == sourceGUID then
      return true
    end
  end
  for i = 1, 40 do
    local token = "raid" .. i
    if UnitExists(token) and UnitGUID(token) == sourceGUID then
      return true
    end
  end
  return false
end

function LeafVE:HandleBossKillDetected(bossName, dedupToken)
  if not bossName then return end
  if not KNOWN_BOSSES[bossName] then return end
  local me = ShortName(UnitName("player"))
  if not me then return end
  EnsureDB()

  -- Require at least one other guildie in the group (solo runs don't count)
  local guildies = self:GetGroupGuildies()
  local numGuildies = table.getn(guildies)
  if numGuildies <= 0 then return end

  -- Dedup: ignore if this boss was already awarded within the last 10 seconds
  local now = Now()
  local dedupKey = tostring(dedupToken or bossName)
  if self.recentBossKills[dedupKey] and (now - self.recentBossKills[dedupKey]) < BOSS_KILL_DEDUP_WINDOW then return end
  self.recentBossKills[dedupKey] = now
  self.recentBossKills[bossName] = now

  self.instanceBossesKilledThisRun = self.instanceBossesKilledThisRun + 1
  local bossPts = (self.instanceIsRaid and RAID_BOSS_POINTS or INSTANCE_BOSS_POINTS)
    + (numGuildies * BOSS_GUILDIE_BONUS_POINTS)
  self.suppressPointNotification = true
  local awarded = self:AddPoints(me, "G", bossPts)
  self.suppressPointNotification = false
  if awarded and awarded > 0 then
    self:AddToHistory(me, "G", awarded, bossName.." slain with "..tostring(numGuildies).." guildie"..(numGuildies ~= 1 and "s" or ""))
    if LeafVE_DB.options.enableNotifications ~= false and LeafVE_DB.options.enablePointNotifications ~= false then
      self:ShowNotification("Boss Slain!", string.format("%s  +%d LP", bossName, awarded), LEAF_EMBLEM, THEME.gold)
    end
    Print(string.format("Boss slain: %s! +%d LP (%d guildie%s)", bossName, awarded, numGuildies, numGuildies ~= 1 and "s" or ""))
    if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
    self:BroadcastLeaderboardData()
  end
end

function LeafVE:OnBossKillChat(msg)
  local bossName = ExtractBossNameFromDeathMessage(msg)
  if not bossName then return end
  self:HandleBossKillDetected(bossName, bossName)
end

function LeafVE:OnBossKillCombatLog(timestamp, subEvent, sourceGUID, sourceName, sourceFlags, destGUID, destName, destFlags)
  if subEvent ~= "PARTY_KILL" and subEvent ~= "UNIT_DIED" then
    return
  end
  if not destName or not KNOWN_BOSSES[destName] then
    return
  end
  if sourceGUID and not IsGUIDInPlayerGroup(sourceGUID) then
    return
  end
  self:HandleBossKillDetected(destName, destGUID or destName)
end

function LeafVE:OnQuestTurnedIn()
  local me = ShortName(UnitName("player"))
  if not me then return end

  -- Guard against double-awarding if QUEST_LOG_UPDATE fires multiple times
  -- for the same turn-in within a short window (e.g. ~3 seconds).
  if Now() - (self.lastQuestTurnInTime or 0) < 3 then
    self:CacheQuestLog()
    return
  end
  -- Set the timestamp immediately as an early lock so back-to-back calls within
  -- the same frame are blocked before any async work or points are awarded.
  self.lastQuestTurnInTime = Now()

  -- Only award quest LP when grouped with at least one guildie
  local guildies = self:GetGroupGuildies()
  if table.getn(guildies) == 0 then
    self:CacheQuestLog()
    return
  end

  EnsureDB()
  local today = DayKey()

  -- Identify which quest was just completed from the pending turn-in capture
  local questTitle = LeafVE.pendingQuestTurnIn

  -- Prevent awarding LP for the same quest title more than once per character
  -- (only when we could actually identify the quest; unknown quests fall through to daily cap)
  if questTitle then
    if not LeafVE_DB.questCompletions[me] then
      LeafVE_DB.questCompletions[me] = {}
    end
    if LeafVE_DB.questCompletions[me][questTitle] then
      -- Already awarded LP for this quest; update cache and return
      self:CacheQuestLog()
      return
    end
  end

  -- Daily cap tracked per character
  if not LeafVE_DB.questTracking[me] then
    LeafVE_DB.questTracking[me] = {}
  end
  if not LeafVE_DB.questTracking[me][today] then
    LeafVE_DB.questTracking[me][today] = 0
  end
  local questPts = QUEST_POINTS
  local awarded = self:AddPoints(me, "G", questPts)
  if awarded and awarded > 0 then
    LeafVE_DB.questTracking[me][today] = LeafVE_DB.questTracking[me][today] + 1
    if questTitle and LeafVE_DB.questCompletions[me] then
      LeafVE_DB.questCompletions[me][questTitle] = Now()
    end
  end
  local displayTitle = questTitle or "Quest"
  local histMsg = "Quest completion"
  if questTitle then histMsg = "Quest: "..questTitle end
  if awarded and awarded > 0 then
    self:AddToHistory(me, "G", awarded, histMsg)
    self:RefreshShinobiDutyProgress(me)
    if LeafVE_DB.options.enableNotifications ~= false and LeafVE_DB.options.enablePointNotifications ~= false then
      self:ShowNotification("Quest Complete!", string.format("[%s] +%d LP", displayTitle, awarded), QUEST_ICON, THEME.gold)
    end
    Print(string.format("Quest complete! [%s] +%d G", displayTitle, awarded))
    if LeafVE.UI and LeafVE.UI.Refresh then LeafVE.UI:Refresh() end
    self:BroadcastLeaderboardData()
  end
  -- Update the cached log to reflect the turn-in
  self:CacheQuestLog()
end

function LeafVE:GiveShoutout(targetName, reason)
  EnsureDB() 
  local giverName = ShortName(UnitName("player")) 
  targetName = ShortName(targetName)
  if not giverName or not targetName then 
    Print("Error: Invalid player names") 
    return false 
  end
  if Lower(giverName) == Lower(targetName) then 
    Print("You cannot shout out yourself!") 
    return false 
  end
  
  -- Daily cap is tracked per giver character
  local today = DayKey()
  local bucket = CurrentWipeVersion()
  if not LeafVE_DB.shoutouts[giverName] then 
    LeafVE_DB.shoutouts[giverName] = {} 
  end
  
  local count = 0
  for tname, timestamp in pairs(LeafVE_DB.shoutouts[giverName]) do
    local shoutTs = tonumber(timestamp) or 0
    local shoutoutDay = DayKeyFromTS(shoutTs)
    if (bucket <= 0 or shoutTs >= bucket) and shoutoutDay == today then 
      count = count + 1 
    else 
      LeafVE_DB.shoutouts[giverName][tname] = nil 
    end
  end
  
  local maxDaily = self:GetShoutoutDailyLimitForPlayer(giverName)
  if (not self:IsUnlimitedShoutoutDailyLimit(maxDaily)) and count >= maxDaily then
    Print(string.format("You've used all %s shoutouts for today!", self:GetShoutoutDailyLimitLabel(maxDaily)))
    return false 
  end
  
  local targetInfo = self:GetGuildInfo(targetName)
  if not targetInfo and LeafVE_DB.persistentRoster then
    targetInfo = LeafVE_DB.persistentRoster[Lower(targetName)]
  end
  if not targetInfo then 
    Print("Player "..targetName.." is not in the guild!") 
    return false 
  end

  local shoutPts = (LeafVE_DB.options and LeafVE_DB.options.shoutoutPoints) or 10
  LeafVE_DB.shoutouts[giverName][targetName] = Now()
  local awardedTarget = self:AddPoints(targetName, "S", shoutPts)
  if awardedTarget and awardedTarget > 0 then
    self:AddToHistory(targetName, "S", awardedTarget, "Shoutout from "..giverName..(reason and (": "..reason) or ""))
    LeafVE.UI:Refresh()
    self:BroadcastLeaderboardData()
  end
  self:CheckAndAwardBadge(giverName, "first_shoutout_given")
  self:RefreshShinobiDutyProgress(giverName)
  
  if InGuild() then
    reason = reason and Trim(reason) or ""
    
    local title = LeafVE:GetEquippedTitleNameForPlayer(giverName)
    
    local message
    if title and title ~= "" then
      message = string.format("[%s] recognizes %s!", title, targetName)
    else
      message = string.format("recognizes %s!", targetName)
    end
    
    if reason ~= "" then 
      message = message .. " - " .. reason 
    end
    
    message = message .. " (+"..shoutPts.." Leaf Points)"
    LeafVE:SendSystemChatMessage(message, "GUILD")
    SendAddonMessage("LeafVE", "SHOUTOUT:"..giverName..":"..targetName, "GUILD")
  end
  
  if self:IsUnlimitedShoutoutDailyLimit(maxDaily) then
    Print(string.format("Shoutout sent to %s! (unlimited remaining today)", targetName))
  else
    local remaining = math.max(0, maxDaily - count - 1)
    Print(string.format("Shoutout sent to %s! (%d remaining today)", targetName, remaining))
  end
  return true
end

function LeafVE:BroadcastMyAchievements()
  EnsureDB()

  local achievements = self:GetLocalCompletedAchievementEntries(true)
  if table.getn(achievements) == 0 then return end

  local me = ShortName(UnitName("player"))
  if me then
    if not LeafVE_GlobalDB.achievementCache then
      LeafVE_GlobalDB.achievementCache = {}
    end

    local selfCache = {}
    local totalPoints = 0
    for _, achievement in ipairs(achievements) do
      local key = AchievementKey(achievement.id)
      if key then
        selfCache[key] = tonumber(achievement.timestamp) or 0
        totalPoints = totalPoints + (tonumber(achievement.points) or 0)
      end
    end
    selfCache._totalPoints = totalPoints
    LeafVE_GlobalDB.achievementCache[me] = selfCache
  end

  local entries = {}
  for _, achievement in ipairs(achievements) do
    local key = AchievementKey(achievement.id)
    local timestamp = tonumber(achievement.timestamp) or 0
    if key then
      table.insert(entries, key..":"..tostring(timestamp))
    end
  end

  if table.getn(entries) == 0 then return end

  if not InGuild() then return end

  -- Send in chunks to stay within the 255-byte WoW addon message limit.
  -- "ACHSYNC:" prefix uses 8 chars (255 - 8 = 247 available). Use 220 for safety.
  local MAX_CHUNK = 220
  local chunk = {}
  local chunkLen = 0

  for _, entry in ipairs(entries) do
    local sep = (chunkLen > 0) and 1 or 0
    if chunkLen > 0 and chunkLen + sep + string.len(entry) > MAX_CHUNK then
      SendAddonMessage("LeafVE", "ACHSYNC:"..table.concat(chunk, ","), "GUILD")
      chunk = {}
      chunkLen = 0
      sep = 0
    end
    table.insert(chunk, entry)
    chunkLen = chunkLen + sep + string.len(entry)
  end

  if table.getn(chunk) > 0 then
    SendAddonMessage("LeafVE", "ACHSYNC:"..table.concat(chunk, ","), "GUILD")
  end
end

function LeafVE:BroadcastBadges()
  local me = ShortName(UnitName("player"))
  if not me then return end
  
  EnsureDB()
  local myBadges = LeafVE_DB.badges[me] or {}
  
  -- Build compressed badge list: "__fw:bucket,badgeID:timestamp,..."
  -- "__fw" is a lightweight season/bucket marker for compatibility.
  local badgeData = {}
  table.insert(badgeData, "__fw:"..tostring(CurrentWipeVersion()))
  for badgeId, timestamp in pairs(myBadges) do
    table.insert(badgeData, badgeId..":"..timestamp)
  end
  
  if table.getn(badgeData) > 0 and InGuild() then
    local message = table.concat(badgeData, ",")
    SendAddonMessage("LeafVE", "BADGES:"..message, "GUILD")
  end
end

-- Broadcast badge progress metrics so other guild members can display progress bars
-- Format: BADGEPROG:<name>:<groupSessions>:<attendance>:<loginStreak>:<guildJoinDate>:<guildieGroupHours>:<guildieHonorableKills>
function LeafVE:BroadcastBadgeProgress()
  if not InGuild() then return end
  local me = ShortName(UnitName("player"))
  if not me then return end
  EnsureDB()
  self:CacheBadgeProgress(me)

  local groupSessions = (LeafVE_DB.groupSessions and LeafVE_DB.groupSessions[me]) or 0
  local cachedGroupSessions = GetCachedProgressNumber(me, "groupSessions")
  if cachedGroupSessions > groupSessions then
    groupSessions = cachedGroupSessions
    if not LeafVE_DB.groupSessions then LeafVE_DB.groupSessions = {} end
    LeafVE_DB.groupSessions[me] = groupSessions
  end

  local attendance = GetBestAttendanceCount(me)
  local streak = GetBestLoginStreak(me)
  local joinDate = GetBestGuildJoinDate(me)
  local guildieGroupHoursMe = GetBestGuildieGroupHours(me)
  local guildieHonorableKillsMe = GetBestGuildieHonorableKills(me)
  SendAddonMessage("LeafVE", "BADGEPROG:"..me..SEP..groupSessions..SEP..attendance..SEP..streak..SEP..joinDate..SEP..guildieGroupHoursMe..SEP..guildieHonorableKillsMe, "GUILD")
end

function LeafVE:BroadcastLeaderboardData(includeKnownCache)
  local me = ShortName(UnitName("player"))
  if not me then return end
  
  EnsureDB()
  self:ApplyGuildWipeMarkerIfNeeded()
  PruneLeaderboardForCurrentWipe()
  
  local wk = WeekKey()
  local data = {}

  if includeKnownCache then
    -- On explicit resync responses, share the full known cache so late logins
    -- can converge even when original broadcasters are offline.
    local seen = {}
    for name, _ in pairs(LeafVE_DB.alltime or {}) do seen[name] = true end
    for name, _ in pairs(LeafVE_DB.lboard.alltime or {}) do seen[name] = true end
    for name, _ in pairs(AggForThisWeek() or {}) do seen[name] = true end
    if type(LeafVE_DB.lboard.weekly[wk]) == "table" then
      for name, _ in pairs(LeafVE_DB.lboard.weekly[wk]) do seen[name] = true end
    end

    local weekAgg = AggForThisWeek()
    local syncedWeek = (type(LeafVE_DB.lboard.weekly[wk]) == "table") and LeafVE_DB.lboard.weekly[wk] or {}

    for name, _ in pairs(seen) do
      local isSelf = SamePlayerName(name, me)
      local lbase
      local myWeeklyExact = nil
      if isSelf then
        local myLifeExact, myWeekExact = BuildMyStatsSnapshotForPlayer(name)
        lbase = myLifeExact
        myWeeklyExact = myWeekExact
      else
        -- Relay only owner-authoritative synced lifetime snapshots for other players.
        local lifeMeta = LeafVE_DB.lboard.updatedAt[name]
        if type(lifeMeta) == "table" and lifeMeta.lifetimeAuthoritative == true then
          lbase = LeafVE_DB.lboard.alltime[name]
        else
          lbase = nil
        end
      end
      local lL = lbase and (lbase.L or 0) or 0
      local lG = lbase and (lbase.G or 0) or 0
      local lS = lbase and (lbase.S or 0) or 0
      if (lL + lG + lS) > 0 then
        table.insert(data, string.format("L:%s:%s:%s:%s", name, LeafVE:FormatPointAmount(lL), LeafVE:FormatPointAmount(lG), LeafVE:FormatPointAmount(lS)))
      end

      local wbase
      if isSelf then
        wbase = myWeeklyExact or weekAgg[name] or syncedWeek[name]
      else
        -- Relay only synced weekly snapshots for other players.
        wbase = syncedWeek[name]
      end
      local wL = wbase and (wbase.L or 0) or 0
      local wG = wbase and (wbase.G or 0) or 0
      local wS = wbase and (wbase.S or 0) or 0
      if (wL + wG + wS) > 0 then
        table.insert(data, string.format("W%s:%s:%s:%s:%s", wk, name, LeafVE:FormatPointAmount(wL), LeafVE:FormatPointAmount(wG), LeafVE:FormatPointAmount(wS)))
      end

      local lifeTotal = lL + lG + lS
      local weekTotal = wL + wG + wS
      if isSelf then
        if lifeTotal > 0 then
          StoreLifetimeSnapshot(name, lL, lG, lS, me, true, true)
        else
          ClearLifetimeSnapshot(name, me, true)
        end

        if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then
          LeafVE_DB.lboard.weekly[wk] = {}
        end
        if weekTotal > 0 then
          LeafVE_DB.lboard.weekly[wk][name] = {L = wL, G = wG, S = wS}
          SetWeeklyEntryWipeVersion(wk, name, CurrentWipeVersion())
          self:UpsertSharedLeaderboard(name, lifeTotal > 0 and {L = lL, G = lG, S = lS} or nil, {L = wL, G = wG, S = wS}, wk, true)
        else
          LeafVE_DB.lboard.weekly[wk][name] = nil
          ClearWeeklyEntryWipeVersion(wk, name)
          if LeafVE_GlobalDB.lboardCache and type(LeafVE_GlobalDB.lboardCache.weekly[wk]) == "table" then
            LeafVE_GlobalDB.lboardCache.weekly[wk][name] = nil
          end
          self:UpsertSharedLeaderboard(name, lifeTotal > 0 and {L = lL, G = lG, S = lS} or nil, nil, wk, true)
        end
      else
        self:UpsertSharedLeaderboard(name, {L = lL, G = lG, S = lS}, nil, wk)
        self:UpsertSharedLeaderboard(name, nil, {L = wL, G = wG, S = wS}, wk)
      end
    end
  else
    -- Self snapshot must match My Stats values so refresh pulls exact owner totals.
    local myLifetimeEntry, myWeeklyEntry = BuildMyStatsSnapshotForPlayer(me)
    local lL = myLifetimeEntry and (myLifetimeEntry.L or 0) or 0
    local lG = myLifetimeEntry and (myLifetimeEntry.G or 0) or 0
    local lS = myLifetimeEntry and (myLifetimeEntry.S or 0) or 0
    local wL = myWeeklyEntry and (myWeeklyEntry.L or 0) or 0
    local wG = myWeeklyEntry and (myWeeklyEntry.G or 0) or 0
    local wS = myWeeklyEntry and (myWeeklyEntry.S or 0) or 0
    local lifeTotal = lL + lG + lS
    local weekTotal = wL + wG + wS

    -- Always include self entries (including zero) so peers can clear stale rows.
    table.insert(data, string.format("L:%s:%s:%s:%s", me, LeafVE:FormatPointAmount(lL), LeafVE:FormatPointAmount(lG), LeafVE:FormatPointAmount(lS)))
    table.insert(data, string.format("W%s:%s:%s:%s:%s", wk, me, LeafVE:FormatPointAmount(wL), LeafVE:FormatPointAmount(wG), LeafVE:FormatPointAmount(wS)))

    if lifeTotal > 0 then
      StoreLifetimeSnapshot(me, lL, lG, lS, me, true, true)
    else
      ClearLifetimeSnapshot(me, me, true)
    end

    if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then
      LeafVE_DB.lboard.weekly[wk] = {}
    end
    if weekTotal > 0 then
      LeafVE_DB.lboard.weekly[wk][me] = {L = wL, G = wG, S = wS}
      SetWeeklyEntryWipeVersion(wk, me, CurrentWipeVersion())
      self:UpsertSharedLeaderboard(me, lifeTotal > 0 and {L = lL, G = lG, S = lS} or nil, {L = wL, G = wG, S = wS}, wk, true)
    else
      LeafVE_DB.lboard.weekly[wk][me] = nil
      ClearWeeklyEntryWipeVersion(wk, me)
      if LeafVE_GlobalDB.lboardCache and type(LeafVE_GlobalDB.lboardCache.weekly[wk]) == "table" then
        LeafVE_GlobalDB.lboardCache.weekly[wk][me] = nil
      end
      self:UpsertSharedLeaderboard(me, lifeTotal > 0 and {L = lL, G = lG, S = lS} or nil, nil, wk, true)
    end
  end

  -- Send in chunks to stay within the 255-byte WoW addon message limit.
  -- Prefix each payload with FW:<fullWipeVersion> so stale clients can
  -- auto-apply wipes and newer clients can reject pre-wipe snapshots.
  if not InGuild() then return end
  local fullWipeVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
  local versionPrefix = "FW:"..tostring(fullWipeVersion)..","
  local MAX_CHUNK = 210
  local chunk = {}
  local chunkLen = 0
  
  for _, entry in ipairs(data) do
    local sep = (chunkLen > 0) and 1 or 0  -- account for comma separator
    if chunkLen > 0 and chunkLen + sep + string.len(entry) > MAX_CHUNK then
      SendAddonMessage("LeafVE", "LBOARD:"..versionPrefix..table.concat(chunk, ","), "GUILD")
      chunk = {}
      chunkLen = 0
      sep = 0
    end
    table.insert(chunk, entry)
    chunkLen = chunkLen + sep + string.len(entry)
  end
  
  if table.getn(chunk) > 0 then
    SendAddonMessage("LeafVE", "LBOARD:"..versionPrefix..table.concat(chunk, ","), "GUILD")
  else
    -- Still broadcast wipe version when there are no point entries so
    -- offline clients can learn/apply a wipe before sharing old snapshots.
    SendAddonMessage("LeafVE", "LBOARD:"..versionPrefix, "GUILD")
  end

  -- Refresh leaderboard panels if any are currently open
  if LeafVE.UI and LeafVE.UI.panels then
    if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() then
      LeafVE.UI:RefreshLeaderboard("leaderLife")
    end
    if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() then
      LeafVE.UI:RefreshLeaderboard("leaderWeek")
    end
  end

end

function LeafVE:SendResyncRequest(force)
  local now = Now()
  if not force and (now - self.lastResyncRequestAt) < LBOARD_RESYNC_COOLDOWN then return end
  self.lastResyncRequestAt = now
  if InGuild() then
    SendAddonMessage("LeafVE", force and "LBOARDREQ_FORCE" or "LBOARDREQ", "GUILD")
    SendAddonMessage("LeafVE", force and "SHOUTSYNCREQ_FORCE" or "SHOUTSYNCREQ", "GUILD")
  end
end

-- Serialize the full shoutout history table and broadcast it in chunks.
function LeafVE:BroadcastShoutoutHistory()
  EnsureDB()

  local entries = {}
  for giver, targets in pairs(LeafVE_DB.shoutouts) do
    for target, timestamp in pairs(targets) do
      if type(timestamp) == "number" and timestamp > 0 then
        table.insert(entries, giver..SEP..target..SEP..tostring(timestamp))
      end
    end
  end

  if table.getn(entries) == 0 then return end
  if not InGuild() then return end

  -- Build payload chunks; "SHOUTSYNC:NN/TT:" prefix is at most ~16 chars,
  -- so 200-char payloads keep each message well under WoW's 255-byte limit.
  local MAX_PAYLOAD = 200
  local chunks = {}
  local current = ""
  for _, entry in ipairs(entries) do
    if current == "" then
      current = entry
    elseif string.len(current) + 1 + string.len(entry) <= MAX_PAYLOAD then
      current = current..","..entry
    else
      table.insert(chunks, current)
      current = entry
    end
  end
  if current ~= "" then
    table.insert(chunks, current)
  end

  local total = table.getn(chunks)
  for i = 1, total do
    SendAddonMessage("LeafVE", "SHOUTSYNC:"..i.."/"..total..":"..chunks[i], "GUILD")
  end
end

-- Idempotently merge received shoutout history into the local DB.
-- Awards +1 S point only for entries not previously known; updates timestamps
-- when incoming data is newer (without awarding an extra point).
function LeafVE:MergeShoutoutHistory(payload)
  EnsureDB()
  if not payload or payload == "" then return end

  local me = ShortName(UnitName("player"))
  local bucket = CurrentWipeVersion()
  local updated = false
  local startPos = 1

  while startPos <= string.len(payload) do
    local commaPos = string.find(payload, ",", startPos)
    local entry
    if commaPos then
      entry = string.sub(payload, startPos, commaPos - 1)
      startPos = commaPos + 1
    else
      entry = string.sub(payload, startPos)
      startPos = string.len(payload) + 1
    end

    -- Parse "giver\31target\31timestamp"
    local sep1 = string.find(entry, SEP)
    if sep1 then
      local giver = string.sub(entry, 1, sep1 - 1)
      local rest = string.sub(entry, sep1 + 1)
      local sep2 = string.find(rest, SEP)
      if sep2 then
        local target = string.sub(rest, 1, sep2 - 1)
        local timestamp = tonumber(string.sub(rest, sep2 + 1))
        if giver ~= "" and target ~= "" and timestamp then
          -- Ignore stale shoutout history from pre-wipe seasons.
          if bucket > 0 and timestamp < bucket then
            -- no-op
          -- Skip entries where we are the giver (already recorded locally)
          elseif not (me and Lower(me) == Lower(giver)) then
            if not LeafVE_DB.shoutouts[giver] then
              LeafVE_DB.shoutouts[giver] = {}
            end
            local existing = LeafVE_DB.shoutouts[giver][target]
            if not existing then
              -- Always record dedup entry so this shoutout is not reprocessed in future merges.
              LeafVE_DB.shoutouts[giver][target] = timestamp
              local syncedAward = ApplyPointMultiplier(10, timestamp)
              local actualDay = DayKeyFromTS(timestamp)
              if not LeafVE_DB.global[actualDay] then LeafVE_DB.global[actualDay] = {} end
              local dayEntry = EnsurePointEntryCurrentBucket(LeafVE_DB.global[actualDay], target)
              dayEntry.S = (dayEntry.S or 0) + syncedAward
              local lifeEntry = EnsurePointEntryCurrentBucket(LeafVE_DB.alltime, target)
              lifeEntry.S = (lifeEntry.S or 0) + syncedAward
              local seasonEntry = EnsurePointEntryCurrentBucket(LeafVE_DB.season, target)
              seasonEntry.S = (seasonEntry.S or 0) + syncedAward
              self:CheckBadgeMilestones(target)
              self:AddToHistory(target, "S", syncedAward, "Shoutout from "..giver.." (synced)")
              self:CheckAndAwardBadge(giver, "first_shoutout_given")
              self:CheckAndAwardBadge(target, "first_shoutout_received")
              updated = true
            elseif timestamp > existing then
              -- Newer timestamp for an already-known entry: update only, no extra point
              LeafVE_DB.shoutouts[giver][target] = timestamp
              updated = true
            end
          end
        end
      end
    end
  end

  -- Refresh leaderboard panels if any are currently open
  if updated and LeafVE.UI and LeafVE.UI.panels then
    if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() then
      LeafVE.UI:RefreshLeaderboard("leaderLife")
    end
    if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() then
      LeafVE.UI:RefreshLeaderboard("leaderWeek")
    end
  end
end

function LeafVE:BroadcastPlayerNote(noteText)
  local me = ShortName(UnitName("player"))
  if not me then return end
  
  noteText = noteText or ""
  
  -- Escape special characters
  noteText = string.gsub(noteText, "|", "||")
  
  if InGuild() then
    SendAddonMessage("LeafVE", "NOTE:"..noteText, "GUILD")
  end
end

-------------------------------------------------
-- GEAR CACHING & BROADCAST
-------------------------------------------------
LeafVE.lastGearBroadcast = 0
LeafVE.lastGearRequestAt = LeafVE.lastGearRequestAt or {}

local leafTalentScanTip

local function GetOrCreateTalentScanTip()
  if not leafTalentScanTip then
    leafTalentScanTip = CreateFrame("GameTooltip", "LeafVE_TalentScanTip", UIParent, "GameTooltipTemplate")
    leafTalentScanTip:SetOwner(UIParent, "ANCHOR_NONE")
  end
  return leafTalentScanTip
end

local function TalentKeySort(a, b)
  local aTab, aIdx = string.match(a or "", "^(%d+)_(%d+)$")
  local bTab, bIdx = string.match(b or "", "^(%d+)_(%d+)$")
  aTab, aIdx = tonumber(aTab) or 0, tonumber(aIdx) or 0
  bTab, bIdx = tonumber(bTab) or 0, tonumber(bIdx) or 0
  if aTab == bTab then return aIdx < bIdx end
  return aTab < bTab
end

function LeafVE:CaptureAndCacheMyTalents(force)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return nil end
  local nameLower = Lower(me)

  if not LeafVE_GlobalDB.talentCache then
    LeafVE_GlobalDB.talentCache = {}
  end
  local now = Now()
  local existing = LeafVE_GlobalDB.talentCache[nameLower]
  if not force and existing and (now - (self.lastTalentCaptureAt or 0)) < 3 then
    return existing
  end

  if not GetNumTalentTabs or not GetTalentTabInfo then
    return existing
  end

  local tabCount = GetNumTalentTabs()
  if not tabCount or tabCount < 1 then
    return existing
  end

  local classTag = self:GetClassTagForPlayer(me)
  local snapshot = {
    updatedAt = now,
    receivedAt = now,
    class = classTag,
    activeTab = 1,
    tabs = {},
    talents = {},
  }

  local maxPoints = -1
  local talentTip = GetOrCreateTalentScanTip()

  for tabIndex = 1, tabCount do
    local tabName, tabIcon, pointsSpent = GetTalentTabInfo(tabIndex)
    pointsSpent = tonumber(pointsSpent) or 0
    local normalizedTabIcon = NormalizeIconPath(tabIcon) or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark"
    snapshot.tabs[tabIndex] = {
      index = tabIndex,
      name = tabName or ("Tree " .. tostring(tabIndex)),
      icon = normalizedTabIcon,
      points = pointsSpent,
    }
    if pointsSpent > maxPoints then
      maxPoints = pointsSpent
      snapshot.activeTab = tabIndex
    end

    local talentCount = (GetNumTalents and GetNumTalents(tabIndex)) or 0
    for talentIndex = 1, talentCount do
      local talentName, talentIcon, tier, column, rank, maxRank = GetTalentInfo(tabIndex, talentIndex)
      if talentName and tier and column then
        local descLines = {}
        if talentTip and talentTip.SetTalent then
          local ok = pcall(function()
            talentTip:ClearLines()
            talentTip:SetTalent(tabIndex, talentIndex)
          end)
          if ok and talentTip.NumLines then
            local lines = talentTip:NumLines() or 0
            for lineIndex = 2, lines do
              local leftFS = getglobal("LeafVE_TalentScanTipTextLeft" .. tostring(lineIndex))
              local textLine = leftFS and leftFS:GetText()
              if textLine and textLine ~= "" then
                if not (lineIndex == 2 and string.find(string.lower(textLine), "rank", 1, true)) then
                  table.insert(descLines, textLine)
                end
              end
            end
          end
        end

        local key = tostring(tabIndex) .. "_" .. tostring(talentIndex)
        snapshot.talents[key] = {
          tab = tabIndex,
          index = talentIndex,
          tier = tonumber(tier) or 1,
          column = tonumber(column) or 1,
          rank = tonumber(rank) or 0,
          maxRank = tonumber(maxRank) or 0,
          name = talentName,
          icon = NormalizeIconPath(talentIcon) or "Interface\\Icons\\INV_Misc_QuestionMark",
          desc = table.concat(descLines, "\n"),
        }
      end
    end
  end

  LeafVE_GlobalDB.talentCache[nameLower] = snapshot
  self.lastTalentCaptureAt = now
  return snapshot
end

function LeafVE:GetTalentTreeSnapshotForPlayer(playerName, classTag, forceRefresh)
  EnsureDB()
  playerName = ShortName(playerName)
  if not playerName then return nil end
  local nameLower = Lower(playerName)
  local me = ShortName(UnitName("player"))

  if me and Lower(me) == nameLower then
    local existing = LeafVE_GlobalDB.talentCache and LeafVE_GlobalDB.talentCache[nameLower]
    if forceRefresh or not existing or (Now() - (existing.updatedAt or 0)) > 30 then
      self:CaptureAndCacheMyTalents(forceRefresh)
    end
  end

  local snapshot = LeafVE_GlobalDB.talentCache and LeafVE_GlobalDB.talentCache[nameLower]
  if not snapshot then return nil end
  if classTag and classTag ~= "" and classTag ~= "UNKNOWN" and (not snapshot.class or snapshot.class == "UNKNOWN") then
    snapshot.class = string.upper(classTag)
  end
  return snapshot
end

function LeafVE:SerializeTalentSnapshot(snapshot)
  if not snapshot then return "" end

  local records = {}
  table.insert(records,
    "H" .. SEP ..
    EncodeTalentField(snapshot.class or "UNKNOWN") .. SEP ..
    tostring(tonumber(snapshot.activeTab) or 1)
  )

  local maxTab = 0
  for tabIndex in pairs(snapshot.tabs or {}) do
    tabIndex = tonumber(tabIndex) or 0
    if tabIndex > maxTab then
      maxTab = tabIndex
    end
  end

  for tabIndex = 1, maxTab do
    local tab = snapshot.tabs and snapshot.tabs[tabIndex]
    if tab then
      table.insert(records,
        "B" .. SEP ..
        tostring(tabIndex) .. SEP ..
        EncodeTalentField(tab.name or ("Tree " .. tostring(tabIndex))) .. SEP ..
        EncodeTalentField(tab.icon or "Interface\\Icons\\INV_Misc_QuestionMark") .. SEP ..
        tostring(tonumber(tab.points) or 0)
      )
    end
  end

  local keys = {}
  for key, talent in pairs(snapshot.talents or {}) do
    if type(talent) == "table" then
      table.insert(keys, key)
    end
  end
  table.sort(keys, TalentKeySort)

  for i = 1, table.getn(keys) do
    local talent = snapshot.talents[keys[i]]
    table.insert(records,
      "T" .. SEP ..
      tostring(tonumber(talent.tab) or 1) .. SEP ..
      tostring(tonumber(talent.index) or 1) .. SEP ..
      tostring(tonumber(talent.tier) or 1) .. SEP ..
      tostring(tonumber(talent.column) or 1) .. SEP ..
      tostring(tonumber(talent.rank) or 0) .. SEP ..
      tostring(tonumber(talent.maxRank) or 0) .. SEP ..
      EncodeTalentField(talent.name or "") .. SEP ..
      EncodeTalentField(talent.icon or "Interface\\Icons\\INV_Misc_QuestionMark") .. SEP ..
      EncodeTalentField(talent.desc or "")
    )
  end

  return table.concat(records, TALENT_RECORD_SEP)
end

function LeafVE:ApplyTalentPayload(playerName, updatedAt, payload)
  EnsureDB()
  playerName = ShortName(playerName)
  if not playerName then return end
  local nameLower = Lower(playerName)

  local snapshot = {
    updatedAt = tonumber(updatedAt) or Now(),
    receivedAt = Now(),
    class = "UNKNOWN",
    activeTab = 1,
    tabs = {},
    talents = {},
  }

  local records = SplitByLiteralSep(payload or "", TALENT_RECORD_SEP)
  for i = 1, table.getn(records) do
    local record = records[i]
    if record and record ~= "" then
      local fields = SplitByLiteralSep(record, SEP)
      local recType = fields[1]
      if recType == "H" then
        snapshot.class = string.upper(DecodeTalentField(fields[2] or "UNKNOWN"))
        snapshot.activeTab = tonumber(fields[3]) or 1
      elseif recType == "B" then
        local tabIndex = tonumber(fields[2]) or 0
        if tabIndex > 0 then
          snapshot.tabs[tabIndex] = {
            index = tabIndex,
            name = DecodeTalentField(fields[3] or ("Tree " .. tostring(tabIndex))),
            icon = NormalizeIconPath(DecodeTalentField(fields[4] or "Interface\\Icons\\INV_Misc_QuestionMark")) or "Interface\\Icons\\INV_Misc_QuestionMark",
            points = tonumber(fields[5]) or 0,
          }
        end
      elseif recType == "T" then
        local tabIndex = tonumber(fields[2]) or 0
        local talentIndex = tonumber(fields[3]) or 0
        if tabIndex > 0 and talentIndex > 0 then
          local key = tostring(tabIndex) .. "_" .. tostring(talentIndex)
          snapshot.talents[key] = {
            tab = tabIndex,
            index = talentIndex,
            tier = tonumber(fields[4]) or 1,
            column = tonumber(fields[5]) or 1,
            rank = tonumber(fields[6]) or 0,
            maxRank = tonumber(fields[7]) or 0,
            name = DecodeTalentField(fields[8] or ""),
            icon = NormalizeIconPath(DecodeTalentField(fields[9] or "Interface\\Icons\\INV_Misc_QuestionMark")) or "Interface\\Icons\\INV_Misc_QuestionMark",
            desc = DecodeTalentField(fields[10] or ""),
          }
        end
      end
    end
  end

  if snapshot.class == "" or snapshot.class == "UNKNOWN" then
    snapshot.class = self:GetClassTagForPlayer(playerName)
  end
  if not LeafVE_GlobalDB.talentCache then
    LeafVE_GlobalDB.talentCache = {}
  end
  LeafVE_GlobalDB.talentCache[nameLower] = snapshot
end

function LeafVE:RequestTalentData(playerName, force)
  if not InGuild() then return end
  playerName = ShortName(playerName)
  if not playerName then return end

  local me = ShortName(UnitName("player"))
  if me and Lower(me) == Lower(playerName) then
    return
  end

  local lname = Lower(playerName)
  local now = Now()
  self.lastTalentRequestAt = self.lastTalentRequestAt or {}
  if not force and self.lastTalentRequestAt[lname] and (now - self.lastTalentRequestAt[lname]) < TALENT_REQUEST_THROTTLE then
    return
  end
  self.lastTalentRequestAt[lname] = now
  SendAddonMessage("LeafVE", "TALREQ:" .. playerName, "GUILD")
end

function LeafVE:BroadcastMyTalents(force)
  if not InGuild() then return end
  local now = Now()
  if not force and (now - (self.lastTalentBroadcast or 0)) < TALENT_BROADCAST_THROTTLE then
    return
  end

  local snapshot = self:CaptureAndCacheMyTalents(force)
  if not snapshot then return end

  local me = ShortName(UnitName("player"))
  if not me then return end

  local payload = self:SerializeTalentSnapshot(snapshot)
  if not payload or payload == "" then return end

  self.lastTalentBroadcast = now

  local chunks = {}
  local startPos = 1
  while startPos <= string.len(payload) do
    table.insert(chunks, string.sub(payload, startPos, startPos + TALENT_SYNC_MAX_PAYLOAD - 1))
    startPos = startPos + TALENT_SYNC_MAX_PAYLOAD
  end
  if table.getn(chunks) == 0 then
    table.insert(chunks, "")
  end

  local totalChunks = table.getn(chunks)
  for i = 1, totalChunks do
    SendAddonMessage("LeafVE",
      "GTALSYNC:" .. me .. ":" .. tostring(snapshot.updatedAt or now) .. ":" .. tostring(i) .. "/" .. tostring(totalChunks) .. ":" .. chunks[i],
      "GUILD"
    )
  end
end

function LeafVE:ParseItemIDFromLink(link)
  if not link then return nil end
  local s = string.find(link, "|Hitem:")
  if not s then return nil end
  local rest = string.sub(link, s + 7)
  local colonPos = string.find(rest, ":")
  local idStr
  if colonPos then
    idStr = string.sub(rest, 1, colonPos - 1)
  else
    idStr = rest
  end
  local id = tonumber(idStr)
  if id and id > 0 then return id end
  return nil
end

function LeafVE:ParseEnchantIDFromLink(link)
  if not link then return nil end
  local s = string.find(link, "|Hitem:")
  if not s then return nil end
  local rest = string.sub(link, s + 7)
  local p1 = string.find(rest, ":")
  if not p1 then return nil end
  local afterItem = string.sub(rest, p1 + 1)
  local p2 = string.find(afterItem, ":")
  local enchantStr
  if p2 then
    enchantStr = string.sub(afterItem, 1, p2 - 1)
  else
    enchantStr = afterItem
  end
  local enchantId = tonumber(enchantStr)
  if enchantId and enchantId > 0 then return enchantId end
  return nil
end

function LeafVE:ResolveIconForItemID(itemId)
  if not itemId then return nil end
  local atlasToken = LeafVE_ItemIcons and LeafVE_ItemIcons[itemId]
  local atlasPath = NormalizeIconPath(atlasToken)
  if atlasPath then
    return atlasPath
  end
  local _, _, _, _, _, _, _, _, _, itemTexture = GetItemInfo(itemId)
  return NormalizeIconPath(itemTexture)
end

function LeafVE:CaptureGearForUnit(unitToken)
  if not unitToken then return {} end
  local slots = {}
  for i = 1, table.getn(GEAR_SLOT_NAMES) do
    local slotName = GEAR_SLOT_NAMES[i]
    local slotId = GetInventorySlotInfo(slotName)
    if slotId then
      local link = GetInventoryItemLink(unitToken, slotId)
      local itemId = self:ParseItemIDFromLink(link)
      if itemId then
        slots[slotName] = itemId
      end
    end
  end
  return slots
end

function LeafVE:CaptureGearIconsForUnit(unitToken, slots)
  local icons = {}
  if not slots then return icons end
  for i = 1, table.getn(GEAR_SLOT_NAMES) do
    local slotName = GEAR_SLOT_NAMES[i]
    local itemId = slots[slotName]
    if itemId then
      local iconTex = nil
      local slotId = GetInventorySlotInfo(slotName)
      if slotId and unitToken and UnitExists(unitToken) then
        iconTex = GetInventoryItemTexture(unitToken, slotId)
      end
      if not iconTex then
        iconTex = self:ResolveIconForItemID(itemId)
      else
        iconTex = NormalizeIconPath(iconTex)
      end
      icons[slotName] = iconTex or "Interface\\Icons\\INV_Misc_QuestionMark"
    end
  end
  return icons
end

function LeafVE:CaptureGearEnchantsForUnit(unitToken, slots)
  local enchants = {}
  if not unitToken or not slots then return enchants end
  for i = 1, table.getn(GEAR_SLOT_NAMES) do
    local slotName = GEAR_SLOT_NAMES[i]
    local itemId = slots[slotName]
    if itemId then
      local slotId = GetInventorySlotInfo(slotName)
      if slotId then
        local link = GetInventoryItemLink(unitToken, slotId)
        local enchantId = self:ParseEnchantIDFromLink(link)
        if enchantId then
          enchants[slotName] = enchantId
        end
      end
    end
  end
  return enchants
end

function LeafVE:CaptureStatSnapshotForUnit(unitToken, slots)
  local stats = {}
  local function SafeBCSCall(methodName)
    if not BCS or type(BCS[methodName]) ~= "function" then return nil end
    local ok, a, b, c, d, e, f = pcall(BCS[methodName], BCS)
    if ok then return a, b, c, d, e, f end
    return nil
  end

  if unitToken and UnitExists(unitToken) then
    for statIdx, key in ipairs({"str", "agi", "sta", "int_", "spi"}) do
      local base, effective, pos, neg = UnitStat(unitToken, statIdx)
      local val = effective
      if not val and base then
        val = base + (pos or 0) + (neg or 0)
      end
      stats[key] = tonumber(val) or 0
    end

    local baseAP, posAP, negAP = UnitAttackPower(unitToken)
    if baseAP then
      stats.ap = (baseAP or 0) + (posAP or 0) + (negAP or 0)
    end

    if UnitArmor then
      local baseArmor, effectiveArmor = UnitArmor(unitToken)
      stats.armor = tonumber(effectiveArmor or baseArmor) or 0
    end
  end

  -- Player-only advanced stats (these APIs are not reliable for other units).
  if unitToken == "player" then
    -- BetterCharacterStats-compatible values when available.
    if BCS and type(BCS.RunScans) == "function" then
      pcall(BCS.RunScans, BCS)
    end

    local hitRating = SafeBCSCall("GetHitRating")
    if hitRating then
      stats.hit = Round2(hitRating)
    end
    local spellHit = SafeBCSCall("GetSpellHitRating")
    if spellHit then
      stats.spellhit = Round2(spellHit)
    end
    local meleeCrit = SafeBCSCall("GetCritChance")
    if meleeCrit then
      stats.crit = Round2(meleeCrit)
    end
    local spellCrit = SafeBCSCall("GetSpellCritChance")
    if spellCrit then
      stats.spellcrit = Round2(spellCrit)
    end
    local spellPower = SafeBCSCall("GetSpellPower")
    if spellPower then
      stats.spelldmg = math.floor((tonumber(spellPower) or 0) + 0.5)
    end
    local healingPower = SafeBCSCall("GetHealingPower")
    if healingPower then
      stats.healing = math.floor((tonumber(healingPower) or 0) + 0.5)
    end
    local _, _, mp5 = SafeBCSCall("GetManaRegen")
    if mp5 then
      stats.mp5 = Round2(mp5)
    end
    local haste, spellHaste = SafeBCSCall("GetHaste")
    if haste then
      stats.haste = Round2(haste)
    end
    if spellHaste then
      stats.spellhaste = Round2(spellHaste)
    end
    local armorPen = SafeBCSCall("GetArmorPen")
    if armorPen then
      stats.armorpen = tonumber(armorPen) or 0
    end
    local spellPen = SafeBCSCall("GetSpellPen")
    if spellPen then
      stats.spellpen = tonumber(spellPen) or 0
    end
    local mhSkill = SafeBCSCall("GetMHWeaponSkill")
    if mhSkill then
      stats.wepskill = tonumber(mhSkill) or 0
    end

    -- Native fallback when BCS is not loaded.
    if GetCritChance and (tonumber(stats.crit) or 0) <= 0 then
      stats.crit = Round2(GetCritChance() or 0)
    end
    if GetSpellCritChance and (tonumber(stats.spellcrit) or 0) <= 0 then
      stats.spellcrit = Round2((GetSpellCritChance(2) or GetSpellCritChance(1) or 0))
    end
    if GetSpellBonusDamage and (tonumber(stats.spelldmg) or 0) <= 0 then
      local best = 0
      for school = 2, 7 do
        local v = GetSpellBonusDamage(school) or 0
        if v > best then best = v end
      end
      stats.spelldmg = best
    end
    if GetSpellBonusHealing and (tonumber(stats.healing) or 0) <= 0 then
      stats.healing = GetSpellBonusHealing() or 0
    end
    if GetDodgeChance then
      stats.dodge = Round2(GetDodgeChance() or 0)
    end
    if GetParryChance then
      stats.parry = Round2(GetParryChance() or 0)
    end
    if GetBlockChance then
      stats.block = Round2(GetBlockChance() or 0)
    end
    if UnitDefense then
      local baseDef, modDef = UnitDefense("player")
      local totalDef = tonumber(baseDef) or 0
      totalDef = totalDef + (tonumber(modDef) or 0)
      stats.defense = totalDef
    end
    if GetManaRegen and (tonumber(stats.mp5) or 0) <= 0 then
      local regenOut, regenCasting = GetManaRegen()
      local mp5Est = ((tonumber(regenCasting) or tonumber(regenOut) or 0) * 5)
      if mp5Est > 0 then
        stats.mp5 = Round2(mp5Est)
      end
    end
  end

  -- Merge tooltip-derived values (hit, spell power, etc.) from equipped items.
  if slots and ComputeGearStats then
    local estimated = ComputeGearStats(slots) or {}
    local preferMax = {
      hit = true, spellhit = true, crit = true, spellcrit = true,
      spelldmg = true, healing = true, mp5 = true, haste = true,
      spellhaste = true, armorpen = true, spellpen = true, wepskill = true,
    }
    for key, val in pairs(estimated) do
      local numericVal = tonumber(val) or 0
      if numericVal > 0 then
        local existing = tonumber(stats[key]) or 0
        if existing <= 0 then
          stats[key] = numericVal
        elseif preferMax[key] then
          if numericVal > existing then
            stats[key] = numericVal
          end
        end
      end
    end
  end

  -- Fill any missing keys so broadcast payload stays consistent.
  for _, key in ipairs(GEAR_STAT_KEYS) do
    if stats[key] == nil then
      stats[key] = 0
    end
  end
  return stats
end

local function BuildSpecSnapshotFor(classTag, idx)
  classTag = string.upper(classTag or "")
  local names = CLASS_SPEC_NAMES[classTag]
  local icons = CLASS_SPEC_ICONS[classTag]
  if not names or table.getn(names) == 0 then
    return {
      class = classTag,
      index = 1,
      name = classTag,
      icon = CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark",
    }
  end
  idx = tonumber(idx) or 1
  if idx < 1 then idx = 1 end
  if idx > table.getn(names) then idx = table.getn(names) end
  return {
    class = classTag,
    index = idx,
    name = names[idx] or classTag,
    icon = icons and icons[idx] or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark",
  }
end

local function SendChunkedSnapshot(prefix, playerName, updatedAt, orderedKeys, valuesByKey)
  local header = prefix .. playerName .. ":" .. tostring(updatedAt) .. ":"
  local maxPayload = 180
  local chunk = {}
  local chunkLen = 0

  for i = 1, table.getn(orderedKeys) do
    local key = orderedKeys[i]
    local value = valuesByKey[key]
    if value ~= nil and value ~= "" then
      local entry = key .. "=" .. tostring(value)
      local entryLen = string.len(entry)
      local sepLen = (chunkLen > 0) and 1 or 0
      if chunkLen > 0 and (chunkLen + sepLen + entryLen) > maxPayload then
        SendAddonMessage("LeafVE", header .. table.concat(chunk, ","), "GUILD")
        chunk = {}
        chunkLen = 0
        sepLen = 0
      end
      table.insert(chunk, entry)
      chunkLen = chunkLen + sepLen + entryLen
    end
  end

  if table.getn(chunk) > 0 then
    SendAddonMessage("LeafVE", header .. table.concat(chunk, ","), "GUILD")
  end
end

function LeafVE:ScheduleMyGearBroadcast(force)
  self.myGearDirty = true
  if force then
    self.pendingGearBroadcastForce = true
  end

  self:ScheduleDeferred("gear_broadcast", GEAR_EVENT_DEBOUNCE, function()
    local shouldForce = LeafVE.pendingGearBroadcastForce and true or false
    LeafVE.pendingGearBroadcastForce = nil
    if shouldForce then
      LeafVE.lastGearBroadcast = 0
    end
    LeafVE:BroadcastMyGear(shouldForce)
  end)
end

function LeafVE:CaptureAndCacheMyGear(force)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  local nameLower = Lower(me)
  if not LeafVE_GlobalDB.gearCache[nameLower] then
    LeafVE_GlobalDB.gearCache[nameLower] = {}
  end
  local existing = LeafVE_GlobalDB.gearCache[nameLower].broadcast
  local now = Now()
  if not force and not self.myGearDirty and existing and (now - (existing.updatedAt or 0)) < GEAR_CAPTURE_CACHE_WINDOW then
    return existing
  end
  local slots = self:CaptureGearForUnit("player")
  local icons = self:CaptureGearIconsForUnit("player", slots)
  local enchants = self:CaptureGearEnchantsForUnit("player", slots)
  local stats = self:CaptureStatSnapshotForUnit("player", slots)
  local classTag = self:GetClassTagForPlayer(me)
  local specIdx = self:GetSpecIndexForClass(classTag)
  local spec = BuildSpecSnapshotFor(classTag, specIdx)
  if not LeafVE_GlobalDB.specCache then LeafVE_GlobalDB.specCache = {} end
  LeafVE_GlobalDB.specCache[nameLower] = {class = classTag, index = specIdx, updatedAt = now}
  local snapshot = {
    updatedAt = now,
    slots = slots,
    icons = icons,
    enchants = enchants,
    stats = stats,
    spec = spec,
  }
  LeafVE_GlobalDB.gearCache[nameLower].broadcast = snapshot
  self.myGearDirty = nil
  return snapshot
end

function LeafVE:CaptureAndCacheInspectedGear(playerName, unitToken)
  if not playerName or not unitToken then return end
  EnsureDB()
  local nameLower = Lower(ShortName(playerName) or playerName)
  if not LeafVE_GlobalDB.gearCache[nameLower] then
    LeafVE_GlobalDB.gearCache[nameLower] = {}
  end
  local slots = self:CaptureGearForUnit(unitToken)
  local icons = self:CaptureGearIconsForUnit(unitToken, slots)
  local enchants = self:CaptureGearEnchantsForUnit(unitToken, slots)
  local stats = self:CaptureStatSnapshotForUnit(unitToken, slots)
  local classTag = self:GetClassTagForPlayer(playerName)
  local existingSpec = LeafVE_GlobalDB.specCache and LeafVE_GlobalDB.specCache[nameLower]
  local spec = BuildSpecSnapshotFor(classTag, existingSpec and existingSpec.index or 1)
  LeafVE_GlobalDB.gearCache[nameLower].inspected = {
    updatedAt = Now(),
    slots = slots,
    icons = icons,
    enchants = enchants,
    stats = stats,
    spec = spec,
  }
end

function LeafVE:RequestGearData(playerName, force)
  if not InGuild() then return end
  playerName = ShortName(playerName)
  if not playerName then return end
  local me = ShortName(UnitName("player"))
  if me and Lower(me) == Lower(playerName) then return end
  local lname = Lower(playerName)
  local now = Now()
  self.lastGearRequestAt = self.lastGearRequestAt or {}
  if not force and self.lastGearRequestAt[lname] and (now - self.lastGearRequestAt[lname]) < GEAR_REQUEST_THROTTLE then
    return
  end
  self.lastGearRequestAt[lname] = now
  SendAddonMessage("LeafVE", "GEARREQ:" .. playerName, "GUILD")
end

function LeafVE:BroadcastMyGear(force)
  if not InGuild() then return end
  local now = Now()
  if not force and (now - self.lastGearBroadcast) < GEAR_BROADCAST_THROTTLE then return end
  self.lastGearBroadcast = now

  self:CaptureAndCacheMyGear(force)

  local me = ShortName(UnitName("player"))
  if not me then return end
  local cache = LeafVE_GlobalDB.gearCache and LeafVE_GlobalDB.gearCache[Lower(me)]
  local snapshot = cache and cache.broadcast
  if not snapshot or not snapshot.slots then return end

  SendChunkedSnapshot("GEAR:", me, snapshot.updatedAt, GEAR_SLOT_NAMES, snapshot.slots or {})
  SendChunkedSnapshot("GICONS:", me, snapshot.updatedAt, GEAR_SLOT_NAMES, snapshot.icons or {})
  SendChunkedSnapshot("GENCH:", me, snapshot.updatedAt, GEAR_SLOT_NAMES, snapshot.enchants or {})
  SendChunkedSnapshot("GSTATS:", me, snapshot.updatedAt, GEAR_STAT_KEYS, snapshot.stats or {})

  local spec = snapshot.spec
  if not spec then
    local classTag = self:GetClassTagForPlayer(me)
    local specIdx = self:GetSpecIndexForClass(classTag)
    spec = BuildSpecSnapshotFor(classTag, specIdx)
  end
  if spec and spec.class and spec.index then
    SendAddonMessage("LeafVE", "GSPEC:" .. me .. ":" .. tostring(snapshot.updatedAt) .. ":" .. spec.class .. ":" .. tostring(spec.index), "GUILD")
  end
end

function LeafVE:GetGuildBankConfig()
  EnsureDB()
  if type(LeafVE_GlobalDB.guildBankConfig) ~= "table" then
    LeafVE_GlobalDB.guildBankConfig = { owner = self.guildBankOwner or "Methllyy", updatedAt = 0, updatedBy = "" }
  end
  local config = LeafVE_GlobalDB.guildBankConfig
  config.owner = ShortName(config.owner or self.guildBankOwner or "Methllyy") or "Methllyy"
  config.updatedAt = tonumber(config.updatedAt) or 0
  config.updatedBy = ShortName(config.updatedBy) or Trim(config.updatedBy or "")
  return config
end

function LeafVE:GetGuildBankOwnerName()
  local config = self:GetGuildBankConfig()
  return config.owner or ShortName(self.guildBankOwner or "Methllyy") or "Methllyy"
end

function LeafVE:IsGuildBankOwner(playerName)
  return SamePlayerName(playerName, self:GetGuildBankOwnerName())
end

local function CopyGuildBankCountTable(source)
  local copy = {}
  if type(source) ~= "table" then
    return copy
  end

  for itemKey, rawCount in pairs(source) do
    local itemId = tonumber(itemKey)
    local count = tonumber(rawCount) or 0
    if itemId and itemId > 0 and count > 0 then
      copy[tostring(itemId)] = count
    end
  end
  return copy
end

local function CopyGuildBankIconTable(source)
  local copy = {}
  if type(source) ~= "table" then
    return copy
  end

  for itemKey, iconPath in pairs(source) do
    local itemId = tonumber(itemKey)
    local normalizedIcon = NormalizeIconPath(iconPath)
    if itemId and itemId > 0 and normalizedIcon then
      copy[tostring(itemId)] = normalizedIcon
    end
  end
  return copy
end

local function MergeGuildBankCountTables(sourceTables)
  local counts = {}
  local itemOrder = {}

  if type(sourceTables) ~= "table" then
    sourceTables = {}
  end

  for _, source in ipairs(sourceTables) do
    if type(source) == "table" then
      for itemKey, rawCount in pairs(source) do
        local itemId = tonumber(itemKey)
        local count = tonumber(rawCount) or 0
        if itemId and itemId > 0 and count > 0 then
          local normalizedKey = tostring(itemId)
          if not counts[normalizedKey] then
            counts[normalizedKey] = 0
            table.insert(itemOrder, normalizedKey)
          end
          counts[normalizedKey] = counts[normalizedKey] + count
        end
      end
    end
  end

  table.sort(itemOrder, function(a, b)
    return (tonumber(a) or 0) < (tonumber(b) or 0)
  end)

  return counts, itemOrder
end

local function MergeGuildBankIconTables(sourceTables)
  local icons = {}

  if type(sourceTables) ~= "table" then
    sourceTables = {}
  end

  for _, source in ipairs(sourceTables) do
    if type(source) == "table" then
      for itemKey, iconPath in pairs(source) do
        local itemId = tonumber(itemKey)
        local normalizedIcon = NormalizeIconPath(iconPath)
        if itemId and itemId > 0 and normalizedIcon then
          icons[tostring(itemId)] = normalizedIcon
        end
      end
    end
  end

  return icons
end

local function RebuildGuildBankSnapshotTotals(cache)
  cache.bagCounts = CopyGuildBankCountTable(cache.bagCounts)
  cache.bankCounts = CopyGuildBankCountTable(cache.bankCounts)
  cache.bagIcons = CopyGuildBankIconTable(cache.bagIcons)
  cache.bankIcons = CopyGuildBankIconTable(cache.bankIcons)
  cache.icons = MergeGuildBankIconTables({cache.bagIcons, cache.bankIcons})
  cache.counts, cache.itemOrder = MergeGuildBankCountTables({cache.bagCounts, cache.bankCounts})
  cache.usedSlots = (tonumber(cache.bagUsedSlots) or 0) + (tonumber(cache.bankUsedSlots) or 0)
  cache.totalSlots = (tonumber(cache.bagTotalSlots) or 0) + (tonumber(cache.bankTotalSlots) or 0)
  cache.totalItems = (tonumber(cache.bagTotalItems) or 0) + (tonumber(cache.bankTotalItems) or 0)
  cache.uniqueItems = table.getn(cache.itemOrder or {})
  cache.totalsDirty = false
  return cache
end

function LeafVE:ClearGuildBankSnapshot(ownerName)
  local cache = self:GetGuildBankSnapshot()
  cache.owner = ShortName(ownerName or self:GetGuildBankOwnerName()) or self:GetGuildBankOwnerName()
  cache.updatedAt = 0
  cache.remoteMergedSnapshot = nil
  cache.bagCounts = {}
  cache.bankCounts = {}
  cache.bagIcons = {}
  cache.bankIcons = {}
  cache.icons = {}
  cache.counts = {}
  cache.itemOrder = {}
  cache.bagUsedSlots = 0
  cache.bagTotalSlots = 0
  cache.bagTotalItems = 0
  cache.bankUsedSlots = 0
  cache.bankTotalSlots = 0
  cache.bankTotalItems = 0
  cache.bankUpdatedAt = 0
  cache.usedSlots = 0
  cache.totalSlots = 0
  cache.totalItems = 0
  cache.uniqueItems = 0
  cache.goldCopper = 0
  cache.totalsDirty = true
  return cache
end

function LeafVE:GetGuildBankSnapshot()
  EnsureDB()
  if type(LeafVE_GlobalDB.guildBankCache) ~= "table" then
    LeafVE_GlobalDB.guildBankCache = { owner = self:GetGuildBankOwnerName(), updatedAt = 0, counts = {}, goldCopper = 0 }
  end

  local cache = LeafVE_GlobalDB.guildBankCache
  if type(cache.counts) ~= "table" then
    cache.counts = {}
  end
  if type(cache.bagCounts) ~= "table" then
    cache.bagCounts = CopyGuildBankCountTable(cache.counts)
  end
  if type(cache.bankCounts) ~= "table" then
    cache.bankCounts = {}
  end
  if type(cache.bagIcons) ~= "table" then
    cache.bagIcons = CopyGuildBankIconTable(cache.icons)
  end
  if type(cache.bankIcons) ~= "table" then
    cache.bankIcons = {}
  end
  if type(cache.icons) ~= "table" then
    cache.icons = {}
  end
  if not cache.owner or cache.owner == "" then
    cache.owner = self:GetGuildBankOwnerName()
  end
  cache.bagUsedSlots = tonumber(cache.bagUsedSlots) or tonumber(cache.usedSlots) or 0
  cache.bagTotalSlots = tonumber(cache.bagTotalSlots) or tonumber(cache.totalSlots) or 0
  cache.bagTotalItems = tonumber(cache.bagTotalItems) or tonumber(cache.totalItems) or 0
  cache.bankUsedSlots = tonumber(cache.bankUsedSlots) or 0
  cache.bankTotalSlots = tonumber(cache.bankTotalSlots) or 0
  cache.bankTotalItems = tonumber(cache.bankTotalItems) or 0
  cache.bankUpdatedAt = tonumber(cache.bankUpdatedAt) or 0
  cache.goldCopper = tonumber(cache.goldCopper) or 0
  if cache.totalsDirty ~= false then
    RebuildGuildBankSnapshotTotals(cache)
  end
  return cache
end

function FormatGuildBankMoney(copper)
  copper = tonumber(copper) or 0
  if copper < 0 then copper = 0 end
  local gold = math.floor(copper / 10000)
  local silver = math.floor(PositiveModulo(copper, 10000) / 100)
  local bronze = PositiveModulo(copper, 100)
  return tostring(gold) .. "g " .. tostring(silver) .. "s " .. tostring(bronze) .. "c"
end

function SetGuildBankMoneyDisplay(display, copper)
  if not display then return end
  copper = tonumber(copper) or 0
  if copper < 0 then copper = 0 end
  display.staticMoney = copper

  if display.amountText then
    local gold = math.floor(copper / 10000)
    local silver = math.floor(PositiveModulo(copper, 10000) / 100)
    local bronze = PositiveModulo(copper, 100)
    display.amountText:SetText(
      "|cFFFFD700" .. tostring(gold) .. "g|r "
      .. "|cFFC7C7CF" .. tostring(silver) .. "s|r "
      .. "|cFFB87333" .. tostring(bronze) .. "c|r"
    )
    return
  end

  if MoneyFrame_Update and display.GetName then
    local frameName = display:GetName()
    if frameName and frameName ~= "" then
      MoneyFrame_Update(frameName, copper)
    end
  end
end

function LeafVE:BroadcastGuildBankOwner(force)
  local config = self:GetGuildBankConfig()
  if not InGuild() then
    return config
  end

  local now = Now()
  self.lastGuildBankOwnerBroadcastAt = self.lastGuildBankOwnerBroadcastAt or 0
  if not force and (now - self.lastGuildBankOwnerBroadcastAt) < 10 then
    return config
  end
  self.lastGuildBankOwnerBroadcastAt = now

  SendAddonMessage(
    "LeafVE",
    "GBANKOWNER:" .. table.concat({
      EncodeTalentField(config.owner or self:GetGuildBankOwnerName()),
      tostring(config.updatedAt or now),
      EncodeTalentField(config.updatedBy or ""),
    }, SEP),
    "GUILD"
  )
  return config
end

function LeafVE:RequestGuildBankOwner(force)
  if not InGuild() then
    return nil
  end
  local now = Now()
  self.lastGuildBankOwnerRequestAt = self.lastGuildBankOwnerRequestAt or 0
  if not force and (now - self.lastGuildBankOwnerRequestAt) < 10 then
    return nil
  end
  self.lastGuildBankOwnerRequestAt = now
  SendAddonMessage("LeafVE", force and "GBANKOWNERREQ_FORCE" or "GBANKOWNERREQ", "GUILD")
  return nil
end

function LeafVE:RequestGuildBankLightweightSync(force)
  if not InGuild() then
    return nil
  end

  self:RequestGuildBankOwner(force)
  self:RequestGuildBankItemRequestSync(force)
  self:RequestGuildBankCategoryOverrideSync(force)
  self:RequestGuildBankHighValueSync(force)
  return true
end

function LeafVE:SetGuildBankOwner(ownerName, suppressBroadcast, updatedAt, updatedBy)
  ownerName = ShortName(Trim(ownerName or ""))
  if not ownerName or ownerName == "" then
    return nil, "Enter a character name."
  end

  local me = ShortName(UnitName("player"))
  if updatedAt == nil and not self:IsAdminRank() then
return nil, "Only Kage / Hokage can change the guild bank character."
  end

  local config = self:GetGuildBankConfig()
  local incomingUpdatedAt = tonumber(updatedAt) or Now()
  if incomingUpdatedAt < (config.updatedAt or 0) then
    return config
  end

  local changedOwner = Lower(config.owner or "") ~= Lower(ownerName)
  config.owner = ownerName
  config.updatedAt = incomingUpdatedAt
  config.updatedBy = ShortName(updatedBy or me) or Trim(updatedBy or "")

  if changedOwner then
    self:ClearGuildBankSnapshot(ownerName)
  end

  if not suppressBroadcast then
    self:BroadcastGuildBankOwner(true)
  end

  if changedOwner or not suppressBroadcast then
    if me and self:IsGuildBankOwner(me) then
      self.lastGuildBankBroadcastAt = 0
      self:BroadcastGuildBankSnapshot(true)
    else
      self:RequestGuildBankSnapshot(true)
    end
  end

  if LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
    LeafVE.UI:RefreshVisibleGuildBankUI(true)
  end

  return config
end

function LeafVE:IsGuildBankBankFrameVisible()
  local me = ShortName(UnitName("player"))
  if not me or not self:IsGuildBankOwner(me) then
    return false
  end
  return BankFrame and BankFrame.IsVisible and BankFrame:IsVisible() or false
end

function LeafVE:ApplyGuildBankOwnerBankMode(active)
  active = active and true or false
  if self.guildBankOwnerBankMode == active then
    return
  end
  self.guildBankOwnerBankMode = active

  if self.HideGuildBankCategoryMenu then
    self:HideGuildBankCategoryMenu()
  end

  local frames = {}
  if self.UI then
    if self.UI.frame then
      table.insert(frames, self.UI.frame)
    end
    if self.UI.guildBankPopup then
      table.insert(frames, self.UI.guildBankPopup)
    end
  end

  for i = 1, table.getn(frames) do
    local frame = frames[i]
    if frame then
      if active then
        if frame.GetFrameStrata and not frame._leafBankPrevStrata then
          frame._leafBankPrevStrata = frame:GetFrameStrata()
        end
        if frame.GetFrameLevel and not frame._leafBankPrevLevel then
          frame._leafBankPrevLevel = frame:GetFrameLevel()
        end
        if frame.SetFrameStrata then
          frame:SetFrameStrata("LOW")
        end
        if frame.SetFrameLevel then
          frame:SetFrameLevel(1)
        end
      else
        if frame.SetFrameStrata then
          frame:SetFrameStrata(frame._leafBankPrevStrata or "MEDIUM")
        end
        if frame.SetFrameLevel then
          frame:SetFrameLevel(frame._leafBankPrevLevel or 1)
        end
        frame._leafBankPrevStrata = nil
        frame._leafBankPrevLevel = nil
      end
    end
  end
end

function LeafVE:CaptureAndCacheGuildBankSnapshot(includeBank)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me or not self:IsGuildBankOwner(me) then
    return nil
  end

  local function CaptureContainerRange(startBag, endBag)
    local counts = {}
    local icons = {}
    local usedSlots = 0
    local totalSlots = 0
    local totalItems = 0

    for bag = startBag, endBag do
      local bagSlots = GetContainerNumSlots and tonumber(GetContainerNumSlots(bag)) or 0
      if bagSlots and bagSlots > 0 then
        totalSlots = totalSlots + bagSlots
        for slot = 1, bagSlots do
          local itemLink = GetContainerItemLink and GetContainerItemLink(bag, slot)
          local itemId = self:ParseItemIDFromLink(itemLink)
          if itemId then
            local itemTexture, stackCount = GetContainerItemInfo(bag, slot)
            local itemKey = tostring(itemId)
            local quantity = tonumber(stackCount) or 1
            local iconPath = NormalizeIconPath(itemTexture) or self:ResolveIconForItemID(itemId)
            counts[itemKey] = (counts[itemKey] or 0) + quantity
            if iconPath then
              icons[itemKey] = iconPath
            end
            usedSlots = usedSlots + 1
            totalItems = totalItems + quantity
          end
        end
      end
    end

    return counts, icons, usedSlots, totalSlots, totalItems
  end

  local shouldIncludeBank = includeBank
  if shouldIncludeBank == nil then
    shouldIncludeBank = self:IsGuildBankBankFrameVisible()
  end

  local cache = self:GetGuildBankSnapshot()
  cache.remoteMergedSnapshot = nil
  local bagCounts, bagIcons, bagUsedSlots, bagTotalSlots, bagTotalItems = CaptureContainerRange(0, NUM_BAG_FRAMES or 4)
  cache.bagCounts = bagCounts
  cache.bagIcons = bagIcons
  cache.bagUsedSlots = bagUsedSlots
  cache.bagTotalSlots = bagTotalSlots
  cache.bagTotalItems = bagTotalItems

  if shouldIncludeBank then
    local bankCounts, bankIcons, bankUsedSlots, bankTotalSlots, bankTotalItems = CaptureContainerRange(BANK_CONTAINER or -1, BANK_CONTAINER or -1)
    local bankBagStart = (NUM_BAG_SLOTS or NUM_BAG_FRAMES or 4) + 1
    local bankBagCount = NUM_BANKBAGSLOTS or NUM_BANKBAG_SLOTS or 6
    if bankBagCount > 0 then
      local bankBagCounts, bankBagIcons, bankBagUsedSlots, bankBagTotalSlots, bankBagTotalItems =
        CaptureContainerRange(bankBagStart, bankBagStart + bankBagCount - 1)
      bankCounts = MergeGuildBankCountTables({bankCounts, bankBagCounts})
      bankIcons = MergeGuildBankIconTables({bankIcons, bankBagIcons})
      bankUsedSlots = bankUsedSlots + bankBagUsedSlots
      bankTotalSlots = bankTotalSlots + bankBagTotalSlots
      bankTotalItems = bankTotalItems + bankBagTotalItems
    end

    cache.bankCounts = bankCounts
    cache.bankIcons = bankIcons
    cache.bankUsedSlots = bankUsedSlots
    cache.bankTotalSlots = bankTotalSlots
    cache.bankTotalItems = bankTotalItems
    cache.bankUpdatedAt = Now()
  end

  cache.owner = me
  cache.updatedAt = Now()
  cache.goldCopper = GetMoney and (tonumber(GetMoney()) or 0) or 0
  RebuildGuildBankSnapshotTotals(cache)
  LeafVE_GlobalDB.guildBankCache = cache
  return cache
end

function LeafVE:BroadcastGuildBankSnapshot(force, includeBank)
  local now = Now()
  self.lastGuildBankBroadcastAt = self.lastGuildBankBroadcastAt or 0
  self.lastGuildBankCaptureAt = self.lastGuildBankCaptureAt or 0
  local snapshot = self:GetGuildBankSnapshot()
  local shouldCapture = force
    or not snapshot
    or not snapshot.updatedAt
    or (now - self.lastGuildBankCaptureAt) >= GUILD_BANK_REFRESH_DEBOUNCE
    or (includeBank and (tonumber(snapshot.bankUpdatedAt) or 0) < (tonumber(snapshot.updatedAt) or 0))

  if shouldCapture then
    snapshot = self:CaptureAndCacheGuildBankSnapshot(includeBank)
    if not snapshot then
      return nil
    end
    self.lastGuildBankCaptureAt = now
  end

  if not InGuild() then
    return snapshot
  end

  if not force and (now - self.lastGuildBankBroadcastAt) < 2 then
    return snapshot
  end
  self.lastGuildBankBroadcastAt = now

  SendAddonMessage(
    "LeafVE",
    "GBANKMETA:" .. tostring(snapshot.owner) .. ":" .. tostring(snapshot.updatedAt or now) .. ":" ..
      tostring(snapshot.usedSlots or 0) .. ":" .. tostring(snapshot.totalSlots or 0) .. ":" ..
      tostring(snapshot.totalItems or 0) .. ":" .. tostring(snapshot.uniqueItems or 0) .. ":" ..
      tostring(snapshot.goldCopper or 0),
    "GUILD"
  )
  SendChunkedSnapshot("GBANK:", snapshot.owner, snapshot.updatedAt or now, snapshot.itemOrder or {}, snapshot.counts or {})
  SendChunkedSnapshot("GBANKICON:", snapshot.owner, snapshot.updatedAt or now, snapshot.itemOrder or {}, snapshot.icons or {})
  return snapshot
end

function LeafVE:ScheduleIncomingGuildBankSnapshotMerge(refreshUI)
  if refreshUI then
    self.pendingGuildBankRemoteRefreshUI = true
  end

  self:ScheduleDeferred("guild_bank_remote_merge", 0.2, function()
    local shouldRefreshUI = LeafVE.pendingGuildBankRemoteRefreshUI and true or false
    LeafVE.pendingGuildBankRemoteRefreshUI = nil

    local cache = LeafVE_GlobalDB and LeafVE_GlobalDB.guildBankCache
    if type(cache) == "table" and cache.totalsDirty ~= false then
      RebuildGuildBankSnapshotTotals(cache)
    end
    if shouldRefreshUI and LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
      LeafVE.UI:RefreshVisibleGuildBankUI(true)
    end
  end)
end

function LeafVE:ScheduleGuildBankSnapshotUpdate(includeBank, refreshUI, localOnly)
  if includeBank then
    self.pendingGuildBankIncludeBank = true
  end
  if refreshUI then
    self.pendingGuildBankRefreshUI = true
  end
  if not localOnly then
    self.pendingGuildBankBroadcast = true
  end

  self:ScheduleDeferred("guild_bank_snapshot", GUILD_BANK_REFRESH_DEBOUNCE, function()
    local shouldIncludeBank = LeafVE.pendingGuildBankIncludeBank and true or false
    local shouldRefreshUI = LeafVE.pendingGuildBankRefreshUI and true or false
    local shouldBroadcast = LeafVE.pendingGuildBankBroadcast and true or false
    LeafVE.pendingGuildBankIncludeBank = nil
    LeafVE.pendingGuildBankRefreshUI = nil
    LeafVE.pendingGuildBankBroadcast = nil

    if shouldBroadcast then
      LeafVE:BroadcastGuildBankSnapshot(true, shouldIncludeBank)
    else
      LeafVE:CaptureAndCacheGuildBankSnapshot(shouldIncludeBank)
    end
    if shouldRefreshUI and LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
      LeafVE.UI:RefreshVisibleGuildBankUI(true)
    end
  end)
end

function LeafVE:RequestGuildBankSnapshot(force)
  local me = ShortName(UnitName("player"))
  if me and self:IsGuildBankOwner(me) then
    local includeBank = self:IsGuildBankBankFrameVisible()
    if force then
      return self:BroadcastGuildBankSnapshot(true, includeBank)
    end
    return self:CaptureAndCacheGuildBankSnapshot(includeBank)
  end
  if not InGuild() then
    return nil
  end

  local now = Now()
  self.lastGuildBankRequestAt = self.lastGuildBankRequestAt or 0
  if not force and (now - self.lastGuildBankRequestAt) < 10 then
    return nil
  end
  self.lastGuildBankRequestAt = now
  SendAddonMessage("LeafVE", force and "GBANKREQ_FORCE" or "GBANKREQ", "GUILD")
  return nil
end

function LeafVE:CanRelayGuildBankSnapshot(snapshot)
  local bankSnapshot = type(snapshot) == "table" and snapshot or self:GetGuildBankSnapshot()
  if type(bankSnapshot) ~= "table" then
    return nil
  end

  local ownerName = ShortName(bankSnapshot.owner or self:GetGuildBankOwnerName())
  if not ownerName or ownerName == "" or not self:IsGuildBankOwner(ownerName) then
    return nil
  end
  if (tonumber(bankSnapshot.updatedAt) or 0) <= 0 then
    return nil
  end
  if type(bankSnapshot.counts) ~= "table" or type(bankSnapshot.icons) ~= "table" then
    return nil
  end
  return bankSnapshot, ownerName
end

function LeafVE:BroadcastCachedGuildBankSnapshot(force)
  if not InGuild() then
    return nil
  end

  local me = ShortName(UnitName("player"))
  if me and self:IsGuildBankOwner(me) then
    return self:BroadcastGuildBankSnapshot(force)
  end

  local snapshot, ownerName = self:CanRelayGuildBankSnapshot()
  if not snapshot then
    return nil
  end

  local now = Now()
  self.lastGuildBankRelayBroadcastAt = self.lastGuildBankRelayBroadcastAt or 0
  if not force and (now - self.lastGuildBankRelayBroadcastAt) < 5 then
    return snapshot
  end
  self.lastGuildBankRelayBroadcastAt = now

  SendAddonMessage(
    "LeafVE",
    "GBANKRELAYMETA:" .. tostring(ownerName) .. ":" .. tostring(snapshot.updatedAt or now) .. ":" ..
      tostring(snapshot.usedSlots or 0) .. ":" .. tostring(snapshot.totalSlots or 0) .. ":" ..
      tostring(snapshot.totalItems or 0) .. ":" .. tostring(snapshot.uniqueItems or 0) .. ":" ..
      tostring(snapshot.goldCopper or 0),
    "GUILD"
  )
  SendChunkedSnapshot("GBANKRELAY:", ownerName, snapshot.updatedAt or now, snapshot.itemOrder or {}, snapshot.counts or {})
  SendChunkedSnapshot("GBANKRELAYICON:", ownerName, snapshot.updatedAt or now, snapshot.itemOrder or {}, snapshot.icons or {})
  return snapshot
end

function LeafVE:ValidateIncomingGuildBankSnapshotSource(sender, declaredName, allowRelay)
  local ownerName = ShortName(declaredName or "")
  local shortSender = ShortName(sender)
  if not ownerName or ownerName == "" or not self:IsGuildBankOwner(ownerName) then
    return nil
  end
  if not shortSender or shortSender == "" then
    return nil
  end
  if not allowRelay and Lower(shortSender) ~= Lower(ownerName) then
    return nil
  end
  return ownerName
end

function LeafVE:HandleIncomingGuildBankMetaPayload(payload, sender, allowRelay)
  local rest = payload or ""
  local p1 = string.find(rest, ":")
  if not p1 then return end
  local ownerName = self:ValidateIncomingGuildBankSnapshotSource(sender, string.sub(rest, 1, p1 - 1), allowRelay)
  if not ownerName then return end

  local rest2 = string.sub(rest, p1 + 1)
  local p2 = string.find(rest2, ":")
  if not p2 then return end
  local updatedAt = tonumber(string.sub(rest2, 1, p2 - 1)) or Now()
  local rest3 = string.sub(rest2, p2 + 1)
  local p3 = string.find(rest3, ":")
  if not p3 then return end
  local usedSlots = tonumber(string.sub(rest3, 1, p3 - 1)) or 0
  local rest4 = string.sub(rest3, p3 + 1)
  local p4 = string.find(rest4, ":")
  if not p4 then return end
  local totalSlots = tonumber(string.sub(rest4, 1, p4 - 1)) or 0
  local rest5 = string.sub(rest4, p4 + 1)
  local p5 = string.find(rest5, ":")
  if not p5 then return end
  local totalItems = tonumber(string.sub(rest5, 1, p5 - 1)) or 0
  local rest6 = string.sub(rest5, p5 + 1)
  local p6 = string.find(rest6, ":")
  local uniqueItems, goldCopper
  if p6 then
    uniqueItems = tonumber(string.sub(rest6, 1, p6 - 1)) or 0
    goldCopper = tonumber(string.sub(rest6, p6 + 1)) or 0
  else
    uniqueItems = tonumber(rest6) or 0
    goldCopper = 0
  end

  local cache = self:GetGuildBankSnapshot()
  if updatedAt > (cache.updatedAt or 0) then
    cache.bagCounts = {}
    cache.bankCounts = {}
    cache.bagIcons = {}
    cache.bankIcons = {}
    cache.icons = {}
    cache.counts = {}
    cache.itemOrder = {}
    cache.bankUsedSlots = 0
    cache.bankTotalSlots = 0
    cache.bankTotalItems = 0
    cache.bankUpdatedAt = 0
    cache.goldCopper = 0
  end
  if updatedAt >= (cache.updatedAt or 0) then
    cache.owner = ownerName
    cache.updatedAt = updatedAt
    cache.remoteMergedSnapshot = true
    cache.bagUsedSlots = usedSlots
    cache.bagTotalSlots = totalSlots
    cache.bagTotalItems = totalItems
    cache.bankUsedSlots = 0
    cache.bankTotalSlots = 0
    cache.bankTotalItems = 0
    cache.bankUpdatedAt = 0
    cache.usedSlots = usedSlots
    cache.totalSlots = totalSlots
    cache.totalItems = totalItems
    cache.uniqueItems = uniqueItems
    cache.goldCopper = goldCopper
    cache.totalsDirty = true
  end
  self:ScheduleIncomingGuildBankSnapshotMerge(true)
end

function LeafVE:HandleIncomingGuildBankCountPayload(payload, sender, allowRelay)
  local rest = payload or ""
  local p1 = string.find(rest, ":")
  if not p1 then return end
  local ownerName = self:ValidateIncomingGuildBankSnapshotSource(sender, string.sub(rest, 1, p1 - 1), allowRelay)
  if not ownerName then return end

  local rest2 = string.sub(rest, p1 + 1)
  local p2 = string.find(rest2, ":")
  if not p2 then return end
  local updatedAt = tonumber(string.sub(rest2, 1, p2 - 1)) or Now()
  local itemData = string.sub(rest2, p2 + 1)

  local cache = self:GetGuildBankSnapshot()
  if updatedAt > (cache.updatedAt or 0) then
    cache.bagCounts = {}
    cache.bankCounts = {}
    cache.bagIcons = {}
    cache.bankIcons = {}
    cache.icons = {}
    cache.counts = {}
    cache.itemOrder = {}
    cache.bagUsedSlots = 0
    cache.bagTotalSlots = 0
    cache.bagTotalItems = 0
    cache.bankUsedSlots = 0
    cache.bankTotalSlots = 0
    cache.bankTotalItems = 0
    cache.bankUpdatedAt = 0
    cache.usedSlots = 0
    cache.totalSlots = 0
    cache.totalItems = 0
    cache.uniqueItems = 0
    cache.goldCopper = 0
  end
  if updatedAt >= (cache.updatedAt or 0) then
    cache.owner = ownerName
    cache.updatedAt = updatedAt
    cache.remoteMergedSnapshot = true
    if type(cache.bagCounts) ~= "table" then
      cache.bagCounts = {}
    end
    local startPos = 1
    while startPos <= string.len(itemData) do
      local commaPos = string.find(itemData, ",", startPos)
      local entry
      if commaPos then
        entry = string.sub(itemData, startPos, commaPos - 1)
        startPos = commaPos + 1
      else
        entry = string.sub(itemData, startPos)
        startPos = string.len(itemData) + 1
      end
      local eqPos = string.find(entry, "=")
      if eqPos then
        local itemKey = string.sub(entry, 1, eqPos - 1)
        local count = tonumber(string.sub(entry, eqPos + 1))
        if itemKey ~= "" and count and count > 0 then
          cache.bagCounts[itemKey] = count
        end
      end
    end
    cache.totalsDirty = true
  end
  self:ScheduleIncomingGuildBankSnapshotMerge(true)
end

function LeafVE:HandleIncomingGuildBankIconPayload(payload, sender, allowRelay)
  local rest = payload or ""
  local p1 = string.find(rest, ":")
  if not p1 then return end
  local ownerName = self:ValidateIncomingGuildBankSnapshotSource(sender, string.sub(rest, 1, p1 - 1), allowRelay)
  if not ownerName then return end

  local rest2 = string.sub(rest, p1 + 1)
  local p2 = string.find(rest2, ":")
  if not p2 then return end
  local updatedAt = tonumber(string.sub(rest2, 1, p2 - 1)) or Now()
  local iconData = string.sub(rest2, p2 + 1)

  local cache = self:GetGuildBankSnapshot()
  if updatedAt > (cache.updatedAt or 0) then
    cache.bagIcons = {}
    cache.bankIcons = {}
    cache.icons = {}
  end
  if updatedAt >= (cache.updatedAt or 0) then
    cache.owner = ownerName
    cache.updatedAt = updatedAt
    cache.remoteMergedSnapshot = true
    if type(cache.bagIcons) ~= "table" then
      cache.bagIcons = {}
    end
    local startPos = 1
    while startPos <= string.len(iconData) do
      local commaPos = string.find(iconData, ",", startPos)
      local entry
      if commaPos then
        entry = string.sub(iconData, startPos, commaPos - 1)
        startPos = commaPos + 1
      else
        entry = string.sub(iconData, startPos)
        startPos = string.len(iconData) + 1
      end
      local eqPos = string.find(entry, "=")
      if eqPos then
        local itemKey = string.sub(entry, 1, eqPos - 1)
        local iconPath = NormalizeIconPath(string.sub(entry, eqPos + 1))
        if itemKey ~= "" and iconPath then
          cache.bagIcons[itemKey] = iconPath
        end
      end
    end
    cache.totalsDirty = true
  end
  self:ScheduleIncomingGuildBankSnapshotMerge(true)
end

function LeafVE:BuildGuildBankDisplayItems(snapshot)
  local bankSnapshot = type(snapshot) == "table" and snapshot or self:GetGuildBankSnapshot()
  if type(bankSnapshot) ~= "table" or type(bankSnapshot.counts) ~= "table" then
    return {}
  end

  local cacheKey = table.concat({
    tostring(bankSnapshot.owner or ""),
    tostring(bankSnapshot.updatedAt or 0),
    tostring(bankSnapshot.uniqueItems or 0),
    tostring(bankSnapshot.totalItems or 0),
    tostring(self:GetGuildBankRequestSignature()),
    tostring(self:GetGuildBankHighValueSignature()),
    tostring(self:GetGuildBankCategoryOverrideSignature()),
  }, "|")
  if self.guildBankDisplayItemsCacheKey == cacheKey and type(self.guildBankDisplayItemsCache) == "table" then
    return self.guildBankDisplayItemsCache
  end

  local items = {}
  for itemKey, rawCount in pairs(bankSnapshot.counts) do
    local itemId = tonumber(itemKey)
    local totalCount = tonumber(rawCount) or 0
    if itemId and itemId > 0 and totalCount > 0 then
      local itemInfo = self:GetGuildBankItemInfoRecord(itemId, self:GetWorkOrderItemName(itemId))
      local reservedCount = self:GetGuildBankReservedRequestQuantity(itemId)
      if reservedCount > totalCount then
        reservedCount = totalCount
      end
      local availableCount = totalCount - reservedCount
      if availableCount < 0 then
        availableCount = 0
      end
      table.insert(items, {
        itemId = itemId,
        count = availableCount,
        totalCount = totalCount,
        reservedCount = reservedCount,
        availableCount = availableCount,
        requestableCount = availableCount,
        uiQuantityMax = availableCount,
        name = itemInfo.name,
        icon = NormalizeIconPath(bankSnapshot.icons and bankSnapshot.icons[itemKey]) or self:ResolveIconForItemID(itemId) or LEAF_FALLBACK,
        searchKey = Lower(itemInfo.name .. " " .. tostring(itemId) .. " " .. tostring(itemInfo.itemTypeRaw or "") .. " " .. tostring(itemInfo.itemSubTypeRaw or "")),
        isHighValue = self:IsGuildBankItemHighValue(itemId),
        itemInfo = itemInfo,
        itemType = itemInfo.itemType,
        itemSubType = itemInfo.itemSubType,
        equipLoc = itemInfo.equipLoc,
        quality = itemInfo.quality,
      })
    end
  end

  table.sort(items, function(a, b)
    local an = Lower(a.name or "")
    local bn = Lower(b.name or "")
    if an == bn then
      return (a.itemId or 0) < (b.itemId or 0)
    end
    return an < bn
  end)
  self.guildBankDisplayItemsCacheKey = cacheKey
  self.guildBankDisplayItemsCache = items
  return items
end

function NormalizeGuildBankRequestStatus(status)
  status = Lower(Trim(tostring(status or "open")))
  if status == "fulfilled" or status == "filled" or status == "complete" or status == "completed" then
    return "fulfilled"
  end
  if status == "cancelled" or status == "canceled" or status == "closed" then
    return "cancelled"
  end
  return "open"
end

