-- UI SYSTEM - ALL TABS
-------------------------------------------------
LeafVE.UI = LeafVE.UI or { activeTab = "me" }

function LeafVE.UI:GetUIScale()
  EnsureDB()
  return LeafVE:ClampUIScale((LeafVE_DB and LeafVE_DB.ui and LeafVE_DB.ui.scale) or LeafVE.uiDefaultScale)
end

function LeafVE.UI:IsFrameWithinMainUI(frame)
  if not frame or not self.frame or not frame.GetParent then return false end
  local parent = frame:GetParent()
  while parent do
    if parent == self.frame then
      return true
    end
    if not parent.GetParent then
      break
    end
    parent = parent:GetParent()
  end
  return false
end

function LeafVE.UI:ApplyPopupScale(frame)
  if not frame or not frame.SetScale then return end
  if self:IsFrameWithinMainUI(frame) then
    frame:SetScale(1)
  else
    frame:SetScale(self:GetUIScale())
  end
end

function LeafVE.UI:RefreshPopupScales()
  local popupFields = {
    "allBadgesFrame",
    "achPopup",
    "gearPopup",
    "talentPopup",
    "professionPopup",
    "workOrderCrafterSignupPopup",
    "workOrderPopup",
    "guildBankPopup",
    "loginBriefingPopup",
  }

  for i = 1, table.getn(popupFields) do
    self:ApplyPopupScale(self[popupFields[i]])
  end

  if LeafVE and LeafVE.versionFrame then
    self:ApplyPopupScale(LeafVE.versionFrame)
  end
  if LeafVE and LeafVE.toastFrame then
    self:ApplyPopupScale(LeafVE.toastFrame)
  end
end

function LeafVE.UI:ShouldUseGroupedNavigation()
  return _G.LEAFVE_FORCE_LEGACY_TABS ~= true
end

function LeafVE.UI:HideGroupedNavigation()
  if self.navCategoryButtons then
    for _, button in pairs(self.navCategoryButtons) do
      if button then
        button:Hide()
      end
    end
  end

  if self.navSubtabButtons then
    for i = 1, table.getn(self.navSubtabButtons) do
      local button = self.navSubtabButtons[i]
      if button then
        button:Hide()
      end
    end
  end
end

function LeafVE.UI:HideAllMainPanels()
  if not self.panels then
    return
  end

  local panelNames = {
    "me", "shoutouts", "leaderWeek", "leaderLife", "roster", "history", "badges",
    "titles", "achievements", "shinobiReputation", "options", "admin", "liveHistory",
    "guildEvents", "workOrders", "shinobiDuties", "workOrderRep", "welcome", "join"
  }

  for i = 1, table.getn(panelNames) do
    local panel = self.panels[panelNames[i]]
    if panel and panel.Hide then
      panel:Hide()
    end
  end
end

-- C_Timer.After polyfill for WoW 1.12 (uses OnUpdate on a hidden frame)
if not C_Timer_After then
  C_Timer_After = function(delay, func)
    if LeafVE and LeafVE.ScheduleDeferred then
      LeafVE:ScheduleDeferred(nil, delay, func)
      return
    end

    local ticker = CreateFrame("Frame")
    local elapsed = 0
    ticker:SetScript("OnUpdate", function()
      elapsed = elapsed + arg1
      if elapsed >= delay then
        ticker:SetScript("OnUpdate", nil)
        ticker:Hide()
        func()
      end
    end)
    ticker:Show()
  end
end

function LeafVE:ShowVersionResults()
  local myVer = LeafVE.version
  -- Build a sorted list of all known guild members
  local results = {}
  -- Add self
  local me = ShortName(UnitName("player"))
  if me then
    table.insert(results, {name = me, ver = myVer, status = "self"})
  end
  -- Add responses received
  if LeafVE.versionResponses then
    for name, ver in pairs(LeafVE.versionResponses) do
      if name ~= me then
        local status
        if ver == myVer then
          status = "ok"
        elseif VersionLessThan(ver, myVer) then
          status = "old"
        else
          status = "newer"
        end
        table.insert(results, {name = name, ver = ver, status = status})
      end
    end
  end
  table.sort(results, function(a, b) return a.name < b.name end)

  -- Create popup frame if needed
  if not LeafVE.versionFrame then
    local f = CreateFrame("Frame", "LeafVE_VersionFrame", UIParent)
    f:SetWidth(300)
    f:SetHeight(400)
    f:SetPoint("CENTER", UIParent, "CENTER", 0, 0)
    f:SetFrameStrata("DIALOG")
    f:SetBackdrop({
      bgFile = "Interface\\Tooltips\\UI-Tooltip-Background",
      edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
      tile = true, tileSize = 16, edgeSize = 16,
      insets = {left = 4, right = 4, top = 4, bottom = 4}
    })
    f:SetBackdropColor(0.05, 0.05, 0.08, 0.95)
    f:SetBackdropBorderColor(THEME.gold[1], THEME.gold[2], THEME.gold[3], 0.8)
    f:EnableMouse(true)
    f:SetMovable(true)
    f:RegisterForDrag("LeftButton")
    f:SetScript("OnDragStart", function() f:StartMoving() end)
    f:SetScript("OnDragStop", function() f:StopMovingOrSizing() end)

    local title = f:CreateFontString(nil, "OVERLAY", "GameFontNormal")
    title:SetPoint("TOP", f, "TOP", 0, -12)
    title:SetText("|cFFFFD700Addon Version Check|r")

    local closeBtn = CreateFrame("Button", nil, f, "UIPanelCloseButton")
    closeBtn:SetPoint("TOPRIGHT", f, "TOPRIGHT", -4, -4)

    local scrollFrame = CreateFrame("ScrollFrame", nil, f)
    scrollFrame:SetPoint("TOPLEFT", f, "TOPLEFT", 8, -40)
    scrollFrame:SetPoint("BOTTOMRIGHT", f, "BOTTOMRIGHT", -8, 8)
    scrollFrame:EnableMouseWheel(true)
    scrollFrame:SetScript("OnMouseWheel", function()
      local cur = scrollFrame:GetVerticalScroll()
      local mx = scrollFrame:GetVerticalScrollRange()
      local ns = cur - (arg1 * 20)
      if ns < 0 then ns = 0 end
      if ns > mx then ns = mx end
      scrollFrame:SetVerticalScroll(ns)
    end)

    local scrollChild = CreateFrame("Frame", nil, scrollFrame)
    scrollChild:SetWidth(270)
    scrollChild:SetHeight(1)
    scrollFrame:SetScrollChild(scrollChild)

    f.scrollChild = scrollChild
    f.resultRows = {}
    if LeafVE.UI and LeafVE.UI.ApplyPopupScale then
      LeafVE.UI:ApplyPopupScale(f)
    end
    LeafVE.versionFrame = f
  end

  local f = LeafVE.versionFrame
  local sc = f.scrollChild

  -- Clear old rows
  for _, row in ipairs(f.resultRows) do row:Hide() end
  f.resultRows = {}

  local yOff = -4
  for i, entry in ipairs(results) do
    local row = CreateFrame("Frame", nil, sc)
    row:SetWidth(270)
    row:SetHeight(20)
    row:SetPoint("TOPLEFT", sc, "TOPLEFT", 0, yOff)

    local icon = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    icon:SetPoint("LEFT", row, "LEFT", 4, 0)
    icon:SetWidth(20)
    if entry.status == "ok" or entry.status == "self" then
      icon:SetText("|cFF00FF00ÃƒÂ¢Ã…â€œÃ¢â‚¬Â|r")
    elseif entry.status == "old" then
      icon:SetText("|cFFFF4444ÃƒÂ¢Ã…â€œÃ‹Å“|r")
    else
      icon:SetText("|cFFAAAAAAÃƒÂ¢Ã…Â¡Ã‚Â |r")
    end

    local nameFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    nameFS:SetPoint("LEFT", row, "LEFT", 28, 0)
    nameFS:SetWidth(140)
    nameFS:SetJustifyH("LEFT")
    nameFS:SetText(entry.name or "")

    local verFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    verFS:SetPoint("LEFT", row, "LEFT", 172, 0)
    verFS:SetWidth(90)
    verFS:SetJustifyH("LEFT")
    if entry.status == "old" then
      verFS:SetText("|cFFFF4444v"..(entry.ver or "?").."  (outdated)|r")
    elseif entry.status == "self" then
      verFS:SetText("|cFFFFD700v"..(entry.ver or "?").."  (you)|r")
    else
      verFS:SetText("|cFF00FF00v"..(entry.ver or "?").."|r")
    end

    table.insert(f.resultRows, row)
    yOff = yOff - 20
  end
  sc:SetHeight(math.max(math.abs(yOff) + 8, 1))
  f:Show()
end


