local function GetAchievementIcon(achId)
  if not achId then return LEAF_FALLBACK end
  
  local meta = LeafVE.GetAchievementMeta and LeafVE:GetAchievementMeta(achId)
  if meta and meta.icon then
    return meta.icon
  end
  
  local lowerAchId = string.lower(tostring(achId))
  
  -- Check the full ACHIEVEMENT_ICONS table
  if ACHIEVEMENT_ICONS[lowerAchId] then
    return ACHIEVEMENT_ICONS[lowerAchId]
  end
  
  local iconMap = {
    lvl_10 = "Interface\\Icons\\INV_Sword_04",
    lvl_20 = "Interface\\Icons\\INV_Sword_27",
    lvl_30 = "Interface\\Icons\\INV_Sword_39",
    lvl_40 = "Interface\\Icons\\INV_Sword_43",
    lvl_50 = "Interface\\Icons\\INV_Sword_62",
    lvl_60 = "Interface\\Icons\\INV_Sword_65",
    gold_10 = "Interface\\Icons\\INV_Misc_Coin_01",
    gold_100 = "Interface\\Icons\\INV_Misc_Coin_05",
    gold_1000 = "Interface\\Icons\\INV_Misc_Gem_Pearl_05",
  }
  
  if iconMap[lowerAchId] then
    return iconMap[lowerAchId]
  end
  
  if string.find(lowerAchId, "lvl") or string.find(lowerAchId, "level") then
    return "Interface\\Icons\\INV_Sword_04"
  elseif string.find(lowerAchId, "gold") then
    return "Interface\\Icons\\INV_Misc_Coin_01"
  end
  
  return LEAF_FALLBACK
end

local function TabButton(parent, text, name)
  local b = CreateFrame("Button", name, parent, "UIPanelButtonTemplate")
  b:SetHeight(20)
  b:SetText(text)
  LeafVECallSkin("SkinTab", b, false)
  SkinButtonAccent(b)
  if LEAFVE_UI_MODERN and LEAFVE_UI_MODERN.StyleButton then
    LEAFVE_UI_MODERN:StyleButton(b)
  end
  return b
end

local function UpdateLeafTabVisual(tabButton, isActive)
  if not tabButton then
    return
  end
  LeafVECallSkin("SkinTab", tabButton, isActive and true or false)
  local fs = tabButton.GetFontString and tabButton:GetFontString()
  if fs then
    if isActive then
      fs:SetTextColor((Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.r) or 1, (Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.g) or 0.84, (Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.b) or 0.0, 1)
    else
      fs:SetTextColor((Colors and Colors.TEXT and Colors.TEXT.off_white and Colors.TEXT.off_white.r) or 0.9, (Colors and Colors.TEXT and Colors.TEXT.off_white and Colors.TEXT.off_white.g) or 0.9, (Colors and Colors.TEXT and Colors.TEXT.off_white and Colors.TEXT.off_white.b) or 0.9, 1)
    end
  end
end

function LeafVE.UI:LayoutLegacyMainTabs()
  local frame = self and self.frame
  if not frame then
    return
  end

  local firstRow = {
    {btn = self.tabWelcome, width = 65},
    {btn = self.tabMe, width = 70},
    {btn = self.tabRoster, width = 60},
    {btn = self.tabLeaderWeek, width = 60},
    {btn = self.tabLeaderLife, width = 65},
    {btn = self.tabAchievements, width = 95},
    {btn = self.tabShinobiReputation, width = 110},
    {btn = self.tabShoutouts, width = 80},
    {btn = self.tabGuildEvents, width = 88},
    {btn = self.tabHistory, width = 60},
    {btn = self.tabLiveHistory, width = 80},
    {btn = self.tabBadges, width = 65},
    {btn = self.tabOptions, width = 56},
  }

  local previousButton = nil
  for i = 1, table.getn(firstRow) do
    local entry = firstRow[i]
    local button = entry.btn
    if button then
      button:ClearAllPoints()
      button:SetWidth(entry.width)
      if previousButton then
        button:SetPoint("LEFT", previousButton, "RIGHT", 4, 0)
      else
        button:SetPoint("TOPLEFT", frame, "TOPLEFT", 14, -52)
      end
      previousButton = button
    end
  end

  if self.tabAdmin then
    self.tabAdmin:ClearAllPoints()
    self.tabAdmin:SetWidth(50)
    self.tabAdmin:SetPoint("TOPLEFT", self.tabWelcome, "BOTTOMLEFT", 0, -6)
  end

  if self.tabWorkOrderRep then
    self.tabWorkOrderRep:ClearAllPoints()
    self.tabWorkOrderRep:SetWidth(142)
    if self.tabAdmin and self.tabAdmin:IsShown() then
      self.tabWorkOrderRep:SetPoint("LEFT", self.tabAdmin, "RIGHT", 4, 0)
    else
      self.tabWorkOrderRep:SetPoint("TOPLEFT", self.tabWelcome, "BOTTOMLEFT", 0, -6)
    end
  end

  if self.tabJoin then
    self.tabJoin:ClearAllPoints()
    self.tabJoin:SetPoint("TOPLEFT", frame, "TOPLEFT", 14, -52)
    self.tabJoin:SetWidth(300)
  end
end

