function LeafVE.UI:ShowAllBadgesPanel(playerName)
  if not playerName then
    playerName = UnitName("player")
  end

  -- Create main frame (only once)
  if not self.allBadgesFrame then
    local f = CreateFrame("Frame", "LeafVEAllBadgesFrame", UIParent)
    f:SetWidth(450)
    f:SetFrameStrata("DIALOG")
    f:EnableMouse(true)
    
    -- Anchor to right side of main UI panel
    if LeafVE.UI.frame then
      f:SetPoint("TOPLEFT", LeafVE.UI.frame, "TOPRIGHT", 5, 0)
      f:SetHeight(LeafVE.UI.frame:GetHeight())
    else
      f:SetPoint("CENTER", UIParent, "CENTER", 0, 0)
      f:SetHeight(550)
    end
    
    -- Backdrop
    f:SetBackdrop({
      bgFile = "Interface\\DialogFrame\\UI-DialogBox-Background",
      edgeFile = "Interface\\DialogFrame\\UI-DialogBox-Border",
      tile = true,
      tileSize = 32,
      edgeSize = 32,
      insets = { left = 11, right = 12, top = 12, bottom = 11 }
    })
    f:SetBackdropColor(0, 0, 0, 1)
    
    -- Title
    f.title = f:CreateFontString(nil, "OVERLAY", "GameFontHighlightLarge")
    f.title:SetPoint("TOP", f, "TOP", 0, -15)
    f.title:SetTextColor(THEME.gold[1], THEME.gold[2], THEME.gold[3])

    f.summary = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
    f.summary:SetPoint("TOP", f.title, "BOTTOM", 0, -2)
    f.summary:SetText("|cFFAAAAAACompletion: 0/0 (0%)|r")
    
    -- Close button
    local closeBtn = CreateFrame("Button", nil, f, "UIPanelCloseButton")
    closeBtn:SetPoint("TOPRIGHT", f, "TOPRIGHT", -5, -5)
    closeBtn:SetScript("OnClick", function() this:GetParent():Hide() end)
    
    -- Scroll Frame
    local scrollFrame = CreateFrame("ScrollFrame", "LeafVEAllBadgesScrollFrame", f, "UIPanelScrollFrameTemplate")
    scrollFrame:SetPoint("TOPLEFT", f, "TOPLEFT", 20, -68)
    scrollFrame:SetPoint("BOTTOMRIGHT", f, "BOTTOMRIGHT", -30, 20)
    
    -- Content Frame
    local content = CreateFrame("Frame", nil, scrollFrame)
    content:SetWidth(400)
    content:SetHeight(1)
    scrollFrame:SetScrollChild(content)
    
    f.scrollFrame = scrollFrame
    f.content = content
    
    if self.ApplyPopupScale then
      self:ApplyPopupScale(f)
    end
    self.allBadgesFrame = f
  end
local f = self.allBadgesFrame
f.title:SetText(playerName .. "'s Badge Collection")

-- Destroy and recreate content frame to force refresh
if f.content then
  f.content:Hide()
  f.content:SetParent(nil)
  f.content = nil
end

-- Create fresh content frame
local content = CreateFrame("Frame", nil, f.scrollFrame)
content:SetWidth(400)
content:SetHeight(1)
f.scrollFrame:SetScrollChild(content)
f.content = content

f.badgeIcons = {}
  
-- Get player's badges
EnsureDB()
local shortName = ShortName(playerName)
local playerBadges = {}
if shortName and LeafVE_DB.badges[shortName] then
  for badgeId, timestamp in pairs(LeafVE_DB.badges[shortName]) do
    playerBadges[badgeId] = {
      id = badgeId,
      earned = timestamp
    }
  end
end

local earnedCount = 0
for _, _ in pairs(playerBadges) do
  earnedCount = earnedCount + 1
end
local totalCount = table.getn(BADGES)
local completion = (totalCount > 0) and math.floor((earnedCount / totalCount) * 100 + 0.5) or 0
if f.summary then
  f.summary:SetText(string.format("|cFFAAAAAACompletion: %d/%d (%d%%)|r", earnedCount, totalCount, completion))
end

-- Organize badges by category
local categories = {}
for i = 1, table.getn(BADGES) do
  local badge = BADGES[i]
  local category = badge.category or "Other"
  
  if not categories[category] then
    categories[category] = {}
  end
  
  table.insert(categories[category], {
    id = badge.id,
    name = badge.name,
    description = badge.desc,
    icon = badge.icon,
    quality = badge.quality or BADGE_QUALITY.COMMON,
    order = i,  -- BADGES array index preserves progression order
    earned = playerBadges[badge.id] ~= nil,
    earnedDate = playerBadges[badge.id] and playerBadges[badge.id].earned or nil
  })
end
  
  -- Sort categories
  local sortedCategories = {}
  for category, _ in pairs(categories) do
    table.insert(sortedCategories, category)
  end
  table.sort(sortedCategories)
  
  -- Build UI
  local yOffset = -10
  local content = f.content
  
  for _, category in ipairs(sortedCategories) do
    -- Category Header
    local header = content:CreateFontString(nil, "OVERLAY", "GameFontNormalLarge")
    header:SetPoint("TOPLEFT", content, "TOPLEFT", 10, yOffset)
    header:SetText("|cFFFFD700" .. category .. "|r")
    table.insert(f.badgeIcons, header)
    yOffset = yOffset - 30
    
    -- Sort badges in category by progression order (BADGES array index)
    table.sort(categories[category], function(a, b)
      return a.order < b.order
    end)
    
    -- Display badges in grid
    local xOffset = 10
    local col = 0
    local maxCols = 4
    local iconSize = 50
    local spacing = 10
    
for _, badgeData in ipairs(categories[category]) do
  local icon = CreateFrame("Frame", nil, content)
  icon:SetWidth(iconSize)
  icon:SetHeight(iconSize)
  icon:SetPoint("TOPLEFT", content, "TOPLEFT", xOffset, yOffset)
  
  icon:EnableMouse(true)
      
      -- Quality background glow (behind texture, only when earned)
      local qualityBG = icon:CreateTexture(nil, "BACKGROUND")
      qualityBG:SetAllPoints()
      qualityBG:SetTexture("Interface\\Tooltips\\UI-Tooltip-Background")
      if badgeData.earned then
        local qr, qg, qb = GetBadgeQualityColor(badgeData.quality)
        qualityBG:SetVertexColor(qr, qg, qb, 0.40)
      else
        qualityBG:SetVertexColor(0, 0, 0, 0.5)
      end

      -- Badge texture
      local tex = icon:CreateTexture(nil, "ARTWORK")
      tex:SetAllPoints()
      tex:SetTexture(badgeData.icon)
      
      if not badgeData.earned then
        tex:SetDesaturated(true)
        tex:SetAlpha(0.3)
      end
      
      -- Border
      local border = icon:CreateTexture(nil, "OVERLAY")
      border:SetAllPoints()
      border:SetTexture("Interface\\AchievementFrame\\UI-Achievement-IconFrame")
      border:SetTexCoord(0, 0.5625, 0, 0.5625)
      
-- Store badge data on icon for tooltip
icon.badgeName = badgeData.name
icon.badgeDesc = badgeData.description
icon.badgeQuality = badgeData.quality
icon.badgeEarned = badgeData.earned
icon.badgeEarnedDate = badgeData.earnedDate
icon.badgeId = badgeData.id
icon.badgePlayerName = shortName

-- Tooltip
icon:SetScript("OnEnter", function()
  GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
  GameTooltip:ClearLines()
  local qr2, qg2, qb2 = GetBadgeQualityColor(this.badgeQuality)
  if this.badgeEarned then
    GameTooltip:SetText(this.badgeName, qr2, qg2, qb2, 1, true)
    GameTooltip:AddLine("|cFF888888"..GetBadgeQualityLabel(this.badgeQuality).."|r", 1, 1, 1)
    GameTooltip:AddLine(this.badgeDesc, 1, 1, 1, true)
    if this.badgeEarnedDate then
      GameTooltip:AddLine(" ", 1, 1, 1)
      GameTooltip:AddLine("Earned: " .. date("%m/%d/%Y", this.badgeEarnedDate), 0.5, 0.8, 0.5)
    end
  else
    GameTooltip:SetText(this.badgeName, 0.6, 0.6, 0.6, 1, true)
    GameTooltip:AddLine("|cFF888888"..GetBadgeQualityLabel(this.badgeQuality).."|r", 1, 1, 1)
    GameTooltip:AddLine(this.badgeDesc, 0.7, 0.7, 0.7, true)
    GameTooltip:AddLine(" ", 1, 1, 1)
    local cur, tgt = LeafVE:GetBadgeProgress(this.badgePlayerName, this.badgeId)
    if cur and tgt then
      GameTooltip:AddLine("Progress: "..cur.." / "..tgt, 1, 0.82, 0)
    end
    GameTooltip:AddLine("Not yet earned", 0.8, 0.4, 0.4)
  end
  GameTooltip:Show()
end)

icon:SetScript("OnLeave", function()
  GameTooltip:Hide()
end)  
      table.insert(f.badgeIcons, icon)
      
      col = col + 1
      if col >= maxCols then
        col = 0
        xOffset = 10
        yOffset = yOffset - (iconSize + spacing)
      else
        xOffset = xOffset + iconSize + spacing
      end
    end
    
    -- Move to next row if we didn't finish a full row
    if col > 0 then
      yOffset = yOffset - (iconSize + spacing)
    end
    
    yOffset = yOffset - 20 -- Extra space between categories
  end
  
  -- Update content height
  content:SetHeight(math.abs(yOffset) + 50)
  
  -- Show frame
  f:Show()
end

function LeafVE.UI:UpdateCardRecentBadges(playerName)
  if not self.cardRecentBadgesFrame then
    return
  end
  
  if not self.cardRecentBadgeFrames then
    return
  end
  
  -- Hide all existing badge frames
  for i = 1, table.getn(self.cardRecentBadgeFrames) do
    self.cardRecentBadgeFrames[i]:Hide()
  end
  
  local shortName = ShortName(playerName)
  
  EnsureDB()
  
  local myBadges = LeafVE_DB.badges[shortName] or {}
  
  -- Build list of earned badges with timestamps
  local earnedBadges = {}
  for i = 1, table.getn(BADGES) do
    local badge = BADGES[i]
    if myBadges[badge.id] then
      table.insert(earnedBadges, {
        id = badge.id,
        name = badge.name,
        desc = badge.desc,
        icon = badge.icon,
        quality = badge.quality or BADGE_QUALITY.COMMON,
        earnedAt = myBadges[badge.id],
        earned = true
      })
    end
  end
  
  -- Sort by most recent first
  table.sort(earnedBadges, function(a, b)
    return a.earnedAt > b.earnedAt
  end)

  if self.cardRecentBadgesSummary then
    local earnedCount = table.getn(earnedBadges)
    if earnedCount > 0 then
      self.cardRecentBadgesSummary:SetText(string.format("%d total earned badge%s", earnedCount, earnedCount == 1 and "" or "s"))
      self.cardRecentBadgesSummary:SetTextColor(0.78, 0.8, 0.86)
    else
      self.cardRecentBadgesSummary:SetText("No badges earned yet")
      self.cardRecentBadgesSummary:SetTextColor(0.58, 0.6, 0.66)
    end
  end
  
  -- Take top 9 earned badges
  local topEarned = {}
  for i = 1, math.min(9, table.getn(earnedBadges)) do
    table.insert(topEarned, earnedBadges[i])
  end
  
  -- Fill remaining slots with locked badges (not yet earned)
  if table.getn(topEarned) < 9 then
    for i = 1, table.getn(BADGES) do
      if table.getn(topEarned) >= 9 then break end
      
      local badge = BADGES[i]
      local alreadyShown = false
      
      for j = 1, table.getn(topEarned) do
        if topEarned[j].id == badge.id then
          alreadyShown = true
          break
        end
      end
      
      if not alreadyShown then
        table.insert(topEarned, {
          id = badge.id,
          name = badge.name,
          desc = badge.desc,
          icon = badge.icon,
          quality = badge.quality or BADGE_QUALITY.COMMON,
          earnedAt = nil,
          earned = false
        })
      end
    end
  end
  
  -- Display all 9 badges (earned + locked)
  local badgeSize = 46
  local xSpacing = 58
  local ySpacing = 50
  local perRow = 3
  
  for i = 1, 9 do  -- ÃƒÂ¢Ã¢â‚¬Â Ã‚Â CHANGE FROM 6 TO 9
    local badge = topEarned[i]
    local frame = self.cardRecentBadgeFrames[i]
    
    if not frame then
      frame = CreateFrame("Frame", nil, self.cardRecentBadgesFrame)
      frame:SetWidth(badgeSize)
      frame:SetHeight(badgeSize)
      frame:EnableMouse(true)
      SkinPlayerCardSection(frame, THEME.soft[1], THEME.soft[2], THEME.soft[3], 0.8, 0.96)
      
      local icon = frame:CreateTexture(nil, "ARTWORK")
      icon:SetPoint("TOPLEFT", frame, "TOPLEFT", 4, -4)
      icon:SetPoint("BOTTOMRIGHT", frame, "BOTTOMRIGHT", -4, 4)
      frame.icon = icon
      
      table.insert(self.cardRecentBadgeFrames, frame)
    end
    
    -- Position: grid layout (3 per row)
    local row = math.floor((i - 1) / perRow)
    local col = PositiveModulo(i - 1, perRow)
    
    frame:ClearAllPoints()
    frame:SetPoint("TOPLEFT", self.cardRecentBadgesFrame, "TOPLEFT", 8 + (col * xSpacing), -row * ySpacing)
    
    if badge then
      -- Set icon
      frame.icon:SetTexture(badge.icon)
      if not frame.icon:GetTexture() then
        frame.icon:SetTexture(LEAF_FALLBACK)
      end
      
      -- Style: earned = full color, locked = greyed out
      if badge.earned then
        local br, bg, bb = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
        frame:SetBackdropColor(0.08, 0.09, 0.12, 0.96)
        frame:SetBackdropBorderColor(br, bg, bb, 0.95)
        frame.icon:SetVertexColor(1, 1, 1, 1)
        frame.icon:SetDesaturated(nil)
      else
        frame:SetBackdropColor(0.05, 0.06, 0.08, 0.9)
        frame:SetBackdropBorderColor(0.28, 0.3, 0.34, 0.85)
        frame.icon:SetVertexColor(0.4, 0.4, 0.4, 0.7)
        if frame.icon.SetDesaturated then
          frame.icon:SetDesaturated(true)
        end
      end
      
      -- Tooltip
      frame:SetScript("OnEnter", function()
        GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
        GameTooltip:ClearLines()
        local qr2, qg2, qb2 = GetBadgeQualityColor(badge.quality or BADGE_QUALITY.COMMON)
        if badge.earned then
          GameTooltip:SetText(badge.name, qr2, qg2, qb2, 1, true)
          GameTooltip:AddLine("|cFF888888"..GetBadgeQualityLabel(badge.quality or BADGE_QUALITY.COMMON).."|r", 1, 1, 1)
          GameTooltip:AddLine(badge.desc, 1, 1, 1, true)
          GameTooltip:AddLine(" ", 1, 1, 1)
          GameTooltip:AddLine("Earned: "..date("%m/%d/%Y", badge.earnedAt), 0.5, 0.8, 0.5)
        else
          GameTooltip:SetText(badge.name, 0.6, 0.6, 0.6, 1, true)
          GameTooltip:AddLine("|cFF888888"..GetBadgeQualityLabel(badge.quality or BADGE_QUALITY.COMMON).."|r", 1, 1, 1)
          GameTooltip:AddLine(badge.desc, 0.7, 0.7, 0.7, true)
          GameTooltip:AddLine(" ", 1, 1, 1)
          local cur, tgt = LeafVE:GetBadgeProgress(shortName, badge.id)
          if cur and tgt then
            GameTooltip:AddLine("Progress: "..cur.." / "..tgt, 1, 0.82, 0)
          end
          GameTooltip:AddLine("Not yet earned", 0.8, 0.4, 0.4)
        end
        GameTooltip:Show()
      end)
      
      frame:SetScript("OnLeave", function()
        GameTooltip:Hide()
      end)
    else
      -- Empty slot
      frame:SetBackdropColor(0.05, 0.06, 0.08, 0.85)
      frame:SetBackdropBorderColor(0.22, 0.24, 0.28, 0.75)
      frame.icon:SetTexture("Interface\\Icons\\INV_Misc_QuestionMark")
      frame.icon:SetVertexColor(0.3, 0.3, 0.3, 0.5)
      if frame.icon.SetDesaturated then
        frame.icon:SetDesaturated(true)
      end
      
      frame:SetScript("OnEnter", function()
        GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
        GameTooltip:ClearLines()
        GameTooltip:SetText("Empty Badge Slot", 0.5, 0.5, 0.5, 1, true)
        GameTooltip:Show()
      end)
      
      frame:SetScript("OnLeave", function()
        GameTooltip:Hide()
      end)
    end
    
    frame:Show()
  end
  
  -- Hide "No badges" text
  if self.cardNoBadgesText then
    self.cardNoBadgesText:Hide()
  end
end

function LeafVE.UI:ShowPlayerCard(playerName)
  EnsureDB()
  playerName = ShortName(playerName)
  if not playerName or not self.card then return end
  
  self.cardCurrentPlayer = playerName
  self.cardName:SetText(playerName)

  local guildInfo = LeafVE:GetGuildInfo(playerName)
  local class = guildInfo and guildInfo.class or "Unknown"
  local level = guildInfo and guildInfo.level or "??"
  local rank = guildInfo and guildInfo.rank or "Unknown"

  class = string.upper(Trim(class))
  if class == "" or class == "UNKNOWN" then
    class = LeafVE:GetClassTagForPlayer(playerName)
  end

  local me = ShortName(UnitName("player"))
  local isSelf = me and Lower(me) == Lower(playerName)
  if not isSelf then
    self:HideNativeTalentFrame()
    -- Keep the card lightweight in crowded areas; detailed gear/talent pulls
    -- happen when the dedicated popups are opened.
    LeafVE:RequestProfessionDesignation(playerName)
    LeafVE:RequestPlayerTitle(playerName)
  else
    LeafVE:CaptureAndCacheMyGear()
    LeafVE:CaptureAndCacheMyTalents(false)
  end

  local classColor = CLASS_COLORS[class] or {1, 1, 1}
  self.cardName:ClearAllPoints()
  if self.cardHonorificText then
    self.cardHonorificText:SetText("")
    self.cardHonorificText:Hide()
  end
  self.cardName:SetPoint("TOP", self.cardHeroPanel or self.card, "TOP", 0, 8)
  self.cardName:SetText(LeafVE:BuildPlayerCardNameMarkup(playerName, class))
  self.cardName:SetTextColor(1, 1, 1)
  self.cardClassLevelRank:SetText(string.format("|cFF%sLevel %s %s|r\n|cFFFFD700%s|r", RGBToHex(classColor[1], classColor[2], classColor[3]), tostring(level), class, rank))
  if self.cardHeroAccent then
    self.cardHeroAccent:SetVertexColor(classColor[1], classColor[2], classColor[3], 0.24)
  end
  if self.cardHeroGlow then
    self.cardHeroGlow:SetGradientAlpha("VERTICAL", classColor[1], classColor[2], classColor[3], 0.22, 0.02, 0.03, 0.05, 0)
  end
  if self.cardPortraitContainer then
    self.cardPortraitContainer:SetBackdropBorderColor(classColor[1], classColor[2], classColor[3], 0.95)
  end
  if self.cardStatusPanel then
    self.cardStatusPanel:SetBackdropBorderColor(classColor[1], classColor[2], classColor[3], 0.45)
  end
  if self.cardStatusAccent then
    self.cardStatusAccent:SetVertexColor(classColor[1], classColor[2], classColor[3], 0.14)
  end

  if self.cardWorkOrderRepBadgeText then
    local repEntry = LeafVE:GetWorkOrderReputationForPlayer(playerName)
    local repTierInfo = repEntry and (repEntry.tierInfo or LeafVE:GetWorkOrderReputationTierInfo(repEntry.totalRep or 0))
      or LeafVE:GetWorkOrderReputationTierInfo(0)
    local repTierName, _, repBadgeIconIndex, repColor = GetWorkOrderReputationTierVisual(repTierInfo)

    self.cardWorkOrderRepBadgeText:SetText("|cFFFFD700" .. repTierName .. "|r")
    if self.cardWorkOrderRepBadgeIcon then
      self.cardWorkOrderRepBadgeIcon:SetTexture(PVP_RANK_ICONS[repBadgeIconIndex] or LEAF_EMBLEM)
      self.cardWorkOrderRepBadgeIcon:SetVertexColor(repColor[1], repColor[2], repColor[3], 1)
    end
    if self.cardWorkOrderRepBadge then
      self.cardWorkOrderRepBadge:SetBackdropColor(repColor[1] * 0.16, repColor[2] * 0.16, repColor[3] * 0.16, 0.92)
      self.cardWorkOrderRepBadge:SetBackdropBorderColor(repColor[1], repColor[2], repColor[3], 0.85)
    end
  end
  if self.cardWorkOrderCrafterRankBadge then
    local crafterRank = LeafVE:GetWorkOrderCrafterRankInfo(playerName)
    local rankLabel = GetWorkOrderCrafterRankLabel(crafterRank)
    if rankLabel then
      local rr, rg, rb = GetWorkOrderCrafterRankColor(crafterRank)
      self.cardWorkOrderCrafterRankBadgeText:SetText("|cFFFFD700" .. rankLabel .. "|r")
      if self.cardWorkOrderCrafterRankBadgeIcon then
        self.cardWorkOrderCrafterRankBadgeIcon:SetTexture("Interface\\Icons\\INV_Crown_01")
        self.cardWorkOrderCrafterRankBadgeIcon:SetVertexColor(rr, rg, rb, 1)
      end
      self.cardWorkOrderCrafterRankBadge:SetBackdropColor(rr * 0.15, rg * 0.15, rb * 0.15, 0.92)
      self.cardWorkOrderCrafterRankBadge:SetBackdropBorderColor(rr, rg, rb, 0.85)
      self.cardWorkOrderCrafterRankBadge:Show()
    else
      self.cardWorkOrderCrafterRankBadge:Hide()
    end
  end
  if self.cardWeeklyCharacterRankBadge then
    local weeklyRank, weeklyEntry = LeafVE:GetWeeklyCharacterRankInfo(playerName)
    local weeklyRankLabel = GetWeeklyCharacterRankLabel(weeklyRank)
    if weeklyRankLabel then
      local wr, wg, wb = GetWeeklyCharacterRankColor(weeklyRank)
      self.cardWeeklyCharacterRankBadgeText:SetText("|cFFFFD700" .. weeklyRankLabel .. "|r")
      if self.cardWeeklyCharacterRankBadgeIcon then
        self.cardWeeklyCharacterRankBadgeIcon:SetTexture(PVP_RANK_ICONS[weeklyRank] or "Interface\\Icons\\INV_Misc_Horn_03")
        self.cardWeeklyCharacterRankBadgeIcon:SetVertexColor(wr, wg, wb, 1)
      end
      self.cardWeeklyCharacterRankBadge:SetBackdropColor(wr * 0.15, wg * 0.15, wb * 0.15, 0.92)
      self.cardWeeklyCharacterRankBadge:SetBackdropBorderColor(wr, wg, wb, 0.85)
      self.cardWeeklyCharacterRankBadge:Show()
    else
      self.cardWeeklyCharacterRankBadge:Hide()
    end
  end

  local unitToken = FindUnitToken(playerName)
  local useModel = unitToken ~= nil and CheckInteractDistance(unitToken, 1)
  if unitToken and useModel then
    LeafVE:CaptureAndCacheInspectedGear(playerName, unitToken)
  end
  local specSnapshot = LeafVE:GetSpecSnapshotForPlayer(playerName, class)
  local talentSnapshot = LeafVE:GetTalentSpecForPlayer(playerName, class)
  local talentName = (talentSnapshot and talentSnapshot.name) or (specSnapshot and specSnapshot.name) or class
  
  if useModel then
    local modelOk = pcall(function()
      self.cardModel:ClearModel()
      self.cardModel:SetCamera(0)
      self.cardModel:SetUnit(unitToken)
      self.cardModel:SetPosition(0, 0, 0)
      self.cardModel:SetFacing(0.5)
    end)
    if not modelOk then useModel = false end
  end

  if useModel then
    self.cardModel:Show()
    self.cardClassIconFrame:Hide()
    if self.cardPortraitTypeText then
      self.cardPortraitTypeText:SetText("|cFF00FF00Live|r")
    end
    -- Apply faction gradient background (red=Horde, blue=Alliance) with gold border.
    if self.cardModelBG then
      local faction = type(UnitFactionGroup) == "function" and UnitFactionGroup(unitToken) or nil
      if faction == "Horde" then
        self.cardModelBG:SetGradientAlpha("VERTICAL", 0.30, 0.02, 0.02, 1, 0.70, 0.08, 0.08, 1)
      elseif faction == "Alliance" then
        self.cardModelBG:SetGradientAlpha("VERTICAL", 0.02, 0.12, 0.35, 1, 0.08, 0.30, 0.75, 1)
      else
        self.cardModelBG:SetGradientAlpha("VERTICAL", 0.06, 0.06, 0.08, 1, 0.12, 0.12, 0.16, 1)
      end
      self.cardModelBG:Show()
    end
    if self.cardPortraitContainer then
      self.cardPortraitContainer:SetBackdropBorderColor(THEME.gold[1], THEME.gold[2], THEME.gold[3], 1)
    end
  else
    self.cardModel:Hide()
    self.cardClassIconFrame:Show()
    self.cardClassIcon:SetTexture(CLASS_ICONS[class] or "Interface\\Icons\\INV_Misc_QuestionMark")
    self.cardClassIcon:SetTexCoord(0, 1, 0, 1)
    self.cardClassIcon:SetVertexColor(1, 1, 1, 1)
    if self.cardPortraitTypeText then
      self.cardPortraitTypeText:SetText("|cFFFFAA00"..class.."|r")
    end
    if self.cardModelBG then self.cardModelBG:Hide() end
  end

  if self.cardSpecCycleBtn then
    if isSelf then
      self.cardSpecCycleBtn:SetText("Spec: " .. ((specSnapshot and specSnapshot.name) or class))
      self.cardSpecCycleBtn:ClearAllPoints()
      self.cardSpecCycleBtn:SetPoint("TOP", self.cardClassLevelRank, "BOTTOM", 0, -4)
      self.cardSpecCycleBtn:Show()
      self.cardSpecCycleBtn:Enable()
    else
      self.cardSpecCycleBtn:ClearAllPoints()
      self.cardSpecCycleBtn:SetPoint("TOP", self.cardTopSpecText or self.cardClassLevelRank, "BOTTOM", 0, -4)
      self.cardSpecCycleBtn:Hide()
      self.cardSpecCycleBtn:Disable()
    end
  end

  if self.cardTopSpecText then
    if isSelf then
      self.cardTopSpecText:Hide()
    else
      self.cardTopSpecText:SetText("|cFFFFD700Spec:|r " .. tostring(talentName))
      self.cardTopSpecText:Show()
    end
  end

  if self.cardPortraitContainer then
    self.cardPortraitContainer:ClearAllPoints()
    if isSelf and self.cardSpecCycleBtn and self.cardSpecCycleBtn:IsShown() then
      self.cardPortraitContainer:SetPoint("TOP", self.cardSpecCycleBtn, "BOTTOM", 0, -10)
    elseif self.cardTopSpecText and self.cardTopSpecText:IsShown() then
      self.cardPortraitContainer:SetPoint("TOP", self.cardTopSpecText, "BOTTOM", 0, -10)
    else
      self.cardPortraitContainer:SetPoint("TOP", self.cardClassLevelRank, "BOTTOM", 0, -10)
    end
  end

  if self.cardTalentBtn then
    self.cardTalentBtn:SetText("Talent Spec: " .. tostring(talentName))
    self.cardTalentBtn:Show()
    self.cardTalentBtn:Enable()
  end

  if self.cardWorkOrderBtn then
    self.cardWorkOrderBtn:Show()
    self.cardWorkOrderBtn:Enable()
  end
  if self.cardProfessionBtn then
    self.cardProfessionBtn:Show()
    self.cardProfessionBtn:Enable()
  end
  LayoutPlayerCardStatusBadges(self)

  if self.talentPopup and self.talentPopup:IsVisible() then
    self:RefreshTalentPopup(playerName, true)
  end
  if self.professionPopup and self.professionPopup:IsVisible() then
    self:RefreshProfessionPopup(playerName)
  end
  if self.workOrderPopup and self.workOrderPopup:IsVisible() then
    self:RefreshWorkOrderPopup(playerName)
  end

  -- UPDATE RECENT BADGES (LEFT SIDE) - REPLACES Today/Week/Season stats
  if self.UpdateCardRecentBadges then
    self:UpdateCardRecentBadges(playerName)
  end
  
 if self.cardNotesEdit then
    EnsureDB()
    if not LeafVE_GlobalDB.playerNotes then
      LeafVE_GlobalDB.playerNotes = {}
    end
    
    local note = LeafVE_GlobalDB.playerNotes[playerName] or ""
    self.cardNotesEdit:SetText(note)
    
    local me2 = ShortName(UnitName("player"))
    
    if me2 and playerName == me2 then
      -- Enable editing
      self.cardNotesEdit:EnableMouse(true)
      self.cardNotesEdit:EnableKeyboard(true)
      self.cardNotesEdit:SetTextColor(0.667, 0.667, 1.0, 1)  -- Bright blue (RGBA)
      self.cardNotesEdit:SetAlpha(1)
      
      -- Show save button
      if self.cardSaveNoteBtn then
        self.cardSaveNoteBtn:Show()
        self.cardSaveNoteBtn:Enable()
      end
    else
      -- Disable editing (Vanilla compatible)
      self.cardNotesEdit:EnableMouse(false)
      self.cardNotesEdit:EnableKeyboard(false)
      self.cardNotesEdit:SetTextColor(0.667, 0.667, 1.0, 1)  -- Bright blue for other players
      self.cardNotesEdit:SetAlpha(0.7)
      
      -- Hide save button for other players
      if self.cardSaveNoteBtn then
        self.cardSaveNoteBtn:Hide()
      end
      
      -- Clear focus to prevent editing
      self.cardNotesEdit:ClearFocus()
    end
  end

    -- Update achievement points display from the built-in client data or synced cache
  
  local achPoints = LeafVE:GetAchievementPointsForPlayer(playerName)
  
  if self.cardAchPoints then
    self.cardAchPoints:SetText(string.format("|cFFFFD700%d|r Points", achPoints))
  end
  
  -- Get recent achievements from the built-in client data or synced cache
  local recentAch = LeafVE:GetAchievementEntriesForPlayer(playerName, 5)
  if self.cardAchSummary then
    if table.getn(recentAch) > 0 then
      if (LeafVillageAchievements or LeafVE_AchTest) and (LeafVillageAchievements or LeafVE_AchTest).API then
        self.cardAchSummary:SetText("Latest LeafVillageAchievements progress")
      else
        self.cardAchSummary:SetText("Latest client and synced achievements")
      end
      self.cardAchSummary:SetTextColor(0.74, 0.79, 0.84)
    else
      if (LeafVillageAchievements or LeafVE_AchTest) and (LeafVillageAchievements or LeafVE_AchTest).API then
        self.cardAchSummary:SetText("LeafVillageAchievements will populate here")
      else
        self.cardAchSummary:SetText("Built-in client or guild sync will populate here")
      end
      self.cardAchSummary:SetTextColor(0.58, 0.61, 0.68)
    end
  end
  
  -- Clear previous recent achievements
  for i = 1, table.getn(self.cardRecentAchEntries) do
    self.cardRecentAchEntries[i]:Hide()
  end
  
  -- Display recent achievements (max 5)
  local maxRecent = math.min(5, table.getn(recentAch))
  local yOffset = 0
  if self.cardRecentAchEmptyText then
    self.cardRecentAchEmptyText:Hide()
  end
  
  for i = 1, maxRecent do
    local ach = recentAch[i]
    local displayName = ach.name or FormatAchievementName(AchievementKey(ach.id) or "")
    local displayIcon = ach.icon or GetAchievementIcon(ach.id)
    local entry = self.cardRecentAchEntries[i]
    
    if not entry then
      entry = CreateFrame("Frame", nil, self.cardRecentAchFrame)
      entry:SetWidth(196)
      entry:SetHeight(22)
      SkinPlayerCardSection(entry, THEME.soft[1], THEME.soft[2], THEME.soft[3], 0.8, 0.94)
      
      local icon = entry:CreateTexture(nil, "ARTWORK")
      icon:SetWidth(14)
      icon:SetHeight(14)
      icon:SetPoint("LEFT", entry, "LEFT", 6, 0)
      entry.icon = icon
      
      local nameText = entry:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
      nameText:SetPoint("LEFT", icon, "RIGHT", 6, 0)
      nameText:SetPoint("RIGHT", entry, "RIGHT", -44, 0)
      nameText:SetJustifyH("LEFT")
      entry.nameText = nameText
      
      local pointsText = entry:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
      pointsText:SetPoint("RIGHT", entry, "RIGHT", -8, 0)
      pointsText:SetWidth(34)
      pointsText:SetJustifyH("RIGHT")
      entry.pointsText = pointsText

      entry:SetScript("OnEnter", function()
        this:SetBackdropBorderColor(THEME.gold[1], THEME.gold[2], THEME.gold[3], 0.9)
      end)
      entry:SetScript("OnLeave", function()
        this:SetBackdropBorderColor(THEME.soft[1], THEME.soft[2], THEME.soft[3], 0.8)
      end)
      
      table.insert(self.cardRecentAchEntries, entry)
    end
    
    entry:SetPoint("TOPLEFT", self.cardRecentAchFrame, "TOPLEFT", 0, -yOffset)
    
    entry.icon:SetTexture(displayIcon)
    if not entry.icon:GetTexture() then
      entry.icon:SetTexture(LEAF_FALLBACK)
    end
    
    entry.nameText:SetText(displayName)
    entry:SetBackdropColor(0.06, 0.07, 0.1, 0.94)
    entry:SetBackdropBorderColor(THEME.soft[1], THEME.soft[2], THEME.soft[3], 0.8)
    
    entry.pointsText:SetText("|cFFFFD700"..ach.points.."|r")
    
    entry:Show()
    yOffset = yOffset + 22
  end

  if self.cardRecentAchFrame then
    local contentHeight = yOffset
    if maxRecent < 1 then
      contentHeight = 60
      if self.cardRecentAchEmptyText then
        self.cardRecentAchEmptyText:Show()
      end
    elseif contentHeight < 22 then
      contentHeight = 22
    end
    self.cardRecentAchFrame:SetHeight(contentHeight)
  end
  
 end

function LeafVE.UI:ShowAchievementPopup(achId, achData)
  if not achId or not achData then return end
  
  -- Create popup frame if it doesn't exist
  if not self.achPopup then
    local popup = CreateFrame("Frame", "LeafVE_AchievementPopup", UIParent)
    popup:SetWidth(300)
    popup:SetHeight(80)
    popup:SetPoint("TOP", UIParent, "TOP", 0, -150)
    popup:SetBackdrop({
      bgFile = "Interface\\DialogFrame\\UI-DialogBox-Background",
      edgeFile = "Interface\\DialogFrame\\UI-DialogBox-Border",
      tile = true, tileSize = 32, edgeSize = 32,
      insets = { left = 11, right = 12, top = 12, bottom = 11 }
    })
    popup:SetBackdropColor(0, 0, 0, 0.9)
    popup:Hide()
    
    -- Icon
    popup.icon = popup:CreateTexture(nil, "ARTWORK")
    popup.icon:SetWidth(36)
    popup.icon:SetHeight(36)
    popup.icon:SetPoint("LEFT", popup, "LEFT", 15, 0)
    
    -- Title text
    popup.title = popup:CreateFontString(nil, "OVERLAY", "GameFontNormalLarge")
    popup.title:SetPoint("TOPLEFT", popup.icon, "TOPRIGHT", 10, -5)
    popup.title:SetText("|cFFFFD700Achievement Earned!|r")
    
    -- Achievement name
    popup.achName = popup:CreateFontString(nil, "OVERLAY", "GameFontNormal")
    popup.achName:SetPoint("TOPLEFT", popup.title, "BOTTOMLEFT", 0, -5)
    popup.achName:SetJustifyH("LEFT")
    popup.achName:SetWidth(220)
    
    -- Points
    popup.points = popup:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    popup.points:SetPoint("BOTTOMLEFT", popup.icon, "BOTTOMRIGHT", 10, 5)
    
    if self.ApplyPopupScale then
      self:ApplyPopupScale(popup)
    end
    self.achPopup = popup
  end
  
  -- Format achievement name
  local displayName = achId
  local meta = LeafVE:GetAchievementMeta(achId)
  if meta and meta.name then
    displayName = meta.name
  else
    displayName = string.gsub(displayName, "_", " ")
    displayName = string.gsub(displayName, "(%a)([%w_']*)", function(first, rest)
      return string.upper(first)..string.lower(rest)
    end)
  end
  
  -- Set popup content
  self.achPopup.icon:SetTexture(GetAchievementIcon(achId))
  self.achPopup.achName:SetText(displayName)
  self.achPopup.points:SetText(achData.points.." Points")
  
  -- Show and auto-hide
  self.achPopup:Show()
  self.achPopup:SetScript("OnUpdate", function()
    if not this.showTime then
      this.showTime = GetTime()
    end
    
    if GetTime() - this.showTime > 5 then
      this:Hide()
      this.showTime = nil
      this:SetScript("OnUpdate", nil)
    end
  end)
  
  -- Play sound
  PlaySound("LevelUp")
end

