-- Hidden tooltip used for stat scanning
local leafScanTip
local leafItemStatCache = {}

local function GetOrCreateScanTip()
  if not leafScanTip then
    leafScanTip = CreateFrame("GameTooltip", "LeafVE_StatScanTip", UIParent, "GameTooltipTemplate")
    leafScanTip:SetOwner(UIParent, "ANCHOR_NONE")
  end
  return leafScanTip
end

local function ParseStatLine(line, stats)
  if not line or line == "" then return end
  -- Strip color codes
  line = string.gsub(line, "|c%x%x%x%x%x%x%x%x", "")
  line = string.gsub(line, "|r", "")

  local function ExtractNumber(pattern)
    local captured
    if string.match then
      captured = string.match(line, pattern)
    end
    if captured == nil then
      local _, _, fallbackCapture = string.find(line, pattern)
      captured = fallbackCapture
    end
    if captured == nil then
      return nil
    end
    return tonumber(captured)
  end

  local val
  -- Primary stats (+X StatName)
  val = ExtractNumber("%+(%d+) Strength")
  if val then stats.str = (stats.str or 0) + val end

  val = ExtractNumber("%+(%d+) Agility")
  if val then stats.agi = (stats.agi or 0) + val end

  val = ExtractNumber("%+(%d+) Stamina")
  if val then stats.sta = (stats.sta or 0) + val end

  val = ExtractNumber("%+(%d+) Intellect")
  if val then stats.int_ = (stats.int_ or 0) + val end

  val = ExtractNumber("%+(%d+) Spirit")
  if val then stats.spi = (stats.spi or 0) + val end

  val = ExtractNumber("%+(%d+) Attack Power")
  if val then stats.ap = (stats.ap or 0) + val end

  -- Hit chance (split melee and spell hit)
  if string.find(line, "chance to hit with spells") then
    val = ExtractNumber("by (%d+)%%")
    if val then stats.spellhit = (stats.spellhit or 0) + val end
  elseif string.find(line, "chance to hit") then
    val = ExtractNumber("by (%d+)%%")
    if val then stats.hit = (stats.hit or 0) + val end
  end

  -- Melee Crit (not spell crit)
  if string.find(line, "chance to get a critical strike") and not string.find(line, "with spells") then
    val = ExtractNumber("by (%d+)%%")
    if val then stats.crit = (stats.crit or 0) + val end
  end

  -- Spell Crit
  if string.find(line, "critical strike with spells") then
    val = ExtractNumber("by (%d+)%%")
    if val then stats.spellcrit = (stats.spellcrit or 0) + val end
  end

  -- Spell Damage + Healing combined
  if string.find(line, "Increases damage and healing done by magical spells") then
    val = ExtractNumber("up to (%d+)")
    if val then
      stats.spelldmg = (stats.spelldmg or 0) + val
      stats.healing = (stats.healing or 0) + val
    end
  -- Spell Damage only
  elseif string.find(line, "Increases damage done by magical spells") then
    val = ExtractNumber("up to (%d+)")
    if val then stats.spelldmg = (stats.spelldmg or 0) + val end
  -- Healing only
  elseif string.find(line, "Increases healing done by spells") then
    val = ExtractNumber("up to (%d+)")
    if val then stats.healing = (stats.healing or 0) + val end
  end

  -- Mana per 5
  val = ExtractNumber("Restores (%d+) mana per 5 sec")
  if val then stats.mp5 = (stats.mp5 or 0) + val end

  -- Defensive combat stats
  val = ExtractNumber("chance to dodge an attack by (%d+)%%")
  if val then stats.dodge = (stats.dodge or 0) + val end

  val = ExtractNumber("chance to parry an attack by (%d+)%%")
  if val then stats.parry = (stats.parry or 0) + val end

  val = ExtractNumber("chance to block attacks with a shield by (%d+)%%")
  if not val then
    val = ExtractNumber("chance to block by (%d+)%%")
  end
  if val then stats.block = (stats.block or 0) + val end

  val = ExtractNumber("Increases defense by (%d+)")
  if val then stats.defense = (stats.defense or 0) + val end

  -- Haste
  val = ExtractNumber("attack speed by (%d+)%%")
  if val then stats.haste = (stats.haste or 0) + val end

  val = ExtractNumber("spell casting speed by (%d+)%%")
  if val then stats.spellhaste = (stats.spellhaste or 0) + val end

  -- Penetration stats
  val = ExtractNumber("Ignores (%d+) of your target's armor")
  if not val then
    val = ExtractNumber("armor penetration by (%d+)")
  end
  if val then stats.armorpen = (stats.armorpen or 0) + val end

  val = ExtractNumber("magical resistances of your spell targets by (%d+)")
  if not val then
    val = ExtractNumber("spell penetration by (%d+)")
  end
  if val then stats.spellpen = (stats.spellpen or 0) + val end

  -- Weapon skill
  val = ExtractNumber("Increased .+ skill by (%d+)")
  if not val then
    val = ExtractNumber("Increased .+ %+(%d+)")
  end
  if val then stats.wepskill = (stats.wepskill or 0) + val end
end

local function CopyStatTable(source)
  local copy = {}
  if type(source) ~= "table" then
    return copy
  end
  for key, value in pairs(source) do
    copy[key] = value
  end
  return copy
end

local function AddStatTable(target, source)
  if type(source) ~= "table" then
    return
  end
  for key, value in pairs(source) do
    local numericValue = tonumber(value) or 0
    if numericValue ~= 0 then
      target[key] = (target[key] or 0) + numericValue
    end
  end
end

local function GetCachedItemStats(itemId)
  itemId = tonumber(itemId)
  if not itemId or itemId <= 0 then
    return {}
  end

  local cached = leafItemStatCache[itemId]
  if cached then
    return cached
  end

  local stats = {}
  local tip = GetOrCreateScanTip()
  tip:ClearLines()
  tip:SetHyperlink("item:" .. tostring(itemId) .. ":0:0:0")

  local numLines = tip:NumLines()
  if numLines and numLines > 0 then
    for i = 1, numLines do
      local leftObj = getglobal("LeafVE_StatScanTipTextLeft" .. i)
      if leftObj then
        ParseStatLine(leftObj:GetText() or "", stats)
      end
    end
  end

  tip:Hide()
  leafItemStatCache[itemId] = CopyStatTable(stats)
  return leafItemStatCache[itemId]
end

ComputeGearStats = function(slots)
  local stats = {}
  for _, itemId in pairs(slots or {}) do
    AddStatTable(stats, GetCachedItemStats(itemId))
  end
  return stats
end

local function AddStatLine(lines, label, val, color, suffix, decimals, force)
  local num = tonumber(val)
  if not force and (not num or num <= 0) then return end
  if not num then num = 0 end
  local valStr
  if decimals and decimals > 0 then
    valStr = string.format("%." .. tostring(decimals) .. "f", num)
  else
    valStr = tostring(math.floor(num + 0.5))
  end
  if suffix then valStr = valStr .. suffix end
  local labelColor = color or "FFFFFF"
  table.insert(lines, "|cFF" .. labelColor .. label .. "|r: |cFFFFFFFF" .. valStr .. "|r")
  table.insert(lines, " ")
end

local function AddStatSection(lines, title)
  while table.getn(lines) > 0 and lines[table.getn(lines)] == " " do
    table.remove(lines, table.getn(lines))
  end
  if table.getn(lines) > 0 then
    table.insert(lines, " ")
  end
  table.insert(lines, "|cFFFFD700== " .. title .. " ==|r")
end

local function IsSpecLike(specName, token)
  if not specName or not token then return false end
  return string.find(string.lower(specName), string.lower(token), 1, true) ~= nil
end

local function GetStatProfileForClassSpec(classTag, specName)
  local classUpper = string.upper(classTag or "")
  if classUpper == "WARRIOR" then
    if IsSpecLike(specName, "Protection") then return "tank" end
    return "melee"
  elseif classUpper == "PALADIN" then
    if IsSpecLike(specName, "Holy") then return "healer" end
    if IsSpecLike(specName, "Protection") then return "tank" end
    return "melee"
  elseif classUpper == "HUNTER" then
    return "ranged"
  elseif classUpper == "ROGUE" then
    return "melee"
  elseif classUpper == "PRIEST" then
    if IsSpecLike(specName, "Holy") or IsSpecLike(specName, "Discipline") then return "healer" end
    return "caster"
  elseif classUpper == "SHAMAN" then
    if IsSpecLike(specName, "Restoration") then return "healer" end
    if IsSpecLike(specName, "Enhancement") then return "melee" end
    return "caster"
  elseif classUpper == "MAGE" then
    return "caster"
  elseif classUpper == "WARLOCK" then
    return "caster"
  elseif classUpper == "DRUID" then
    if IsSpecLike(specName, "Restoration") then return "healer" end
    if IsSpecLike(specName, "Balance") then return "caster" end
    if IsSpecLike(specName, "Feral") then return "tank" end
    return "hybrid"
  end
  return "hybrid"
end

