local function AddProfileSection(lines, stats, sectionDef, forceAll)
  AddStatSection(lines, sectionDef.title)
  for i = 1, table.getn(sectionDef.rows) do
    local row = sectionDef.rows[i]
    AddStatLine(lines, row[1], stats[row[2]], row[3], row[4], row[5], forceAll)
  end
end

local function FormatGearStats(stats, class, specName)
  stats = stats or {}
  local lines = {}
  local hasRealStats = false
  for _, key in ipairs(GEAR_STAT_KEYS) do
    if (tonumber(stats[key]) or 0) > 0 then
      hasRealStats = true
      break
    end
  end
  if not hasRealStats then
    return "|cFF888888No stats cached|r"
  end

  local forceAll = true
  local profileKey = GetStatProfileForClassSpec(class, specName)
  local sections = STAT_PROFILE_SECTIONS[profileKey] or STAT_PROFILE_SECTIONS.hybrid
  for i = 1, table.getn(sections) do
    AddProfileSection(lines, stats, sections[i], forceAll)
  end
  while table.getn(lines) > 0 and lines[table.getn(lines)] == " " do
    table.remove(lines, table.getn(lines))
  end
  return table.concat(lines, "\n")
end

local function BuildDefenseSection(profileSections)
  local source = nil
  for i = 1, table.getn(profileSections) do
    local sec = profileSections[i]
    if sec and (sec.title == "Defense" or sec.title == "Avoidance") then
      source = sec
      break
    end
  end

  local rows = {
    {"Defense", "defense", "CCCCAA"},
  }

  if source and source.rows then
    for i = 1, table.getn(source.rows) do
      local row = source.rows[i]
      if row and row[2] and row[2] ~= "defense" then
        table.insert(rows, row)
      end
    end
  else
    table.insert(rows, {"Dodge", "dodge", "88FF88", "%", 2})
    table.insert(rows, {"Parry", "parry", "88FF88", "%", 2})
    table.insert(rows, {"Block", "block", "88FF88", "%", 2})
  end

  return {title = "Defense", rows = rows}
end

local function BuildPowerSection(profileSections)
  for i = 1, table.getn(profileSections) do
    local sec = profileSections[i]
    if sec and sec.title == "Power" then
      return sec
    end
  end
  return {
    title = "Power",
    rows = {
      {"Armor Pen", "armorpen", "FFAA44"},
      {"Spell Pen", "spellpen", "AA88FF"},
    }
  }
end

local function BuildPrimaryOffenseSections(profileSections)
  local primary = nil
  local offense = nil
  for i = 1, table.getn(profileSections) do
    local sec = profileSections[i]
    if sec then
      if sec.title == "Primary" then
        primary = sec
      elseif sec.title == "Offense" then
        offense = sec
      end
    end
  end
  return primary, offense
end

local function FormatGearStatsColumns(stats, class, specName)
  stats = stats or {}
  local hasRealStats = false
  for _, key in ipairs(GEAR_STAT_KEYS) do
    if (tonumber(stats[key]) or 0) > 0 then
      hasRealStats = true
      break
    end
  end
  if not hasRealStats then
    return "|cFF888888No stats cached|r", ""
  end

  local profileKey = GetStatProfileForClassSpec(class, specName)
  local profileSections = STAT_PROFILE_SECTIONS[profileKey] or STAT_PROFILE_SECTIONS.hybrid
  local primarySection, offenseSection = BuildPrimaryOffenseSections(profileSections)
  local powerSection = BuildPowerSection(profileSections)
  local defenseSection = BuildDefenseSection(profileSections)
  local forceAll = true

  local leftLines = {}
  local rightLines = {}

  if primarySection then
    AddProfileSection(leftLines, stats, primarySection, forceAll)
  end
  AddProfileSection(leftLines, stats, powerSection, forceAll)

  if offenseSection then
    AddProfileSection(rightLines, stats, offenseSection, forceAll)
  end
  AddProfileSection(rightLines, stats, defenseSection, forceAll)

  while table.getn(leftLines) > 0 and leftLines[table.getn(leftLines)] == " " do
    table.remove(leftLines, table.getn(leftLines))
  end
  while table.getn(rightLines) > 0 and rightLines[table.getn(rightLines)] == " " do
    table.remove(rightLines, table.getn(rightLines))
  end

  return table.concat(leftLines, "\n"), table.concat(rightLines, "\n")
end

local function HasAnyStatValue(stats)
  if not stats then return false end
  for _, key in ipairs(GEAR_STAT_KEYS) do
    if (tonumber(stats[key]) or 0) > 0 then
      return true
    end
  end
  return false
end

local function BuildGearDisplaySnapshot(playerName)
  EnsureDB()
  local nameLower = Lower(playerName)
  local cache = LeafVE_GlobalDB.gearCache and LeafVE_GlobalDB.gearCache[nameLower]
  if not cache then return nil, nil end

  local preferred = nil
  local sourceLabel = nil
  local inspectedTS = cache.inspected and cache.inspected.updatedAt or 0
  local broadcastTS = cache.broadcast and cache.broadcast.updatedAt or 0
  if cache.inspected and cache.inspected.slots and inspectedTS >= broadcastTS then
    preferred = cache.inspected
    sourceLabel = "Source: |cFF88FF88Inspected|r"
  elseif cache.broadcast and cache.broadcast.slots then
    preferred = cache.broadcast
    sourceLabel = "Source: |cFFAAAA88Broadcast|r"
  end
  if not preferred then return nil, nil end

  local merged = {
    updatedAt = preferred.updatedAt or Now(),
    slots = preferred.slots or {},
    icons = {},
    enchants = {},
    stats = {},
    spec = preferred.spec,
  }

  local fallback = cache.broadcast or {}
  for i = 1, table.getn(GEAR_SLOT_NAMES) do
    local slotName = GEAR_SLOT_NAMES[i]
    local itemId = merged.slots[slotName]
    if itemId then
      local iconPath = (preferred.icons and preferred.icons[slotName]) or (fallback.icons and fallback.icons[slotName])
      iconPath = NormalizeIconPath(iconPath)
      if iconPath and string.find(string.lower(iconPath), "inv_misc_questionmark", 1, true) then
        iconPath = nil
      end
      if not iconPath then
        iconPath = LeafVE:ResolveIconForItemID(itemId)
      end
      merged.icons[slotName] = NormalizeIconPath(iconPath) or "Interface\\Icons\\INV_Misc_QuestionMark"
      local enchId = (preferred.enchants and preferred.enchants[slotName]) or (fallback.enchants and fallback.enchants[slotName])
      if tonumber(enchId) and tonumber(enchId) > 0 then
        merged.enchants[slotName] = tonumber(enchId)
      end
    end
  end

  if HasAnyStatValue(preferred.stats) then
    merged.stats = preferred.stats
  elseif HasAnyStatValue(fallback.stats) then
    merged.stats = fallback.stats
  end

  if not merged.spec then
    merged.spec = fallback.spec
  end
  if not merged.spec then
    merged.spec = LeafVE:GetSpecSnapshotForPlayer(playerName, nil)
  end
  return merged, sourceLabel
end

local function CreateGearSlotEntry(parent, opts)
  opts = opts or {}
  local iconSize = tonumber(opts.iconSize) or 34
  local rowHeight = tonumber(opts.rowHeight) or (iconSize + 10)
  local rightInset = tonumber(opts.rightInset) or 4

  local row = CreateFrame("Frame", nil, parent)
  row.layoutHeight = rowHeight
  row:SetHeight(rowHeight)
  row:SetBackdrop({
    bgFile = "Interface\\Tooltips\\UI-Tooltip-Background",
    edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
    tile = true, tileSize = 12, edgeSize = 10,
    insets = {left = 2, right = 2, top = 2, bottom = 2},
  })
  row:SetBackdropColor(0.03, 0.03, 0.06, 0.85)
  row:SetBackdropBorderColor(0.1, 0.5, 0.9, 0.45)
  row:EnableMouse(true)

  local icon = row:CreateTexture(nil, "ARTWORK")
  icon:SetWidth(iconSize)
  icon:SetHeight(iconSize)
  icon:SetPoint("LEFT", row, "LEFT", 4, 0)
  row.icon = icon

  local slotText = row:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
  slotText:SetPoint("TOPLEFT", icon, "TOPRIGHT", 4, -2)
  slotText:SetPoint("RIGHT", row, "RIGHT", -rightInset, 0)
  slotText:SetJustifyH("LEFT")
  if opts.smallText and slotText.SetFont then
    slotText:SetFont(STANDARD_TEXT_FONT, 10, "")
  end
  row.slotText = slotText

  local itemText = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  itemText:SetPoint("TOPLEFT", slotText, "BOTTOMLEFT", 0, -2)
  itemText:SetPoint("RIGHT", row, "RIGHT", -rightInset, 0)
  itemText:SetJustifyH("LEFT")
  if opts.smallText and itemText.SetFont then
    itemText:SetFont(STANDARD_TEXT_FONT, 10, "")
  end
  row.itemText = itemText

  row:SetScript("OnEnter", function()
    if this.itemId then
      GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
      local ench = tonumber(this.enchantId) or 0
      GameTooltip:SetHyperlink("item:" .. tostring(this.itemId) .. ":" .. tostring(ench) .. ":0:0:0")
      GameTooltip:Show()
    end
  end)
  row:SetScript("OnLeave", function() GameTooltip:Hide() end)
  return row
end

local function LayoutGearColumn(columnFrame, entries, spacing)
  spacing = tonumber(spacing) or 5
  local count = table.getn(entries)
  if count <= 0 then
    columnFrame:SetHeight(1)
    return 0
  end
  local yOffset = 0
  for i = 1, count do
    local entry = entries[i]
    local entryH = entry.layoutHeight or entry:GetHeight() or 40
    entry:ClearAllPoints()
    entry:SetPoint("TOPLEFT", columnFrame, "TOPLEFT", 0, -yOffset)
    entry:SetPoint("TOPRIGHT", columnFrame, "TOPRIGHT", 0, -yOffset)
    entry:SetHeight(entryH)
    yOffset = yOffset + entryH
    if i < count then
      yOffset = yOffset + spacing
    end
  end
  columnFrame:SetHeight(yOffset)
  return yOffset
end

local function CountLines(text)
  if not text or text == "" then return 1 end
  local lineCount = 1
  local startPos = 1
  while true do
    local nl = string.find(text, "\n", startPos, true)
    if not nl then break end
    lineCount = lineCount + 1
    startPos = nl + 1
  end
  return lineCount
end

local function SplitLines(text)
  local lines = {}
  if not text or text == "" then return lines end
  local startPos = 1
  while true do
    local nl = string.find(text, "\n", startPos, true)
    if nl then
      table.insert(lines, string.sub(text, startPos, nl - 1))
      startPos = nl + 1
    else
      table.insert(lines, string.sub(text, startPos))
      break
    end
  end
  return lines
end

local function TrimBlankEdgeLines(lines)
  local first = 1
  local last = table.getn(lines)
  while first <= last and (not lines[first] or lines[first] == "" or lines[first] == " ") do
    first = first + 1
  end
  while last >= first and (not lines[last] or lines[last] == "" or lines[last] == " ") do
    last = last - 1
  end
  local out = {}
  for i = first, last do
    table.insert(out, lines[i])
  end
  return out
end

local function SplitStatsForColumns(formattedStats)
  if not formattedStats or formattedStats == "" then
    return "|cFF888888No stats cached|r", ""
  end
  if string.find(formattedStats, "No stats cached", 1, true) then
    return formattedStats, ""
  end

  local allLines = SplitLines(formattedStats)
  if table.getn(allLines) <= 2 then
    return formattedStats, ""
  end

  local sections = {}
  local current = {}
  for i = 1, table.getn(allLines) do
    local line = allLines[i]
    if string.find(line, "|cFFFFD700== ", 1, true) == 1 and table.getn(current) > 0 then
      table.insert(sections, TrimBlankEdgeLines(current))
      current = {}
    end
    table.insert(current, line)
  end
  if table.getn(current) > 0 then
    table.insert(sections, TrimBlankEdgeLines(current))
  end
  if table.getn(sections) <= 1 then
    return formattedStats, ""
  end

  local left = {}
  local right = {}
  local leftCount = 0
  local rightCount = 0

  local function AppendSection(target, section)
    if table.getn(target) > 0 then
      table.insert(target, " ")
    end
    for idx = 1, table.getn(section) do
      table.insert(target, section[idx])
    end
  end

  for i = 1, table.getn(sections) do
    local section = sections[i]
    local sectionCount = table.getn(section)
    if leftCount <= rightCount then
      AppendSection(left, section)
      leftCount = leftCount + sectionCount
    else
      AppendSection(right, section)
      rightCount = rightCount + sectionCount
    end
  end

  return table.concat(left, "\n"), table.concat(right, "\n")
end

local function LayoutGearPopupContent(popup)
  if not popup or not popup.scrollFrame or not popup.scrollChild then return end

  local viewportHeight = popup.scrollFrame:GetHeight()
  if not viewportHeight or viewportHeight < 1 then
    viewportHeight = popup:GetHeight() - 92
  end

  local contentWidth = popup:GetWidth() - 66
  if contentWidth < 320 then
    contentWidth = 320
  end
  popup.scrollChild:SetWidth(contentWidth)

  local pairGap = 8
  local columnWidth = math.floor((contentWidth - pairGap) / 2)
  if columnWidth < 150 then
    columnWidth = 150
  end

  local topSectionHeight = 0
  if popup.specPanel then
    local specTextHeight = 12
    specTextHeight = LeafVEGetTextHeight(popup.specText, 12)
    topSectionHeight = 56 + 4 + specTextHeight + 6
    popup.specPanel:ClearAllPoints()
    popup.specPanel:SetPoint("TOPLEFT", popup.scrollChild, "TOPLEFT", 0, 0)
    popup.specPanel:SetWidth(contentWidth)
    popup.specPanel:SetHeight(topSectionHeight)
  end
  local gearTop = topSectionHeight
  if gearTop > 0 then
    gearTop = gearTop + 6
  end

  popup.leftColumn:ClearAllPoints()
  popup.leftColumn:SetPoint("TOPLEFT", popup.scrollChild, "TOPLEFT", 0, -gearTop)
  popup.leftColumn:SetWidth(columnWidth)

  popup.rightColumn:ClearAllPoints()
  popup.rightColumn:SetPoint("TOPLEFT", popup.leftColumn, "TOPRIGHT", pairGap, 0)
  popup.rightColumn:SetWidth(columnWidth)

  local leftHeight = LayoutGearColumn(popup.leftColumn, popup.leftEntries, 5)
  local rightHeight = LayoutGearColumn(popup.rightColumn, popup.rightEntries, 5)
  local pairedHeight = leftHeight
  if rightHeight > pairedHeight then
    pairedHeight = rightHeight
  end

  popup.weaponRow:ClearAllPoints()
  popup.weaponRow:SetPoint("TOPLEFT", popup.scrollChild, "TOPLEFT", 0, -((gearTop + pairedHeight) + 8))
  popup.weaponRow:SetWidth(contentWidth)

  local weaponCount = table.getn(popup.weaponEntries or {})
  local weaponGap = 6
  local weaponWidth = 0
  if weaponCount > 0 then
    weaponWidth = math.floor((contentWidth - (weaponGap * (weaponCount - 1))) / weaponCount)
  end
  if weaponWidth < 94 then
    weaponWidth = 94
  end

  local xOffset = 0
  local weaponHeight = 0
  for i = 1, weaponCount do
    local entry = popup.weaponEntries[i]
    local entryH = entry.layoutHeight or entry:GetHeight() or 34
    if entryH > weaponHeight then
      weaponHeight = entryH
    end
    entry:ClearAllPoints()
    entry:SetPoint("TOPLEFT", popup.weaponRow, "TOPLEFT", xOffset, 0)
    entry:SetWidth(weaponWidth)
    entry:SetHeight(entryH)
    xOffset = xOffset + weaponWidth + weaponGap
  end
  popup.weaponRow:SetHeight(weaponHeight)

  popup.summaryPanel:SetWidth(contentWidth)

  local statsLeftHeight = 0
  local statsRightHeight = 0
  statsLeftHeight = LeafVEGetTextHeight(popup.statsLeftText, 0)
  statsRightHeight = LeafVEGetTextHeight(popup.statsRightText, 0)
  local statsHeight = statsLeftHeight
  if statsRightHeight > statsHeight then
    statsHeight = statsRightHeight
  end
  if statsHeight < 1 then
    local leftLines = CountLines((popup.statsLeftText and popup.statsLeftText:GetText()) or "")
    local rightLines = CountLines((popup.statsRightText and popup.statsRightText:GetText()) or "")
    statsHeight = leftLines * 13
    if (rightLines * 13) > statsHeight then
      statsHeight = rightLines * 13
    end
  end
  if statsHeight < 72 then
    statsHeight = 72
  end
  if popup.statsLeftText then
    popup.statsLeftText:SetHeight(statsHeight)
  end
  if popup.statsRightText then
    popup.statsRightText:SetHeight(statsHeight)
  end

  local summaryHeight = 30 + statsHeight
  popup.summaryPanel:SetHeight(summaryHeight)

  local baseSummaryTop = gearTop + pairedHeight + 8 + weaponHeight + 12
  local naturalHeight = baseSummaryTop + summaryHeight + 6
  local filler = 0
  if viewportHeight > naturalHeight then
    filler = viewportHeight - naturalHeight
  end

  popup.summaryPanel:ClearAllPoints()
  popup.summaryPanel:SetPoint("TOPLEFT", popup.scrollChild, "TOPLEFT", 0, -(baseSummaryTop + filler))

  popup.scrollChild:SetHeight(naturalHeight + filler)
end

local function ApplySlotEntryData(entry, slotName, itemId, iconTex, enchantId, unitToken)
  entry.slotText:SetText("|cFFBFBFBF" .. (GEAR_SLOT_LABELS[slotName] or slotName) .. "|r")
  entry.itemId = itemId
  entry.enchantId = enchantId

  if itemId then
    local itemName, _, itemRarity, _, _, _, _, _, _, itemTexture = GetItemInfo(itemId)
    local texture = NormalizeIconPath(iconTex) or NormalizeIconPath(itemTexture) or "Interface\\Icons\\INV_Misc_QuestionMark"
    entry.icon:SetTexture(texture)
    entry.icon:SetVertexColor(1, 1, 1, 1)

    local displayText = itemName or ("#" .. tostring(itemId))
    if itemName and itemRarity and GetItemQualityColor then
      local r, g, b = GetItemQualityColor(itemRarity)
      if r then
        displayText = string.format("|cFF%02X%02X%02X%s|r", math.floor(r * 255), math.floor(g * 255), math.floor(b * 255), itemName)
      end
    else
      displayText = "|cFF888888" .. displayText .. "|r"
    end
    if enchantId and enchantId > 0 then
      displayText = displayText .. " |cFF66FF66[E]|r"
    end
    entry.itemText:SetText(displayText)
    entry:SetBackdropBorderColor(0.1, 0.5, 0.9, 0.55)
  else
    entry.itemId = nil
    entry.enchantId = nil
    entry.icon:SetTexture(EMPTY_SLOT_TEXTURES[slotName] or "Interface\\Icons\\INV_Misc_QuestionMark")
    entry.icon:SetVertexColor(0.45, 0.45, 0.45, 1)
    entry.itemText:SetText("|cFF444444--empty--|r")
    entry:SetBackdropBorderColor(0.2, 0.2, 0.2, 0.45)
  end
end

