  scrollChild:SetHeight(1)
  scrollFrame:SetScrollChild(scrollChild)
  popup.scrollChild = scrollChild

  local leftColumn = CreateFrame("Frame", nil, scrollChild)
  popup.leftColumn = leftColumn

  local rightColumn = CreateFrame("Frame", nil, scrollChild)
  popup.rightColumn = rightColumn

  local weaponRow = CreateFrame("Frame", nil, scrollChild)
  popup.weaponRow = weaponRow

  local specPanel = CreateFrame("Frame", nil, scrollChild)
  popup.specPanel = specPanel

  local specIcon = specPanel:CreateTexture(nil, "ARTWORK")
  specIcon:SetWidth(56)
  specIcon:SetHeight(56)
  specIcon:SetPoint("TOP", specPanel, "TOP", 0, 0)
  popup.specIcon = specIcon

  local specText = specPanel:CreateFontString(nil, "OVERLAY", "GameFontNormal")
  specText:SetPoint("TOP", specIcon, "BOTTOM", 0, -4)
  specText:SetTextColor(0.95, 0.95, 0.95)
  popup.specText = specText

  local summaryPanel = CreateFrame("Frame", nil, scrollChild)
  popup.summaryPanel = summaryPanel

  local statsTitle = summaryPanel:CreateFontString(nil, "OVERLAY", "GameFontNormal")
  statsTitle:SetPoint("TOP", summaryPanel, "TOP", 0, -4)
  statsTitle:SetText("|cFFFFD700Cached Stats|r")
  popup.statsTitle = statsTitle

  local statsLeftText = summaryPanel:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  statsLeftText:SetPoint("TOPLEFT", summaryPanel, "TOPLEFT", 10, -32)
  statsLeftText:SetPoint("LEFT", summaryPanel, "LEFT", 10, 0)
  statsLeftText:SetPoint("RIGHT", summaryPanel, "CENTER", -6, 0)
  statsLeftText:SetJustifyH("CENTER")
  statsLeftText:SetJustifyV("TOP")
  if statsLeftText.SetFont then
    statsLeftText:SetFont(STANDARD_TEXT_FONT, 12, "")
  end
  popup.statsLeftText = statsLeftText

  local statsRightText = summaryPanel:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  statsRightText:SetPoint("TOPLEFT", summaryPanel, "TOP", 6, -32)
  statsRightText:SetPoint("LEFT", summaryPanel, "CENTER", 6, 0)
  statsRightText:SetPoint("RIGHT", summaryPanel, "RIGHT", -10, 0)
  statsRightText:SetJustifyH("CENTER")
  statsRightText:SetJustifyV("TOP")
  if statsRightText.SetFont then
    statsRightText:SetFont(STANDARD_TEXT_FONT, 12, "")
  end
  popup.statsRightText = statsRightText

  local statsDivider = summaryPanel:CreateTexture(nil, "BORDER")
  statsDivider:SetTexture(1, 1, 1, 0.12)
  statsDivider:SetPoint("TOP", summaryPanel, "TOP", 0, -30)
  statsDivider:SetPoint("BOTTOM", summaryPanel, "BOTTOM", 0, 4)
  statsDivider:SetWidth(1)
  popup.statsDivider = statsDivider

  popup.statsText = statsLeftText

  popup.leftEntries = {}
  for i = 1, table.getn(GEAR_LEFT_COLUMN_SLOTS) do
    popup.leftEntries[i] = CreateGearSlotEntry(leftColumn, {iconSize = 28, rowHeight = 40})
  end

  popup.rightEntries = {}
  for i = 1, table.getn(GEAR_RIGHT_COLUMN_SLOTS) do
    popup.rightEntries[i] = CreateGearSlotEntry(rightColumn, {iconSize = 28, rowHeight = 40})
  end

  popup.weaponEntries = {}
  for i = 1, table.getn(GEAR_WEAPON_ROW_SLOTS) do
    popup.weaponEntries[i] = CreateGearSlotEntry(weaponRow, {iconSize = 20, rowHeight = 34, rightInset = 3, smallText = true})
  end

  LayoutGearPopupContent(popup)
  if self.ApplyPopupScale then
    self:ApplyPopupScale(popup)
  end
  self.gearPopup = popup
end

function LeafVE.UI:RefreshGearPopup(playerName, skipDeferredLayout)
  if not self.gearPopup then return end
  playerName = ShortName(playerName)
  if not playerName then return end

  self.gearPopup.titleText:SetText(playerName .. "'s Gear")
  local me = ShortName(UnitName("player"))
  if not (me and Lower(me) == Lower(playerName)) then
    LeafVE:RequestGearData(playerName)
  end

  local unitToken = FindUnitToken(playerName)
  if unitToken and CheckInteractDistance(unitToken, 1) then
    LeafVE:CaptureAndCacheInspectedGear(playerName, unitToken)
  end

  local snapshot, sourceLabel = BuildGearDisplaySnapshot(playerName)
  if snapshot and not HasAnyStatValue(snapshot.stats) and not (me and Lower(me) == Lower(playerName)) then
    LeafVE.lastStatsRetryAt = LeafVE.lastStatsRetryAt or {}
    local retryKey = Lower(playerName)
    local now = Now()
    if not LeafVE.lastStatsRetryAt[retryKey] or (now - LeafVE.lastStatsRetryAt[retryKey]) >= 5 then
      LeafVE.lastStatsRetryAt[retryKey] = now
      LeafVE:RequestGearData(playerName, true)
    end
  end
  if snapshot then
    local timeAgo = Now() - (snapshot.updatedAt or 0)
    if timeAgo < 0 then timeAgo = 0 end
    local timeStr
    if timeAgo < 60 then
      timeStr = timeAgo .. "s ago"
    elseif timeAgo < 3600 then
      timeStr = math.floor(timeAgo / 60) .. "m ago"
    else
      timeStr = math.floor(timeAgo / 3600) .. "h ago"
    end
    self.gearPopup.sourceText:SetText((sourceLabel or "Source: |cFF888888Unknown|r") .. "  |cFF888888" .. timeStr .. "|r")
  else
    self.gearPopup.sourceText:SetText("|cFF888888No gear data cached|r")
  end

  local equipped = 0
  local slots = snapshot and snapshot.slots or {}
  for i = 1, table.getn(GEAR_SLOT_NAMES) do
    if slots[GEAR_SLOT_NAMES[i]] then equipped = equipped + 1 end
  end
  self.gearPopup.equippedText:SetText("Equipped: " .. equipped .. "/" .. tostring(table.getn(GEAR_SLOT_NAMES)))

  local function PopulateSlotEntry(entry, slotName)
    local itemId = slots and slots[slotName]
    local iconTex = snapshot and snapshot.icons and snapshot.icons[slotName]
    local enchantId = snapshot and snapshot.enchants and snapshot.enchants[slotName]
    if not iconTex and itemId then
      local slotId = GetInventorySlotInfo(slotName)
      if unitToken and slotId then
        iconTex = GetInventoryItemTexture(unitToken, slotId)
      end
    end
    if (not enchantId) and unitToken and itemId then
      local slotId = GetInventorySlotInfo(slotName)
      if slotId then
        local link = GetInventoryItemLink(unitToken, slotId)
        enchantId = LeafVE:ParseEnchantIDFromLink(link)
      end
    end
    ApplySlotEntryData(entry, slotName, itemId, iconTex, enchantId, unitToken)
    entry:Show()
  end

  for i = 1, table.getn(GEAR_LEFT_COLUMN_SLOTS) do
    PopulateSlotEntry(self.gearPopup.leftEntries[i], GEAR_LEFT_COLUMN_SLOTS[i])
  end

  for i = 1, table.getn(GEAR_RIGHT_COLUMN_SLOTS) do
    PopulateSlotEntry(self.gearPopup.rightEntries[i], GEAR_RIGHT_COLUMN_SLOTS[i])
  end

  for i = 1, table.getn(GEAR_WEAPON_ROW_SLOTS) do
    PopulateSlotEntry(self.gearPopup.weaponEntries[i], GEAR_WEAPON_ROW_SLOTS[i])
  end

  local classTag = LeafVE:GetClassTagForPlayer(playerName)
  local spec = snapshot and snapshot.spec or LeafVE:GetSpecSnapshotForPlayer(playerName, classTag)
  if not spec then
    spec = LeafVE:GetSpecSnapshotForPlayer(playerName, classTag)
  end
  self.gearPopup.specIcon:SetTexture((spec and spec.icon) or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark")
  self.gearPopup.specIcon:SetVertexColor(1, 1, 1, 1)
  self.gearPopup.specText:SetText((spec and spec.name and string.upper(spec.name)) or classTag)

  local stats = snapshot and snapshot.stats
  if not HasAnyStatValue(stats) and slots and next(slots) then
    stats = ComputeGearStats(slots)
  end
  local statsLeft, statsRight = FormatGearStatsColumns(stats or {}, classTag, spec and spec.name)
  self.gearPopup.statsLeftText:SetText(statsLeft or "")
  self.gearPopup.statsRightText:SetText(statsRight or "")
  LayoutGearPopupContent(self.gearPopup)

  -- Re-run one frame later so layout uses final shown dimensions.
  if not skipDeferredLayout and self.gearPopup:IsVisible() then
    if not self.gearPopup.relayoutPending then
      self.gearPopup.relayoutPending = true
      LeafVE:ScheduleDeferred("gear_popup_relayout", 0, function()
        self.gearPopup.relayoutPending = nil
        if LeafVE and LeafVE.UI and LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() and LeafVE.UI.cardCurrentPlayer then
          LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer, true)
        end
      end)
    end
  end
end

function LeafVE.UI:GetNativeTalentFrame()
  return PlayerTalentFrame or TalentFrame
end

function LeafVE.UI:IsNativeTalentFrameVisible()
  local talentFrame = self:GetNativeTalentFrame()
  return talentFrame and talentFrame:IsVisible() or false
end

function LeafVE.UI:HideNativeTalentFrame()
  local talentFrame = self:GetNativeTalentFrame()
  if not talentFrame or not talentFrame:IsVisible() then return end
  if HideUIPanel then
    HideUIPanel(talentFrame)
  else
    talentFrame:Hide()
  end
end

function LeafVE.UI:ShowNativeTalentFrame()
  if ToggleTalentFrame then
    ToggleTalentFrame()
  end

  local talentFrame = self:GetNativeTalentFrame()
  if not talentFrame then return false end

  if not talentFrame:IsVisible() then
    if ShowUIPanel then
      ShowUIPanel(talentFrame)
    else
      talentFrame:Show()
    end
  end
  if not talentFrame:IsVisible() then
    return false
  end

  if self.frame then
    talentFrame:ClearAllPoints()
    talentFrame:SetPoint("TOPLEFT", self.frame, "TOPRIGHT", 5, 0)
  end
  if talentFrame.SetFrameStrata then
    talentFrame:SetFrameStrata("DIALOG")
  end
  return true
end

