    btn:SetWidth(122)
    btn:SetHeight(22)
    if i == 1 then
      btn:SetPoint("BOTTOMLEFT", popup, "BOTTOMLEFT", 18, 20)
    else
      btn:SetPoint("LEFT", popup.tabButtons[i - 1], "RIGHT", 9, 0)
    end
    SkinButtonAccent(btn)
    btn:SetScript("OnClick", function()
      if not this.tabIndex then return end
      popup.selectedTab = this.tabIndex
      if LeafVE and LeafVE.UI and LeafVE.UI.cardCurrentPlayer then
        LeafVE.UI:RefreshTalentPopup(LeafVE.UI.cardCurrentPlayer, true)
      end
    end)
    popup.tabButtons[i] = btn
  end

  popup.talentButtons = {}

  if self.ApplyPopupScale then
    self:ApplyPopupScale(popup)
  end
  self.talentPopup = popup
end

function LeafVE.UI:RefreshTalentPopup(playerName, keepSelectedTab)
  if not self.talentPopup then return end
  playerName = ShortName(playerName)
  if not playerName then return end

  if not keepSelectedTab or self.talentPopup.currentPlayer ~= playerName then
    self.talentPopup.selectedTab = nil
  end
  self.talentPopup.currentPlayer = playerName

  local me = ShortName(UnitName("player"))
  local isSelf = me and Lower(me) == Lower(playerName)
  local classTag = LeafVE:GetClassTagForPlayer(playerName)

  if isSelf then
    LeafVE:CaptureAndCacheMyTalents(false)
  else
    LeafVE:RequestTalentData(playerName)
  end

  self.talentPopup.titleText:SetText(playerName .. "'s Talents")

  local treeSnapshot = LeafVE:GetTalentTreeSnapshotForPlayer(playerName, classTag, false)
  local sourceText
  if isSelf then
    sourceText = "|cFF88FF88Source: Live talents|r"
  elseif treeSnapshot and treeSnapshot.receivedAt then
    local age = Now() - (treeSnapshot.receivedAt or treeSnapshot.updatedAt or Now())
    if age < 0 then age = 0 end
    local ageLabel
    if age < 60 then
      ageLabel = tostring(age) .. "s ago"
    elseif age < 3600 then
      ageLabel = tostring(math.floor(age / 60)) .. "m ago"
    else
      ageLabel = tostring(math.floor(age / 3600)) .. "h ago"
    end
    sourceText = "Source: |cFF88CCFFGuild broadcast|r  |cFF888888" .. ageLabel .. "|r"
  else
    sourceText = "|cFF888888Source: Waiting for broadcast...|r"
  end
  self.talentPopup.sourceText:SetText(sourceText)

  local tabs = {}
  local maxTab = 0
  if treeSnapshot and treeSnapshot.tabs then
    for idx in pairs(treeSnapshot.tabs) do
      idx = tonumber(idx) or 0
      if idx > maxTab then maxTab = idx end
    end
    for idx = 1, maxTab do
      if treeSnapshot.tabs[idx] then
        tabs[idx] = treeSnapshot.tabs[idx]
      end
    end
  end

  if maxTab < 1 then
    local names = CLASS_SPEC_NAMES[classTag]
    if names and table.getn(names) > 0 then
      maxTab = table.getn(names)
      for idx = 1, maxTab do
        tabs[idx] = {
          index = idx,
          name = names[idx],
          points = 0,
          icon = (CLASS_SPEC_ICONS[classTag] and CLASS_SPEC_ICONS[classTag][idx]) or CLASS_ICONS[classTag] or "Interface\\Icons\\INV_Misc_QuestionMark",
        }
      end
    end
  end

  local selectedTab = self.talentPopup.selectedTab
  if not selectedTab then
    selectedTab = treeSnapshot and tonumber(treeSnapshot.activeTab) or 1
  end
  if not tabs[selectedTab] then
    selectedTab = nil
    for idx = 1, maxTab do
      if tabs[idx] then
        selectedTab = idx
        break
      end
    end
  end
  if not selectedTab then selectedTab = 1 end
  self.talentPopup.selectedTab = selectedTab

  for i = 1, table.getn(self.talentPopup.tabButtons) do
    local btn = self.talentPopup.tabButtons[i]
    local tabData = tabs[i]
    if tabData then
      btn.tabIndex = i
      if i == selectedTab then
        btn:SetText("|cFFFFFF99" .. tostring(tabData.name or ("Tree " .. tostring(i))) .. "|r")
      else
        btn:SetText(tostring(tabData.name or ("Tree " .. tostring(i))))
      end
      btn:Show()
      btn:Enable()
    else
      btn:Hide()
    end
  end

  local selectedTabData = tabs[selectedTab]
  if selectedTabData then
    self.talentPopup.pointsText:SetText("Points spent in " .. tostring(selectedTabData.name or ("Tree " .. tostring(selectedTab))) .. ": " .. tostring(tonumber(selectedTabData.points) or 0))
  else
    self.talentPopup.pointsText:SetText("|cFF888888No tree selected|r")
  end

  local talents = {}
  if treeSnapshot and treeSnapshot.talents then
    for _, talent in pairs(treeSnapshot.talents) do
      if type(talent) == "table" and (tonumber(talent.tab) or 0) == selectedTab then
        table.insert(talents, talent)
      end
    end
  end

  table.sort(talents, function(a, b)
    local at = tonumber(a.tier) or 0
    local bt = tonumber(b.tier) or 0
    if at == bt then
      local ac = tonumber(a.column) or 0
      local bc = tonumber(b.column) or 0
      if ac == bc then
        return (tonumber(a.index) or 0) < (tonumber(b.index) or 0)
      end
      return ac < bc
    end
    return at < bt
  end)

  local function AcquireTalentButton(i)
    local btn = self.talentPopup.talentButtons[i]
    if btn then return btn end
    btn = CreateFrame("Button", nil, self.talentPopup.treeFrame)
    btn:SetWidth(40)
    btn:SetHeight(40)
    btn:SetBackdrop({
      bgFile = "Interface\\Tooltips\\UI-Tooltip-Background",
      edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
      tile = false, tileSize = 8, edgeSize = 10,
      insets = {left = 2, right = 2, top = 2, bottom = 2}
    })
    btn:SetBackdropColor(0.1, 0.1, 0.1, 0.85)
    btn:SetBackdropBorderColor(0.5, 0.5, 0.5, 0.8)

    local icon = btn:CreateTexture(nil, "ARTWORK")
    icon:SetPoint("TOPLEFT", btn, "TOPLEFT", 3, -3)
    icon:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", -3, 3)
    btn.icon = icon

    local dim = btn:CreateTexture(nil, "OVERLAY")
    dim:SetAllPoints(icon)
    dim:SetTexture(0, 0, 0, 0.5)
    dim:Hide()
    btn.dim = dim

    local rankText = btn:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    rankText:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", -1, 2)
    rankText:SetJustifyH("RIGHT")
    rankText:SetText("")
    btn.rankText = rankText

    btn:SetScript("OnEnter", function()
      if not this.talentData then return end
      local data = this.talentData
      GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
      GameTooltip:ClearLines()
      GameTooltip:SetText(data.name or "Talent", THEME.gold[1], THEME.gold[2], THEME.gold[3], 1, true)
      GameTooltip:AddLine("Rank " .. tostring(tonumber(data.rank) or 0) .. "/" .. tostring(tonumber(data.maxRank) or 0), 1, 0.82, 0)
      if data.desc and data.desc ~= "" then
        local lines = SplitByLiteralSep(data.desc, "\n")
        for j = 1, table.getn(lines) do
          local line = lines[j]
          if line and line ~= "" then
            GameTooltip:AddLine(line, 1, 1, 1, true)
          end
        end
      end
      GameTooltip:Show()
    end)
    btn:SetScript("OnLeave", function() GameTooltip:Hide() end)

    self.talentPopup.talentButtons[i] = btn
    return btn
  end

  for i = 1, table.getn(talents) do
    local talent = talents[i]
    local btn = AcquireTalentButton(i)
    local col = tonumber(talent.column) or 1
    local tier = tonumber(talent.tier) or 1
    if col < 1 then col = 1 end
    if col > 4 then col = 4 end
    if tier < 1 then tier = 1 end
    if tier > 8 then tier = 8 end
    btn:ClearAllPoints()
    btn:SetPoint("TOPLEFT", self.talentPopup.treeFrame, "TOPLEFT", 18 + ((col - 1) * 84), -18 - ((tier - 1) * 58))
    btn.talentData = talent
    btn.icon:SetTexture(talent.icon or "Interface\\Icons\\INV_Misc_QuestionMark")

    local rank = tonumber(talent.rank) or 0
    local maxRank = tonumber(talent.maxRank) or 0
    btn.rankText:SetText("|cFFFFD700" .. tostring(rank) .. "|r/" .. tostring(maxRank))
    if rank > 0 then
      btn.icon:SetVertexColor(1, 1, 1, 1)
      btn.dim:Hide()
      btn:SetBackdropBorderColor(0.75, 0.75, 0.6, 0.9)
    else
      btn.icon:SetVertexColor(0.45, 0.45, 0.45, 1)
      btn.dim:Show()
      btn:SetBackdropBorderColor(0.35, 0.35, 0.35, 0.75)
    end
    btn:Show()
  end

  for i = table.getn(talents) + 1, table.getn(self.talentPopup.talentButtons) do
    self.talentPopup.talentButtons[i]:Hide()
  end

  if table.getn(talents) > 0 then
    self.talentPopup.emptyText:Hide()
  else
    if isSelf then
      self.talentPopup.emptyText:SetText("|cFF888888No talents learned yet.|r")
    else
      self.talentPopup.emptyText:SetText("|cFF888888Waiting for " .. playerName .. "'s talent broadcast...|r")
    end
    self.talentPopup.emptyText:Show()
  end
end

-------------------------------------------------
-- WORK ORDER UI + DATA
-------------------------------------------------

function ResolveWorkOrderProfessionForTable(tableKey)
  if not tableKey or tableKey == "" then return nil end
  if WORK_ORDER_TABLE_OVERRIDES[tableKey] ~= nil then
    return WORK_ORDER_TABLE_OVERRIDES[tableKey]
  end
  for prefix, profession in pairs(WORK_ORDER_TABLE_PREFIX_MAP) do
    if string.sub(tableKey, 1, string.len(prefix)) == prefix then
      return profession
    end
  end
  return nil
end

function ExtractWorkOrderRecipeName(token)
  token = tostring(token or "")
  if token == "" then return nil end
  local name = string.match(token, "=q%d+=(.*)")
  if not name or name == "" then
    name = string.match(token, "=ds=(.*)")
  end
  if not name or name == "" then
    name = string.match(token, "=%a+%d*=(.*)")
  end
  if not name or name == "" then
    name = token
  end
  name = string.gsub(name, "|c%x%x%x%x%x%x%x%x", "")
  name = string.gsub(name, "|r", "")
  name = Trim(name)
  if name == "" then return nil end
  return name
end

function ExtractWorkOrderQuality(token)
  local matchedQuality = string.match(tostring(token or ""), "=q(%d+)=")
  local quality = matchedQuality and tonumber(matchedQuality) or nil
  return quality or 1
end

function ExtractWorkOrderSkillRequirement(token)
  local matchedValue = string.match(tostring(token or ""), "#sr#%s*(%d+)")
  return matchedValue and tonumber(matchedValue) or nil
end

function ParseWorkOrderIDToken(rawId)
  if type(rawId) == "number" then
    if rawId > 0 then return rawId, nil end
    return nil, nil
  end

  local token = tostring(rawId or "")
  if token == "" or token == "0" then return nil, nil end
  if string.sub(token, 1, 1) == "s" then
    return nil, tonumber(string.sub(token, 2))
  end
  if string.sub(token, 1, 1) == "e" then
    return nil, tonumber(string.sub(token, 2))
  end
  local numeric = tonumber(token)
  if numeric and numeric > 0 then
    return numeric, nil
  end
  return nil, nil
end

function BuildWorkOrderSearchKey(recipe)
  local parts = {
    Lower(recipe and recipe.name or ""),
    Lower(recipe and recipe.profession or ""),
    tostring(recipe and recipe.itemId or ""),
    tostring(recipe and recipe.spellId or ""),
  }
  return table.concat(parts, " ")
end

function GetWorkOrderRecipeKey(recipe)
  return table.concat({
    Lower(recipe and recipe.profession or ""),
    Lower(recipe and recipe.name or ""),
    (recipe and recipe.spellId and ("spell:" .. tostring(recipe.spellId)))
      or (recipe and recipe.itemId and ("item:" .. tostring(recipe.itemId)))
      or "id:0",
  }, ":")
end

function ClampWorkOrderTipCopper(value)
  value = math.floor(tonumber(value) or 0)
  if value < 0 then value = 0 end
  if value > 1000000000 then value = 1000000000 end
  return value
end

function SplitWorkOrderTipCopper(tipCopper)
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  local gold = math.floor(tipCopper / 10000)
  local silver = math.floor(PositiveModulo(tipCopper, 10000) / 100)
  local copper = PositiveModulo(tipCopper, 100)
  return gold, silver, copper
end

function ParseWorkOrderTipCoinField(rawValue)
  local text = Trim(tostring(rawValue or ""))
  if text == "" then
    return 0
  end
  if not string.find(text, "^%d+$") then
    return nil
  end
  local value = tonumber(text)
  if not value or value < 0 then
    return nil
  end
  return math.floor(value)
end

function ParseWorkOrderTipCoinInputs(goldValue, silverValue, copperValue)
  local gold = ParseWorkOrderTipCoinField(goldValue)
  local silver = ParseWorkOrderTipCoinField(silverValue)
  local copper = ParseWorkOrderTipCoinField(copperValue)
  if gold == nil or silver == nil or copper == nil then
    return nil
  end
  return ClampWorkOrderTipCopper((gold * 10000) + (silver * 100) + copper)
end

function ParseWorkOrderTipInput(rawValue)
  local text = Trim(tostring(rawValue or ""))
  if text == "" then
    return 0
  end

  text = string.gsub(text, "%s+", "")
  text = string.gsub(text, "[gG]$", "")
  text = string.gsub(text, ",", ".")
  local gold = tonumber(text)
  if not gold or gold < 0 then
    return nil
  end
  return ClampWorkOrderTipCopper((gold * 10000) + 0.5)
end

function FormatWorkOrderTipText(tipCopper)
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  if tipCopper < 1 then
    return "No tip"
  end

  local gold, silver, copper = SplitWorkOrderTipCopper(tipCopper)
  local parts = {}
  if gold > 0 then
    table.insert(parts, tostring(gold) .. "g")
  end
  if silver > 0 then
    table.insert(parts, tostring(silver) .. "s")
  end
  if copper > 0 then
    table.insert(parts, tostring(copper) .. "c")
  end
  if table.getn(parts) < 1 then
    return "No tip"
  end
  return table.concat(parts, " ")
end

function FormatWorkOrderTipInputValue(tipCopper)
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  if tipCopper < 1 then
    return ""
  end

  local gold = string.format("%.2f", tipCopper / 10000)
  return string.gsub(gold, "%.?0+$", "")
end

function ClampWorkOrderQuantity(value)
  local quantity = math.floor(tonumber(value) or 1)
  if quantity < 1 then quantity = 1 end
  if quantity > 99 then quantity = 99 end
  return quantity
end

function GetWorkOrderRequestedQuantity(order)
  local requestedQuantity = ClampWorkOrderQuantity(order and (order.requestedQuantity or order.quantity) or 1)
  local activeQuantity = math.floor(tonumber(order and order.quantity) or requestedQuantity)
  if activeQuantity < 0 then activeQuantity = 0 end
  if activeQuantity > 99 then activeQuantity = 99 end
  if requestedQuantity < activeQuantity then
    requestedQuantity = activeQuantity
  end
  return requestedQuantity
end

function GetWorkOrderCompletedQuantity(order)
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local completedQuantity = math.floor(tonumber(order and order.completedQuantity) or 0)
  if completedQuantity < 0 then completedQuantity = 0 end
  if completedQuantity > requestedQuantity then
    completedQuantity = requestedQuantity
  end
  return completedQuantity
end

function GetWorkOrderParentId(order)
  local parentId = Trim(tostring(order and order.parentOrderId or ""))
  if parentId == "" then
    return nil
  end
  return parentId
end

function IsWorkOrderPartialClaim(order)
  return GetWorkOrderParentId(order) ~= nil
end

function GetWorkOrderFulfilledQuantity(order)
  local status = NormalizeWorkOrderStatus(order and order.status)
  local completedQuantity = GetWorkOrderCompletedQuantity(order)
  if completedQuantity > 0 then
    return completedQuantity
  end
  if status == "completed" or status == "finalized" then
    local requestedQuantity = GetWorkOrderRequestedQuantity(order)
    local quantity = ClampWorkOrderQuantity(order and order.quantity or requestedQuantity)
    if quantity > requestedQuantity then
      quantity = requestedQuantity
    end
    return quantity
  end
  return 0
end

function GetWorkOrderRemainingQuantity(order)
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  local remainingQuantity = requestedQuantity - fulfilledQuantity
  if remainingQuantity < 0 then
    remainingQuantity = 0
  end
  return remainingQuantity
end

function GetWorkOrderCompletionRatio(order)
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  if requestedQuantity < 1 then
    return 1
  end
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  if fulfilledQuantity < 1 then
    return 1
  end
  return math.min(1, fulfilledQuantity / requestedQuantity)
end

function GetWorkOrderQuantitySummary(order)
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local quantity = math.floor(tonumber(order and order.quantity) or requestedQuantity)
  if quantity < 0 then quantity = 0 end
  if quantity > 99 then quantity = 99 end
  local status = NormalizeWorkOrderStatus(order and order.status)
  if IsWorkOrderPartialClaim(order) and requestedQuantity > quantity then
    return "Qty " .. tostring(quantity) .. " / " .. tostring(requestedQuantity)
  end
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  if status == "open" and requestedQuantity > quantity then
    return "Qty " .. tostring(quantity) .. " remaining"
  end
  if (status == "completed" or status == "finalized") and fulfilledQuantity > 0 and requestedQuantity > fulfilledQuantity then
    return "Qty " .. tostring(fulfilledQuantity) .. " / " .. tostring(requestedQuantity)
  end
  return "Qty " .. tostring(quantity)
end

function GetWorkOrderPartialProgressText(order)
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  if fulfilledQuantity > 0 and requestedQuantity > fulfilledQuantity then
    return "Completed " .. tostring(fulfilledQuantity) .. " / " .. tostring(requestedQuantity) .. "  |  " .. tostring(requestedQuantity - fulfilledQuantity) .. " remaining"
  end
  return nil
end

function SplitWorkOrderTipByQuantity(tipCopper, fulfilledQuantity, requestedQuantity)
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  requestedQuantity = ClampWorkOrderQuantity(requestedQuantity)
  fulfilledQuantity = ClampWorkOrderQuantity(fulfilledQuantity)
  if fulfilledQuantity > requestedQuantity then
    fulfilledQuantity = requestedQuantity
  end
  if tipCopper < 1 or requestedQuantity < 1 then
    return 0, 0
  end

  local deliveredTip = math.floor((tipCopper * fulfilledQuantity) / requestedQuantity)
  local remainingTip = tipCopper - deliveredTip
  if remainingTip < 0 then
    remainingTip = 0
  end
  return deliveredTip, remainingTip
end

function NormalizeWorkOrderMatsMode(value)
  local mode = Lower(Trim(tostring(value or "")))
  if mode == "your" or mode == "yours" or mode == "yourmats" or mode == "crafter" or mode == "craftermats" then
    return "crafter"
  end
  if mode == "my" or mode == "mine" or mode == "mymats" or mode == "requester" or mode == "requestermats" then
    return "requester"
  end
  return "requester"
end

function GetWorkOrderMatsTag(mode, profession)
  if LeafVE and LeafVE:IsGatheringWorkOrderProfession(profession) then
    return "Gathering Request"
  end
  if NormalizeWorkOrderMatsMode(mode) == "crafter" then
    return "Crafter Mats"
  end
  return "My Mats"
end

function GetWorkOrderMatsLine(mode, requesterName, profession)
  if LeafVE and LeafVE:IsGatheringWorkOrderProfession(profession) then
    return "Gatherer collects the requested materials."
  end
  if NormalizeWorkOrderMatsMode(mode) == "crafter" then
    return "Crafter provides the mats."
  end

  local shortRequester = ShortName(requesterName)
  if shortRequester and shortRequester ~= "" then
    return shortRequester .. " provides the mats."
  end
  return "Requester provides the mats."
end

function GetWorkOrderRequesterInstructionText(mode, profession)
  if LeafVE and LeafVE:IsGatheringWorkOrderProfession(profession) then
    return "You have requested gathered materials from guildmates. Adding a tip is a great way to reward the gatherer for their time. Please click Verify once the delivered materials are received so the gatherer receives Leaf Points. Partial deliveries can be verified separately while the remaining quantity stays live."
  end
  if NormalizeWorkOrderMatsMode(mode) == "crafter" then
    return "You have requested a work order utilizing the crafter's materials. It's common courtesy to add a tip to cover the cost of the materials, or if they already have their own materials, the crafter will communicate that once the order is picked up. Please click Verify once the delivered items are received to reward the crafter Leaf Points. Partial deliveries can be verified separately while the remaining quantity stays live."
  end

  return "You have requested a work order utilizing your own mats. When it is picked up, you'll need to send the mats to the crafter via mail or trade so they can fulfill your order. Please click Verify once the delivered items are received to reward the crafter Leaf Points. Partial deliveries can be verified separately while the remaining quantity stays live."
end

function GetWorkOrderFulfillerInstructionText(mode, profession)
  if LeafVE and LeafVE:IsGatheringWorkOrderProfession(profession) then
    return "You have selected to fulfill a gathering request. Gather the requested materials and deliver them to the requester by trade or mail. You can reserve part of the request if needed, and the remaining quantity will stay live for other guildmates. Please select Complete once you have delivered the quantity you reserved."
  end
  if NormalizeWorkOrderMatsMode(mode) == "crafter" then
    return "You have selected to fulfill a work order using your own materials. It's common courtesy for the requester to add a tip to cover that cost. If not, communicate the desired outcome with the requester via in-game chat or mail. You can reserve part of the request if needed, and the remaining quantity will stay live for other guildmates. Please select Complete once you have delivered the quantity you reserved."
  end

  return "You have selected to fulfill an order using the requester's materials. If not already arranged, please send an in-game chat or a letter in the mail requesting the materials to complete this order. You can reserve part of the request if needed, and the remaining quantity will stay live for other guildmates. Please select Complete once you have delivered the quantity you reserved."
end

StaticPopupDialogs["LEAFVE_WORKORDER_CONFIRM"] = {
  text = "%s",
  button1 = "Continue",
  button2 = CANCEL or "Cancel",
  OnAccept = function(dialog, data)
    local popup = dialog
    if popup and not popup.leafveData and popup.GetParent then
      popup = popup:GetParent()
    end
    if popup and popup.leafveData then
      data = data or popup.leafveData
    end
    data = data or (dialog and dialog.data)
    if not data and this then
      data = this.leafveData or this.data or (this.GetParent and this:GetParent() and (this:GetParent().leafveData or this:GetParent().data))
    end
    if type(data) == "table" and type(data.onAccept) == "function" then
      data.onAccept()
    end
  end,
  OnCancel = function(dialog, data)
    local popup = dialog
    if popup and not popup.leafveData and popup.GetParent then
      popup = popup:GetParent()
    end
    if popup and popup.leafveData then
      data = data or popup.leafveData
    end
    data = data or (dialog and dialog.data)
    if not data and this then
      data = this.leafveData or this.data or (this.GetParent and this:GetParent() and (this:GetParent().leafveData or this:GetParent().data))
    end
    if type(data) == "table" and type(data.onCancel) == "function" then
      data.onCancel()
    end
  end,
  timeout = 0,
  whileDead = 1,
  hideOnEscape = 1,
}

StaticPopupDialogs["LEAFVE_CONFIRM_RESET_MY_BADGES"] = {
  text = "Reset your current-season badges?\n\nThis clears your earned badges so you can re-earn and re-test them.",
  button1 = "Reset Badges",
  button2 = "Cancel",
  OnAccept = function()
    local ok, err = LeafVE:ResetMyBadges()
    if not ok and err then
      Print("|cFFFF4444" .. tostring(err) .. "|r")
    end
  end,
  timeout = 0,
  whileDead = 1,
  hideOnEscape = 1,
}

StaticPopupDialogs["LEAFVE_WORKORDER_QUANTITY"] = {
  text = "%s",
  button1 = "Complete",
  button2 = CANCEL or "Cancel",
  hasEditBox = 1,
  maxLetters = 2,
  OnShow = function(dialog, data)
    data = data or (dialog and dialog.data)
    if dialog and dialog.editBox then
      local maxQuantity = ClampWorkOrderQuantity(type(data) == "table" and data.maxQuantity or 1)
      local defaultQuantity = ClampWorkOrderQuantity(type(data) == "table" and data.defaultQuantity or maxQuantity)
      if defaultQuantity > maxQuantity then
        defaultQuantity = maxQuantity
      end
      dialog.editBox:SetText(tostring(defaultQuantity))
      if dialog.editBox.SetFocus then
        dialog.editBox:SetFocus()
      end
      if dialog.editBox.HighlightText then
        dialog.editBox:HighlightText()
      end
    end
    if dialog and dialog.button1 then
      dialog.button1:SetText(type(data) == "table" and (data.confirmLabel or "Complete") or "Complete")
      dialog.button1:Enable(1)
    end
  end,
  OnAccept = function(dialog, data)
    local popup = dialog
    if popup and not popup.editBox and popup.GetParent then
      popup = popup:GetParent()
    end
    if (not popup or not popup.editBox) and this then
      popup = this.GetParent and this:GetParent() or popup
    end
    if popup and popup.leafveData then
      data = data or popup.leafveData
    end
    data = data or (dialog and dialog.data)
    if not data and this then
      data = this.leafveData or this.data or (this.GetParent and this:GetParent() and (this:GetParent().leafveData or this:GetParent().data))
    end
    local quantityText = popup and popup.editBox and popup.editBox:GetText() or ""
    local quantity = math.floor(tonumber(Trim(quantityText or "")) or 0)
    if type(data) == "table" and type(data.onAccept) == "function" then
      data.onAccept(quantity)
    end
  end,
  OnCancel = function(dialog, data)
    local popup = dialog
    if popup and not popup.leafveData and popup.GetParent then
      popup = popup:GetParent()
    end
    if popup and popup.leafveData then
      data = data or popup.leafveData
    end
    data = data or (dialog and dialog.data)
    if not data and this then
      data = this.leafveData or this.data or (this.GetParent and this:GetParent() and (this:GetParent().leafveData or this:GetParent().data))
    end
    if type(data) == "table" and type(data.onCancel) == "function" then
      data.onCancel()
    end
  end,
  EditBoxOnEnterPressed = function(editBox)
    local dialog = editBox and editBox.GetParent and editBox:GetParent() or nil
    if dialog and dialog.button1 and dialog.button1.Click then
      dialog.button1:Click()
    end
  end,
  EditBoxOnEscapePressed = function(editBox)
    local dialog = editBox and editBox.GetParent and editBox:GetParent() or nil
    if dialog and dialog.Hide then
      dialog:Hide()
    end
  end,
  EditBoxOnTextChanged = function(editBox)
    local dialog = editBox and editBox.GetParent and editBox:GetParent() or nil
    if not dialog or not dialog.button1 then
      return
    end
    local data = dialog.data
    local maxQuantity = ClampWorkOrderQuantity(type(data) == "table" and data.maxQuantity or 1)
    local quantity = math.floor(tonumber(Trim(editBox:GetText() or "")) or 0)
    if quantity >= 1 and quantity <= maxQuantity then
      dialog.button1:Enable(1)
    else
      dialog.button1:Disable()
    end
  end,
  timeout = 0,
  whileDead = 1,
  hideOnEscape = 1,
}

StaticPopupDialogs["LEAFVE_INFO_ONLY"] = {
  text = "%s",
  button1 = OKAY or "Okay",
  timeout = 0,
  whileDead = 1,
  hideOnEscape = 1,
}

function LeafVE:ShowWorkOrderInstructionPopup(message, confirmLabel, onAccept, onCancel)
  local popupText = Trim(message or "")
  if popupText == "" then
    if type(onAccept) == "function" then
      onAccept()
    end
    return
  end

  popupText = string.gsub(popupText, "%%", "%%%%")
  local callbackData = {
    onAccept = onAccept,
    onCancel = onCancel,
  }
  local dialog = StaticPopup_Show("LEAFVE_WORKORDER_CONFIRM", popupText, nil, callbackData)
  if dialog then
    dialog.leafveData = callbackData
    dialog.data = callbackData
  end
  if dialog and dialog.button1 then
    dialog.button1.leafveData = callbackData
    dialog.button1.data = callbackData
    dialog.button1:SetText(confirmLabel or "Continue")
  end
  if dialog and dialog.button2 then
    dialog.button2.leafveData = callbackData
    dialog.button2.data = callbackData
    dialog.button2:SetText(CANCEL or "Cancel")
  end
end

function LeafVE:ShowWorkOrderQuantityPopup(order, onAccept, onCancel, confirmLabel, promptText)
  local availableQuantity = ClampWorkOrderQuantity(order and order.quantity or 1)
  local popupText = promptText or ("How many units do you want to reserve from this order? Enter a quantity between 1 and " .. tostring(availableQuantity) .. ".")
  popupText = string.gsub(popupText, "%%", "%%%%")

  local dialog = StaticPopup_Show("LEAFVE_WORKORDER_QUANTITY", popupText, nil, {
    maxQuantity = availableQuantity,
    defaultQuantity = availableQuantity,
    confirmLabel = confirmLabel or "Complete",
    onAccept = onAccept,
    onCancel = onCancel,
  })
  if dialog then
    dialog.leafveData = dialog.data
  end
  if dialog and dialog.button1 then
    dialog.button1.leafveData = dialog.data
    dialog.button1.data = dialog.data
  end
  if dialog and dialog.button2 then
    dialog.button2.leafveData = dialog.data
    dialog.button2.data = dialog.data
  end
  if dialog and dialog.editBox then
    dialog.editBox.leafveData = dialog.data
    dialog.editBox.data = dialog.data
  end
end

function LeafVE:ShowInfoPopup(message)
  local popupText = Trim(message or "")
  if popupText == "" then
    return
  end

  popupText = string.gsub(popupText, "%%", "%%%%")
  StaticPopup_Show("LEAFVE_INFO_ONLY", popupText)
end

function NormalizeWorkOrderReagents(rawReagents)
  if type(rawReagents) ~= "table" then return nil end

  local reagents = {}
  for i = 1, table.getn(rawReagents) do
    local entry = rawReagents[i]
    local itemId = type(entry) == "table" and tonumber(entry[1]) or nil
    if itemId and itemId > 0 then
      table.insert(reagents, {
        itemId = itemId,
        quantity = math.max(1, tonumber(entry[2]) or 1),
      })
    end
  end

  if table.getn(reagents) < 1 then
    return nil
  end
  return reagents
end

function EnsureWorkOrderScanTip()
  if not LeafVE_WorkOrderScanTip then
    LeafVE_WorkOrderScanTip = CreateFrame("GameTooltip", "LeafVE_WorkOrderScanTip", UIParent, "GameTooltipTemplate")
    LeafVE_WorkOrderScanTip:SetOwner(UIParent, "ANCHOR_NONE")
  end
  return LeafVE_WorkOrderScanTip
end

function IsWorkOrderBindOnPickupLine(text)
  local line = Lower(text or "")
  if line == "" then
    return false
  end

  local bindOnPickup = Lower(ITEM_BIND_ON_PICKUP or "Binds when picked up")
  local soulbound = Lower(ITEM_SOULBOUND or "Soulbound")
  if line == bindOnPickup or line == soulbound then
    return true
  end

  return line == "binds when picked up"
    or line == "bound on pickup"
    or line == "bound on pick up"
    or line == "bind on pickup"
end

function LeafVE:IsWorkOrderItemBindOnPickup(itemId)
  itemId = tonumber(itemId)
  if not itemId or itemId < 1 then
    return false
  end

  if WORK_ORDER_ALWAYS_TRADEABLE_ITEM_IDS[itemId] then
    return false
  end

  self.workOrderBindCache = self.workOrderBindCache or {}
  if self.workOrderBindCache[itemId] ~= nil then
    return self.workOrderBindCache[itemId]
  end

  local scanTip = EnsureWorkOrderScanTip()
  if not scanTip then
    return false
  end

  local itemName = GetItemInfo(itemId)
  scanTip:ClearLines()
  scanTip:SetOwner(UIParent, "ANCHOR_NONE")
  scanTip:SetHyperlink("item:" .. tostring(itemId) .. ":0:0:0")

  local numLines = scanTip:NumLines() or 0
  local isBindOnPickup = false
  if numLines > 0 then
    for i = 1, numLines do
      local leftObj = getglobal("LeafVE_WorkOrderScanTipTextLeft" .. tostring(i))
      if leftObj and IsWorkOrderBindOnPickupLine(leftObj:GetText()) then
        isBindOnPickup = true
        break
      end
    end
  end

  itemName = itemName or GetItemInfo(itemId)
  local resolved = itemName ~= nil or numLines > 1
  scanTip:Hide()
  if resolved then
    if self.workOrderBindCache[itemId] ~= isBindOnPickup then
      self.workOrderBindCacheVersion = (self.workOrderBindCacheVersion or 0) + 1
    end
    self.workOrderBindCache[itemId] = isBindOnPickup
  end
  return isBindOnPickup
end

function LeafVE:GetTradeableWorkOrderRecipes(recipes)
  if type(recipes) ~= "table" then
    return {}
  end

  local filtered = {}
  for i = 1, table.getn(recipes) do
    local recipe = recipes[i]
    if type(recipe) == "table" and not self:IsWorkOrderItemBindOnPickup(recipe.itemId) then
      table.insert(filtered, recipe)
    end
  end
  return filtered
end

function LeafVE:EnsureWorkOrderSpellInfoIndex()
  if self.workOrderSpellInfoIndex then
    return self.workOrderSpellInfoIndex
  end

  local index = {
    bySpellId = {},
    byItemId = {},
    byName = {},
  }

  local spellDB = GetSpellInfoAtlasLootDB
  if type(spellDB) == "table" then
    local craftspells = spellDB["craftspells"]
    if type(craftspells) == "table" then
      for rawSpellId, data in pairs(craftspells) do
        local spellId = tonumber(rawSpellId)
        if spellId and type(data) == "table" then
          local entry = {
            kind = "craft",
            spellId = spellId,
            itemId = tonumber(data["craftItem"]),
            data = data,
            nameKey = Lower(tostring(data["name"] or "")),
          }
          index.bySpellId[spellId] = entry
          if entry.itemId then
            if not index.byItemId[entry.itemId] then
              index.byItemId[entry.itemId] = {}
            end
            table.insert(index.byItemId[entry.itemId], entry)
          end
          if entry.nameKey ~= "" then
            if not index.byName[entry.nameKey] then
              index.byName[entry.nameKey] = {}
            end
            table.insert(index.byName[entry.nameKey], entry)
          end
        end
      end
    end

    local enchants = spellDB["enchants"]
    if type(enchants) == "table" then
      for rawSpellId, data in pairs(enchants) do
        local spellId = tonumber(rawSpellId)
        if spellId and type(data) == "table" and not index.bySpellId[spellId] then
          local entry = {
            kind = "enchant",
            spellId = spellId,
            itemId = tonumber(data["item"]),
            data = data,
            nameKey = Lower(tostring(data["name"] or "")),
          }
          index.bySpellId[spellId] = entry
          if entry.itemId then
            if not index.byItemId[entry.itemId] then
              index.byItemId[entry.itemId] = {}
            end
            table.insert(index.byItemId[entry.itemId], entry)
          end
          if entry.nameKey ~= "" then
            if not index.byName[entry.nameKey] then
              index.byName[entry.nameKey] = {}
            end
            table.insert(index.byName[entry.nameKey], entry)
          end
        end
      end
    end
  end

  self.workOrderSpellInfoIndex = index
  return index
end

function LeafVE:FindWorkOrderSpellInfo(itemId, spellId, recipeName)
  local index = self:EnsureWorkOrderSpellInfoIndex()

  spellId = tonumber(spellId)
  if spellId and index.bySpellId[spellId] then
    return index.bySpellId[spellId]
  end

  local nameKey = Lower(recipeName or "")
  itemId = tonumber(itemId)
  if itemId and index.byItemId[itemId] then
    local candidates = index.byItemId[itemId]
    if nameKey ~= "" then
      for i = 1, table.getn(candidates) do
        if candidates[i].nameKey == nameKey then
          return candidates[i]
        end
      end
    end
    return candidates[1]
  end

  if nameKey ~= "" and index.byName[nameKey] then
    return index.byName[nameKey][1]
  end

  return nil
end

function LeafVE:GetWorkOrderSpellTexture(spellId, spellName)
  local iconPath = nil
  local numericSpellId = tonumber(spellId)

  if numericSpellId and GetSpellTexture then
    local okTexture, texture = pcall(GetSpellTexture, numericSpellId)
    if okTexture then
      iconPath = NormalizeIconPath(texture)
    end
  end

  spellName = tostring(spellName or "")
  if iconPath or spellName == "" then
    return iconPath
  end

  if type(GetNumSpellTabs) ~= "function"
    or type(GetSpellTabInfo) ~= "function"
    or type(GetSpellName) ~= "function"
    or type(GetSpellTexture) ~= "function"
  then
    return nil
  end

  local targetName = Lower(spellName)
  local bookType = BOOKTYPE_SPELL or "spell"
  local numTabs = tonumber(GetNumSpellTabs()) or 0

  for tabIndex = 1, numTabs do
    local _, _, offset, numSpells = GetSpellTabInfo(tabIndex)
    offset = tonumber(offset) or 0
    numSpells = tonumber(numSpells) or 0

    for spellOffset = 1, numSpells do
      local slot = offset + spellOffset
      local okName, resolvedName = pcall(GetSpellName, slot, bookType)
      if okName and resolvedName and Lower(resolvedName) == targetName then
        local okTexture, texture = pcall(GetSpellTexture, slot, bookType)
        if okTexture then
          iconPath = NormalizeIconPath(texture)
        end
        return iconPath
      end
    end
  end

  return nil
end

function LeafVE:ApplyWorkOrderSpellInfo(recipe)
  if type(recipe) ~= "table" then return end

  local spellInfo = self:FindWorkOrderSpellInfo(recipe.itemId, recipe.spellId, recipe.name)
  if not spellInfo then
    return
  end

  if not recipe.spellId and spellInfo.spellId then
    recipe.spellId = spellInfo.spellId
  end
  if not recipe.itemId and spellInfo.itemId then
    recipe.itemId = spellInfo.itemId
  end

  local iconPath = NormalizeIconPath(spellInfo.data and spellInfo.data["icon"])
  if not iconPath then
    iconPath = self:GetWorkOrderSpellTexture(recipe.spellId, recipe.name or (spellInfo.data and spellInfo.data["name"]))
  end
  if iconPath and (not recipe.icon or recipe.icon == LEAF_FALLBACK) then
    recipe.icon = iconPath
  end

  if spellInfo.kind == "craft" then
    recipe.reagents = NormalizeWorkOrderReagents(spellInfo.data and spellInfo.data["reagents"])
    recipe.craftQuantityMin = tonumber(spellInfo.data and spellInfo.data["craftQuantityMin"])
    recipe.craftQuantityMax = tonumber(spellInfo.data and spellInfo.data["craftQuantityMax"])
  end
end

function LeafVE:GetWorkOrderResultIcon(itemId, spellId, currentIcon)
  local iconPath = NormalizeIconPath((itemId and GetItemIcon and GetItemIcon(itemId)) or nil)
  if not iconPath then
    local spellInfo = self:FindWorkOrderSpellInfo(itemId, spellId, nil)
    iconPath = self:GetWorkOrderSpellTexture(spellId, spellInfo and spellInfo.data and spellInfo.data["name"])
  end
  local rawIcon = tostring(currentIcon or "")
  if not iconPath and rawIcon ~= "" and (
    string.find(rawIcon, "\\", 1, true)
    or string.find(rawIcon, "INV_", 1, true)
    or string.find(rawIcon, "Spell_", 1, true)
    or string.find(rawIcon, "Ability_", 1, true)
  ) then
    iconPath = NormalizeIconPath(currentIcon)
  end
  return iconPath or LEAF_FALLBACK
end

function LeafVE:GetWorkOrderItemName(itemId)
  itemId = tonumber(itemId)
  if not itemId then
    return nil
  end

  local itemName = GetItemInfo(itemId)
  if itemName then
    return itemName
  end

  local scanTip = EnsureWorkOrderScanTip()
  if scanTip then
    scanTip:ClearLines()
    scanTip:SetOwner(UIParent, "ANCHOR_NONE")
    scanTip:SetHyperlink("item:" .. tostring(itemId))
    itemName = GetItemInfo(itemId)
  end

  return itemName or ("Item #" .. tostring(itemId))
end

function LeafVE:GetWorkOrderResolvedReagents(recipe)
  if type(recipe) ~= "table" then return nil end
  if type(recipe.reagents) == "table" and table.getn(recipe.reagents) > 0 then
    return recipe.reagents
  end

  local lookupName = recipe.recipeName or recipe.name
  local catalogRecipe = self:FindWorkOrderCatalogRecipe(recipe.profession, lookupName, recipe.itemId, recipe.spellId)
  if catalogRecipe and type(catalogRecipe.reagents) == "table" and table.getn(catalogRecipe.reagents) > 0 then
    return catalogRecipe.reagents
  end
  return nil
end

function LeafVE:GetWorkOrderReagentLines(recipe, quantity)
  local reagents = self:GetWorkOrderResolvedReagents(recipe)
  if type(reagents) ~= "table" or table.getn(reagents) < 1 then
    return nil
  end

  quantity = tonumber(quantity) or 1
  if quantity < 1 then quantity = 1 end

  local lines = {}
  for i = 1, table.getn(reagents) do
    local reagent = reagents[i]
    local totalQty = (tonumber(reagent.quantity) or 1) * quantity
    local reagentName = self:GetWorkOrderItemName(reagent.itemId) or ("Item #" .. tostring(reagent.itemId))
    table.insert(lines, tostring(totalQty) .. "x " .. reagentName)
  end
  return lines
end

function LeafVE:GetWorkOrderReagentEntries(recipe, quantity)
  local reagents = self:GetWorkOrderResolvedReagents(recipe)
  if type(reagents) ~= "table" or table.getn(reagents) < 1 then
    return nil
  end

  quantity = tonumber(quantity) or 1
  if quantity < 1 then quantity = 1 end

  local entries = {}
  for i = 1, table.getn(reagents) do
    local reagent = reagents[i]
    local itemId = tonumber(reagent.itemId)
    local totalQty = (tonumber(reagent.quantity) or 1) * quantity
    local reagentName = self:GetWorkOrderItemName(itemId) or ("Item #" .. tostring(itemId or "?"))
    table.insert(entries, {
      itemId = itemId,
      quantity = tonumber(reagent.quantity) or 1,
      totalQuantity = totalQty,
      name = reagentName,
      icon = self:GetWorkOrderResultIcon(itemId, nil, nil),
    })
  end
  return entries
end

function LeafVE:GetWorkOrderReagentBlockText(recipe, quantity, maxLines)
  local entries = self:GetWorkOrderReagentEntries(recipe, quantity)
  if type(entries) ~= "table" or table.getn(entries) < 1 then
    return nil
  end

  maxLines = tonumber(maxLines) or table.getn(entries)
  if maxLines < 1 then
    maxLines = 1
  end

  local lines = {}
  for i = 1, math.min(table.getn(entries), maxLines) do
    local entry = entries[i]
    table.insert(lines, tostring(entry.totalQuantity) .. "x " .. tostring(entry.name or "Unknown Reagent"))
  end
  if table.getn(entries) > maxLines then
    table.insert(lines, "+" .. tostring(table.getn(entries) - maxLines) .. " more material" .. ((table.getn(entries) - maxLines) ~= 1 and "s" or ""))
  end
  return table.concat(lines, "\n")
end

function LeafVE:GetWorkOrderReagentSummary(recipe, quantity)
  local lines = self:GetWorkOrderReagentLines(recipe, quantity)
  if type(lines) ~= "table" or table.getn(lines) < 1 then
    return nil
  end
  return table.concat(lines, ", ")
end

function LeafVE:GetWorkOrderCraftYieldText(recipe)
  if type(recipe) ~= "table" then
    return nil
  end

  local minQty = tonumber(recipe.craftQuantityMin) or 1
  local maxQty = tonumber(recipe.craftQuantityMax) or minQty
  if minQty < 1 then
    minQty = 1
  end
  if maxQty < minQty then
    maxQty = minQty
  end
  if minQty == maxQty then
    return "Creates " .. tostring(minQty)
  end
  return "Creates " .. tostring(minQty) .. "-" .. tostring(maxQty)
end

function LeafVE:GetWorkOrderRecipeMetaText(recipe)
  if type(recipe) ~= "table" then
    return ""
  end

  local parts = {}
  if recipe.profession and recipe.profession ~= "" then
    table.insert(parts, tostring(recipe.profession))
  end
  if tonumber(recipe.skillRequirement) then
    table.insert(parts, "Skill " .. tostring(recipe.skillRequirement))
  end
  local yieldText = self:GetWorkOrderCraftYieldText(recipe)
  if yieldText then
    table.insert(parts, yieldText)
  end
  return table.concat(parts, "  |  ")
end

function LeafVE:GetWorkOrderYieldShortText(recipe)
  if type(recipe) ~= "table" then
    return ""
  end

  local minQty = tonumber(recipe.craftQuantityMin) or 1
  local maxQty = tonumber(recipe.craftQuantityMax) or minQty
  if minQty < 1 then
    minQty = 1
  end
  if maxQty < minQty then
    maxQty = minQty
  end
  if minQty == maxQty then
    return minQty > 1 and ("x" .. tostring(minQty)) or ""
  end
  return "x" .. tostring(minQty) .. "-" .. tostring(maxQty)
end

function LeafVE:GetWorkOrderListMaterialsText(recipe, quantity, maxLines)
  if type(recipe) == "table" and self:IsGatheringWorkOrderProfession(recipe.profession) then
    return "|cFFAAAAAARequested delivery:|r " .. tostring(tonumber(quantity) or 1) .. "x " .. tostring(recipe.recipeName or recipe.name or "materials")
  end
  local reagentText = self:GetWorkOrderReagentBlockText(recipe, quantity, maxLines)
  if reagentText and reagentText ~= "" then
    return "|cFFAAAAAA" .. reagentText .. "|r"
  end
  return "|cFF666666Reagent data will appear here once the craft info is cached.|r"
end

function CanonicalMainProfession(name)
  local target = Lower(Trim(tostring(name or "")))
  if target == "" then return nil end
  for i = 1, table.getn(WORK_ORDER_MAIN_PROFESSION_ORDER) do
    local profession = WORK_ORDER_MAIN_PROFESSION_ORDER[i]
    if Lower(profession) == target then
      return profession
    end
  end
  return nil
end

function CanonicalSecondaryProfession(name)
  local target = Lower(Trim(tostring(name or "")))
  if target == "" then return nil end
  for i = 1, table.getn(WORK_ORDER_SECONDARY_PROFESSION_ORDER) do
    local profession = WORK_ORDER_SECONDARY_PROFESSION_ORDER[i]
    if Lower(profession) == target then
      return profession
    end
  end
  return nil
end

function CanonicalWorkOrderProfession(name)
  local trimmed = Trim(tostring(name or ""))
  if Lower(trimmed) == "farming" then
    return "Farming"
  end
  return CanonicalMainProfession(name) or CanonicalSecondaryProfession(name)
end

function NormalizeProfessionDesignationRecord(playerName, data)
  local recordPlayer = ShortName(playerName or (type(data) == "table" and data.player) or nil)
  if not recordPlayer or type(data) ~= "table" then return nil end

  local record = {
    player = recordPlayer,
    updatedAt = tonumber(data.updatedAt) or Now(),
    main = {},
    secondary = {},
  }

  local mainSeen = {}
  local rawMain = type(data.main) == "table" and data.main or { data.main1, data.main2 }
  for i = 1, table.getn(rawMain) do
    local profession = CanonicalMainProfession(rawMain[i])
    if profession and not mainSeen[profession] and table.getn(record.main) < 2 then
      mainSeen[profession] = true
      table.insert(record.main, profession)
    end
  end

  local secondarySeen = {}
  local rawSecondary = {}
  if type(data.secondary) == "table" then
    if data.secondary[1] ~= nil then
      rawSecondary = data.secondary
    else
      for profession, enabled in pairs(data.secondary) do
        if enabled then
          table.insert(rawSecondary, profession)
        end
      end
    end
  end
  for i = 1, table.getn(rawSecondary) do
    local profession = CanonicalSecondaryProfession(rawSecondary[i])
    if profession and not secondarySeen[profession] then
      secondarySeen[profession] = true
      table.insert(record.secondary, profession)
    end
  end

  return record
end

function LeafVE:GetProfessionDesignation(playerName)
  EnsureDB()
  local shortName = ShortName(playerName)
  if not shortName then return nil end

  local key = Lower(shortName)
  local designation = LeafVE_GlobalDB.professionDesignations and LeafVE_GlobalDB.professionDesignations[key]
  if type(designation) == "table" then
    return designation
  end
  return nil
end

function LeafVE:GetProfessionDesignationSummary(playerName)
  local designation = type(playerName) == "table" and playerName or self:GetProfessionDesignation(playerName)
  if type(designation) ~= "table" then
    return "No professions submitted."
  end

  local parts = {}
  if type(designation.main) == "table" and table.getn(designation.main) > 0 then
    table.insert(parts, "Main: " .. table.concat(designation.main, ", "))
  end
  if type(designation.secondary) == "table" and table.getn(designation.secondary) > 0 then
    table.insert(parts, "Secondary: " .. table.concat(designation.secondary, ", "))
  end
  if table.getn(parts) < 1 then
    return "No professions submitted."
  end
  return table.concat(parts, "  |  ")
end

function LeafVE:SaveProfessionDesignation(mainList, secondaryList)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local record = NormalizeProfessionDesignationRecord(me, {
    player = me,
    updatedAt = Now(),
    main = mainList or {},
    secondary = secondaryList or {},
  })
  if not record then
    return nil, "Unable to save your professions."
  end

  LeafVE_GlobalDB.professionDesignations[Lower(me)] = record
  self:BroadcastMyProfessionDesignation(true)
  return record
end

function LeafVE:BroadcastMyProfessionDesignation(force)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me or not InGuild() then return end

  self.lastProfessionBroadcastAt = self.lastProfessionBroadcastAt or 0
  local now = Now()
  if not force and (now - self.lastProfessionBroadcastAt) < 30 then
    return
  end

  local record = self:GetProfessionDesignation(me)
  if type(record) ~= "table" then
    return
  end

  self.lastProfessionBroadcastAt = now
  local payload = table.concat({
    tostring(record.updatedAt or now),
    EncodeTalentField(record.main and record.main[1] or ""),
    EncodeTalentField(record.main and record.main[2] or ""),
    EncodeTalentField(table.concat(record.secondary or {}, ",")),
  }, SEP)
  SendAddonMessage("LeafVE", "PROFDES:" .. payload, "GUILD")
end

function LeafVE:RequestProfessionDesignation(playerName, force)
  local shortName = ShortName(playerName)
  local me = ShortName(UnitName("player"))
  if not shortName or not me or Lower(shortName) == Lower(me) or not InGuild() then
    return
  end

  self.lastProfessionRequestAt = self.lastProfessionRequestAt or {}
  local key = Lower(shortName)
  local now = Now()
  if not force and self.lastProfessionRequestAt[key] and (now - self.lastProfessionRequestAt[key]) < 15 then
    return
  end
  self.lastProfessionRequestAt[key] = now
  SendAddonMessage("LeafVE", "PROFREQ:" .. shortName, "GUILD")
end

function LeafVE:HasProfessionDesignation(playerName, profession)
  local canonicalProfession = CanonicalWorkOrderProfession(profession)
  local designation = self:GetProfessionDesignation(playerName)
  if not canonicalProfession or type(designation) ~= "table" then
    return false
  end

  for i = 1, table.getn(designation.main or {}) do
    if designation.main[i] == canonicalProfession then
      return true
    end
  end
  for i = 1, table.getn(designation.secondary or {}) do
    if designation.secondary[i] == canonicalProfession then
      return true
    end
  end
  return false
end

function LeafVE:IsGatheringWorkOrderProfession(profession)
  local canonicalProfession = CanonicalWorkOrderProfession(profession) or Trim(tostring(profession or ""))
  local lowered = Lower(canonicalProfession or "")
  return lowered == "herbalism"
    or lowered == "mining"
    or lowered == "skinning"
    or lowered == "fishing"
    or lowered == "farming"
end

function LeafVE:DoesWorkOrderRequireDesignation(order)
  if type(order) ~= "table" then
    return true
  end
  local profession = CanonicalWorkOrderProfession(order.profession) or Trim(tostring(order.profession or ""))
  return Lower(profession or "") ~= "farming"
end

function LeafVE:GetNormalizedGuildRankName(playerName)
  local info = self:GetGuildInfo(playerName)
  if not info and LeafVE_DB and LeafVE_DB.persistentRoster then
    info = LeafVE_DB.persistentRoster[Lower(ShortName(playerName) or "")]
  end
  return info and info.rank and Lower(Trim(info.rank)) or ""
end

function LeafVE:IsUnlimitedShoutoutDailyLimit(limit)
  return tonumber(limit) == 0
end

function LeafVE:GetShoutoutDailyLimitLabel(limit)
  limit = tonumber(limit)
  if self:IsUnlimitedShoutoutDailyLimit(limit) then
    return "unlimited"
  end
  if not limit or limit < 0 then
    limit = SHOUTOUT_MAX_PER_DAY
  end
  return tostring(limit)
end

function LeafVE:GetShoutoutUsageStatusText(usedCount, maxDaily)
  usedCount = tonumber(usedCount) or 0
  if self:IsUnlimitedShoutoutDailyLimit(maxDaily) then
    return string.format("Shoutouts used today: %d | Remaining: unlimited", usedCount)
  end

  local cap = tonumber(maxDaily) or SHOUTOUT_MAX_PER_DAY
  local remaining = math.max(0, cap - usedCount)
  return string.format("Shoutouts remaining today: %d / %d", remaining, cap)
end

function LeafVE:GetShoutoutDailyLimitForPlayer(playerName)
  local baseLimit = (LeafVE_DB and LeafVE_DB.options and tonumber(LeafVE_DB.options.shoutoutMaxDaily)) or SHOUTOUT_MAX_PER_DAY
  if not baseLimit or baseLimit < 1 then
    baseLimit = SHOUTOUT_MAX_PER_DAY
  end

  local rank = self:GetNormalizedGuildRankName(playerName)
  if rank == "kage" or rank == "hokage" then
    return 0
  end
  if rank == "akatsuki" or rank == "sannin" or rank == "anbu" then
    return math.max(baseLimit, 10)
  end
  if rank == "jonin" or rank == "jounin" then
    return math.max(baseLimit, 3)
  end

  return baseLimit
end

function GetWorkOrderCrafterRecipeToken(recipe)
  if type(recipe) ~= "table" then return nil end

  local spellId = tonumber(recipe.spellId)
  if spellId and spellId > 0 then
    return "s" .. tostring(spellId)
  end

  local itemId = tonumber(recipe.itemId)
  if itemId and itemId > 0 then
    return "i" .. tostring(itemId)
  end

  return nil
end

function ParseWorkOrderCrafterRecipeToken(token)
  token = Lower(Trim(tostring(token or "")))
  if token == "" then return nil, nil end

  local prefix = string.sub(token, 1, 1)
  local number = tonumber(string.sub(token, 2))
  if not number or number < 1 then
    return nil, nil
  end

  if prefix == "s" then
    return nil, number
  end
  if prefix == "i" then
    return number, nil
  end

  return nil, nil
end

function NormalizeWorkOrderCrafterRecipeTokens(rawTokens)
  local tokens = {}
  local seen = {}
  if type(rawTokens) ~= "table" then
    return tokens
  end

  for i = 1, table.getn(rawTokens) do
    local rawToken = rawTokens[i]
    local itemId, spellId = ParseWorkOrderCrafterRecipeToken(rawToken)
    if itemId or spellId then
      local token = spellId and ("s" .. tostring(spellId)) or ("i" .. tostring(itemId))
      if not seen[token] then
        seen[token] = true
        table.insert(tokens, token)
      end
    end
  end

  table.sort(tokens)
  return tokens
end

function NormalizeWorkOrderCrafterSignupMeta(playerName, updatedAt)
  local shortName = ShortName(playerName)
  if not shortName then return nil end

  return {
    player = shortName,
    updatedAt = tonumber(updatedAt) or Now(),
  }
end

function NormalizeWorkOrderCrafterSignupEntry(playerName, profession, data)
  local shortName = ShortName(playerName or (type(data) == "table" and data.player) or nil)
  local canonicalProfession = CanonicalWorkOrderProfession(profession or (type(data) == "table" and data.profession) or nil)
  if not shortName or not canonicalProfession or type(data) ~= "table" then
    return nil
  end

  local tokens = NormalizeWorkOrderCrafterRecipeTokens(data.recipes or data.tokens or {})
  if table.getn(tokens) < 1 then
    return nil
  end

  return {
    player = shortName,
    profession = canonicalProfession,
    updatedAt = tonumber(data.updatedAt) or Now(),
    recipes = tokens,
  }
end

function CountWorkOrderCrafterSelectionMap(selectionMap)
  if type(selectionMap) ~= "table" then return 0 end

  local count = 0
  for _, enabled in pairs(selectionMap) do
    if enabled then
      count = count + 1
    end
  end
  return count
end

function LeafVE:GetWorkOrderCrafterSignupMeta(playerName)
  EnsureDB()

  local shortName = ShortName(playerName)
  if not shortName then return nil end

  local key = Lower(shortName)
  local meta = LeafVE_GlobalDB.workOrderCrafterSignupMeta and LeafVE_GlobalDB.workOrderCrafterSignupMeta[key]
  if type(meta) == "table" and tonumber(meta.updatedAt) then
    return meta
  end

  local bucket = LeafVE_GlobalDB.workOrderCrafterSignups and LeafVE_GlobalDB.workOrderCrafterSignups[key]
  if type(bucket) ~= "table" then
    return nil
  end

  local updatedAt = 0
  for _, entry in pairs(bucket) do
    if type(entry) == "table" then
      local entryUpdatedAt = tonumber(entry.updatedAt) or 0
      if entryUpdatedAt > updatedAt then
        updatedAt = entryUpdatedAt
      end
    end
  end
  if updatedAt < 1 then
    return nil
  end

  meta = NormalizeWorkOrderCrafterSignupMeta(shortName, updatedAt)
  LeafVE_GlobalDB.workOrderCrafterSignupMeta[key] = meta
  return meta
end

function LeafVE:GetWorkOrderCrafterSignupUpdatedAt(playerName)
  local meta = self:GetWorkOrderCrafterSignupMeta(playerName)
  return type(meta) == "table" and (tonumber(meta.updatedAt) or 0) or 0
end

function LeafVE:EnsureWorkOrderCrafterRecipeIndex()
  if self.workOrderCrafterRecipeIndex then
    return self.workOrderCrafterRecipeIndex
  end

  local catalog = self:EnsureWorkOrderCatalog()
  local index = {}
  for i = 1, table.getn(catalog.order or {}) do
    local profession = catalog.order[i]
    index[profession] = {}
    local recipes = catalog.byProfession and catalog.byProfession[profession] or {}
    for j = 1, table.getn(recipes) do
      local recipe = recipes[j]
      local token = GetWorkOrderCrafterRecipeToken(recipe)
      if token then
        index[profession][token] = recipe
      end
    end
  end

  self.workOrderCrafterRecipeIndex = index
  return index
end

function LeafVE:ResolveWorkOrderCrafterRecipeToken(profession, token)
  local canonicalProfession = CanonicalWorkOrderProfession(profession)
  local itemId, spellId = ParseWorkOrderCrafterRecipeToken(token)
  if not canonicalProfession or (not itemId and not spellId) then
    return nil
  end

  local index = self:EnsureWorkOrderCrafterRecipeIndex()
  local recipe = index[canonicalProfession] and index[canonicalProfession][Lower(Trim(tostring(token or "")))] or nil
  if recipe then
    return recipe
  end

  return {
    profession = canonicalProfession,
    itemId = itemId,
    spellId = spellId,
    icon = (WORK_ORDER_PROFESSION_META[canonicalProfession] and WORK_ORDER_PROFESSION_META[canonicalProfession].icon) or LEAF_FALLBACK,
    name = spellId and ("Spell " .. tostring(spellId)) or ("Item " .. tostring(itemId or "?")),
    searchKey = Lower(spellId and ("spell " .. tostring(spellId)) or ("item " .. tostring(itemId or "?"))),
  }
end

function LeafVE:GetWorkOrderCrafterSignupGroup(playerName)
  EnsureDB()

  local shortName = ShortName(playerName)
  if not shortName then return nil end

  local bucket = LeafVE_GlobalDB.workOrderCrafterSignups and LeafVE_GlobalDB.workOrderCrafterSignups[Lower(shortName)]
  if type(bucket) ~= "table" then
    return nil
  end

  local group = {
    player = shortName,
    displayName = self:GetStoredDisplayPlayerName(shortName),
    classTag = self:GetClassTagForPlayer(shortName),
    updatedAt = self:GetWorkOrderCrafterSignupUpdatedAt(shortName),
    professions = {},
    professionMap = {},
    professionCount = 0,
    totalRecipes = 0,
    summaryText = "",
    icon = LEAF_FALLBACK,
  }

  local repEntry, repSnapshot = self:GetWorkOrderReputationForPlayer(shortName)
  local repTierInfo = repEntry and (repEntry.tierInfo or self:GetWorkOrderReputationTierInfo(repEntry.totalRep or 0))
    or self:GetWorkOrderReputationTierInfo(0)
  local repTierName, _, repBadgeIconIndex, repColor = GetWorkOrderReputationTierVisual(repTierInfo)
  local crafterRank = self:GetWorkOrderCrafterRankInfo(shortName, repSnapshot)
  group.repTotal = tonumber(repEntry and repEntry.totalRep) or 0
  group.repCrafterRep = tonumber(repEntry and repEntry.crafterRep) or 0
  group.repRequesterRep = tonumber(repEntry and repEntry.requesterRep) or 0
  group.repTierName = repTierName
  group.repTierInfo = repTierInfo
  group.repBadgeIconIndex = repBadgeIconIndex
  group.repColor = repColor
  group.crafterRank = crafterRank

  local summaryParts = {}
  for i = 1, table.getn(WORK_ORDER_PROFESSION_ORDER) do
    local profession = WORK_ORDER_PROFESSION_ORDER[i]
    local entry = bucket[profession]
    if type(entry) == "table" and type(entry.recipes) == "table" and table.getn(entry.recipes) > 0 then
      local recipes = {}
      for j = 1, table.getn(entry.recipes) do
        local recipe = self:ResolveWorkOrderCrafterRecipeToken(profession, entry.recipes[j])
        if recipe then
          table.insert(recipes, recipe)
        end
      end
      if table.getn(recipes) > 0 then
        table.sort(recipes, function(a, b)
          local an = Lower(a.name or "")
          local bn = Lower(b.name or "")
          if an == bn then
            local aid = tonumber(a.spellId or a.itemId or 0) or 0
            local bid = tonumber(b.spellId or b.itemId or 0) or 0
            return aid < bid
          end
          return an < bn
        end)

        local professionEntry = {
          player = shortName,
          profession = profession,
          updatedAt = tonumber(entry.updatedAt) or group.updatedAt,
          recipes = recipes,
          recipeCount = table.getn(recipes),
        }
        table.insert(group.professions, professionEntry)
        group.professionMap[profession] = professionEntry
        group.professionCount = group.professionCount + 1
        group.totalRecipes = group.totalRecipes + professionEntry.recipeCount
        table.insert(summaryParts, profession .. " (" .. tostring(professionEntry.recipeCount) .. ")")
        if group.icon == LEAF_FALLBACK then
          group.icon = (WORK_ORDER_PROFESSION_META[profession] and WORK_ORDER_PROFESSION_META[profession].icon) or LEAF_FALLBACK
        end
      end
    end
  end

  if group.professionCount < 1 then
    return nil
  end

  group.primaryProfession = group.professions[1] and group.professions[1].profession or nil
  group.summaryText = table.concat(summaryParts, ", ")
  return group
end

function LeafVE:GetSortedWorkOrderCrafterSignupGroups()
  EnsureDB()

  local groups = {}
  for playerName, bucket in pairs(LeafVE_GlobalDB.workOrderCrafterSignups or {}) do
    if type(bucket) == "table" then
      local group = self:GetWorkOrderCrafterSignupGroup(playerName)
      if group then
        table.insert(groups, group)
      end
    end
  end

  local me = ShortName(UnitName("player"))
  table.sort(groups, function(a, b)
    local aIsMe = me and SamePlayerName(a.player, me)
    local bIsMe = me and SamePlayerName(b.player, me)
    if aIsMe ~= bIsMe then
      return aIsMe and true or false
    end
    return Lower(a.player or "") < Lower(b.player or "")
  end)

  return groups
end

function LeafVE:RefreshWorkOrderCrafterViews()
  if not LeafVE or not LeafVE.UI then return end

  if LeafVE.UI.workOrderPopup and LeafVE.UI.workOrderPopup:IsVisible() and LeafVE.UI.cardCurrentPlayer then
    LeafVE.UI:RefreshWorkOrderPopup(LeafVE.UI.cardCurrentPlayer)
  end

  if LeafVE.UI.workOrderCrafterSignupPopup and LeafVE.UI.workOrderCrafterSignupPopup:IsVisible() then
    local popup = LeafVE.UI.workOrderCrafterSignupPopup
    if popup.currentPlayer and LeafVE.UI.RefreshWorkOrderCrafterSignupPopup then
      LeafVE.UI:RefreshWorkOrderCrafterSignupPopup(popup.currentPlayer, popup.isEditable)
    end
  end
end

function LeafVE:BroadcastWorkOrderCrafterSignupReset(playerName, updatedAt)
  local meta = NormalizeWorkOrderCrafterSignupMeta(playerName, updatedAt)
  if not meta or not InGuild() then return end

  local payload = table.concat({
    EncodeTalentField(meta.player),
    tostring(meta.updatedAt or Now()),
  }, SEP)
  SendAddonMessage("LeafVE", "WORKCRAFTERRESET:" .. payload, "GUILD")
end

function LeafVE:BroadcastWorkOrderCrafterSignupEntry(entry)
  if type(entry) ~= "table" or not entry.player or not entry.profession or not InGuild() then
    return
  end

  local chunks = {}
  local currentChunk = ""
  local currentLen = 0
  local maxChunkLen = 170
  for i = 1, table.getn(entry.recipes or {}) do
    local token = tostring(entry.recipes[i] or "")
    if token ~= "" then
      local sepLen = currentLen > 0 and 1 or 0
      local tokenLen = string.len(token)
      if currentLen > 0 and (currentLen + sepLen + tokenLen) > maxChunkLen then
        table.insert(chunks, currentChunk)
        currentChunk = token
        currentLen = tokenLen
      else
        currentChunk = currentLen > 0 and (currentChunk .. "," .. token) or token
        currentLen = currentLen + sepLen + tokenLen
      end
    end
  end
  if currentLen > 0 then
    table.insert(chunks, currentChunk)
  end
  if table.getn(chunks) < 1 then
    table.insert(chunks, "")
  end

  local totalChunks = table.getn(chunks)
  for chunkIndex = 1, totalChunks do
    local payload = table.concat({
      EncodeTalentField(entry.player),
      tostring(tonumber(entry.updatedAt) or Now()),
      EncodeTalentField(entry.profession),
      tostring(chunkIndex),
      tostring(totalChunks),
      EncodeTalentField(chunks[chunkIndex] or ""),
    }, SEP)
    SendAddonMessage("LeafVE", "WORKCRAFTER:" .. payload, "GUILD")
  end
end

function LeafVE:BroadcastMyWorkOrderCrafterSignup(force)
  EnsureDB()

  local me = ShortName(UnitName("player"))
  if not me or not InGuild() then
    return
  end

  self.lastWorkOrderCrafterBroadcastAt = self.lastWorkOrderCrafterBroadcastAt or 0
  local now = Now()
  if not force and (now - self.lastWorkOrderCrafterBroadcastAt) < 30 then
    return
  end

  local key = Lower(me)
  local meta = self:GetWorkOrderCrafterSignupMeta(me)
  local bucket = LeafVE_GlobalDB.workOrderCrafterSignups and LeafVE_GlobalDB.workOrderCrafterSignups[key]
  if type(meta) ~= "table" and type(bucket) ~= "table" then
    return
  end

  self.lastWorkOrderCrafterBroadcastAt = now
  self:BroadcastWorkOrderCrafterSignupReset(me, type(meta) == "table" and meta.updatedAt or now)

  for i = 1, table.getn(WORK_ORDER_PROFESSION_ORDER) do
    local profession = WORK_ORDER_PROFESSION_ORDER[i]
    local entry = type(bucket) == "table" and bucket[profession] or nil
    if type(entry) == "table" then
      self:BroadcastWorkOrderCrafterSignupEntry(entry)
    end
  end
end

function LeafVE:RequestWorkOrderCrafterSync(force)
  if not InGuild() then return end

  local now = Now()
  if not force and (now - (self.lastWorkOrderCrafterSyncRequestAt or 0)) < 20 then
    return
  end
  self.lastWorkOrderCrafterSyncRequestAt = now
  SendAddonMessage("LeafVE", force and "WORKCRAFTERREQ_FORCE" or "WORKCRAFTERREQ", "GUILD")
end

function LeafVE:HandleIncomingWorkOrderCrafterSignupReset(payload, sender)
  local fields = SplitByLiteralSep(payload, SEP)
  local playerName = ShortName(DecodeTalentField(fields[1] or ""))
  local updatedAt = tonumber(fields[2]) or 0
  local senderName = ShortName(sender)
  if not playerName or updatedAt < 1 then
    return
  end
  if senderName and Lower(senderName or "") ~= Lower(playerName or "") then
    return
  end

  EnsureDB()
  local currentUpdatedAt = self:GetWorkOrderCrafterSignupUpdatedAt(playerName)
  if updatedAt < currentUpdatedAt then
    return
  end

  local key = Lower(playerName)
  LeafVE_GlobalDB.workOrderCrafterSignups[key] = nil
  LeafVE_GlobalDB.workOrderCrafterSignupMeta[key] = NormalizeWorkOrderCrafterSignupMeta(playerName, updatedAt)
  self:RefreshWorkOrderCrafterViews()
end

function LeafVE:HandleIncomingWorkOrderCrafterSignup(payload, sender)
  local fields = SplitByLiteralSep(payload, SEP)
  if table.getn(fields) < 4 then
    return
  end

  local playerName = ShortName(DecodeTalentField(fields[1] or ""))
  local updatedAt = tonumber(fields[2]) or 0
  local profession = CanonicalWorkOrderProfession(DecodeTalentField(fields[3] or ""))
  local recipeList = DecodeTalentField(fields[4] or "")
  local senderName = ShortName(sender)
  if not playerName or not profession or updatedAt < 1 then
    return
  end
  if senderName and Lower(senderName or "") ~= Lower(playerName or "") then
    return
  end

  local recipes = nil
  if table.getn(fields) >= 6 then
    local chunkIndex = tonumber(fields[4]) or 1
    local totalChunks = tonumber(fields[5]) or 1
    recipeList = DecodeTalentField(fields[6] or "")
    self.workOrderCrafterSignupBuffer = self.workOrderCrafterSignupBuffer or {}

    local bufferKey = Lower(playerName) .. "::" .. Lower(profession) .. "::" .. tostring(updatedAt)
    local buffer = self.workOrderCrafterSignupBuffer[bufferKey]
    if type(buffer) ~= "table" or tonumber(buffer.totalChunks) ~= totalChunks then
      buffer = {
        totalChunks = totalChunks,
        parts = {},
      }
      self.workOrderCrafterSignupBuffer[bufferKey] = buffer
    end
    buffer.parts[chunkIndex] = recipeList

    local ready = true
    for i = 1, totalChunks do
      if buffer.parts[i] == nil then
        ready = false
        break
      end
    end
    if not ready then
      return
    end

    local combined = {}
    for i = 1, totalChunks do
      local part = buffer.parts[i]
      if part and part ~= "" then
        local partTokens = SplitByLiteralSep(part, ",")
        for j = 1, table.getn(partTokens) do
          table.insert(combined, partTokens[j])
        end
      end
    end
    self.workOrderCrafterSignupBuffer[bufferKey] = nil
    recipes = combined
  else
    recipes = {}
    if recipeList ~= "" then
      recipes = SplitByLiteralSep(recipeList, ",")
    end
  end

  local entry = NormalizeWorkOrderCrafterSignupEntry(playerName, profession, {
    player = playerName,
    profession = profession,
    updatedAt = updatedAt,
    recipes = recipes,
  })
  if not entry then
    return
  end

  EnsureDB()
  local currentUpdatedAt = self:GetWorkOrderCrafterSignupUpdatedAt(playerName)
  if updatedAt < currentUpdatedAt then
    return
  end

  local key = Lower(playerName)
  if type(LeafVE_GlobalDB.workOrderCrafterSignups[key]) ~= "table" then
    LeafVE_GlobalDB.workOrderCrafterSignups[key] = {}
  end
  LeafVE_GlobalDB.workOrderCrafterSignups[key][profession] = entry
  LeafVE_GlobalDB.workOrderCrafterSignupMeta[key] = NormalizeWorkOrderCrafterSignupMeta(playerName, updatedAt)
  self:RefreshWorkOrderCrafterViews()
end

function LeafVE:SaveWorkOrderCrafterSignups(selectionMap)
  EnsureDB()

  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local priorUpdatedAt = self:GetWorkOrderCrafterSignupUpdatedAt(me)
  local updatedAt = Now()
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  local newBucket = {}
  local professionCount = 0
  local totalRecipes = 0
  for i = 1, table.getn(WORK_ORDER_PROFESSION_ORDER) do
    local profession = WORK_ORDER_PROFESSION_ORDER[i]
    local rawTokens = {}
    local selected = type(selectionMap) == "table" and selectionMap[profession] or nil
    if type(selected) == "table" then
      for token, enabled in pairs(selected) do
        if enabled then
          table.insert(rawTokens, token)
        end
      end
    end

    local entry = NormalizeWorkOrderCrafterSignupEntry(me, profession, {
      player = me,
      profession = profession,
      updatedAt = updatedAt,
      recipes = rawTokens,
    })
    if entry then
      newBucket[profession] = entry
      professionCount = professionCount + 1
      totalRecipes = totalRecipes + table.getn(entry.recipes or {})
    end
  end

  local key = Lower(me)
  LeafVE_GlobalDB.workOrderCrafterSignupMeta[key] = NormalizeWorkOrderCrafterSignupMeta(me, updatedAt)
  if professionCount > 0 then
    LeafVE_GlobalDB.workOrderCrafterSignups[key] = newBucket
  else
    LeafVE_GlobalDB.workOrderCrafterSignups[key] = nil
  end

  self:BroadcastMyWorkOrderCrafterSignup(true)
  self:RefreshWorkOrderCrafterViews()

  return {
    player = me,
    updatedAt = updatedAt,
    professionCount = professionCount,
    totalRecipes = totalRecipes,
    removed = professionCount < 1,
  }
end

function NormalizeWorkOrderStatus(status)
  status = Lower(Trim(tostring(status or "open")))
  if status == "claimed" then
    status = "pending"
  end
  if status == "final" then
    status = "finalized"
  end
  if status ~= "open" and status ~= "pending" and status ~= "completed" and status ~= "cancelled" and status ~= "finalized" then
    status = "open"
  end
  return status
end

function LeafVE:GetEffectiveWorkOrderStatus(order, now)
  local status = NormalizeWorkOrderStatus(type(order) == "table" and order.status or "open")
  if status == "pending" then
    local expiresAt = tonumber(order and order.claimExpiresAt) or 0
    if expiresAt > 0 and (tonumber(now) or Now()) >= expiresAt then
      return "open"
    end
  end
  return status
end

function LeafVE:GetStoredWorkOrderFulfiller(order)
  return ShortName(order and (order.fulfiller or order.crafter) or nil)
end

function LeafVE:GetEffectiveWorkOrderFulfiller(order, now)
  if self:GetEffectiveWorkOrderStatus(order, now) ~= "pending" then
    return nil
  end
  return self:GetStoredWorkOrderFulfiller(order)
end

function LeafVE:BuildWorkOrderPickupLine(order, actorName)
  local actor = ShortName(actorName) or self:GetStoredWorkOrderFulfiller(order) or "Someone"
  if IsWorkOrderPartialClaim(order) and GetWorkOrderRequestedQuantity(order) > ClampWorkOrderQuantity(order and order.quantity or 1) then
    return tostring(actor) ..
      " reserved " .. tostring(order and order.recipeName or "an order") ..
      " (" .. tostring(ClampWorkOrderQuantity(order and order.quantity or 1)) .. "/" .. tostring(GetWorkOrderRequestedQuantity(order)) .. ")" ..
      " for " .. tostring(order and order.requester or "Unknown") ..
      ". Ready within 48 hours."
  end
  return tostring(actor) ..
    " picked up " .. tostring(order and order.recipeName or "an order") ..
    " for " .. tostring(order and order.requester or "Unknown") ..
    ". Ready within 48 hours."
end

function LeafVE:BuildWorkOrderCompletionLine(order, actorName)
  local actor = ShortName(actorName) or self:GetStoredWorkOrderFulfiller(order) or "Someone"
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  if fulfilledQuantity > 0 and requestedQuantity > fulfilledQuantity then
    return tostring(actor) ..
      " completed a partial fill of " .. tostring(order and order.recipeName or "an order") ..
      " (" .. tostring(fulfilledQuantity) .. "/" .. tostring(requestedQuantity) .. ")" ..
      " for " .. tostring(order and order.requester or "Unknown") .. "."
  end
  return tostring(actor) ..
    " completed " .. tostring(order and order.recipeName or "an order") ..
    " for " .. tostring(order and order.requester or "Unknown") .. "."
end

function LeafVE:BuildWorkOrderRevertLine(order, actorName)
  local actor = ShortName(actorName) or ShortName(order and order.requester) or "Someone"
  if IsWorkOrderPartialClaim(order) then
    return tostring(actor) ..
      " returned " .. tostring(order and order.recipeName or "an order") ..
      " (" .. tostring(ClampWorkOrderQuantity(order and order.quantity or 1)) .. "/" .. tostring(GetWorkOrderRequestedQuantity(order)) .. ")" ..
      " to the live board."
  end
  local fulfiller = self:GetStoredWorkOrderFulfiller(order) or "the fulfiller"
  local requestedQuantity = GetWorkOrderRequestedQuantity(order)
  local fulfilledQuantity = GetWorkOrderFulfilledQuantity(order)
  local quantityNote = ""
  if fulfilledQuantity > 0 and requestedQuantity > fulfilledQuantity then
    quantityNote = " (" .. tostring(fulfilledQuantity) .. "/" .. tostring(requestedQuantity) .. " was marked complete)"
  end
  return tostring(actor) ..
    " sent " .. tostring(order and order.recipeName or "an order") .. quantityNote ..
    " back to " .. tostring(fulfiller) ..
    ". Ready within 48 hours."
end

function LeafVE:ApplyWorkOrderFinalReward(order)
  EnsureDB()
  if type(order) ~= "table" or not order.id then
    return 0
  end

  local me = ShortName(UnitName("player"))
  local fulfiller = self:GetStoredWorkOrderFulfiller(order)
  if not me or not fulfiller or Lower(me) ~= Lower(fulfiller) then
    return 0
  end

  if LeafVE_DB.workOrderFinalRewardClaims[order.id] then
    return 0
  end
  LeafVE_DB.workOrderFinalRewardClaims[order.id] = Now()

  local today = DayKey()
  local daily = LeafVE_DB.workOrderFinalRewardDaily[me]
  if type(daily) ~= "table" or daily.date ~= today then
    daily = { date = today, earned = 0 }
    LeafVE_DB.workOrderFinalRewardDaily[me] = daily
  end

  local remaining = WORK_ORDER_FINAL_REWARD_DAILY_CAP - (tonumber(daily.earned) or 0)
  if remaining <= 0 then
    Print("|cFFFFAA00Work Order reward skipped - verification reward cap reached for today.|r")
    return 0
  end

  local carry = tonumber(LeafVE_DB.workOrderFinalRewardCarry[me]) or 0
  local rewardFloat = (WORK_ORDER_FINAL_REWARD_POINTS * GetWorkOrderCompletionRatio(order)) + carry
  local rewardWhole = math.floor(rewardFloat)
  local reward = rewardWhole
  if reward > remaining then
    reward = remaining
  end
  LeafVE_DB.workOrderFinalRewardCarry[me] = rewardFloat - rewardWhole
  if reward < 1 then
    return 0
  end

  local awarded = self:AddPoints(me, "G", reward, true)
  if not awarded or awarded <= 0 then
    if reward > 0 then
      Print("|cFFFFAA00Work Order reward could not be added because your daily point cap was reached.|r")
    end
    return 0
  end

  daily.earned = (daily.earned or 0) + awarded
  self:AddToHistory(me, "G", awarded, "Work order verified by " .. tostring(order.requester or "Unknown") .. ": " .. tostring(order.recipeName or "Work Order"))
  self:BroadcastLeaderboardData()
  Print("|cFF88CCFFWork Order|r Verified by " .. tostring(order.requester or "Unknown") .. ". +" .. tostring(awarded) .. " G awarded.")
  return awarded
end

function LeafVE:GenerateWorkOrderId(requesterName, createdAt)
  requesterName = ShortName(requesterName) or "unknown"
  createdAt = tonumber(createdAt) or Now()
  self.workOrderSerial = (self.workOrderSerial or 0) + 1
  return Lower(requesterName) .. "-" .. tostring(createdAt) .. "-" .. tostring(self.workOrderSerial)
end

function LeafVE:CreateWorkOrderPartialClaim(rootOrder, claimedQuantity, fulfillerName, updatedAt)
  EnsureDB()
  if type(rootOrder) ~= "table" then
    return nil, "Order not found."
  end
  if IsWorkOrderPartialClaim(rootOrder) then
    return nil, "Partial claims cannot be claimed again."
  end

  local requester = ShortName(rootOrder.requester)
  local fulfiller = ShortName(fulfillerName)
  if not requester or not fulfiller then
    return nil, "Player name could not be determined."
  end

  local availableQuantity = ClampWorkOrderQuantity(rootOrder.quantity or 1)
  claimedQuantity = ClampWorkOrderQuantity(claimedQuantity or availableQuantity)
  if claimedQuantity > availableQuantity then
    return nil, "Enter a quantity between 1 and " .. tostring(availableQuantity) .. "."
  end

  updatedAt = tonumber(updatedAt) or Now()
  local originalRequestedQuantity = GetWorkOrderRequestedQuantity(rootOrder)
  local claimedTipCopper, remainingTipCopper = SplitWorkOrderTipByQuantity(rootOrder.tipCopper, claimedQuantity, availableQuantity)

  rootOrder.quantity = availableQuantity - claimedQuantity
  rootOrder.requestedQuantity = originalRequestedQuantity
  rootOrder.completedQuantity = 0
  rootOrder.tipCopper = remainingTipCopper
  rootOrder.updatedAt = updatedAt
  rootOrder.claimExpiresAt = 0
  rootOrder.status = rootOrder.quantity > 0 and "open" or "cancelled"
  self:StoreWorkOrderRecord(rootOrder)
  self:BroadcastWorkOrder(rootOrder)

  local childUpdatedAt = updatedAt + 1
  local partialOrder = {
    id = self:GenerateWorkOrderId(requester, childUpdatedAt),
    parentOrderId = rootOrder.id,
    requester = requester,
    fulfiller = fulfiller,
    crafter = fulfiller,
    createdAt = tonumber(rootOrder.createdAt) or childUpdatedAt,
    updatedAt = childUpdatedAt,
    claimExpiresAt = childUpdatedAt + (48 * SECONDS_PER_HOUR),
    completedAt = 0,
    profession = rootOrder.profession,
    recipeName = rootOrder.recipeName,
    itemId = rootOrder.itemId,
    spellId = rootOrder.spellId,
    quantity = claimedQuantity,
    requestedQuantity = originalRequestedQuantity,
    completedQuantity = 0,
    tipCopper = claimedTipCopper,
    matsMode = NormalizeWorkOrderMatsMode(rootOrder.matsMode),
    icon = rootOrder.icon,
    status = "pending",
  }

  local stored = self:StoreWorkOrderRecord(partialOrder)
  if stored then
    self:BroadcastWorkOrder(stored)
  end
  return stored
end

function LeafVE:RestoreWorkOrderPartialQuantity(partialOrder, updatedAt)
  EnsureDB()
  if not IsWorkOrderPartialClaim(partialOrder) then
    return nil
  end

  local rootId = GetWorkOrderParentId(partialOrder)
  local rootOrder = rootId and LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[rootId] or nil
  if type(rootOrder) ~= "table" then
    return nil
  end

  updatedAt = tonumber(updatedAt) or Now()
  rootOrder.quantity = ClampWorkOrderQuantity((tonumber(rootOrder.quantity) or 0) + ClampWorkOrderQuantity(partialOrder.quantity or 1))
  rootOrder.requestedQuantity = math.max(GetWorkOrderRequestedQuantity(rootOrder), GetWorkOrderRequestedQuantity(partialOrder))
  rootOrder.completedQuantity = 0
  rootOrder.tipCopper = ClampWorkOrderTipCopper((tonumber(rootOrder.tipCopper) or 0) + ClampWorkOrderTipCopper(partialOrder.tipCopper))
  rootOrder.updatedAt = updatedAt
  rootOrder.status = "open"
  rootOrder.claimExpiresAt = 0
  self:StoreWorkOrderRecord(rootOrder)
  self:BroadcastWorkOrder(rootOrder)
  return rootOrder
end

function LeafVE:CreateWorkOrderFollowup(order, remainingQuantity, remainingTipCopper, createdAt)
  if type(order) ~= "table" then
    return nil
  end

  remainingQuantity = ClampWorkOrderQuantity(remainingQuantity)
  remainingTipCopper = ClampWorkOrderTipCopper(remainingTipCopper)
  createdAt = tonumber(createdAt) or Now()
  local requester = ShortName(order.requester)
  if not requester then
    return nil
  end

  local followup = {
    id = self:GenerateWorkOrderId(requester, createdAt),
    requester = requester,
    fulfiller = nil,
    crafter = nil,
    createdAt = createdAt,
    updatedAt = createdAt,
    claimExpiresAt = 0,
    completedAt = 0,
    profession = order.profession,
    recipeName = order.recipeName,
    itemId = order.itemId,
    spellId = order.spellId,
    quantity = remainingQuantity,
    requestedQuantity = remainingQuantity,
    completedQuantity = 0,
    tipCopper = remainingTipCopper,
    matsMode = NormalizeWorkOrderMatsMode(order.matsMode),
    icon = order.icon,
    status = "open",
  }

  local stored = self:StoreWorkOrderRecord(followup)
  if stored then
    self:BroadcastWorkOrder(stored)
  end
  return stored
end

function CreateWorkOrderReputationEntry(playerName)
  return {
    name = ShortName(playerName) or tostring(playerName or "Unknown"),
    totalRep = 0,
    crafterRep = 0,
    requesterRep = 0,
    dutyBonusRep = 0,
    ordersCompleted = 0,
    ordersVerified = 0,
    totalTurnaroundSeconds = 0,
    turnaroundSamples = 0,
    avgTurnaroundHours = 0,
    totalVerifyDelaySeconds = 0,
    verifyDelaySamples = 0,
    avgVerifyDelayHours = 0,
    crafterMatsOrders = 0,
    fastCrafts12h = 0,
    fastCrafts24h = 0,
    promptVerifies24h = 0,
    professionRep = {},
    professionRanked = {},
    recentHistory = {},
    topProfession = nil,
    topProfessionRep = 0,
    breakdown = {
      baseCrafterRep = 0,
      baseRequesterRep = 0,
      crafterMatsBonus = 0,
      fastCraftBonus = 0,
      promptVerifyBonus = 0,
      dutyBonusRep = 0,
      pairReduction = 0,
      pairScaledOrders = 0,
    },
  }
end

function BuildWorkOrderReputationPairKey(a, b)
  local an = Lower(ShortName(a) or "")
  local bn = Lower(ShortName(b) or "")
  if an == "" or bn == "" then
    return nil
  end
  if an < bn then
    return an .. "::" .. bn
  end
  return bn .. "::" .. an
end

function GetWorkOrderReputationPairFactor(recentCount)
  recentCount = tonumber(recentCount) or 0
  if recentCount < 3 then
    return 1
  end
  if recentCount < 6 then
    return 0.5
  end
  return 0.2
end

function RoundWorkOrderReputationValue(value)
  return math.max(0, math.floor((tonumber(value) or 0) + 0.5))
end

function GetWorkOrderVerificationTimestamp(order)
  local verifiedAt = tonumber(order and order.updatedAt) or 0
  if verifiedAt < 1 then
    verifiedAt = tonumber(order and order.completedAt) or 0
  end
  if verifiedAt < 1 then
    verifiedAt = tonumber(order and order.createdAt) or 0
  end
  return verifiedAt
end

function GetWorkOrderReputationCrafterMatsBonus(order)
  if NormalizeWorkOrderMatsMode(order and order.matsMode) == "crafter" then
    return WORK_ORDER_REPUTATION_CRAFTER_MATS_BONUS
  end
  return 0
end

function GetWorkOrderReputationSpeedBonus(turnaroundSeconds)
  turnaroundSeconds = tonumber(turnaroundSeconds) or 0
  if turnaroundSeconds < 0 then
    return 0
  end
  if turnaroundSeconds > 0 and turnaroundSeconds <= (12 * SECONDS_PER_HOUR) then
    return WORK_ORDER_REPUTATION_FAST_COMPLETE_12H_BONUS
  end
  if turnaroundSeconds > 0 and turnaroundSeconds <= (24 * SECONDS_PER_HOUR) then
    return WORK_ORDER_REPUTATION_FAST_COMPLETE_24H_BONUS
  end
  return 0
end

function GetWorkOrderReputationPromptVerifyBonus(order, verifiedAt)
  local completedAt = tonumber(order and order.completedAt) or 0
  verifiedAt = tonumber(verifiedAt) or 0
  if completedAt > 0 and verifiedAt >= completedAt and (verifiedAt - completedAt) <= (24 * SECONDS_PER_HOUR) then
    return WORK_ORDER_REPUTATION_PROMPT_VERIFY_24H_BONUS
  end
  return 0
end

function LeafVE:GetWorkOrderReputationIdentityName(playerName)
  EnsureDB()

  local resolvedName = ShortName(playerName)
  if not resolvedName then
    return nil
  end

  local links = LeafVE_GlobalDB.workOrderIdentityLinks or {}
  local seen = {}
  local hops = 0
  while resolvedName and hops < 12 do
    local key = Lower(resolvedName or "")
    if key == "" or seen[key] then
      break
    end
    seen[key] = true
    hops = hops + 1

    local mappedName = ShortName(links[key])
    if not mappedName or mappedName == "" or SamePlayerName(mappedName, resolvedName) then
      break
    end
    resolvedName = mappedName
  end

  return resolvedName
end

function LeafVE:SetWorkOrderReputationIdentityLink(playerName, identityName, silent)
  EnsureDB()

  local player = ShortName(playerName)
  if not player then
    return nil, "Player name could not be determined."
  end

  local store = LeafVE_GlobalDB.workOrderIdentityLinks or {}
  LeafVE_GlobalDB.workOrderIdentityLinks = store

  local key = Lower(player)
  local identity = ShortName(identityName)
  if not identity or identity == "" or SamePlayerName(player, identity) then
    store[key] = nil
    self.workOrderReputationDirty = true
    if not silent then
      Print("|cFF88CCFFWork Order Reputation|r Cleared linked identity for " .. tostring(player) .. ".")
    end
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.workOrderRep
      and LeafVE.UI.panels.workOrderRep.IsVisible and LeafVE.UI.panels.workOrderRep:IsVisible()
      and LeafVE.UI.RefreshWorkOrderReputationPanel then
      LeafVE.UI:RefreshWorkOrderReputationPanel()
    end
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.shinobiReputation
      and LeafVE.UI.panels.shinobiReputation.IsVisible and LeafVE.UI.panels.shinobiReputation:IsVisible()
      and LeafVE.UI.RefreshShinobiReputationLeaderboard then
      LeafVE.UI:RefreshShinobiReputationLeaderboard()
    end
    return true
  end

  store[key] = identity
  self.workOrderReputationDirty = true
  if not silent then
    Print("|cFF88CCFFWork Order Reputation|r " .. tostring(player) .. " now resolves to " .. tostring(identity) .. ".")
  end
  if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.workOrderRep
    and LeafVE.UI.panels.workOrderRep.IsVisible and LeafVE.UI.panels.workOrderRep:IsVisible()
    and LeafVE.UI.RefreshWorkOrderReputationPanel then
    LeafVE.UI:RefreshWorkOrderReputationPanel()
  end
  if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.shinobiReputation
    and LeafVE.UI.panels.shinobiReputation.IsVisible and LeafVE.UI.panels.shinobiReputation:IsVisible()
    and LeafVE.UI.RefreshShinobiReputationLeaderboard then
    LeafVE.UI:RefreshShinobiReputationLeaderboard()
  end
  return true
end

function LeafVEEllipsizeText(text, maxLen)
  text = Trim(tostring(text or ""))
  maxLen = tonumber(maxLen) or 0
  if maxLen > 3 and string.len(text) > maxLen then
    return string.sub(text, 1, maxLen - 3) .. "..."
  end
  return text
end

function FormatWorkOrderReputationHistoryLine(historyEntry)
  if type(historyEntry) ~= "table" then
    return "|cFF777777No verified orders yet.|r"
  end

  local verifiedAt = tonumber(historyEntry.verifiedAt) or 0
  local whenText = verifiedAt > 0 and date("%m/%d", verifiedAt) or "--/--"
  local roleText = historyEntry.role == "crafter" and "Craft" or "Req"
  local otherPrefix = historyEntry.role == "crafter" and "for " or "by "
  local recipeName = LeafVEEllipsizeText(historyEntry.recipeName or "Work Order", 16)
  local otherName = LeafVEEllipsizeText(historyEntry.otherPlayer or "Unknown", 10)
  local repGain = tonumber(historyEntry.repGain) or 0
  local turnaroundHours = tonumber(historyEntry.turnaroundHours) or 0
  local turnaroundText = ""
  if turnaroundHours > 0 then
    turnaroundText = " | " .. string.format("%.1fh", turnaroundHours)
  end

  return whenText .. " [" .. roleText .. "] " .. recipeName .. " " .. otherPrefix .. otherName .. " | +" .. tostring(repGain) .. turnaroundText
end

function LeafVE:GetWorkOrderReputationTierInfo(totalRep)
  totalRep = math.max(0, math.floor(tonumber(totalRep) or 0))

  local tiers = WORK_ORDER_REPUTATION_TIERS or {}
  local currentTier = tiers[1] or { name = "Leaf Apprentice", min = 0 }
  local nextTier = nil

  for i = 1, table.getn(tiers) do
    local tier = tiers[i]
    local candidateNext = tiers[i + 1]
    if not candidateNext or totalRep < (candidateNext.min or 0) then
      currentTier = tier
      nextTier = candidateNext
      break
    end
  end

  local currentMin = tonumber(currentTier.min) or 0
  local nextMin = nextTier and (tonumber(nextTier.min) or currentMin) or nil
  local progressValue = totalRep - currentMin
  if progressValue < 0 then
    progressValue = 0
  end

  local progressMax = nextMin and math.max(1, nextMin - currentMin) or 0
  if nextTier and progressValue > progressMax then
    progressValue = progressMax
  end

  return {
    current = currentTier,
    next = nextTier,
    currentMin = currentMin,
    nextMin = nextMin,
    progressValue = progressValue,
    progressMax = progressMax,
  }
end

function LeafVE:GetWorkOrderReputationSnapshot()
  EnsureDB()

  if self.workOrderReputationCache and not self.workOrderReputationDirty then
    return self.workOrderReputationCache
  end

  local snapshot = {
    players = {},
    ranked = {},
    topCrafters = {},
    topRequesters = {},
    totalVerifiedOrders = 0,
    identitySkippedOrders = 0,
  }

  local finalizedOrders = {}
  local pairWindows = {}
  local now = Now()
  for _, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    if type(order) == "table" and self:GetEffectiveWorkOrderStatus(order, now) == "finalized" then
      table.insert(finalizedOrders, order)
    end
  end

  table.sort(finalizedOrders, function(a, b)
    local aVerifiedAt = GetWorkOrderVerificationTimestamp(a)
    local bVerifiedAt = GetWorkOrderVerificationTimestamp(b)
    if aVerifiedAt == bVerifiedAt then
      local aKey = Lower(tostring(a.id or a.recipeName or "")) or ""
      local bKey = Lower(tostring(b.id or b.recipeName or "")) or ""
      if aKey == bKey then
        return (tonumber(a.createdAt) or 0) < (tonumber(b.createdAt) or 0)
      end
      return aKey < bKey
    end
    return aVerifiedAt < bVerifiedAt
  end)

  for i = 1, table.getn(finalizedOrders) do
    local order = finalizedOrders[i]
    local requester = ShortName(order.requester)
    local crafter = ShortName(self:GetStoredWorkOrderFulfiller(order) or order.crafter or order.fulfiller)
    if requester and crafter and not SamePlayerName(requester, crafter) then
      local requesterIdentity = self:GetWorkOrderReputationIdentityName(requester) or requester
      local crafterIdentity = self:GetWorkOrderReputationIdentityName(crafter) or crafter
      if SamePlayerName(requesterIdentity, crafterIdentity) then
        snapshot.identitySkippedOrders = (tonumber(snapshot.identitySkippedOrders) or 0) + 1
      else
        local requesterKey = Lower(requesterIdentity)
        local crafterKey = Lower(crafterIdentity)

        if not snapshot.players[requesterKey] then
          snapshot.players[requesterKey] = CreateWorkOrderReputationEntry(requesterIdentity)
        end
        if not snapshot.players[crafterKey] then
          snapshot.players[crafterKey] = CreateWorkOrderReputationEntry(crafterIdentity)
        end

        local requesterEntry = snapshot.players[requesterKey]
        local crafterEntry = snapshot.players[crafterKey]
        local verifiedAt = GetWorkOrderVerificationTimestamp(order)
        local pairFactor = 1
        local pairKey = BuildWorkOrderReputationPairKey(requesterIdentity, crafterIdentity)
        local pairWindow = nil

        if pairKey then
          pairWindow = pairWindows[pairKey]
          if not pairWindow then
            pairWindow = {}
            pairWindows[pairKey] = pairWindow
          end
          if verifiedAt > 0 then
            local cutoff = verifiedAt - (7 * SECONDS_PER_DAY)
            local kept = {}
            for j = 1, table.getn(pairWindow) do
              if (tonumber(pairWindow[j]) or 0) >= cutoff then
                table.insert(kept, pairWindow[j])
              end
            end
            pairWindow = kept
            pairWindows[pairKey] = pairWindow
          end
          pairFactor = GetWorkOrderReputationPairFactor(table.getn(pairWindow))
        end

        local turnaroundStart = tonumber(order.createdAt) or 0
        local completedAt = tonumber(order.completedAt) or 0
        local turnaroundEnd = completedAt
        if turnaroundEnd < 1 then
          turnaroundEnd = tonumber(order.updatedAt) or 0
        end
        local turnaroundSeconds = turnaroundEnd - turnaroundStart
        local turnaroundHours = 0
        if turnaroundStart > 0 and turnaroundEnd > 0 and turnaroundSeconds >= 0 then
          turnaroundHours = turnaroundSeconds / SECONDS_PER_HOUR
          requesterEntry.totalTurnaroundSeconds = requesterEntry.totalTurnaroundSeconds + turnaroundSeconds
          requesterEntry.turnaroundSamples = requesterEntry.turnaroundSamples + 1

          crafterEntry.totalTurnaroundSeconds = crafterEntry.totalTurnaroundSeconds + turnaroundSeconds
          crafterEntry.turnaroundSamples = crafterEntry.turnaroundSamples + 1
        else
          turnaroundSeconds = 0
        end

        local verifyDelaySeconds = 0
        if completedAt > 0 and verifiedAt >= completedAt then
          verifyDelaySeconds = verifiedAt - completedAt
          requesterEntry.totalVerifyDelaySeconds = requesterEntry.totalVerifyDelaySeconds + verifyDelaySeconds
          requesterEntry.verifyDelaySamples = requesterEntry.verifyDelaySamples + 1
          crafterEntry.totalVerifyDelaySeconds = crafterEntry.totalVerifyDelaySeconds + verifyDelaySeconds
          crafterEntry.verifyDelaySamples = crafterEntry.verifyDelaySamples + 1
        end

        local completionRatio = GetWorkOrderCompletionRatio(order)
        local crafterMatsBonus = GetWorkOrderReputationCrafterMatsBonus(order) * completionRatio
        local speedBonus = (completedAt > 0 and GetWorkOrderReputationSpeedBonus(turnaroundSeconds) or 0) * completionRatio
        local promptVerifyBonus = GetWorkOrderReputationPromptVerifyBonus(order, verifiedAt) * completionRatio
        local requesterBaseRep = WORK_ORDER_REPUTATION_REQUESTER_REP * completionRatio
        local crafterBaseRep = WORK_ORDER_REPUTATION_CRAFTER_REP * completionRatio
        local requesterBaseTotal = requesterBaseRep + promptVerifyBonus
        local crafterBaseTotal = crafterBaseRep + crafterMatsBonus + speedBonus
        local requesterRepGain = requesterBaseTotal * pairFactor
        local crafterRepGain = crafterBaseTotal * pairFactor

        requesterEntry.requesterRep = requesterEntry.requesterRep + requesterRepGain
        requesterEntry.totalRep = requesterEntry.totalRep + requesterRepGain
        requesterEntry.ordersVerified = requesterEntry.ordersVerified + 1
        requesterEntry.breakdown.baseRequesterRep = (tonumber(requesterEntry.breakdown.baseRequesterRep) or 0) + requesterBaseRep
        requesterEntry.breakdown.promptVerifyBonus = (tonumber(requesterEntry.breakdown.promptVerifyBonus) or 0) + promptVerifyBonus
        if promptVerifyBonus > 0 then
          requesterEntry.promptVerifies24h = (tonumber(requesterEntry.promptVerifies24h) or 0) + 1
        end
        if requesterRepGain + 0.0001 < requesterBaseTotal then
          requesterEntry.breakdown.pairReduction = (tonumber(requesterEntry.breakdown.pairReduction) or 0) + (requesterBaseTotal - requesterRepGain)
          requesterEntry.breakdown.pairScaledOrders = (tonumber(requesterEntry.breakdown.pairScaledOrders) or 0) + 1
        end

        crafterEntry.crafterRep = crafterEntry.crafterRep + crafterRepGain
        crafterEntry.totalRep = crafterEntry.totalRep + crafterRepGain
        crafterEntry.ordersCompleted = crafterEntry.ordersCompleted + 1
        crafterEntry.breakdown.baseCrafterRep = (tonumber(crafterEntry.breakdown.baseCrafterRep) or 0) + crafterBaseRep
        crafterEntry.breakdown.crafterMatsBonus = (tonumber(crafterEntry.breakdown.crafterMatsBonus) or 0) + crafterMatsBonus
        crafterEntry.breakdown.fastCraftBonus = (tonumber(crafterEntry.breakdown.fastCraftBonus) or 0) + speedBonus
        if crafterMatsBonus > 0 then
          crafterEntry.crafterMatsOrders = (tonumber(crafterEntry.crafterMatsOrders) or 0) + 1
        end
        if speedBonus >= (WORK_ORDER_REPUTATION_FAST_COMPLETE_12H_BONUS * completionRatio) and completionRatio > 0 then
          crafterEntry.fastCrafts12h = (tonumber(crafterEntry.fastCrafts12h) or 0) + 1
        elseif speedBonus > 0 then
          crafterEntry.fastCrafts24h = (tonumber(crafterEntry.fastCrafts24h) or 0) + 1
        end
        if crafterRepGain + 0.0001 < crafterBaseTotal then
          crafterEntry.breakdown.pairReduction = (tonumber(crafterEntry.breakdown.pairReduction) or 0) + (crafterBaseTotal - crafterRepGain)
          crafterEntry.breakdown.pairScaledOrders = (tonumber(crafterEntry.breakdown.pairScaledOrders) or 0) + 1
        end

        local professionName = CanonicalWorkOrderProfession(order.profession) or Trim(tostring(order.profession or ""))
        if professionName ~= "" then
          crafterEntry.professionRep[professionName] = (tonumber(crafterEntry.professionRep[professionName]) or 0) + crafterRepGain
        end

        local recipeName = Trim(tostring(order.recipeName or "Work Order"))
        table.insert(requesterEntry.recentHistory, {
          verifiedAt = verifiedAt,
          role = "requester",
          otherPlayer = crafter,
          repGain = requesterRepGain,
          profession = professionName,
          recipeName = recipeName,
          turnaroundHours = turnaroundHours,
          pairFactor = pairFactor,
        })
        table.insert(crafterEntry.recentHistory, {
          verifiedAt = verifiedAt,
          role = "crafter",
          otherPlayer = requester,
          repGain = crafterRepGain,
          profession = professionName,
          recipeName = recipeName,
          turnaroundHours = turnaroundHours,
          pairFactor = pairFactor,
        })

        if pairWindow then
          table.insert(pairWindow, verifiedAt > 0 and verifiedAt or (tonumber(order.createdAt) or 0))
        end

        snapshot.totalVerifiedOrders = snapshot.totalVerifiedOrders + 1
      end
    end
  end

  for _, bonusEntry in pairs(LeafVE_GlobalDB.shinobiDutyRepBonuses or {}) do
    if type(bonusEntry) == "table" then
      local playerName = ShortName(bonusEntry.name)
      local dutyRep = math.max(0, tonumber(bonusEntry.amount) or 0)
      if playerName and dutyRep > 0 then
        local identityName = self:GetWorkOrderReputationIdentityName(playerName) or playerName
        local identityKey = Lower(identityName or "")
        if identityKey ~= "" then
          if not snapshot.players[identityKey] then
            snapshot.players[identityKey] = CreateWorkOrderReputationEntry(identityName)
          end
          local entry = snapshot.players[identityKey]
          entry.dutyBonusRep = math.max(tonumber(entry.dutyBonusRep) or 0, dutyRep)
          entry.breakdown.dutyBonusRep = math.max(tonumber(entry.breakdown.dutyBonusRep) or 0, dutyRep)
          entry.totalRep = (tonumber(entry.totalRep) or 0) + dutyRep
        end
      end
    end
  end

  for _, entry in pairs(snapshot.players) do
    if entry.turnaroundSamples > 0 then
      entry.avgTurnaroundHours = entry.totalTurnaroundSeconds / entry.turnaroundSamples / SECONDS_PER_HOUR
    else
      entry.avgTurnaroundHours = 0
    end
    if entry.verifyDelaySamples > 0 then
      entry.avgVerifyDelayHours = entry.totalVerifyDelaySeconds / entry.verifyDelaySamples / SECONDS_PER_HOUR
    else
      entry.avgVerifyDelayHours = 0
    end

    entry.totalRep = RoundWorkOrderReputationValue(entry.totalRep)
    entry.crafterRep = RoundWorkOrderReputationValue(entry.crafterRep)
    entry.requesterRep = RoundWorkOrderReputationValue(entry.requesterRep)
    entry.dutyBonusRep = RoundWorkOrderReputationValue(entry.dutyBonusRep)
    entry.breakdown.baseCrafterRep = RoundWorkOrderReputationValue(entry.breakdown.baseCrafterRep)
    entry.breakdown.baseRequesterRep = RoundWorkOrderReputationValue(entry.breakdown.baseRequesterRep)
    entry.breakdown.crafterMatsBonus = RoundWorkOrderReputationValue(entry.breakdown.crafterMatsBonus)
    entry.breakdown.fastCraftBonus = RoundWorkOrderReputationValue(entry.breakdown.fastCraftBonus)
    entry.breakdown.promptVerifyBonus = RoundWorkOrderReputationValue(entry.breakdown.promptVerifyBonus)
    entry.breakdown.dutyBonusRep = RoundWorkOrderReputationValue(entry.breakdown.dutyBonusRep)
    entry.breakdown.pairReduction = RoundWorkOrderReputationValue(entry.breakdown.pairReduction)

    for professionName, professionRep in pairs(entry.professionRep or {}) do
      entry.professionRep[professionName] = RoundWorkOrderReputationValue(professionRep)
      professionRep = entry.professionRep[professionName]
      professionRep = tonumber(professionRep) or 0
      table.insert(entry.professionRanked, {
        name = professionName,
        rep = professionRep,
      })
    end
    table.sort(entry.professionRanked, function(a, b)
      if (a.rep or 0) == (b.rep or 0) then
        return Lower(a.name or "") < Lower(b.name or "")
      end
      return (a.rep or 0) > (b.rep or 0)
    end)
    if table.getn(entry.professionRanked) > 0 then
      entry.topProfession = entry.professionRanked[1].name
      entry.topProfessionRep = tonumber(entry.professionRanked[1].rep) or 0
    else
      entry.topProfession = nil
      entry.topProfessionRep = 0
    end

    table.sort(entry.recentHistory, function(a, b)
      local aVerifiedAt = tonumber(a and a.verifiedAt) or 0
      local bVerifiedAt = tonumber(b and b.verifiedAt) or 0
      if aVerifiedAt == bVerifiedAt then
        return Lower(tostring(a and a.recipeName or "")) < Lower(tostring(b and b.recipeName or ""))
      end
      return aVerifiedAt > bVerifiedAt
    end)
    while table.getn(entry.recentHistory) > 10 do
      table.remove(entry.recentHistory)
    end
    for i = 1, table.getn(entry.recentHistory) do
      if entry.recentHistory[i] then
        entry.recentHistory[i].repGain = RoundWorkOrderReputationValue(entry.recentHistory[i].repGain)
      end
    end

    entry.tierInfo = self:GetWorkOrderReputationTierInfo(entry.totalRep)

    table.insert(snapshot.ranked, entry)
    table.insert(snapshot.topCrafters, entry)
    table.insert(snapshot.topRequesters, entry)
  end

  table.sort(snapshot.ranked, function(a, b)
    if (a.totalRep or 0) == (b.totalRep or 0) then
      return Lower(a.name or "") < Lower(b.name or "")
    end
    return (a.totalRep or 0) > (b.totalRep or 0)
  end)
  table.sort(snapshot.topCrafters, function(a, b)
    if (a.crafterRep or 0) == (b.crafterRep or 0) then
      if (a.totalRep or 0) == (b.totalRep or 0) then
        return Lower(a.name or "") < Lower(b.name or "")
      end
      return (a.totalRep or 0) > (b.totalRep or 0)
    end
    return (a.crafterRep or 0) > (b.crafterRep or 0)
  end)
  table.sort(snapshot.topRequesters, function(a, b)
    if (a.requesterRep or 0) == (b.requesterRep or 0) then
      if (a.totalRep or 0) == (b.totalRep or 0) then
        return Lower(a.name or "") < Lower(b.name or "")
      end
      return (a.totalRep or 0) > (b.totalRep or 0)
    end
    return (a.requesterRep or 0) > (b.requesterRep or 0)
  end)

  self.workOrderReputationCache = snapshot
  self.workOrderReputationDirty = nil
  return snapshot
end

function LeafVE:GetWorkOrderReputationForPlayer(playerName)
  local snapshot = self:GetWorkOrderReputationSnapshot()
  local identityName = self:GetWorkOrderReputationIdentityName(playerName) or ShortName(playerName)
  local key = Lower(identityName or "")
  local entry = snapshot.players[key]
  if entry then
    return entry, snapshot
  end

  local emptyEntry = CreateWorkOrderReputationEntry(identityName or playerName)
  emptyEntry.tierInfo = self:GetWorkOrderReputationTierInfo(emptyEntry.totalRep)
  return emptyEntry, snapshot
end

function GetWorkOrderReputationTierVisual(tierInfo)
  local tierName = tostring(tierInfo and tierInfo.current and tierInfo.current.name or "Leaf Apprentice")
  local tierIndex = 1
  for i = 1, table.getn(WORK_ORDER_REPUTATION_TIERS or {}) do
    local tier = WORK_ORDER_REPUTATION_TIERS[i]
    if tier and tier.name == tierName then
      tierIndex = i
      break
    end
  end

  local badgeIconIndex = 6 - tierIndex
  if badgeIconIndex < 1 then
    badgeIconIndex = 1
  end

  local color = {THEME.leaf[1], THEME.leaf[2], THEME.leaf[3]}
  if tierIndex == 2 then
    color = {0.65, 0.85, 1.0}
  elseif tierIndex == 3 then
    color = {0.82, 0.7, 1.0}
  elseif tierIndex == 4 then
    color = {1.0, 0.84, 0.35}
  elseif tierIndex >= 5 then
    color = {1.0, 0.55, 0.2}
  end

  return tierName, tierIndex, badgeIconIndex, color
end

function GetWorkOrderCrafterRankLabel(rank)
  rank = tonumber(rank) or 0
  if rank < 1 or rank > 5 then
    return nil
  end
  return "#" .. tostring(rank) .. " Ranked Crafter"
end

function GetWeeklyCharacterRankLabel(rank)
  rank = tonumber(rank) or 0
  if rank < 1 or rank > 5 then
    return nil
  end
  return "#" .. tostring(rank) .. " Ranked Shinobi"
end

function GetWorkOrderCrafterRankColor(rank)
  rank = tonumber(rank) or 0
  if rank == 1 then
    return 1.0, 0.82, 0.2
  elseif rank == 2 then
    return 0.78, 0.86, 1.0
  elseif rank == 3 then
    return 0.93, 0.66, 0.4
  elseif rank == 4 then
    return 0.6, 0.9, 0.6
  elseif rank == 5 then
    return 0.76, 0.76, 0.76
  end
  return THEME.gold[1], THEME.gold[2], THEME.gold[3]
end

function GetWeeklyCharacterRankColor(rank)
  return GetWorkOrderCrafterRankColor(rank)
end

function LeafVE:GetWorkOrderCrafterRankInfo(playerName, snapshot)
  playerName = ShortName(playerName)
  if not playerName then
    return nil, nil
  end

  snapshot = snapshot or self:GetWorkOrderReputationSnapshot()
  local identityName = self:GetWorkOrderReputationIdentityName(playerName) or playerName
  local targetKey = Lower(identityName or "")
  if targetKey == "" then
    return nil, nil
  end

  local visibleRank = 0
  for i = 1, table.getn(snapshot and snapshot.topCrafters or {}) do
    local leader = snapshot.topCrafters[i]
    if leader and (tonumber(leader.crafterRep) or 0) > 0 then
      visibleRank = visibleRank + 1
      if Lower(leader.name or "") == targetKey then
        if visibleRank <= 5 then
          return visibleRank, leader
        end
        return nil, leader
      end
      if visibleRank >= 5 then
        break
      end
    end
  end
  return nil, nil
end

function LeafVE:GetWeeklyCharacterRankInfo(playerName, leaders)
  playerName = ShortName(playerName)
  if not playerName then
    return nil, nil
  end

  leaders = leaders or self:GetWeeklyLeaderboardLeadersForWeek(WeekKey())
  for i = 1, math.min(5, table.getn(leaders or {})) do
    local leader = leaders[i]
    if type(leader) == "table" and SamePlayerName(leader.name, playerName) then
      return i, leader
    end
  end
  return nil, nil
end

function FormatWorkOrderRemainingTime(expiresAt, now)
  expiresAt = tonumber(expiresAt) or 0
  now = tonumber(now) or Now()
  if expiresAt <= now then
    return "Expired"
  end

  local remaining = expiresAt - now
  local days = math.floor(remaining / SECONDS_PER_DAY)
  local hours = math.floor(PositiveModulo(remaining, SECONDS_PER_DAY) / SECONDS_PER_HOUR)
  local mins = math.floor(PositiveModulo(remaining, SECONDS_PER_HOUR) / 60)
  if days > 0 then
    return tostring(days) .. "d " .. tostring(hours) .. "h"
  end
  if hours > 0 then
    return tostring(hours) .. "h " .. tostring(mins) .. "m"
  end
  return tostring(math.max(1, mins)) .. "m"
end

function LeafVE:GetLiveWorkOrders()
  EnsureDB()
  local now = Now()
  local orders = {}
  for _, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    if type(order) == "table" and self:IsValidWorkOrderRecord(order) then
      local status = self:GetEffectiveWorkOrderStatus(order, now)
      if (status == "open" and (tonumber(order.quantity) or 0) > 0) or status == "pending" then
        table.insert(orders, order)
      end
    end
  end

  table.sort(orders, function(a, b)
    local aStatus = LeafVE:GetEffectiveWorkOrderStatus(a, now)
    local bStatus = LeafVE:GetEffectiveWorkOrderStatus(b, now)
    if aStatus ~= bStatus then
      return aStatus == "open"
    end

    if aStatus == "pending" then
      local aExpires = tonumber(a.claimExpiresAt or 0) or 0
      local bExpires = tonumber(b.claimExpiresAt or 0) or 0
      if aExpires ~= bExpires then
        return aExpires < bExpires
      end
    end

    local aUpdated = tonumber(a.updatedAt or a.createdAt or 0) or 0
    local bUpdated = tonumber(b.updatedAt or b.createdAt or 0) or 0
    if aUpdated ~= bUpdated then
      return aUpdated > bUpdated
    end
    return Lower(a.recipeName or "") < Lower(b.recipeName or "")
  end)

  return orders
end

function LeafVE:CanPlayerFulfillWorkOrder(playerName, order)
  if type(order) ~= "table" then
    return false
  end
  playerName = ShortName(playerName)
  if not playerName then
    return false
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "open" then
    return false
  end
  if (tonumber(order.quantity) or 0) < 1 then
    return false
  end
  if order.requester and Lower(order.requester) == Lower(playerName) then
    return false
  end
  if not self:DoesWorkOrderRequireDesignation(order) then
    return true
  end
  return self:HasProfessionDesignation(playerName, order.profession)
end

function LeafVE:GetOpenDesignatedWorkOrdersForPlayer(playerName, sinceAt)
  playerName = ShortName(playerName)
  if not playerName then
    return {}
  end

  local orders = {}
  local threshold = tonumber(sinceAt) or 0
  local liveOrders = self:GetLiveWorkOrders()
  for i = 1, table.getn(liveOrders) do
    local order = liveOrders[i]
    local orderSeenAt = math.max(tonumber(order.updatedAt or 0) or 0, tonumber(order.createdAt or 0) or 0)
    if self:DoesWorkOrderRequireDesignation(order)
      and self:CanPlayerFulfillWorkOrder(playerName, order)
      and orderSeenAt > threshold then
      table.insert(orders, order)
    end
  end

  return orders
end

function LeafVE:BuildWorkOrderLoginAlertMessage(playerName, orders)
  playerName = ShortName(playerName)
  if not playerName or type(orders) ~= "table" or table.getn(orders) < 1 then
    return ""
  end

  local grouped = {}
  local orderedProfessions = {}
  local totalOrders = 0

  for i = 1, table.getn(orders) do
    local order = orders[i]
    local profession = CanonicalWorkOrderProfession(order.profession) or Trim(tostring(order.profession or "Work Order"))
    if profession ~= "" then
      if not grouped[profession] then
        grouped[profession] = {count = 0, samples = {}, sampleSeen = {}}
        table.insert(orderedProfessions, profession)
      end
      local bucket = grouped[profession]
      bucket.count = bucket.count + 1
      totalOrders = totalOrders + 1

      local sampleName = Trim(tostring(order.recipeName or "Work Order"))
      if sampleName ~= "" and not bucket.sampleSeen[Lower(sampleName)] and table.getn(bucket.samples) < 2 then
        bucket.sampleSeen[Lower(sampleName)] = true
        if string.len(sampleName) > 24 then
          sampleName = string.sub(sampleName, 1, 21) .. "..."
        end
        table.insert(bucket.samples, sampleName)
      end
    end
  end

  table.sort(orderedProfessions, function(a, b)
    return Lower(a or "") < Lower(b or "")
  end)

  local lines = {
    "While you were offline, " .. tostring(totalOrders) .. " open work order" .. (totalOrders ~= 1 and "s" or "") .. " matched your saved professions.",
    "",
  }

  local shownProfessions = 0
  for i = 1, table.getn(orderedProfessions) do
    local profession = orderedProfessions[i]
    local bucket = grouped[profession]
    if bucket then
      local sampleText = table.getn(bucket.samples) > 0 and (" (" .. table.concat(bucket.samples, ", ") .. (bucket.count > table.getn(bucket.samples) and ", ..." or "") .. ")") or ""
      table.insert(lines, profession .. ": " .. tostring(bucket.count) .. " open" .. sampleText)
      shownProfessions = shownProfessions + 1
      if shownProfessions >= 5 then
        if table.getn(orderedProfessions) > shownProfessions then
          table.insert(lines, "+" .. tostring(table.getn(orderedProfessions) - shownProfessions) .. " more profession" .. ((table.getn(orderedProfessions) - shownProfessions) ~= 1 and "s" or ""))
        end
        break
      end
    end
  end

  table.insert(lines, "")
  table.insert(lines, "Open Work Orders to review and claim them.")

  return table.concat(lines, "\n")
end

function LeafVE:MaybeShowWorkOrderLoginAlert(force)
  EnsureDB()

  if LeafVE_DB.options.enableWorkOrderLoginAlerts == false then
    return false
  end

  local playerName = ShortName(UnitName("player"))
  if not playerName then
    return false
  end

  local designation = self:GetProfessionDesignation(playerName)
  local hasDesignation = type(designation) == "table"
    and ((type(designation.main) == "table" and table.getn(designation.main) > 0)
      or (type(designation.secondary) == "table" and table.getn(designation.secondary) > 0))
  if not hasDesignation then
    return false
  end

  local now = Now()
  local lastAlertAt = tonumber(LeafVE_DB.workOrderLoginAlertAt) or 0
  if not force and lastAlertAt > 0 and (now - lastAlertAt) < WORK_ORDER_LOGIN_ALERT_COOLDOWN then
    return false
  end

  local lastLogoutAt = tonumber(LeafVE_DB.lastLogoutAt) or 0
  if not force and lastLogoutAt <= 0 then
    return false
  end

  local orders = self:GetOpenDesignatedWorkOrdersForPlayer(playerName, force and 0 or lastLogoutAt)
  if table.getn(orders) < 1 then
    return false
  end

  local message = self:BuildWorkOrderLoginAlertMessage(playerName, orders)
  if message == "" then
    return false
  end

  LeafVE_DB.workOrderLoginAlertAt = now
  self:ShowInfoPopup(message)
  return true
end

function LeafVE:ClaimWorkOrder(orderId, claimedQuantity)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if not self:CanPlayerFulfillWorkOrder(me, order) then
    if self:DoesWorkOrderRequireDesignation(order) then
      return nil, "You have not saved the required profession."
    end
    return nil, "You are not eligible to fulfill this order."
  end

  local now = Now()
  local updatedAt = now
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  local claimedOrder, claimErr = self:CreateWorkOrderPartialClaim(order, claimedQuantity or order.quantity, me, updatedAt)
  if not claimedOrder then
    return nil, claimErr or "Unable to claim the order."
  end
  local pickupLine = self:BuildWorkOrderPickupLine(claimedOrder, me)
  PrintWorkOrderMessage("|cFF88CCFFWork Order|r " .. pickupLine)
  return claimedOrder
end

function LeafVE:ReleaseWorkOrder(orderId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "pending" then
    return nil, "Order is not pending fulfillment."
  end
  if Lower(self:GetEffectiveWorkOrderFulfiller(order) or "") ~= Lower(me) then
    return nil, "Only the assigned fulfiller can release this order."
  end

  local now = Now()
  local updatedAt = now
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  if IsWorkOrderPartialClaim(order) then
    self:RestoreWorkOrderPartialQuantity(order, updatedAt)
    order.status = "cancelled"
    order.updatedAt = updatedAt + 1
    order.claimExpiresAt = 0
    order.completedAt = 0
    order.completedQuantity = 0
    self:StoreWorkOrderRecord(order)
    self:BroadcastWorkOrder(order)
  else
    order.status = "open"
    order.fulfiller = nil
    order.crafter = nil
    order.requestedQuantity = ClampWorkOrderQuantity(order.quantity or GetWorkOrderRequestedQuantity(order))
    order.completedQuantity = 0
    order.updatedAt = updatedAt
    order.claimExpiresAt = 0
    self:StoreWorkOrderRecord(order)
    self:BroadcastWorkOrder(order)
  end
  PrintWorkOrderMessage(
    "|cFF88CCFFWork Order|r " .. tostring(order.recipeName or "An order") ..
    " is back to waiting for a crafter."
  )
  return order
end

function LeafVE:CompleteWorkOrder(orderId, completedQuantity)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "pending" then
    return nil, "Order is not pending fulfillment."
  end
  if Lower(self:GetEffectiveWorkOrderFulfiller(order) or "") ~= Lower(me) then
    return nil, "Only the assigned fulfiller can complete this order."
  end

  local now = Now()
  local updatedAt = now
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  order.status = "completed"
  order.completedQuantity = ClampWorkOrderQuantity(order.quantity or completedQuantity or 1)
  order.updatedAt = updatedAt
  order.completedAt = updatedAt
  order.claimExpiresAt = 0
  self:StoreWorkOrderRecord(order)
  self:BroadcastWorkOrder(order)
  self:RefreshShinobiDutyProgress(me)
  local completionLine = self:BuildWorkOrderCompletionLine(order, me)
  PrintWorkOrderMessage("|cFF88CCFFWork Order|r " .. completionLine)
  return order
end

function LeafVE:FinalizeWorkOrder(orderId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if Lower(order.requester or "") ~= Lower(me) then
    return nil, "Only the requester can verify this order."
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "completed" then
    return nil, "Order is not ready for verification."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  order.status = "finalized"
  order.completedQuantity = ClampWorkOrderQuantity(order.quantity or GetWorkOrderFulfilledQuantity(order))
  order.updatedAt = updatedAt
  order.claimExpiresAt = 0
  self:StoreWorkOrderRecord(order)
  self:BroadcastWorkOrder(order)
  self:RefreshShinobiDutyProgress(me)
  return order
end

function LeafVE:RevertCompletedWorkOrder(orderId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if Lower(order.requester or "") ~= Lower(me) then
    return nil, "Only the requester can revert this order."
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "completed" then
    return nil, "Only completed orders can be reverted."
  end

  local fulfiller = self:GetStoredWorkOrderFulfiller(order)
  if not fulfiller then
    return nil, "This order has no fulfiller to return it to."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  if IsWorkOrderPartialClaim(order) then
    self:RestoreWorkOrderPartialQuantity(order, updatedAt)
    order.status = "cancelled"
    order.updatedAt = updatedAt + 1
    order.completedAt = 0
    order.claimExpiresAt = 0
    order.completedQuantity = 0
    self:StoreWorkOrderRecord(order)
    self:BroadcastWorkOrder(order)
    PrintWorkOrderMessage("|cFF88CCFFWork Order|r " .. self:BuildWorkOrderRevertLine(order, me))
    return order
  end

  order.status = "pending"
  order.fulfiller = fulfiller
  order.crafter = fulfiller
  order.quantity = GetWorkOrderRequestedQuantity(order)
  order.requestedQuantity = order.quantity
  order.completedQuantity = 0
  order.updatedAt = updatedAt
  order.completedAt = 0
  order.claimExpiresAt = updatedAt + (48 * SECONDS_PER_HOUR)
  self:StoreWorkOrderRecord(order)
  self:BroadcastWorkOrder(order)
  PrintWorkOrderMessage("|cFF88CCFFWork Order|r " .. self:BuildWorkOrderRevertLine(order, me))
  return order
end

function LeafVE:ReassignWorkOrder(orderId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if Lower(order.requester or "") ~= Lower(me) then
    return nil, "Only the requester can reassign this order."
  end
  if self:GetEffectiveWorkOrderStatus(order) ~= "pending" then
    return nil, "Only pending orders can be reassigned."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  if IsWorkOrderPartialClaim(order) then
    self:RestoreWorkOrderPartialQuantity(order, updatedAt)
    order.status = "cancelled"
    order.updatedAt = updatedAt + 1
    order.completedAt = 0
    order.claimExpiresAt = 0
    order.completedQuantity = 0
    self:StoreWorkOrderRecord(order)
    self:BroadcastWorkOrder(order)
  else
    order.status = "open"
    order.fulfiller = nil
    order.crafter = nil
    order.quantity = ClampWorkOrderQuantity(order.quantity or GetWorkOrderRequestedQuantity(order))
    order.requestedQuantity = order.quantity
    order.completedQuantity = 0
    order.updatedAt = updatedAt
    order.completedAt = 0
    order.claimExpiresAt = 0
    self:StoreWorkOrderRecord(order)
    self:BroadcastWorkOrder(order)
  end
  PrintWorkOrderMessage(
    "|cFF88CCFFWork Order|r " .. tostring(order.recipeName or "An order") ..
    " is back to waiting for a crafter."
  )
  return order
end

function BuildWorkOrderGatheringRecipe(entry)
  if type(entry) ~= "table" then return nil end

  local profession = CanonicalWorkOrderProfession(entry.profession)
  local itemId = tonumber(entry.itemId)
  local recipeName = Trim(tostring(entry.name or ""))
  if not profession or not itemId or itemId < 1 or recipeName == "" then
    return nil
  end

  local iconPath = NormalizeIconPath(GetItemIcon and GetItemIcon(itemId))
  if not iconPath then
    iconPath = (WORK_ORDER_PROFESSION_META[profession] and WORK_ORDER_PROFESSION_META[profession].icon)
      or (WORK_ORDER_PROFESSION_META["Gathering"] and WORK_ORDER_PROFESSION_META["Gathering"].icon)
      or LEAF_FALLBACK
  end

  local recipe = {
    profession = profession,
    requestCategory = "Gathering",
    name = recipeName,
    itemId = itemId,
    spellId = nil,
    icon = iconPath,
    quality = 1,
    sourceTable = "Gathering",
  }
  recipe.uid = GetWorkOrderRecipeKey(recipe)
  recipe.searchKey = BuildWorkOrderSearchKey(recipe) .. " gathering"
  return recipe
end

function BuildCustomGatheringWorkOrderRecipe(baseRecipe, customName)
  customName = Trim(tostring(customName or ""))
  if customName == "" then
    return type(baseRecipe) == "table" and baseRecipe or nil
  end

  local profession = type(baseRecipe) == "table" and baseRecipe.profession or nil
  if not LeafVE or not LeafVE:IsGatheringWorkOrderProfession(profession) then
    profession = "Farming"
  end

  local iconPath = type(baseRecipe) == "table" and baseRecipe.icon or nil
  if not iconPath then
    iconPath = (WORK_ORDER_PROFESSION_META[profession] and WORK_ORDER_PROFESSION_META[profession].icon)
      or (WORK_ORDER_PROFESSION_META["Gathering"] and WORK_ORDER_PROFESSION_META["Gathering"].icon)
      or LEAF_FALLBACK
  end

  local recipe = {
    profession = profession,
    requestCategory = "Gathering",
    name = customName,
    itemId = nil,
    spellId = nil,
    icon = iconPath,
    quality = 1,
    sourceTable = "GatheringCustom",
  }
  recipe.uid = "gcustom:" .. Lower(profession or "gathering") .. ":" .. Lower(customName)
  recipe.searchKey = BuildWorkOrderSearchKey(recipe) .. " gathering custom"
  return recipe
end

function AppendGatheringWorkOrderCatalogRecipes(catalog, seen)
  if type(catalog) ~= "table" or type(catalog.byProfession) ~= "table" then return end
  if type(catalog.byProfession["Gathering"]) ~= "table" then
    catalog.byProfession["Gathering"] = {}
  end

  for i = 1, table.getn(WORK_ORDER_GATHERING_ITEMS or {}) do
    local recipe = BuildWorkOrderGatheringRecipe(WORK_ORDER_GATHERING_ITEMS[i])
    if recipe and not seen[recipe.uid] then
      seen[recipe.uid] = true
      table.insert(catalog.byProfession["Gathering"], recipe)
      catalog.totalRecipes = catalog.totalRecipes + 1
    end
  end
end

function LeafVE:EnsureWorkOrderCatalog()
  if self.workOrderCatalog then
    return self.workOrderCatalog
  end

  local catalog = {
    order = {},
    byProfession = {},
    totalRecipes = 0,
    totalProfessions = 0,
  }
  local seen = {}
  for i = 1, table.getn(WORK_ORDER_REQUEST_CATEGORY_ORDER) do
    local profession = WORK_ORDER_REQUEST_CATEGORY_ORDER[i]
    table.insert(catalog.order, profession)
    catalog.byProfession[profession] = {}
  end

  local source = AtlasLoot_Data and AtlasLoot_Data["AtlasLootCrafting"]
  if type(source) == "table" then
    for tableKey, entries in pairs(source) do
      if type(entries) == "table" then
        local currentProfession = ResolveWorkOrderProfessionForTable(tableKey)
        for i = 1, table.getn(entries) do
          local row = entries[i]
          if type(row) == "table" then
            local iconProfession = WORK_ORDER_PROFESSION_BY_ICON[tostring(row[2] or "")]
            if iconProfession then
              currentProfession = iconProfession
            end

            local itemIdRow2, spellIdRow2 = ParseWorkOrderIDToken(row[2])
            local itemIdRow3, spellIdRow3 = ParseWorkOrderIDToken(row[3])
            local itemId = itemIdRow3 or itemIdRow2
            local spellId = spellIdRow2 or spellIdRow3
            local profession = currentProfession
            if (itemId or spellId) and profession and catalog.byProfession[profession] then
              local recipeName = ExtractWorkOrderRecipeName(row[4]) or ExtractWorkOrderRecipeName(row[3]) or ExtractWorkOrderRecipeName(row[5])
              local recipe = {
                profession = profession,
                name = recipeName,
                itemId = itemId,
                spellId = spellId,
                icon = self:GetWorkOrderResultIcon(itemId, spellId, row[2]),
                quality = ExtractWorkOrderQuality(row[4] or row[3]),
                skillRequirement = ExtractWorkOrderSkillRequirement(row[5] or row[4]),
                sourceTable = tableKey,
              }
              if recipe.name and recipe.name ~= "" then
                self:ApplyWorkOrderSpellInfo(recipe)
                recipe.icon = self:GetWorkOrderResultIcon(recipe.itemId, recipe.spellId, recipe.icon)
                if not self:IsWorkOrderItemBindOnPickup(recipe.itemId) then
                  recipe.uid = GetWorkOrderRecipeKey(recipe)
                  recipe.searchKey = BuildWorkOrderSearchKey(recipe)
                  if not seen[recipe.uid] then
                    seen[recipe.uid] = true
                    table.insert(catalog.byProfession[profession], recipe)
                    catalog.totalRecipes = catalog.totalRecipes + 1
                  end
                end
              end
            end
          end
        end
      end
    end
  end

  AppendGatheringWorkOrderCatalogRecipes(catalog, seen)

  for i = 1, table.getn(catalog.order) do
    local profession = catalog.order[i]
    local recipes = catalog.byProfession[profession]
    table.sort(recipes, function(a, b)
      local ap = Lower(a.profession or "")
      local bp = Lower(b.profession or "")
      if ap ~= bp then
        return ap < bp
      end
      local an = Lower(a.name or "")
      local bn = Lower(b.name or "")
      if an == bn then
        local aid = tonumber(a.itemId or a.spellId or 0) or 0
        local bid = tonumber(b.itemId or b.spellId or 0) or 0
        return aid < bid
      end
      return an < bn
    end)
    if table.getn(recipes) > 0 then
      catalog.totalProfessions = catalog.totalProfessions + 1
    end
  end

  self.workOrderCatalog = catalog
  return catalog
end

function FindWorkOrderCatalogRecipeInList(recipes, expectedName, itemId, spellId)
  if type(recipes) ~= "table" then return nil end
  for i = 1, table.getn(recipes) do
    local recipe = recipes[i]
    if Lower(recipe.name or "") == expectedName then
      if itemId and recipe.itemId and tonumber(recipe.itemId) == tonumber(itemId) then
        return recipe
      end
      if spellId and recipe.spellId and tonumber(recipe.spellId) == tonumber(spellId) then
        return recipe
      end
      if not itemId and not spellId then
        return recipe
      end
    end
  end
  return nil
end

function LeafVE:FindWorkOrderCatalogRecipe(profession, recipeName, itemId, spellId)
  local catalog = self:EnsureWorkOrderCatalog()
  local expectedName = Lower(recipeName or "")
  local recipe = FindWorkOrderCatalogRecipeInList(catalog.byProfession and catalog.byProfession[profession], expectedName, itemId, spellId)
  if recipe then
    return recipe
  end
  if profession ~= "Gathering" then
    return FindWorkOrderCatalogRecipeInList(catalog.byProfession and catalog.byProfession["Gathering"], expectedName, itemId, spellId)
  end
  return nil
end

function LeafVE:IsValidWorkOrderRecord(order)
  if type(order) ~= "table" then
    return false
  end
  if Trim(tostring(order.id or "")) == "" then
    return false
  end

  local requester = ShortName(order.requester)
  if not requester or Trim(tostring(requester or "")) == "" then
    return false
  end

  if not CanonicalWorkOrderProfession(order.profession) then
    return false
  end

  if Trim(tostring(order.recipeName or "")) == "" then
    return false
  end

  return true
end

function LeafVE:PurgeInvalidWorkOrders()
  EnsureDB()
  for orderId, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    if not self:IsValidWorkOrderRecord(order) then
      LeafVE_GlobalDB.workOrders[orderId] = nil
    end
  end
end

function LeafVE:StoreWorkOrderRecord(order)
  EnsureDB()
  if type(order) ~= "table" or not order.id then return nil, false end

  local requester = ShortName(order.requester)
  if not requester or Trim(tostring(requester or "")) == "" then return nil, false end
  local profession = CanonicalWorkOrderProfession(order.profession)
  if not profession then return nil, false end
  local recipeName = Trim(tostring(order.recipeName or ""))
  if recipeName == "" then return nil, false end

  local status = NormalizeWorkOrderStatus(order.status)
  local fulfiller = ShortName(order.fulfiller)
  if not fulfiller and status == "pending" then
    fulfiller = ShortName(order.crafter)
  end
  local claimExpiresAt = tonumber(order.claimExpiresAt) or 0
  if status == "open" then
    fulfiller = nil
    claimExpiresAt = 0
  elseif status == "pending" and claimExpiresAt < 1 then
    claimExpiresAt = (tonumber(order.updatedAt) or tonumber(order.createdAt) or Now()) + (48 * SECONDS_PER_HOUR)
  elseif status ~= "pending" then
    claimExpiresAt = 0
  end
  local rawQuantity = math.floor(tonumber(order.quantity) or 1)
  if rawQuantity < 0 then rawQuantity = 0 end
  if rawQuantity > 99 then rawQuantity = 99 end

  local record = {
    id = tostring(order.id),
    parentOrderId = GetWorkOrderParentId(order),
    requester = requester,
    crafter = fulfiller,
    fulfiller = fulfiller,
    createdAt = tonumber(order.createdAt) or Now(),
    updatedAt = tonumber(order.updatedAt) or tonumber(order.createdAt) or Now(),
    claimExpiresAt = status == "pending" and claimExpiresAt or 0,
    completedAt = tonumber(order.completedAt) or 0,
    profession = profession,
    recipeName = recipeName,
    itemId = tonumber(order.itemId),
    spellId = tonumber(order.spellId),
    quantity = rawQuantity,
    requestedQuantity = ClampWorkOrderQuantity(order.requestedQuantity or order.quantity),
    completedQuantity = math.floor(tonumber(order.completedQuantity) or 0),
    tipCopper = ClampWorkOrderTipCopper(order.tipCopper),
    matsMode = NormalizeWorkOrderMatsMode(order.matsMode),
    icon = NormalizeIconPath(order.icon),
    status = status,
  }
  if record.requestedQuantity < record.quantity then
    record.requestedQuantity = record.quantity
  end
  if record.quantity < 1 and (status == "pending" or status == "completed" or status == "finalized" or IsWorkOrderPartialClaim(order)) then
    record.quantity = 1
  end
  if record.completedQuantity < 0 then
    record.completedQuantity = 0
  end
  if status == "completed" or status == "finalized" then
    if record.completedQuantity < 1 then
      record.completedQuantity = math.min(record.quantity, record.requestedQuantity)
    end
  else
    record.completedQuantity = 0
  end
  if record.completedQuantity > record.requestedQuantity then
    record.completedQuantity = record.requestedQuantity
  end
  if not record.icon then
    local catalogRecipe = self:FindWorkOrderCatalogRecipe(record.profession, record.recipeName, record.itemId, record.spellId)
    if catalogRecipe then
      record.icon = catalogRecipe.icon
    end
  end
  if not record.icon then
    record.icon = (WORK_ORDER_PROFESSION_META[record.profession] and WORK_ORDER_PROFESSION_META[record.profession].icon) or LEAF_FALLBACK
  end

  local existing = LeafVE_GlobalDB.workOrders[record.id]
  local existingUpdatedAt = existing and (tonumber(existing.updatedAt or existing.createdAt or 0) or 0) or 0
  if existing and existingUpdatedAt > record.updatedAt then
    return existing, false
  end

  LeafVE_GlobalDB.workOrders[record.id] = record
  local changed = false
  if not existing then
    self.workOrderReputationDirty = true
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.workOrderRep
      and LeafVE.UI.panels.workOrderRep.IsVisible and LeafVE.UI.panels.workOrderRep:IsVisible()
      and LeafVE.UI.RefreshWorkOrderReputationPanel then
      LeafVE.UI:RefreshWorkOrderReputationPanel()
    end
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.shinobiReputation
      and LeafVE.UI.panels.shinobiReputation.IsVisible and LeafVE.UI.panels.shinobiReputation:IsVisible()
      and LeafVE.UI.RefreshShinobiReputationLeaderboard then
      LeafVE.UI:RefreshShinobiReputationLeaderboard()
    end
    changed = true
  end

  if existing and existingUpdatedAt < record.updatedAt then
    changed = true
  elseif existing and (existing.status or "open") ~= record.status then
    changed = true
  elseif existing and tonumber(existing.quantity or 1) ~= record.quantity then
    changed = true
  elseif existing and GetWorkOrderRequestedQuantity(existing) ~= record.requestedQuantity then
    changed = true
  elseif existing and GetWorkOrderCompletedQuantity(existing) ~= record.completedQuantity then
    changed = true
  elseif existing and GetWorkOrderParentId(existing) ~= record.parentOrderId then
    changed = true
  elseif existing and ClampWorkOrderTipCopper(existing.tipCopper) ~= record.tipCopper then
    changed = true
  elseif existing and NormalizeWorkOrderMatsMode(existing.matsMode) ~= record.matsMode then
    changed = true
  elseif existing and Lower(existing.fulfiller or "") ~= Lower(record.fulfiller or "") then
    changed = true
  elseif existing and tonumber(existing.claimExpiresAt or 0) ~= record.claimExpiresAt then
    changed = true
  elseif existing and tonumber(existing.completedAt or 0) ~= tonumber(record.completedAt or 0) then
    changed = true
  end

  if changed or not existing then
    self.workOrderReputationDirty = true
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.workOrderRep
      and LeafVE.UI.panels.workOrderRep.IsVisible and LeafVE.UI.panels.workOrderRep:IsVisible()
      and LeafVE.UI.RefreshWorkOrderReputationPanel then
      LeafVE.UI:RefreshWorkOrderReputationPanel()
    end
    if LeafVE and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.shinobiReputation
      and LeafVE.UI.panels.shinobiReputation.IsVisible and LeafVE.UI.panels.shinobiReputation:IsVisible()
      and LeafVE.UI.RefreshShinobiReputationLeaderboard then
      LeafVE.UI:RefreshShinobiReputationLeaderboard()
    end
  end
  local previousStatus = existing and self:GetEffectiveWorkOrderStatus(existing) or nil
  local currentStatus = self:GetEffectiveWorkOrderStatus(record)
  if currentStatus == "finalized" and previousStatus ~= "finalized" then
    self:CheckBadgeMilestones(record.requester)
    if record.fulfiller then
      self:CheckBadgeMilestones(record.fulfiller)
    end
  end
  return record, changed
end

function LeafVE:GetOpenWorkOrderCountForCrafter(crafterName)
  EnsureDB()
  crafterName = ShortName(crafterName)
  if not crafterName then return 0 end

  local count = 0
  local now = Now()
  for _, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    if type(order) == "table"
      and self:GetEffectiveWorkOrderStatus(order, now) == "pending"
      and self:GetEffectiveWorkOrderFulfiller(order, now)
      and Lower(self:GetEffectiveWorkOrderFulfiller(order, now)) == Lower(crafterName) then
      count = count + 1
    end
  end
  return count
end

function LeafVE:GetWorkOrdersForRequester(requesterName, preferredCrafter)
  EnsureDB()
  requesterName = ShortName(requesterName)
  if not requesterName then return {} end

  local orders = {}
  local now = Now()
  for _, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    local status = self:GetEffectiveWorkOrderStatus(order, now)
    if type(order) == "table"
      and self:IsValidWorkOrderRecord(order)
      and order.requester
      and Lower(order.requester) == Lower(requesterName)
      and (((status == "open") and (tonumber(order.quantity) or 0) > 0) or status == "pending" or status == "completed") then
      table.insert(orders, order)
    end
  end

  table.sort(orders, function(a, b)
    local aStatus = LeafVE:GetEffectiveWorkOrderStatus(a, now)
    local bStatus = LeafVE:GetEffectiveWorkOrderStatus(b, now)
    if aStatus ~= bStatus then
      local priority = { completed = 1, pending = 2, open = 3 }
      return (priority[aStatus] or 9) < (priority[bStatus] or 9)
    end

    if aStatus == "pending" then
      local aExpires = tonumber(a.claimExpiresAt or 0) or 0
      local bExpires = tonumber(b.claimExpiresAt or 0) or 0
      if aExpires ~= bExpires then
        return aExpires < bExpires
      end
    elseif aStatus == "completed" then
      local aCompleted = tonumber(a.completedAt or a.updatedAt or a.createdAt or 0) or 0
      local bCompleted = tonumber(b.completedAt or b.updatedAt or b.createdAt or 0) or 0
      if aCompleted ~= bCompleted then
        return aCompleted > bCompleted
      end
    end

    local aUpdated = tonumber(a.updatedAt or a.createdAt or 0) or 0
    local bUpdated = tonumber(b.updatedAt or b.createdAt or 0) or 0
    if aUpdated ~= bUpdated then
      return aUpdated > bUpdated
    end
    return Lower(a.recipeName or "") < Lower(b.recipeName or "")
  end)

  return orders
end

function LeafVE:CancelWorkOrder(orderId)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local order = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[orderId]
  if type(order) ~= "table" then
    return nil, "Order not found."
  end
  if Lower(order.requester or "") ~= Lower(me) then
    return nil, "You can only cancel your own orders."
  end
  local effectiveStatus = self:GetEffectiveWorkOrderStatus(order)
  if effectiveStatus ~= "open" and effectiveStatus ~= "pending" then
    return nil, "Order is already closed."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  if IsWorkOrderPartialClaim(order) then
    self:RestoreWorkOrderPartialQuantity(order, updatedAt)
    order.updatedAt = updatedAt + 1
  else
    order.updatedAt = updatedAt
  end
  order.status = "cancelled"
  order.fulfiller = nil
  order.crafter = nil
  order.completedAt = 0
  order.claimExpiresAt = 0
  order.completedQuantity = 0
  self:StoreWorkOrderRecord(order)
  self:BroadcastWorkOrder(order)
  return order
end

function LeafVE:BroadcastWorkOrder(order, messageType)
  if not order or not order.id or not InGuild() then return end

  messageType = messageType or "WORKORDER:"

  local payload = table.concat({
    EncodeTalentField(order.id),
    EncodeTalentField(GetWorkOrderParentId(order) or ""),
    EncodeTalentField(order.requester),
    EncodeTalentField(order.fulfiller or order.crafter or ""),
    tostring(order.createdAt or Now()),
    tostring(order.updatedAt or order.createdAt or Now()),
    tostring(order.claimExpiresAt or 0),
    EncodeTalentField(order.profession),
    EncodeTalentField(order.recipeName),
    tostring(order.itemId or ""),
    tostring(order.spellId or ""),
    tostring(order.quantity or 1),
    EncodeTalentField(order.icon or ""),
    EncodeTalentField(order.status or "open"),
    tostring(ClampWorkOrderTipCopper(order.tipCopper)),
    EncodeTalentField(NormalizeWorkOrderMatsMode(order.matsMode)),
    tostring(tonumber(order.completedAt) or 0),
    tostring(GetWorkOrderRequestedQuantity(order)),
    tostring(GetWorkOrderCompletedQuantity(order)),
  }, SEP)
  SendAddonMessage("LeafVE", messageType .. payload, "GUILD")
end

function LeafVE:BroadcastWorkOrderSnapshot(force)
  if not InGuild() then return end

  local now = Now()
  if not force and (now - (self.lastWorkOrderSyncRespondAt or 0)) < 20 then
    return
  end
  self.lastWorkOrderSyncRespondAt = now

  EnsureDB()
  for _, order in pairs(LeafVE_GlobalDB.workOrders or {}) do
    if type(order) == "table" and self:IsValidWorkOrderRecord(order) then
      local effectiveStatus = self:GetEffectiveWorkOrderStatus(order, now)
      local updatedAt = tonumber(order.updatedAt or order.createdAt or 0) or 0
      if effectiveStatus == "open" or effectiveStatus == "pending" or updatedAt >= (now - (7 * SECONDS_PER_DAY)) then
        self:BroadcastWorkOrder(order, "WORKORDERSYNC:")
      end
    end
  end
end

function LeafVE:RequestWorkOrderSync(force)
  if not InGuild() then return end

  local now = Now()
  if not force and (now - (self.lastWorkOrderSyncRequestAt or 0)) < 20 then
    return
  end
  self.lastWorkOrderSyncRequestAt = now
  SendAddonMessage("LeafVE", force and "WORKORDERREQ_FORCE" or "WORKORDERREQ", "GUILD")
end

function LeafVE:SubmitWorkOrder(crafterName, recipe, quantity, tipCopper, matsMode)
  EnsureDB()
  local requester = ShortName(UnitName("player"))
  if not requester then
    return nil, "Your player name could not be determined."
  end
  if type(recipe) ~= "table" or not recipe.name then
    return nil, "Select a recipe first."
  end

  quantity = tonumber(quantity) or 1
  if quantity < 1 then quantity = 1 end
  if quantity > 99 then quantity = 99 end
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  matsMode = NormalizeWorkOrderMatsMode(matsMode)

  local createdAt = Now()
  local order = {
    id = self:GenerateWorkOrderId(requester, createdAt),
    requester = requester,
    fulfiller = nil,
    crafter = nil,
    createdAt = createdAt,
    updatedAt = createdAt,
    claimExpiresAt = 0,
    profession = recipe.profession,
    recipeName = recipe.name,
    itemId = recipe.itemId,
    spellId = recipe.spellId,
    quantity = ClampWorkOrderQuantity(quantity),
    requestedQuantity = ClampWorkOrderQuantity(quantity),
    completedQuantity = 0,
    tipCopper = tipCopper,
    matsMode = matsMode,
    icon = recipe.icon,
    status = "open",
  }

  local stored = self:StoreWorkOrderRecord(order)
  if not stored then
    return nil, "Unable to save the work order."
  end

  self:BroadcastWorkOrder(stored)
  self:RefreshShinobiDutyProgress(requester)
  return stored
end

function LeafVE:HandleIncomingWorkOrderMessage(payload, sender, isRelay)
  local fields = SplitByLiteralSep(payload, SEP)
  local fieldCount = table.getn(fields)
  if fieldCount < 10 then return end

  local order
  if fieldCount >= 19 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = DecodeTalentField(fields[2] or ""),
      requester = ShortName(DecodeTalentField(fields[3] or "")),
      fulfiller = ShortName(DecodeTalentField(fields[4] or "")),
      createdAt = tonumber(fields[5]) or Now(),
      updatedAt = tonumber(fields[6]) or tonumber(fields[5]) or Now(),
      claimExpiresAt = tonumber(fields[7]) or 0,
      profession = DecodeTalentField(fields[8] or ""),
      recipeName = DecodeTalentField(fields[9] or ""),
      itemId = tonumber(fields[10]),
      spellId = tonumber(fields[11]),
      quantity = tonumber(fields[12]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[13] or "")),
      status = DecodeTalentField(fields[14] or "open"),
      tipCopper = ClampWorkOrderTipCopper(fields[15]),
      matsMode = NormalizeWorkOrderMatsMode(DecodeTalentField(fields[16] or "requester")),
      completedAt = tonumber(fields[17]) or 0,
      requestedQuantity = tonumber(fields[18]) or tonumber(fields[12]) or 1,
      completedQuantity = tonumber(fields[19]) or 0,
    }
  elseif fieldCount >= 18 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[5]) or tonumber(fields[4]) or Now(),
      claimExpiresAt = tonumber(fields[6]) or 0,
      profession = DecodeTalentField(fields[7] or ""),
      recipeName = DecodeTalentField(fields[8] or ""),
      itemId = tonumber(fields[9]),
      spellId = tonumber(fields[10]),
      quantity = tonumber(fields[11]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[12] or "")),
      status = DecodeTalentField(fields[13] or "open"),
      tipCopper = ClampWorkOrderTipCopper(fields[14]),
      matsMode = NormalizeWorkOrderMatsMode(DecodeTalentField(fields[15] or "requester")),
      completedAt = tonumber(fields[16]) or 0,
      requestedQuantity = tonumber(fields[17]) or tonumber(fields[11]) or 1,
      completedQuantity = tonumber(fields[18]) or 0,
    }
  elseif fieldCount >= 16 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[5]) or tonumber(fields[4]) or Now(),
      claimExpiresAt = tonumber(fields[6]) or 0,
      profession = DecodeTalentField(fields[7] or ""),
      recipeName = DecodeTalentField(fields[8] or ""),
      itemId = tonumber(fields[9]),
      spellId = tonumber(fields[10]),
      quantity = tonumber(fields[11]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[12] or "")),
      status = DecodeTalentField(fields[13] or "open"),
      tipCopper = ClampWorkOrderTipCopper(fields[14]),
      matsMode = NormalizeWorkOrderMatsMode(DecodeTalentField(fields[15] or "requester")),
      completedAt = tonumber(fields[16]) or 0,
      requestedQuantity = tonumber(fields[11]) or 1,
      completedQuantity = 0,
    }
  elseif fieldCount >= 15 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[5]) or tonumber(fields[4]) or Now(),
      claimExpiresAt = tonumber(fields[6]) or 0,
      profession = DecodeTalentField(fields[7] or ""),
      recipeName = DecodeTalentField(fields[8] or ""),
      itemId = tonumber(fields[9]),
      spellId = tonumber(fields[10]),
      quantity = tonumber(fields[11]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[12] or "")),
      status = DecodeTalentField(fields[13] or "open"),
      tipCopper = ClampWorkOrderTipCopper(fields[14]),
      matsMode = NormalizeWorkOrderMatsMode(DecodeTalentField(fields[15] or "requester")),
      completedAt = 0,
      requestedQuantity = tonumber(fields[11]) or 1,
      completedQuantity = 0,
    }
  elseif fieldCount >= 14 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[5]) or tonumber(fields[4]) or Now(),
      claimExpiresAt = tonumber(fields[6]) or 0,
      profession = DecodeTalentField(fields[7] or ""),
      recipeName = DecodeTalentField(fields[8] or ""),
      itemId = tonumber(fields[9]),
      spellId = tonumber(fields[10]),
      quantity = tonumber(fields[11]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[12] or "")),
      status = DecodeTalentField(fields[13] or "open"),
      tipCopper = ClampWorkOrderTipCopper(fields[14]),
      matsMode = "requester",
      completedAt = 0,
      requestedQuantity = tonumber(fields[11]) or 1,
      completedQuantity = 0,
    }
  elseif fieldCount >= 12 then
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = nil,
      crafter = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[5]) or tonumber(fields[4]) or Now(),
      profession = DecodeTalentField(fields[6] or ""),
      recipeName = DecodeTalentField(fields[7] or ""),
      itemId = tonumber(fields[8]),
      spellId = tonumber(fields[9]),
      quantity = tonumber(fields[10]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[11] or "")),
      status = DecodeTalentField(fields[12] or "open"),
      tipCopper = 0,
      matsMode = "requester",
      completedAt = 0,
      requestedQuantity = tonumber(fields[10]) or 1,
      completedQuantity = 0,
    }
  else
    order = {
      id = DecodeTalentField(fields[1] or ""),
      parentOrderId = "",
      requester = ShortName(DecodeTalentField(fields[2] or "")),
      fulfiller = nil,
      crafter = ShortName(DecodeTalentField(fields[3] or "")),
      createdAt = tonumber(fields[4]) or Now(),
      updatedAt = tonumber(fields[4]) or Now(),
      profession = DecodeTalentField(fields[5] or ""),
      recipeName = DecodeTalentField(fields[6] or ""),
      itemId = tonumber(fields[7]),
      spellId = tonumber(fields[8]),
      quantity = tonumber(fields[9]) or 1,
      icon = NormalizeIconPath(DecodeTalentField(fields[10] or "")),
      status = "open",
      tipCopper = 0,
      matsMode = "requester",
      completedAt = 0,
      requestedQuantity = tonumber(fields[9]) or 1,
      completedQuantity = 0,
    }
  end
  if not order.status or order.status == "" then
    order.status = "open"
  end
  if not order.id or order.id == "" or not order.requester or order.recipeName == "" then
    return
  end

  local previous = LeafVE_GlobalDB.workOrders and LeafVE_GlobalDB.workOrders[order.id]
  local previousStatus = previous and self:GetEffectiveWorkOrderStatus(previous) or nil
  local previousFulfiller = previous and self:GetEffectiveWorkOrderFulfiller(previous) or nil
  local previousStoredFulfiller = previous and self:GetStoredWorkOrderFulfiller(previous) or nil
  local senderKey = Lower(sender or "")

  if not isRelay then
    local requesterKey = Lower(order.requester or "")
    local fulfillerKey = Lower(order.fulfiller or order.crafter or "")
    local status = NormalizeWorkOrderStatus(order.status)
    local partialRootUpdate = false
    if not GetWorkOrderParentId(order) and previous then
      partialRootUpdate = ((tonumber(previous.quantity) or 0) ~= (tonumber(order.quantity) or 0))
        or (ClampWorkOrderTipCopper(previous.tipCopper) ~= ClampWorkOrderTipCopper(order.tipCopper))
    end
    if status == "open" or status == "cancelled" or status == "finalized" then
      local releaseByFulfiller = false
      if status == "open"
        and previousStatus == "pending"
        and previousFulfiller
        and senderKey == Lower(previousFulfiller) then
        releaseByFulfiller = true
      end
      if senderKey ~= requesterKey and not releaseByFulfiller and not partialRootUpdate then
        return
      end
    elseif status == "pending" or status == "completed" then
      local requesterRevert = status == "pending"
        and previousStatus == "completed"
        and requesterKey ~= ""
        and senderKey == requesterKey
        and previousStoredFulfiller
        and Lower(previousStoredFulfiller) == fulfillerKey
      if fulfillerKey == "" or (senderKey ~= fulfillerKey and not requesterRevert) then
        return
      end
    else
      return
    end
  end

  local stored, changed = self:StoreWorkOrderRecord(order)
  if not stored then return end

  local me = ShortName(UnitName("player"))
  local currentStatus = self:GetEffectiveWorkOrderStatus(stored)
  local currentFulfiller = self:GetStoredWorkOrderFulfiller(stored)
  local isNewRecord = previous == nil
  local senderIsMe = me and senderKey ~= "" and senderKey == Lower(me)
  local requesterReverted = not isRelay
    and changed
    and currentStatus == "pending"
    and previousStatus == "completed"
    and currentFulfiller
    and senderKey ~= ""
    and senderKey == Lower(stored.requester or "")

  if not isRelay
    and isNewRecord
    and NormalizeWorkOrderStatus(stored.status) == "open"
    and me
    and Lower(stored.requester) ~= Lower(me)
    and (self:IsGatheringWorkOrderProfession(stored.profession) or self:HasProfessionDesignation(me, stored.profession)) then
    local tipNote = ClampWorkOrderTipCopper(stored.tipCopper) > 0 and (" Tip: " .. FormatWorkOrderTipText(stored.tipCopper) .. ".") or ""
    local matsNote = " " .. GetWorkOrderMatsLine(stored.matsMode, stored.requester, stored.profession)
    PrintWorkOrderMessage(
      "|cFF88CCFFWork Order|r " .. tostring(stored.requester or "Someone") ..
      " created a |cFFFFD700" .. tostring(stored.profession or "Profession") .. "|r order for " ..
      tostring(stored.recipeName or "an item") .. " x" .. tostring(stored.quantity or 1) .. "." .. matsNote .. tipNote
    )
  end

  if requesterReverted and not senderIsMe then
    PrintWorkOrderMessage(
      "|cFF88CCFFWork Order|r " .. self:BuildWorkOrderRevertLine(stored, stored.requester)
    )
  elseif not isRelay
    and changed
    and currentStatus == "pending"
    and currentFulfiller
    and (previousStatus ~= "pending" or Lower(previousFulfiller or "") ~= Lower(currentFulfiller))
    and not senderIsMe then
    PrintWorkOrderMessage(
      "|cFF88CCFFWork Order|r " .. self:BuildWorkOrderPickupLine(stored, currentFulfiller)
    )
  end

  if not isRelay
    and changed
    and currentStatus == "open"
    and previousStatus == "pending"
    and previousFulfiller
    and not senderIsMe then
    PrintWorkOrderMessage(
      "|cFF88CCFFWork Order|r " .. tostring(stored.recipeName or "An order") ..
      " is back to waiting for a crafter."
    )
  end

  if not isRelay
    and changed
    and currentStatus == "completed"
    and currentFulfiller
    and previousStatus ~= "completed"
    and not senderIsMe then
    PrintWorkOrderMessage(
      "|cFF88CCFFWork Order|r " .. self:BuildWorkOrderCompletionLine(stored, currentFulfiller)
    )
  end

  if currentStatus == "finalized" then
    self:ApplyWorkOrderFinalReward(stored)
  end

  if LeafVE.UI and LeafVE.UI.workOrderPopup and LeafVE.UI.workOrderPopup:IsVisible() and LeafVE.UI.cardCurrentPlayer then
    LeafVE.UI:RefreshWorkOrderPopup(LeafVE.UI.cardCurrentPlayer)
  end
end

function UpdateWorkOrderProfessionButtonVisual(btn, selected)
  if not btn then return end
  btn.isSelected = selected and true or nil
  if selected then
    btn:SetBackdropColor(THEME.leaf2[1], THEME.leaf2[2], THEME.leaf2[3], 0.9)
    btn:SetBackdropBorderColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
    if btn.text then btn.text:SetTextColor(1, 1, 1) end
    if btn.countText then btn.countText:SetTextColor(1, 0.92, 0.55) end
  else
    btn:SetBackdropColor(0.09, 0.09, 0.11, 0.92)
    btn:SetBackdropBorderColor(0.35, 0.35, 0.4, 0.85)
    if btn.text then btn.text:SetTextColor(0.9, 0.9, 0.9) end
    if btn.countText then btn.countText:SetTextColor(0.65, 0.65, 0.65) end
  end
end

function UpdateWorkOrderRecipeButtonVisual(btn, selected)
  if not btn then return end
  btn.isSelected = selected and true or nil
  if selected then
    btn:SetBackdropColor(0.16, 0.28, 0.16, 0.95)
    btn:SetBackdropBorderColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
  else
    btn:SetBackdropColor(0.08, 0.08, 0.09, 0.92)
    btn:SetBackdropBorderColor(0.3, 0.3, 0.35, 0.75)
  end
end

function UpdateGuildBankItemButtonVisual(btn, hovered)
  if not btn then return end
  if hovered then
    btn:SetBackdropColor(0.14, 0.14, 0.17, 0.98)
    btn:SetBackdropBorderColor(THEME.gold[1], THEME.gold[2], THEME.gold[3], 0.85)
  else
    btn:SetBackdropColor(0.08, 0.08, 0.09, 0.92)
    btn:SetBackdropBorderColor(0.3, 0.3, 0.35, 0.75)
  end
end

function FormatGuildBankRequestAge(ts)
  local age = Now() - (tonumber(ts) or 0)
  if age < 0 then age = 0 end
  if age < 60 then
    return tostring(age) .. "s ago"
  end
  if age < 3600 then
    return tostring(math.floor(age / 60)) .. "m ago"
  end
  if age < SECONDS_PER_DAY then
    return tostring(math.floor(age / 3600)) .. "h ago"
  end
  return tostring(math.floor(age / SECONDS_PER_DAY)) .. "d ago"
end

function ClampGuildBankRequestQuantity(value, maxCount)
  local text = tostring(value or "")
  text = string.gsub(text, "%D", "")
  local quantity = tonumber(text) or 1
  if quantity < 1 then quantity = 1 end
  maxCount = tonumber(maxCount) or 99
  if maxCount < 1 then maxCount = 1 end
  if quantity > maxCount then quantity = maxCount end
  return quantity
end

function CreateGuildBankItemButton(parent)
