    insets = {left = 3, right = 3, top = 3, bottom = 3}
  })
  qtyBG:SetBackdropColor(0.06, 0.06, 0.08, 0.92)
  qtyBG:SetBackdropBorderColor(0.3, 0.3, 0.35, 1)
