  btn.icon = icon

  local actionBtn = CreateFrame("Button", nil, btn, "UIPanelButtonTemplate")
  actionBtn:SetWidth(54)
  actionBtn:SetHeight(20)
  actionBtn:SetPoint("RIGHT", btn, "RIGHT", -8, 0)
