function GetWorkOrderTipCopperFromPopup(popup)
  if not popup or not popup.tipGoldInput or not popup.tipSilverInput or not popup.tipCopperInput then
    return 0
  end
  return ParseWorkOrderTipCoinInputs(
    popup.tipGoldInput:GetText() or "",
    popup.tipSilverInput:GetText() or "",
    popup.tipCopperInput:GetText() or ""
  )
end

function UpdateWorkOrderTipPreviewFromPopup(popup)
  if not popup or not popup.tipMoneyDisplay then return end
  local tipCopper = GetWorkOrderTipCopperFromPopup(popup)
  SetGuildBankMoneyDisplay(popup.tipMoneyDisplay, tipCopper or 0)
  popup.tipMoneyDisplay:Show()
end

function SetWorkOrderTipInputsFromCopper(popup, tipCopper)
  if not popup then return end
  local gold, silver, copper = SplitWorkOrderTipCopper(tipCopper)
  if popup.tipGoldInput then
    popup.tipGoldInput:SetText(gold > 0 and tostring(gold) or "")
  end
  if popup.tipSilverInput then
    popup.tipSilverInput:SetText(silver > 0 and tostring(silver) or "")
  end
  if popup.tipCopperInput then
    popup.tipCopperInput:SetText(copper > 0 and tostring(copper) or "")
  end
  UpdateWorkOrderTipPreviewFromPopup(popup)
end

function BindWorkOrderCoinInput(input, popup)
  if not input then return end
  input.popup = popup
  input:SetScript("OnEscapePressed", function() this:ClearFocus() end)
  input:SetScript("OnTextChanged", function()
    if this.popup then
      UpdateWorkOrderTipPreviewFromPopup(this.popup)
    end
  end)
  input:SetScript("OnEditFocusLost", function()
    if not this.popup then return end
    local tipCopper = GetWorkOrderTipCopperFromPopup(this.popup)
    if tipCopper == nil then
      this:SetText("")
      tipCopper = GetWorkOrderTipCopperFromPopup(this.popup) or 0
    end
    SetWorkOrderTipInputsFromCopper(this.popup, tipCopper)
  end)
  input:SetScript("OnEnterPressed", function()
    this:ClearFocus()
    if this.popup and this.popup.submitBtn and this.popup.submitBtn:IsEnabled() then
      this.popup.submitBtn:Click()
    end
  end)
end

function SetWorkOrderRowTipDisplay(btn, tipCopper)
  if not btn or not btn.tipMoneyDisplay or not btn.tipLabel then return end
  tipCopper = ClampWorkOrderTipCopper(tipCopper)
  if tipCopper > 0 then
    btn.tipLabel:Show()
    SetGuildBankMoneyDisplay(btn.tipMoneyDisplay, tipCopper)
    btn.tipMoneyDisplay:Show()
  else
    btn.tipLabel:Hide()
    btn.tipMoneyDisplay:Hide()
  end
end

function HideWorkOrderSelectionReagentRows(popup)
  if not popup or type(popup.reagentRows) ~= "table" then return end
  for i = 1, table.getn(popup.reagentRows) do
    local row = popup.reagentRows[i]
    if row then
      row.entry = nil
      row:Hide()
    end
  end
end

function LayoutWorkOrderSelectionReagentRows(popup)
  if not popup or type(popup.reagentRows) ~= "table" or not popup.reagentsLabel then
    return 0
  end

  local availableWidth = (popup.selectionPanel and popup.selectionPanel:GetWidth()) or 0
  availableWidth = availableWidth - 190
  if availableWidth < 180 then
    availableWidth = 180
  end

  local columns = 1
  if availableWidth >= 420 then
    columns = 2
  end

  local rowsPerColumn = 4
  local columnGap = 12
  local columnWidth = math.floor((availableWidth - ((columns - 1) * columnGap)) / columns)
  if columnWidth < 160 then
    columnWidth = 160
  end

  for i = 1, table.getn(popup.reagentRows) do
    local row = popup.reagentRows[i]
    if row then
      local column = math.floor((i - 1) / rowsPerColumn)
      local rowIndex = (i - 1) - (column * rowsPerColumn)
      row:ClearAllPoints()
      if column < columns then
        row:SetPoint("TOPLEFT", popup.reagentsLabel, "BOTTOMLEFT", column * (columnWidth + columnGap), -2 - (rowIndex * 22))
        row:SetWidth(columnWidth)
        row.layoutEnabled = true
      else
        row.layoutEnabled = false
        row:Hide()
      end
    end
  end

  popup.reagentRowCapacity = rowsPerColumn * columns
  return popup.reagentRowCapacity
end

function SetWorkOrderSelectionReagentRows(popup, entries)
  if not popup or type(popup.reagentRows) ~= "table" then
    return false
  end

  local capacity = LayoutWorkOrderSelectionReagentRows(popup)
  if capacity < 1 then
    capacity = table.getn(popup.reagentRows)
  end

  local shown = 0
  for i = 1, table.getn(popup.reagentRows) do
    local row = popup.reagentRows[i]
    local entry = (i <= capacity and type(entries) == "table") and entries[i] or nil
    if row and entry and row.layoutEnabled ~= false then
      row.entry = entry
      if row.icon then
        row.icon:SetTexture(entry.icon or LEAF_FALLBACK)
      end
      if row.qtyText then
        row.qtyText:SetText("|cFFFFD700" .. tostring(entry.totalQuantity or entry.quantity or 1) .. "x|r")
      end
      if row.nameText then
        row.nameText:SetText(tostring(entry.name or "Unknown Reagent"))
      end
      row:Show()
      shown = shown + 1
    elseif row then
      row.entry = nil
      row:Hide()
    end
  end

  return shown > 0
end

function GetCustomGatheringNameFromPopup(popup)
  if not popup or not popup.customGatherInput then
    return ""
  end
  return Trim(popup.customGatherInput:GetText() or "")
end

function GetPopupSelectedWorkOrderRecipe(popup)
  if not popup then
    return nil
  end
  if popup.selectedProfession == "Gathering" then
    return BuildCustomGatheringWorkOrderRecipe(popup.selectedRecipe, GetCustomGatheringNameFromPopup(popup))
  end
  return popup.selectedRecipe
end

function SyncWorkOrderSlider(scrollBar, offset, maxOffset)
  if not scrollBar then return end

  offset = tonumber(offset) or 0
  maxOffset = tonumber(maxOffset) or 0
  if maxOffset < 0 then maxOffset = 0 end
  if offset < 0 then offset = 0 end
  if offset > maxOffset then offset = maxOffset end

  scrollBar.ignoreUpdate = true
  scrollBar:SetMinMaxValues(0, maxOffset)
  scrollBar:SetValueStep(1)
  scrollBar:SetValue(offset)
  scrollBar:EnableMouse(maxOffset > 0)
  if maxOffset > 0 then
    scrollBar:SetAlpha(1)
  else
    scrollBar:SetAlpha(0.35)
  end
  scrollBar.ignoreUpdate = nil
end

function GetWorkOrderVisibleRowCount(listFrame, rowHeight, fallbackRows)
  rowHeight = tonumber(rowHeight) or 1
  fallbackRows = tonumber(fallbackRows) or 1
  if fallbackRows < 1 then fallbackRows = 1 end

  local height = listFrame and listFrame:GetHeight() or 0
  if not height or height < rowHeight then
    return fallbackRows
  end

  local visibleRows = math.floor(height / rowHeight)
  if visibleRows < 1 then
    visibleRows = 1
  end
  return visibleRows
end

function UpdateProfessionSelectionButtonVisual(btn, selected, editable)
  if not btn then return end
  btn.isSelected = selected and true or nil
  if selected then
    btn:SetBackdropColor(THEME.leaf2[1], THEME.leaf2[2], THEME.leaf2[3], 0.92)
    btn:SetBackdropBorderColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
    if btn.text then btn.text:SetTextColor(1, 1, 1) end
  else
    btn:SetBackdropColor(0.09, 0.09, 0.11, 0.92)
    btn:SetBackdropBorderColor(0.35, 0.35, 0.4, 0.85)
    if btn.text then
      if editable == false then
        btn.text:SetTextColor(0.6, 0.6, 0.6)
      else
        btn.text:SetTextColor(0.9, 0.9, 0.9)
      end
    end
  end
  if btn.icon then
    if editable == false and not selected then
      btn.icon:SetVertexColor(0.6, 0.6, 0.6, 1)
    else
      btn.icon:SetVertexColor(1, 1, 1, 1)
    end
  end
end

