    metaText:SetWidth(480)
    metaText:SetJustifyH("LEFT")
    metaText:SetText("|cFF777777Progress updates automatically from tracked activity.|r")
    row.metaText = metaText

    local statusText = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    statusText:SetPoint("BOTTOMRIGHT", row, "BOTTOMRIGHT", -14, 30)
    statusText:SetWidth(180)
    statusText:SetJustifyH("RIGHT")
    statusText:SetText("|cFFAAAAAAIn Progress|r")
    row.statusText = statusText

    local progressBG = CreateFrame("Frame", nil, row)
    progressBG:SetPoint("BOTTOMLEFT", row, "BOTTOMLEFT", 62, 12)
    progressBG:SetPoint("BOTTOMRIGHT", row, "BOTTOMRIGHT", -14, 12)
    progressBG:SetHeight(16)
    progressBG:SetBackdrop({
      bgFile = "Interface\\Tooltips\\UI-Tooltip-Background",
      edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
      tile = true, tileSize = 16, edgeSize = 12,
      insets = {left = 3, right = 3, top = 3, bottom = 3}
    })
    progressBG:SetBackdropColor(0.05, 0.05, 0.05, 0.92)
    progressBG:SetBackdropBorderColor(0.25, 0.25, 0.28, 1)
    row.progressBG = progressBG

    local progressBar = CreateFrame("StatusBar", nil, progressBG)
    progressBar:SetPoint("TOPLEFT", progressBG, "TOPLEFT", 2, -2)
    progressBar:SetPoint("BOTTOMRIGHT", progressBG, "BOTTOMRIGHT", -2, 2)
    progressBar:SetStatusBarTexture("Interface\\TARGETINGFRAME\\UI-StatusBar")
    progressBar:SetStatusBarColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
    progressBar:SetMinMaxValues(0, 1)
    progressBar:SetValue(0)
    row.progressBar = progressBar

    local progressText = progressBG:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    progressText:SetPoint("CENTER", progressBG, "CENTER", 0, 0)
    progressText:SetText("Progress")
    row.progressText = progressText

    panel.dutyRows[i] = row
    previous = row
  end
end

function LeafVE.UI:RefreshShinobiDutiesPanel()
  local panel = self.panels and self.panels.shinobiDuties
  if not panel then
    return
  end

  local me = ShortName(UnitName("player"))
  if not me then
    return
  end

  local function FormatDutyValue(value)
    value = tonumber(value) or 0
    if math.abs(value - math.floor(value + 0.0001)) < 0.001 then
      return tostring(math.floor(value + 0.0001))
    end
    return string.format("%.1f", value)
  end

  local state = LeafVE:RefreshShinobiDutyProgress(me)
  local duties = state and state.duties or {}
  local totalCount = table.getn(duties)
  local completedCount = 0
  local remainingLP = 0
  local remainingRep = 0
  local now = Now()
  local nextResetTS = WeekStartTS(now) + (7 * SECONDS_PER_DAY)

  for i = 1, totalCount do
    local duty = duties[i]
    if type(duty) == "table" then
      local tierInfo = LeafVE:GetShinobiDutyTierInfo(duty.tier) or {}
      if duty.completedAt then
        completedCount = completedCount + 1
      else
        remainingLP = remainingLP + (tonumber(duty.lpReward) or tonumber(tierInfo.lpReward) or 0)
        remainingRep = remainingRep + (tonumber(duty.repReward) or tonumber(tierInfo.repReward) or 0)
      end
    end
  end

  if panel.shinobiDutiesWeekRangeText then
    panel.shinobiDutiesWeekRangeText:SetText("|cFFAAAAAAWeek|r  " .. tostring(GetWeekDateRange()))
  end
  if panel.shinobiDutiesResetText then
    panel.shinobiDutiesResetText:SetText("|cFFAAAAAAReset in|r  |cFFFFD700" .. FormatCompactCountdownText(nextResetTS - now) .. "|r")
  end
  if panel.shinobiDutiesCompletedValue then
    panel.shinobiDutiesCompletedValue:SetText("|cFFFFD700" .. tostring(completedCount) .. " / " .. tostring(math.max(5, totalCount)) .. "|r")
  end
  if panel.shinobiDutiesRemainingText then
    panel.shinobiDutiesRemainingText:SetText(
      "|cFF88CC88Remaining Rewards|r  |cFFFFD700+" .. LeafVE:FormatPointAmount(remainingLP) .. " LP|r  |  |cFF88CCFF+" .. tostring(remainingRep) .. " REP|r"
    )
  end
  if panel.shinobiDutiesDutyBonusText then
    panel.shinobiDutiesDutyBonusText:SetText("|cFF88CCFFDuty REP Bonus: +" .. tostring(LeafVE:GetShinobiDutyRepBonusAmount(me)) .. "|r")
  end
  if panel.shinobiDutiesHintText then
    if totalCount > 0 and completedCount >= totalCount then
      panel.shinobiDutiesHintText:SetText("|cFF88CC88All weekly duties complete. A new mission board arrives after the weekly reset.|r")
    else
      panel.shinobiDutiesHintText:SetText("|cFF888888Progress comes from tracked kills with guildies, grouped hours, shoutouts, quests, and work orders.|r")
    end
  end

  for i = 1, table.getn(panel.dutyRows or {}) do
    local row = panel.dutyRows[i]
    local duty = duties[i]
    if row and type(duty) == "table" then
      local tierInfo = LeafVE:GetShinobiDutyTierInfo(duty.tier) or {}
      local metricDef = LeafVE:GetShinobiDutyMetricDefinition(duty.metricKey)
      local color = tierInfo.color or THEME.gold
      local rr, gg, bb = color[1] or THEME.gold[1], color[2] or THEME.gold[2], color[3] or THEME.gold[3]
      local target = math.max(1, tonumber(duty.target) or 1)
      local progress = tonumber(duty.cachedProgress) or LeafVE:GetShinobiDutyMetricProgress(me, duty) or 0
      local shownProgress = math.max(0, math.min(progress, target))
      local lpReward = tonumber(duty.lpReward) or tonumber(tierInfo.lpReward) or 0
      local repReward = tonumber(duty.repReward) or tonumber(tierInfo.repReward) or 0

      row.badgeText:SetText(tostring(duty.tier or "?"))
      row.badgeFrame:SetBackdropColor(rr * 0.22, gg * 0.22, bb * 0.22, 0.96)
      row.badgeFrame:SetBackdropBorderColor(rr, gg, bb, 1)
      row.icon:SetTexture(duty.icon or LEAF_EMBLEM)
      row.titleText:SetText("|cFF" .. RGBToHex(rr, gg, bb) .. tostring(duty.title or "Duty") .. "|r")
      row.rewardText:SetText("|cFFFFD700+" .. tostring(lpReward) .. " LP|r  |  |cFF88CCFF+" .. tostring(repReward) .. " REP|r")
      row.descText:SetText("|cFFCCCCCC" .. tostring(duty.description or "Weekly mission") .. "|r")
      row.metaText:SetText("|cFF777777" .. tostring((metricDef and metricDef.sourceHint) or "Progress updates automatically from tracked addon activity.") .. "|r")
      row.progressBar:SetMinMaxValues(0, target)
      row.progressBar:SetValue(shownProgress)
      if duty.completedAt then
        row.progressBar:SetStatusBarColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
        row.statusText:SetText("|cFF88CC88Completed " .. date("%m/%d %H:%M", tonumber(duty.completedAt) or now) .. "|r")
      else
        row.progressBar:SetStatusBarColor(rr, gg, bb, 1)
        row.statusText:SetText("|cFFAAAAAAIn Progress|r")
      end
      row.progressText:SetText(
        tostring((metricDef and metricDef.progressLabel) or "Progress") .. ": " .. FormatDutyValue(progress) .. " / " .. FormatDutyValue(target)
      )
      row:Show()
    elseif row then
      row:Hide()
    end
  end
end

function LeafVE.UI:EnsureEmbeddedWorkOrderView()
  local panel = self.panels and self.panels.workOrders
  if not panel then
    return nil
  end

  BuildWorkOrdersPanel(panel)

  if not self.workOrderPopup then
    self:CreateWorkOrderPopup()
  end

  local popup = self.workOrderPopup
  if not popup then
    return nil
  end

  if popup:GetParent() ~= UIParent then
    popup:SetParent(UIParent)
  end
  panel.workOrderView = popup

  self:ApplyEmbeddedWorkOrderLayout(popup, panel)
  if self.ApplyPopupScale then
    self:ApplyPopupScale(popup)
  end

  return popup
end

function LeafVE.UI:RefreshWorkOrdersPanel()
  local popup = self:EnsureEmbeddedWorkOrderView()
  if not popup then
    return
  end

  local playerName = self:GetActiveWorkOrderPlayerName()
  if not playerName then
    return
  end

  if self.ApplyEmbeddedWorkOrderLayout and self.panels and self.panels.workOrders then
    self:ApplyEmbeddedWorkOrderLayout(popup, self.panels.workOrders)
  end
  self:RefreshWorkOrderPopup(playerName)
  popup:Show()
end

function LeafVE.UI:RefreshWorkOrderBrowseView(playerName, popup, catalog)
  popup.professionPanel:Show()
  popup.recipePanel:Show()
  popup.selectionPanel:Show()
  if popup.ordersPanel then
    popup.ordersPanel:Hide()
  end
  if popup.craftersPanel then
    popup.craftersPanel:Hide()
  end

  popup.subtitleText:SetText("Draft a village request from the Epoch crafting board")
  popup.matsMode = NormalizeWorkOrderMatsMode(popup.matsMode)

  local selectedProfession = popup.selectedProfession
  if not selectedProfession or not catalog.byProfession[selectedProfession] or table.getn(LeafVE:GetTradeableWorkOrderRecipes(catalog.byProfession[selectedProfession])) < 1 then
    selectedProfession = nil
    for i = 1, table.getn(catalog.order) do
      local profession = catalog.order[i]
      if table.getn(LeafVE:GetTradeableWorkOrderRecipes(catalog.byProfession[profession])) > 0 then
        selectedProfession = profession
        break
      end
    end
    popup.selectedProfession = selectedProfession
  end

  for i = 1, table.getn(popup.professionButtons) do
    local btn = popup.professionButtons[i]
    local recipes = LeafVE:GetTradeableWorkOrderRecipes(catalog.byProfession[btn.profession])
    local count = table.getn(recipes)
    if btn.countText then
      btn.countText:SetText("")
      btn.countText:Hide()
    end
    if count > 0 then
      btn:Enable()
      btn.icon:SetVertexColor(1, 1, 1, 1)
      UpdateWorkOrderProfessionButtonVisual(btn, btn.profession == selectedProfession)
    else
      btn:Disable()
      btn:SetBackdropColor(0.05, 0.05, 0.07, 0.78)
      btn:SetBackdropBorderColor(0.2, 0.2, 0.24, 0.65)
      btn.text:SetTextColor(0.45, 0.45, 0.45)
      btn.countText:SetTextColor(0.35, 0.35, 0.35)
      btn.icon:SetVertexColor(0.4, 0.4, 0.4, 1)
    end
  end

  local recipes = selectedProfession and LeafVE:GetTradeableWorkOrderRecipes(catalog.byProfession[selectedProfession]) or {}
  local filterText = Lower(Trim(popup.searchBox and popup.searchBox:GetText() or ""))
  local listKey = tostring(selectedProfession or "") .. "|" .. filterText .. "|" .. tostring(LeafVE.workOrderBindCacheVersion or 0)
  local filtered = popup.filteredRecipes or {}
  if popup.lastListKey ~= listKey or not popup.filteredRecipes then
    filtered = {}
    for i = 1, table.getn(recipes) do
      local recipe = recipes[i]
      if filterText == "" or string.find(recipe.searchKey or "", filterText, 1, true) then
        table.insert(filtered, recipe)
      end
    end
    popup.filteredRecipes = filtered
    popup.lastListKey = listKey
    popup.recipeOffset = 0
  end

  local selectedKey = popup.selectedRecipe and popup.selectedRecipe.uid or nil
  local selectionFound = nil
  if selectedKey then
    for i = 1, table.getn(filtered) do
      if filtered[i].uid == selectedKey then
        selectionFound = filtered[i]
        break
      end
    end
  end
  if selectionFound then
    popup.selectedRecipe = selectionFound
  elseif table.getn(filtered) > 0 then
    popup.selectedRecipe = filtered[1]
  else
    popup.selectedRecipe = nil
  end

  local selectedRecipe = GetPopupSelectedWorkOrderRecipe(popup)

  local rowHeight = popup.recipeRowHeight or 26
  local visibleRows = GetWorkOrderVisibleRowCount(popup.recipeListFrame, rowHeight, 12)
  local rowCount = table.getn(filtered)
  local maxOffset = math.max(0, rowCount - visibleRows)
  if (popup.recipeOffset or 0) > maxOffset then
    popup.recipeOffset = maxOffset
  end
  popup.recipeVisibleRows = visibleRows

  while table.getn(popup.recipeButtons) < visibleRows do
    local btn = CreateWorkOrderRecipeButton(popup.recipeListFrame)
    btn.popup = popup
    btn:SetScript("OnClick", function()
      this.popup.selectedRecipe = this.recipe
      if this.popup.feedbackText then
        this.popup.feedbackText:SetText("")
      end
      if LeafVE and LeafVE.UI and LeafVE.UI.cardCurrentPlayer then
        LeafVE.UI:RefreshWorkOrderPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end)
    table.insert(popup.recipeButtons, btn)
  end

  local listWidth = popup.recipeListFrame:GetWidth() or 0
  if not listWidth or listWidth < 220 then
    listWidth = 240
  end

  local startIndex = (popup.recipeOffset or 0) + 1
  for row = 1, table.getn(popup.recipeButtons) do
    local btn = popup.recipeButtons[row]
    local dataIndex = startIndex + row - 1
    if row <= visibleRows and dataIndex <= rowCount then
      local recipe = filtered[dataIndex]
      btn.recipe = recipe
      btn:SetWidth(listWidth - 4)
      if btn.text then
        btn.text:SetWidth(math.max(140, listWidth - 96))
      end
      if btn.metaText then
        btn.metaText:SetWidth(math.max(140, listWidth - 96))
      end
      if btn.reagentText then
        btn.reagentText:SetWidth(math.max(150, listWidth - 96))
      end
      btn:ClearAllPoints()
      btn:SetPoint("TOPLEFT", popup.recipeListFrame, "TOPLEFT", 2, -((row - 1) * rowHeight) - 2)
      btn.icon:SetTexture(recipe.icon or LEAF_FALLBACK)
      if selectedProfession == "Gathering" then
        btn.text:SetText("|cFF88CCFF[" .. tostring(recipe.profession or "Gathering") .. "]|r " .. tostring(recipe.name or "Recipe"))
      else
        btn.text:SetText((WORK_ORDER_QUALITY_COLORS[recipe.quality or 1] or "|cFFFFFFFF") .. tostring(recipe.name or "Recipe") .. "|r")
      end
      if btn.metaText then
        local metaText = LeafVE:GetWorkOrderRecipeMetaText(recipe)
        if metaText == "" and selectedProfession == "Gathering" then
          metaText = tostring(recipe.profession or "Gathering") .. " request"
        end
        btn.metaText:SetText("|cFF88CCFF" .. tostring(metaText) .. "|r")
      end
      if btn.reagentText then
        btn.reagentText:SetText(LeafVE:GetWorkOrderListMaterialsText(recipe, 1, 2))
      end
      if btn.idText then
        local yieldShort = LeafVE:GetWorkOrderYieldShortText(recipe)
        if yieldShort ~= "" then
          btn.idText:SetText("|cFFFFD700" .. yieldShort .. "|r")
          btn.idText:Show()
        else
          btn.idText:SetText("")
          btn.idText:Hide()
        end
      end
      if btn.accent then
        local color = THEME.leaf
        btn.accent:SetVertexColor(color[1], color[2], color[3], 0.55)
      end
      UpdateWorkOrderRecipeButtonVisual(btn, popup.selectedRecipe and popup.selectedRecipe.uid == recipe.uid)
      btn:Show()
    else
      btn.recipe = nil
      btn:Hide()
    end
  end

  SyncWorkOrderSlider(popup.recipeScrollBar, popup.recipeOffset or 0, maxOffset)

  if rowCount > 0 then
    popup.emptyText:Hide()
  else
    popup.emptyText:Show()
    if selectedProfession then
      popup.emptyText:SetText("|cFF888888No recipes matched this filter.|r")
    else
      popup.emptyText:SetText("|cFF888888No supported crafting recipes were found in the loaded DB.|r")
    end
  end

  local totalInProfession = table.getn(recipes)
  local liveOrders = LeafVE:GetLiveWorkOrders()
  local liveOpenCount = 0
  local livePendingCount = 0
  for i = 1, table.getn(liveOrders) do
    if LeafVE:GetEffectiveWorkOrderStatus(liveOrders[i]) == "pending" then
      livePendingCount = livePendingCount + 1
    else
      liveOpenCount = liveOpenCount + 1
    end
  end
  local me = ShortName(UnitName("player"))
  local myClaims = me and LeafVE:GetOpenWorkOrderCountForCrafter(me) or 0
  if selectedProfession then
    popup.summaryText:SetText(
      tostring(selectedProfession) .. ": " .. tostring(rowCount) .. "/" .. tostring(totalInProfession) ..
      " recipes  |  Live: " .. tostring(liveOpenCount) .. " open / " .. tostring(livePendingCount) ..
      " pending  |  Your claims: " .. tostring(myClaims)
    )
  else
    popup.summaryText:SetText(
      "Loaded categories: " .. tostring(catalog.totalProfessions) ..
      "  |  Live: " .. tostring(liveOpenCount) .. " open / " .. tostring(livePendingCount) ..
      " pending  |  Your claims: " .. tostring(myClaims)
    )
  end

  local isGatheringSelection = selectedProfession == "Gathering"
  if popup.selectedRecipe and LeafVE:IsGatheringWorkOrderProfession(popup.selectedRecipe.profession) then
    isGatheringSelection = true
  end

  if isGatheringSelection then
    popup.matsMode = "requester"
  end

  if popup.myMatsBtn then
    if isGatheringSelection then
      popup.myMatsBtn:Hide()
    else
      popup.myMatsBtn:Show()
      UpdateWorkOrderModeButtonVisual(popup.myMatsBtn, popup.matsMode ~= "crafter")
    end
  end
  if popup.yourMatsBtn then
    if isGatheringSelection then
      popup.yourMatsBtn:Hide()
    else
      popup.yourMatsBtn:Show()
      UpdateWorkOrderModeButtonVisual(popup.yourMatsBtn, popup.matsMode == "crafter")
    end
  end
  if popup.matsLabel then
    if isGatheringSelection then
      popup.matsLabel:Hide()
    else
      popup.matsLabel:Show()
    end
  end
  if popup.customGatherLabel then
    if isGatheringSelection then
      popup.customGatherLabel:Show()
    else
      popup.customGatherLabel:Hide()
    end
  end
  if popup.customGatherBG then
    if isGatheringSelection then
      popup.customGatherBG:Show()
    else
      popup.customGatherBG:Hide()
    end
  end
  if popup.customGatherHint then
    if isGatheringSelection then
      popup.customGatherHint:Show()
    else
      popup.customGatherHint:Hide()
    end
  end
  if popup.submitBtn then
    popup.submitBtn:ClearAllPoints()
    if isGatheringSelection and popup.customGatherBG then
      popup.submitBtn:SetPoint("TOP", popup.customGatherBG, "BOTTOM", 0, -26)
    else
      popup.submitBtn:SetPoint("TOP", popup.myMatsBtn, "BOTTOM", 40, -8)
    end
  end
  UpdateWorkOrderTipPreviewFromPopup(popup)
  LayoutWorkOrderSelectionReagentRows(popup)

  if selectedRecipe then
    local selectedQuantity = tonumber(Trim(popup.qtyInput and popup.qtyInput:GetText() or "")) or 1
    if selectedQuantity < 1 then selectedQuantity = 1 end
    if selectedQuantity > 99 then selectedQuantity = 99 end
    local reagentBlock = LeafVE:GetWorkOrderReagentBlockText(selectedRecipe, selectedQuantity, 8)
    local reagentEntries = LeafVE:GetWorkOrderReagentEntries(selectedRecipe, selectedQuantity)
    local metaText = LeafVE:GetWorkOrderRecipeMetaText(selectedRecipe)
    if metaText == "" then
      metaText = tostring(selectedRecipe.profession or "")
    end
    if popup.selectedIcon then
      popup.selectedIcon:SetTexture(selectedRecipe.icon or LEAF_FALLBACK)
    end
    if popup.selectedIconBG then
      popup.selectedIconBG:SetBackdropBorderColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 0.9)
    end
    popup.selectedText:SetText("|cFFFFD700" .. tostring(selectedRecipe.name or "Selected Craft") .. "|r")
    popup.detailText:SetText(tostring(metaText) .. "  |  " .. GetWorkOrderMatsTag(popup.matsMode, selectedRecipe.profession))
    if LeafVE:IsGatheringWorkOrderProfession(selectedRecipe.profession) and popup.reagentsText then
      HideWorkOrderSelectionReagentRows(popup)
      popup.reagentsText:Show()
      popup.reagentsText:SetText(
        "|cFFCCCCCCGather exactly |r|cFFFFD700" .. tostring(selectedQuantity) .. "x|r|cFFCCCCCC " ..
        tostring(selectedRecipe.name or "materials") .. " and deliver them to the requester.|r"
      )
      if popup.reagentsLabel then
        popup.reagentsLabel:SetText("Request")
      end
    elseif type(reagentEntries) == "table" and table.getn(reagentEntries) > 0 then
      local shownAny = SetWorkOrderSelectionReagentRows(popup, reagentEntries)
      if popup.reagentsLabel then
        popup.reagentsLabel:SetText(selectedQuantity > 1 and ("Exact Materials (x" .. tostring(selectedQuantity) .. ")") or "Exact Materials")
      end
      if shownAny and popup.reagentsText then
        local remainingCount = table.getn(reagentEntries) - (tonumber(popup.reagentRowCapacity) or table.getn(popup.reagentRows or {}))
        if remainingCount > 0 then
          popup.reagentsText:SetText("|cFF888888+" .. tostring(remainingCount) .. " more material" .. (remainingCount ~= 1 and "s" or "") .. " for this craft.|r")
          popup.reagentsText:Show()
        else
          popup.reagentsText:SetText("")
          popup.reagentsText:Hide()
        end
      elseif popup.reagentsText then
        HideWorkOrderSelectionReagentRows(popup)
        popup.reagentsText:SetText("|cFFCCCCCC" .. tostring(reagentBlock or "") .. "|r")
        popup.reagentsText:Show()
      end
    elseif popup.reagentsText then
      HideWorkOrderSelectionReagentRows(popup)
      popup.reagentsText:Show()
      popup.reagentsText:SetText("|cFF888888No reagent data is cached for this recipe yet.|r")
      if popup.reagentsLabel then
        popup.reagentsLabel:SetText("Exact Materials")
      end
    end
    popup.submitBtn:Enable()
  else
    popup.selectedText:SetText("|cFF888888No recipe selected|r")
    popup.detailText:SetText("")
    if popup.selectedIcon then
      popup.selectedIcon:SetTexture(LEAF_FALLBACK)
    end
    HideWorkOrderSelectionReagentRows(popup)
    if popup.reagentsText then
      popup.reagentsText:SetText("")
      popup.reagentsText:Hide()
    end
    if popup.reagentsLabel then
      popup.reagentsLabel:SetText("Exact Materials")
    end
    popup.submitBtn:Disable()
  end
end

function LeafVE.UI:RefreshWorkOrderLiveView(playerName, popup)
  popup.professionPanel:Hide()
  popup.recipePanel:Hide()
  popup.selectionPanel:Hide()
  if popup.ordersPanel then
    popup.ordersPanel:Show()
  end
  if popup.craftersPanel then
    popup.craftersPanel:Hide()
  end

  LeafVE:RequestWorkOrderSync(false)

  popup.subtitleText:SetText("Watch open and pending requests across the village")
  if popup.ordersTitle then
    popup.ordersTitle:SetText("|cFFFFD700Live Orders|r")
  end
  if popup.ordersHint then
    popup.ordersHint:SetText("|cFFAAAAAACrafted and profession-based requests are fulfilled by matching saved professions.\nFarming requests can be picked up by anyone, and you can use |cFFFFD700Partial|r to reserve only part of a request while the rest stays live.|r")
  end

  local me = ShortName(UnitName("player"))
  local now = Now()
  local orders = LeafVE:GetLiveWorkOrders()
  local openCount = 0
  local pendingCount = 0
  local eligibleCount = 0
  for i = 1, table.getn(orders) do
    local status = LeafVE:GetEffectiveWorkOrderStatus(orders[i], now)
    if status == "pending" then
      pendingCount = pendingCount + 1
    else
      openCount = openCount + 1
      if me and LeafVE:CanPlayerFulfillWorkOrder(me, orders[i]) then
        eligibleCount = eligibleCount + 1
      end
    end
  end
  popup.openOrderRows = orders

  local rowHeight = popup.orderRowHeight or 56
  local visibleRows = GetWorkOrderVisibleRowCount(popup.orderListFrame, rowHeight, 6)
  local totalOrders = table.getn(orders)
  local maxOffset = math.max(0, totalOrders - visibleRows)
  if (popup.orderOffset or 0) > maxOffset then
    popup.orderOffset = maxOffset
  end
  popup.orderVisibleRows = visibleRows

  while table.getn(popup.orderButtons) < visibleRows do
    local btn = CreateWorkOrderOrderButton(popup.orderListFrame)
    btn.popup = popup
    table.insert(popup.orderButtons, btn)
  end

  local listWidth = popup.orderListFrame:GetWidth() or 0
  if not listWidth or listWidth < 260 then
    listWidth = 340
  end

  local startIndex = (popup.orderOffset or 0) + 1
  for row = 1, table.getn(popup.orderButtons) do
    local btn = popup.orderButtons[row]
    local dataIndex = startIndex + row - 1
    if row <= visibleRows and dataIndex <= totalOrders then
      local order = orders[dataIndex]
      local status = LeafVE:GetEffectiveWorkOrderStatus(order, now)
      local fulfiller = LeafVE:GetEffectiveWorkOrderFulfiller(order, now)
      local timerText = tonumber(order.claimExpiresAt or 0) > now and FormatWorkOrderRemainingTime(order.claimExpiresAt, now) or "Expired"
      local requiresDesignation = LeafVE:DoesWorkOrderRequireDesignation(order)

      btn.order = order
      btn.popup = popup
      btn:SetWidth(listWidth - 4)
      btn:SetHeight(rowHeight - 4)
      btn:ClearAllPoints()
      btn:SetPoint("TOPLEFT", popup.orderListFrame, "TOPLEFT", 2, -((row - 1) * rowHeight) - 2)
      btn.icon:SetTexture(order.icon or LEAF_FALLBACK)
      btn.text:SetText("|cFFFFD700" .. tostring(order.recipeName or "Work Order") .. "|r")
      local matsLine = GetWorkOrderMatsLine(order.matsMode, order.requester, order.profession)
      local materialsText = LeafVE:GetWorkOrderListMaterialsText(order, order.quantity or 1, 2)
      btn.detailText:SetText(
        "Requester: " .. tostring(order.requester or "Unknown") ..
        "  |  " .. tostring(order.profession or "Unknown") ..
        "  |  " .. GetWorkOrderQuantitySummary(order) ..
        "  |  " .. FormatWorkOrderTipText(order.tipCopper)
      )
      SetWorkOrderRowTipDisplay(btn, order.tipCopper)

      btn.actionType = nil
      btn.secondaryActionType = nil
      btn.statusText:SetText("")
      if status == "pending" then
        if me and fulfiller and Lower(fulfiller) == Lower(me) then
          btn.actionType = "complete"
          btn.secondaryActionType = "release"
          if IsWorkOrderPartialClaim(order) then
            btn.statusText:SetText("|cFFFFFF99Pending by you.|r Reserved " .. tostring(order.quantity or 1) .. " for this request. " .. tostring(timerText) .. " left.")
          else
            btn.statusText:SetText("|cFFFFFF99Pending by you.|r " .. tostring(timerText) .. " left.")
          end
        else
          btn.statusText:SetText("|cFFFFFF99Pending:|r " .. tostring(fulfiller or "Unknown") .. "  |  " .. tostring(timerText) .. " left")
        end
      elseif me and not IsWorkOrderPartialClaim(order) and LeafVE:CanPlayerFulfillWorkOrder(me, order) then
        btn.actionType = "fulfill"
        if (tonumber(order.quantity) or 0) > 1 then
          btn.secondaryActionType = "partial_fulfill"
        end
        if requiresDesignation then
          btn.statusText:SetText("|cFF88FF88Eligible to fulfill.|r Your saved professions match this order.")
        else
          btn.statusText:SetText("|cFF88FF88Eligible to fulfill.|r This farming request can be claimed by anyone.")
        end
      elseif me and order.requester and Lower(order.requester) == Lower(me) then
        if requiresDesignation then
          btn.statusText:SetText("|cFFAAAAAAYour request is live for qualified crafters.|r")
        else
          btn.statusText:SetText("|cFFAAAAAAYour farming request is live for anyone to claim.|r")
        end
      else
        if requiresDesignation then
          btn.statusText:SetText("|cFFAAAAAARequires a saved " .. tostring(order.profession or "profession") .. " profession to fulfill.|r")
        else
          btn.statusText:SetText("|cFFAAAAAAOpen farming request.|r Anyone can pick this up.")
        end
      end
      if btn.reagentText then
        btn.reagentText:SetText("|cFF88CCFF" .. tostring(matsLine) .. "|r\n" .. tostring(materialsText or ""))
      end

      if btn.idText then
        btn.idText:SetText("")
        btn.idText:Hide()
      end

      if btn.actionType == "fulfill" then
        btn.actionBtn:SetText("Fulfill")
        btn.actionBtn:Show()
        btn.actionBtn:Enable()
      elseif btn.actionType == "complete" then
        btn.actionBtn:SetText("Complete")
        btn.actionBtn:Show()
        btn.actionBtn:Enable()
      else
        btn.actionBtn:SetText("")
        btn.actionBtn:Hide()
      end
      if btn.secondaryActionType == "release" then
        btn.secondaryActionBtn:SetText("Release")
        btn.secondaryActionBtn:Show()
        btn.secondaryActionBtn:Enable()
      elseif btn.secondaryActionType == "partial_fulfill" then
        btn.secondaryActionBtn:SetText("Partial")
        btn.secondaryActionBtn:Show()
        btn.secondaryActionBtn:Enable()
      else
        btn.secondaryActionBtn:SetText("")
        btn.secondaryActionBtn:Hide()
      end
      local reservedRight = ClampWorkOrderTipCopper(order.tipCopper) > 0 and 118 or 18
      if btn.actionType or btn.secondaryActionType then
        reservedRight = math.max(reservedRight, 96)
      end
      local textWidth = math.max(150, listWidth - reservedRight - 42)
      btn.text:SetWidth(textWidth)
      btn.detailText:SetWidth(textWidth)
      btn.statusText:SetWidth(textWidth)
      if btn.reagentText then
        btn.reagentText:SetWidth(textWidth)
      end
      btn:Show()
    else
      btn.order = nil
      btn.actionType = nil
      btn.secondaryActionType = nil
      SetWorkOrderRowTipDisplay(btn, 0)
      if btn.actionBtn then
        btn.actionBtn:SetText("")
        btn.actionBtn:Hide()
      end
      if btn.secondaryActionBtn then
        btn.secondaryActionBtn:SetText("")
        btn.secondaryActionBtn:Hide()
      end
      if btn.idText then
        btn.idText:SetText("")
        btn.idText:Hide()
      end
      if btn.reagentText then
        btn.reagentText:SetText("")
      end
      btn:Hide()
    end
  end

  SyncWorkOrderSlider(popup.orderScrollBar, popup.orderOffset or 0, maxOffset)

  if totalOrders > 0 then
    popup.noOrdersText:Hide()
  else
    popup.noOrdersText:Show()
    popup.noOrdersText:SetText("|cFF888888There are no active work orders right now.|r")
  end

  popup.summaryText:SetText(
    "Live: " .. tostring(openCount) .. " open  |  " .. tostring(pendingCount) .. " pending  |  Eligible: " .. tostring(eligibleCount)
  )
end

function LeafVE.UI:RefreshWorkOrderOrdersView(playerName, popup)
  popup.professionPanel:Hide()
  popup.recipePanel:Hide()
  popup.selectionPanel:Hide()
  if popup.ordersPanel then
    popup.ordersPanel:Show()
  end
  if popup.craftersPanel then
    popup.craftersPanel:Hide()
  end

  LeafVE:RequestWorkOrderSync(false)

  popup.subtitleText:SetText("Track your requests from posting to verification")
  if popup.ordersTitle then
    popup.ordersTitle:SetText("|cFFFFD700My Orders|r")
  end
  if popup.ordersHint then
    popup.ordersHint:SetText("|cFFAAAAAACancel open requests here, reassign pending ones if needed, and use |cFFFFD700Verify|r or |cFFFFD700Revert|r once a crafter marks an order complete. Partial fills stay separate so the remaining quantity can keep moving on the live board.|r")
  end

  local me = ShortName(UnitName("player"))
  local now = Now()
  local orders = me and LeafVE:GetWorkOrdersForRequester(me, playerName) or {}
  local openCount = 0
  local pendingCount = 0
  local completedCount = 0
  for i = 1, table.getn(orders) do
    local status = LeafVE:GetEffectiveWorkOrderStatus(orders[i], now)
    if status == "pending" then
      pendingCount = pendingCount + 1
    elseif status == "completed" then
      completedCount = completedCount + 1
    else
      openCount = openCount + 1
    end
  end
  popup.openOrderRows = orders

  local rowHeight = popup.orderRowHeight or 56
  local visibleRows = GetWorkOrderVisibleRowCount(popup.orderListFrame, rowHeight, 6)
  local totalOrders = table.getn(orders)
  local maxOffset = math.max(0, totalOrders - visibleRows)
  if (popup.orderOffset or 0) > maxOffset then
    popup.orderOffset = maxOffset
  end
  popup.orderVisibleRows = visibleRows

  while table.getn(popup.orderButtons) < visibleRows do
    local btn = CreateWorkOrderOrderButton(popup.orderListFrame)
    btn.popup = popup
    table.insert(popup.orderButtons, btn)
  end

  local listWidth = popup.orderListFrame:GetWidth() or 0
  if not listWidth or listWidth < 260 then
    listWidth = 340
  end

  local startIndex = (popup.orderOffset or 0) + 1
  for row = 1, table.getn(popup.orderButtons) do
    local btn = popup.orderButtons[row]
    local dataIndex = startIndex + row - 1
    if row <= visibleRows and dataIndex <= totalOrders then
      local order = orders[dataIndex]
      local status = LeafVE:GetEffectiveWorkOrderStatus(order, now)
      local fulfiller = LeafVE:GetStoredWorkOrderFulfiller(order)
      local timerText = tonumber(order.claimExpiresAt or 0) > now and FormatWorkOrderRemainingTime(order.claimExpiresAt, now) or "Expired"
      local requiresDesignation = LeafVE:DoesWorkOrderRequireDesignation(order)

      btn.order = order
      btn.popup = popup
      btn:SetWidth(listWidth - 4)
      btn:SetHeight(rowHeight - 4)
      btn:ClearAllPoints()
      btn:SetPoint("TOPLEFT", popup.orderListFrame, "TOPLEFT", 2, -((row - 1) * rowHeight) - 2)
      btn.icon:SetTexture(order.icon or LEAF_FALLBACK)
      btn.text:SetText("|cFFFFD700" .. tostring(order.recipeName or "Work Order") .. "|r")
      local matsLine = GetWorkOrderMatsLine(order.matsMode, order.requester, order.profession)
      local materialsText = LeafVE:GetWorkOrderListMaterialsText(order, order.quantity or 1, 2)
      btn.detailText:SetText(
        "Requester: " .. tostring(order.requester or "Unknown") ..
        "  |  " .. tostring(order.profession or "Unknown") ..
        "  |  " .. GetWorkOrderQuantitySummary(order) ..
        "  |  " .. FormatWorkOrderTipText(order.tipCopper)
      )
      SetWorkOrderRowTipDisplay(btn, order.tipCopper)
      if status == "pending" then
        if IsWorkOrderPartialClaim(order) then
          btn.statusText:SetText("|cFFFFFF99Pending partial:|r " .. tostring(fulfiller or "Unknown") .. " reserved " .. tostring(order.quantity or 1) .. ". " .. tostring(timerText) .. " left. Reassign to return it to the live board.")
        else
          btn.statusText:SetText("|cFFFFFF99Pending:|r " .. tostring(fulfiller or "Unknown") .. "  |  " .. tostring(timerText) .. " left. Reassign for a different crafter.")
        end
        btn.actionType = "cancel"
        btn.actionBtn:SetText("Cancel")
        btn.actionBtn:Show()
        btn.actionBtn:Enable()
        btn.secondaryActionType = "reassign"
        btn.secondaryActionBtn:SetText("Reassign")
        btn.secondaryActionBtn:Show()
        btn.secondaryActionBtn:Enable()
      elseif status == "completed" then
        if IsWorkOrderPartialClaim(order) then
          btn.statusText:SetText("|cFF88FF88Completed:|r " .. tostring(fulfiller or "Unknown") .. " delivered this partial fill. Verify when received, or Revert to return it to the live board.")
        else
          btn.statusText:SetText("|cFF88FF88Completed:|r " .. tostring(fulfiller or "Unknown") .. " marked it done. Verify when received, or Revert for more work.")
        end
        btn.actionType = "final"
        btn.actionBtn:SetText("Verify")
        btn.actionBtn:Show()
        btn.actionBtn:Enable()
        btn.secondaryActionType = "revert"
        btn.secondaryActionBtn:SetText("Revert")
        btn.secondaryActionBtn:Show()
        btn.secondaryActionBtn:Enable()
      else
        if requiresDesignation then
          btn.statusText:SetText("|cFFAAAAAAOpen on the live board.|r Waiting for a qualified crafter.")
        else
          btn.statusText:SetText("|cFFAAAAAAOpen on the live board.|r Waiting for someone to farm it.")
        end
        btn.actionType = "cancel"
        btn.actionBtn:SetText("Cancel")
        btn.actionBtn:Show()
        btn.actionBtn:Enable()
        btn.secondaryActionType = nil
        btn.secondaryActionBtn:SetText("")
        btn.secondaryActionBtn:Hide()
      end
      if btn.idText then
        btn.idText:SetText("")
        btn.idText:Hide()
      end
      if not btn.secondaryActionType and btn.secondaryActionBtn then
        btn.secondaryActionBtn:SetText("")
        btn.secondaryActionBtn:Hide()
      end
      if btn.reagentText then
        btn.reagentText:SetText("|cFF88CCFF" .. tostring(matsLine) .. "|r\n" .. tostring(materialsText or ""))
      end
      local reservedRight = ClampWorkOrderTipCopper(order.tipCopper) > 0 and 118 or 18
      if btn.actionType or btn.secondaryActionType then
        reservedRight = math.max(reservedRight, 96)
      end
      local textWidth = math.max(150, listWidth - reservedRight - 42)
      btn.text:SetWidth(textWidth)
      btn.detailText:SetWidth(textWidth)
      btn.statusText:SetWidth(textWidth)
      if btn.reagentText then
        btn.reagentText:SetWidth(textWidth)
      end
      btn:Show()
    else
      btn.order = nil
      btn.actionType = nil
      btn.secondaryActionType = nil
      SetWorkOrderRowTipDisplay(btn, 0)
      if btn.actionBtn then
        btn.actionBtn:SetText("")
        btn.actionBtn:Hide()
      end
      if btn.secondaryActionBtn then
        btn.secondaryActionBtn:SetText("")
        btn.secondaryActionBtn:Hide()
      end
      if btn.idText then
        btn.idText:SetText("")
        btn.idText:Hide()
      end
      if btn.reagentText then
        btn.reagentText:SetText("")
      end
      btn:Hide()
    end
  end

  SyncWorkOrderSlider(popup.orderScrollBar, popup.orderOffset or 0, maxOffset)

  if totalOrders > 0 then
    popup.noOrdersText:Hide()
  else
    popup.noOrdersText:Show()
    if me then
      popup.noOrdersText:SetText("|cFF888888You have no active work orders right now.|r")
    else
      popup.noOrdersText:SetText("|cFF888888Your player name could not be determined.|r")
    end
  end

  popup.summaryText:SetText(
    "My orders: " .. tostring(totalOrders) .. "  |  " .. tostring(openCount) .. " open  |  " .. tostring(pendingCount) .. " pending  |  " .. tostring(completedCount) .. " awaiting verify"
  )
end

function LeafVE.UI:RefreshWorkOrderPopup(playerName)
  if not self.workOrderPopup then return end
  playerName = ShortName(playerName or UnitName("player"))
  if not playerName then return end

  local popup = self.workOrderPopup
  local switchedPlayer = popup.currentPlayer and Lower(popup.currentPlayer) ~= Lower(playerName)
  popup.currentPlayer = playerName
  if switchedPlayer then
    if popup.feedbackText then
      popup.feedbackText:SetText("")
    end
    if popup.ordersFeedbackText then
      popup.ordersFeedbackText:SetText("")
    end
    if popup.craftersFeedbackText then
      popup.craftersFeedbackText:SetText("")
    end
  end

  if not popup.viewMode or popup.viewMode == "" then
    popup.viewMode = "live"
  end

  if popup.isEmbeddedWorkOrderView then
    popup.titleText:SetText("Shinobi Orders Board")
  else
    popup.titleText:SetText("Work Orders")
  end
  UpdateWorkOrderModeButtonVisual(popup.browseModeBtn, popup.viewMode == "browse")
  UpdateWorkOrderModeButtonVisual(popup.liveModeBtn, popup.viewMode == "live")
  UpdateWorkOrderModeButtonVisual(popup.ordersModeBtn, popup.viewMode == "orders")
  if popup.craftersModeBtn then
    UpdateWorkOrderModeButtonVisual(popup.craftersModeBtn, popup.viewMode == "crafters")
  end

  if popup.viewMode == "live" then
    self:RefreshWorkOrderLiveView(playerName, popup)
  elseif popup.viewMode == "crafters" then
    self:RefreshWorkOrderCraftersView(playerName, popup)
  elseif popup.viewMode == "orders" then
    self:RefreshWorkOrderOrdersView(playerName, popup)
  else
    self:RefreshWorkOrderBrowseView(playerName, popup, LeafVE:EnsureWorkOrderCatalog())
  end

  if popup.isEmbeddedWorkOrderView and self.RefreshEmbeddedWorkOrderOverview then
    self:RefreshEmbeddedWorkOrderOverview(popup, playerName)
  end
end

function LeafVE.UI:CreateGuildBankPopup()
