  end
  UpdateWorkOrderModeButtonVisual(panel.guideModeBtn, panel.activeWelcomeSection == "guide")
  UpdateWorkOrderModeButtonVisual(panel.allianceModeBtn, panel.activeWelcomeSection == "alliance")
