        local rankIcon = frame:CreateTexture(nil, "ARTWORK")
        rankIcon:SetWidth(32)
        rankIcon:SetHeight(32)
        rankIcon:SetPoint("LEFT", frame, "LEFT", 5, 0)
        frame.rankIcon = rankIcon

        local rank = frame:CreateFontString(nil, "OVERLAY", "GameFontNormalLarge")
        rank:SetPoint("LEFT", frame, "LEFT", 5, 0)
        rank:SetWidth(30)
        rank:SetJustifyH("RIGHT")
        frame.rank = rank

        local nameText = frame:CreateFontString(nil, "OVERLAY", "GameFontNormal")
        nameText:SetPoint("TOPLEFT", frame, "TOPLEFT", 75, -8)
        nameText:SetWidth(230)
        nameText:SetJustifyH("LEFT")
        frame.nameText = nameText

        local metaText = frame:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
        metaText:SetPoint("TOPLEFT", nameText, "BOTTOMLEFT", 0, -2)
        metaText:SetWidth(260)
        metaText:SetJustifyH("LEFT")
        frame.metaText = metaText

        local pointsText = frame:CreateFontString(nil, "OVERLAY", "GameFontHighlight")
        pointsText:SetPoint("TOPRIGHT", frame, "TOPRIGHT", -10, -10)
        pointsText:SetWidth(140)
        pointsText:SetJustifyH("RIGHT")
        frame.pointsText = pointsText

        local detailText = frame:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
        detailText:SetPoint("TOPRIGHT", pointsText, "BOTTOMRIGHT", 0, -2)
        detailText:SetWidth(170)
        detailText:SetJustifyH("RIGHT")
        frame.detailText = detailText

        local bg = frame:CreateTexture(nil, "BACKGROUND")
        bg:SetAllPoints(frame)
        bg:SetTexture("Interface\\Tooltips\\UI-Tooltip-Background")
        bg:SetVertexColor(0.1, 0.1, 0.1, 0.3)
        frame.bg = bg

        frame:EnableMouse(true)
        frame:SetScript("OnEnter", function()
          this.bg:SetVertexColor(0.14, 0.20, 0.12, 0.75)
        end)
        frame:SetScript("OnLeave", function()
          this.bg:SetVertexColor(0.1, 0.1, 0.1, 0.3)
        end)
        frame:SetScript("OnMouseUp", function()
          if this.playerName then
            if LeafVE.UI.allBadgesFrame and LeafVE.UI.allBadgesFrame:IsVisible() then
              LeafVE.UI.allBadgesFrame:Hide()
            end
            if LeafVE.UI.achPopup and LeafVE.UI.achPopup:IsVisible() then
              LeafVE.UI.achPopup:Hide()
            end
            if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
              LeafVE.UI.gearPopup:Hide()
            end
            if LeafVE.UI.workOrderPopup and LeafVE.UI.workOrderPopup:IsVisible() then
              LeafVE.UI.workOrderPopup:Hide()
            end
            if LeafVE.UI.talentPopup and LeafVE.UI.talentPopup:IsVisible() then
              LeafVE.UI.talentPopup:Hide()
            end
            LeafVE.UI:HideNativeTalentFrame()
            LeafVE.UI.inspectedPlayer = this.playerName
            LeafVE.UI:ShowPlayerCard(this.playerName)
          end
        end)

        table.insert(panel.repEntries, frame)
      end

      frame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", 5, yOffset)

      if i <= 5 and PVP_RANK_ICONS[i] then
        frame.rankIcon:SetTexture(PVP_RANK_ICONS[i])
        frame.rankIcon:Show()
        frame.rank:Hide()
      else
        frame.rankIcon:Hide()
        frame.rank:Show()
        frame.rank:SetText("#" .. i)
        frame.rank:SetTextColor(1, 1, 1)
      end

      local classTag = LeafVE:GetClassTagForPlayer(leader.name) or "UNKNOWN"
      local tierInfo = leader.tierInfo or LeafVE:GetWorkOrderReputationTierInfo(leader.totalRep or 0)
      local tierName = tierInfo and tierInfo.current and tierInfo.current.name or "Leaf Apprentice"
      local topProfessionText = leader.topProfession and tostring(leader.topProfession) or "No profession focus"

      frame.nameText:SetText(LeafVE:BuildStyledPlayerName(leader.name, classTag))
      frame.playerName = leader.name
      frame.metaText:SetText("|cFF888888" .. tostring(tierName) .. "  |  " .. tostring(topProfessionText) .. "|r")
      frame.pointsText:SetText("|cFFFFD700" .. LeafVE:FormatPointAmount(leader.totalRep or 0) .. " rep|r")
      frame.detailText:SetText("|cFF88CC88C " .. LeafVE:FormatPointAmount(leader.crafterRep or 0) .. "|r  |  |cFF88CCFFR " .. LeafVE:FormatPointAmount(leader.requesterRep or 0) .. "|r")

      frame:Show()
      yOffset = yOffset - entryHeight - 8
    end
  end

  scrollChild:SetHeight(math.max(1, math.abs(yOffset) + 50))

  local scrollRange = panel.scrollFrame:GetVerticalScrollRange()
  if scrollRange > 0 then
    panel.scrollBar:Show()
  else
    panel.scrollBar:Hide()
  end

  panel.scrollFrame:SetVerticalScroll(0)
  panel.scrollBar:SetValue(0)
end

function LeafVE.UI:Build()
  if self.frame then return end
  
  EnsureDB()
  
  local f = (LEAFVE_UI_MODERN and LEAFVE_UI_MODERN.CreateMainFrame and LEAFVE_UI_MODERN:CreateMainFrame(UIParent))
    or CreateFrame("Frame", "LeafVE_MainFrame", UIParent)
  self.frame = f
  _G["LeafVE_MainFrame"] = f
  if UISpecialFrames then
    local hasMainFrameEscape = false
    for _, frameName in ipairs(UISpecialFrames) do
      if frameName == "LeafVE_MainFrame" then
        hasMainFrameEscape = true
        break
      end
    end
    if not hasMainFrameEscape then
      table.insert(UISpecialFrames, "LeafVE_MainFrame")
    end
  end
  f:SetPoint("CENTER", UIParent, "CENTER", 0, 0)
  
  local w, h = LeafVE:ClampUISize(LeafVE_DB.ui.w, LeafVE_DB.ui.h)
  local uiScale = LeafVE:ClampUIScale(LeafVE_DB.ui.scale)
  
  f:SetWidth(w)
  f:SetHeight(h)
  if f.SetFrameStrata then
    f:SetFrameStrata("DIALOG")
  end
  if f.SetToplevel then
    f:SetToplevel(true)
  end
  if f.SetScale then
    f:SetScale(uiScale)
  end
  f:EnableMouse(false)
  f:SetMovable(true)
  if f.SetClampedToScreen then
    f:SetClampedToScreen(true)
  end

  local function StopLeafFrameDrag()
    f:StopMovingOrSizing()
    if LeafVE_DB and LeafVE_DB.ui then
      local point, _, relativePoint, x, y = f:GetPoint()
      LeafVE_DB.ui.point = point
      LeafVE_DB.ui.relativePoint = relativePoint
      LeafVE_DB.ui.x = x
      LeafVE_DB.ui.y = y
    end
  end

  local dragHandle = CreateFrame("Frame", nil, f)
  dragHandle:SetPoint("TOPLEFT", f, "TOPLEFT", 10, -6)
  dragHandle:SetPoint("TOPRIGHT", f, "TOPRIGHT", -34, -6)
  dragHandle:SetHeight(34)
  dragHandle:EnableMouse(true)
  dragHandle:RegisterForDrag("LeftButton")
  dragHandle:SetScript("OnDragStart", function() f:StartMoving() end)
  dragHandle:SetScript("OnDragStop", StopLeafFrameDrag)
  self.dragHandle = dragHandle
  
  SkinFrameModern(f)
  if LEAFVE_UI_MODERN and LEAFVE_UI_MODERN.ApplyModernFrame then
    LEAFVE_UI_MODERN:ApplyModernFrame(f)
  end
  if Colors and Colors.PRIMARY and Colors.PRIMARY.darkest and f.SetBackdropColor then
    f:SetBackdropColor(Colors.PRIMARY.darkest.r, Colors.PRIMARY.darkest.g, Colors.PRIMARY.darkest.b, 0.95)
  end
  LeafVECallSkin("SkinBorder", f, (Colors and Colors.TEXT and Colors.TEXT.gold) or nil, 2)
  MakeResizeHandle(f)
  
  f:SetScript("OnSizeChanged", function()
    if LeafVE_DB and LeafVE_DB.ui then
      LeafVE_DB.ui.w = f:GetWidth()
      LeafVE_DB.ui.h = f:GetHeight()
    end
    if LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.options and LeafVE.UI.panels.options:IsVisible() then
      LeafVE.UI:RefreshOptions()
    end
  end)

  if f.HookScript then
    f:HookScript("OnShow", function()
      if this and this.Raise then
        this:Raise()
      end
    end)
    f:HookScript("OnHide", function()
      if LeafVE.UI.allBadgesFrame then LeafVE.UI.allBadgesFrame:Hide() end
      if LeafVE.UI.achPopup then LeafVE.UI.achPopup:Hide() end
      if LeafVE.UI.gearPopup then LeafVE.UI.gearPopup:Hide() end
      if LeafVE.UI.professionPopup then LeafVE.UI.professionPopup:Hide() end
      if LeafVE.UI.workOrderPopup then LeafVE.UI.workOrderPopup:Hide() end
      if LeafVE.UI.guildBankPopup then LeafVE.UI.guildBankPopup:Hide() end
      if LeafVE.UI.talentPopup then LeafVE.UI.talentPopup:Hide() end
      LeafVE.UI:HideNativeTalentFrame()
    end)
  else
    local _prevOnShow = f:GetScript("OnShow")
    local _prevOnHide = f:GetScript("OnHide")
    f:SetScript("OnShow", function()
      if _prevOnShow then _prevOnShow(f) end
      if f.Raise then
        f:Raise()
      end
    end)
    f:SetScript("OnHide", function()
      if _prevOnHide then _prevOnHide(f) end
      if LeafVE.UI.allBadgesFrame then LeafVE.UI.allBadgesFrame:Hide() end
      if LeafVE.UI.achPopup then LeafVE.UI.achPopup:Hide() end
      if LeafVE.UI.gearPopup then LeafVE.UI.gearPopup:Hide() end
      if LeafVE.UI.professionPopup then LeafVE.UI.professionPopup:Hide() end
      if LeafVE.UI.workOrderPopup then LeafVE.UI.workOrderPopup:Hide() end
      if LeafVE.UI.guildBankPopup then LeafVE.UI.guildBankPopup:Hide() end
      if LeafVE.UI.talentPopup then LeafVE.UI.talentPopup:Hide() end
      LeafVE.UI:HideNativeTalentFrame()
    end)
  end
  
  -- Title (CENTERED, GOLD)
  local title = f:CreateFontString(nil, "OVERLAY", "GameFontNormalLarge")
  title:SetPoint("TOP", f, "TOP", 0, -12)  -- ÃƒÂ¢Ã¢â‚¬Â Ã‚Â CENTERED
  title:SetText("Leaf Village Legends")
  if not LeafVEApplyFont(title, "header_large", "OUTLINE") then
    title:SetTextColor(THEME.gold[1], THEME.gold[2], THEME.gold[3])
  else
    title:SetTextColor((Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.r) or THEME.gold[1], (Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.g) or THEME.gold[2], (Colors and Colors.TEXT and Colors.TEXT.gold and Colors.TEXT.gold.b) or THEME.gold[3], 1)
  end
  
  -- Subtitle description (centered below title)
  local sub = f:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  sub:SetPoint("TOP", title, "BOTTOM", 0, -2)
  sub:SetText("Auto-tracking: Login + Group Points")
  LeafVEApplyFont(sub, "body_small")
  sub:SetTextColor((Colors and Colors.TEXT and Colors.TEXT.muted_gray and Colors.TEXT.muted_gray.r) or 0.7, (Colors and Colors.TEXT and Colors.TEXT.muted_gray and Colors.TEXT.muted_gray.g) or 0.7, (Colors and Colors.TEXT and Colors.TEXT.muted_gray and Colors.TEXT.muted_gray.b) or 0.7)
  
  -- Emblem (left side, keep existing)
  local emblem = f:CreateTexture(nil, "ARTWORK")
  emblem:SetWidth(22)
  emblem:SetHeight(22)
  emblem:SetPoint("TOPLEFT", f, "TOPLEFT", 14, -12)
  emblem:SetTexture(LEAF_EMBLEM)
  if not emblem:GetTexture() then emblem:SetTexture(LEAF_FALLBACK) end
  emblem:SetVertexColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 1)
  
  -- Created by credit (FAR RIGHT)
  local credit = f:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
  credit:SetPoint("TOPRIGHT", f, "TOPRIGHT", -35, -12)
  credit:SetText("|cFF2DD35CCreated by Methl|r")
  credit:SetAlpha(0.9)
  
  local close = CreateFrame("Button", nil, f, "UIPanelCloseButton")
