  end
  self:LayoutLegacyMainTabs()
  
  self.inset = CreateInset(f)
  self.inset:SetPoint("TOPLEFT", f, "TOPLEFT", 12, -106)
  self.inset:SetPoint("BOTTOMRIGHT", f, "BOTTOMRIGHT", -12, 12)
  
  self.left = CreateFrame("Frame", nil, self.inset)
