    self.panels.guildEvents.loadErrorText = guildEventLoadErrorText
  end

  self.panels.workOrders = CreateFrame("Frame", nil, self.inset)
  self.panels.workOrders:SetAllPoints(self.inset)
  SkinPrimaryPanel(self.panels.workOrders)
  BuildWorkOrdersPanel(self.panels.workOrders)

  self.panels.shinobiDuties = CreateFrame("Frame", nil, self.inset)
  self.panels.shinobiDuties:SetAllPoints(self.inset)
  SkinPrimaryPanel(self.panels.shinobiDuties)
  BuildShinobiDutiesPanel(self.panels.shinobiDuties)

  self.panels.workOrderRep = CreateFrame("Frame", nil, self.inset)
  self.panels.workOrderRep:SetAllPoints(self.inset)
  SkinPrimaryPanel(self.panels.workOrderRep)
  BuildWorkOrderReputationPanel(self.panels.workOrderRep)

  self.panels.welcome = CreateFrame("Frame", nil, self.inset)
  self.panels.welcome:SetAllPoints(self.inset)
  SkinPrimaryPanel(self.panels.welcome)
  BuildWelcomePanel(self.panels.welcome)

  self.panels.join = CreateFrame("Frame", nil, self.left)
  self.panels.join:SetAllPoints(self.left)
  SkinPrimaryPanel(self.panels.join)
  BuildJoinPanel(self.panels.join)
  
  -- Tab click handlers
  self.tabMe:SetScript("OnClick", function()
    self.activeTab = "me"
    local me = ShortName(UnitName("player"))
    if me then self:ShowPlayerCard(me) end
    self:Refresh()
  end)
  
  self.tabLeaderWeek:SetScript("OnClick", function()
    self.activeTab = "leaderWeek"
    self:Refresh()
  end)
  
  self.tabLeaderLife:SetScript("OnClick", function()
    self.activeTab = "leaderLife"
    self:Refresh()
  end)
  
  self.tabRoster:SetScript("OnClick", function()
    self.activeTab = "roster"
    self:Refresh()
  end)
  
  self.tabHistory:SetScript("OnClick", function()
    self.activeTab = "history"
    self:Refresh()
  end)
  
  self.tabBadges:SetScript("OnClick", function()
    self.activeTab = "badges"
    self:Refresh()
  end)
  
  self.tabShoutouts:SetScript("OnClick", function()
    self.activeTab = "shoutouts"
    self:Refresh()
  end)

  self.tabAchievements:SetScript("OnClick", function()
    self.activeTab = "achievements"
    self:Refresh()
  end)

  self.tabShinobiReputation:SetScript("OnClick", function()
    self.activeTab = "shinobiReputation"
    self:Refresh()
  end)

  self.tabOptions:SetScript("OnClick", function()
    self.activeTab = "options"
    self:Refresh()
  end)

  self.tabAdmin:SetScript("OnClick", function()
    self.activeTab = "admin"
    self:Refresh()
  end)

  self.tabLiveHistory:SetScript("OnClick", function()
    self.activeTab = "liveHistory"
    self:Refresh()
  end)

  self.tabGuildEvents:SetScript("OnClick", function()
    self.activeTab = "guildEvents"
    self:Refresh()
  end)

  self.tabWorkOrderRep:SetScript("OnClick", function()
    self.activeTab = "workOrderRep"
    self:Refresh()
  end)

  self.tabWelcome:SetScript("OnClick", function()
    self.activeTab = "welcome"
    self:Refresh()
  end)
  
  self.tabJoin:SetScript("OnClick", function()
    self.activeTab = "join"
    self:Refresh()
  end)
  
  -- Initial state - hide all panels except "me"
  self.activeTab = "me"

  self:HideAllMainPanels()
  if self:ShouldUseGroupedNavigation() then
    self:HideLegacyMainTabs()
  else
    self:HideGroupedNavigation()
  end
  self.panels.me:Show()
  
  local me = ShortName(UnitName("player"))
  if me then
    self:ShowPlayerCard(me)
  end
  
  if LeafVE_DB.ui.point and LeafVE_DB.ui.x and LeafVE_DB.ui.y then
    f:ClearAllPoints()
    f:SetPoint(LeafVE_DB.ui.point, UIParent, LeafVE_DB.ui.relativePoint or "CENTER", LeafVE_DB.ui.x, LeafVE_DB.ui.y)
  end
  
  f:Hide()
end

function LeafVE.UI:Refresh()
  EnsureDB()
  LeafVE:PurgeStaleWeeklyData()
  
  -- Safety check: UI may not be built yet on early login events; silently skip.
  if not self.panels then 
    return 
  end
  if self.frame and self.frame.IsVisible and not self.frame:IsVisible() then
    return
  end

  if self.activeTab ~= "welcome" and self.UnloadAllianceWelcomeRoster then
    self:UnloadAllianceWelcomeRoster(false)
  end

  -- If in "update required" mode, only show the update panel.
  if self.panels.update then
    self.panels.update:Show()
    return
  end

  self:HideAllMainPanels()
  if self.card then
    self.card:Hide()
  end
  if self.workOrderPopup and self.workOrderPopup.isEmbeddedWorkOrderView and self.activeTab ~= "workOrders" then
    self.workOrderPopup:Hide()
  end

  local hasAccess = LeafVE:HasLeafAccess()
  if not hasAccess and self.activeTab ~= "join" then
    self.activeTab = "join"
  elseif hasAccess and self.activeTab == "join" then
    self.activeTab = "me"
  end
  if self.activeTab == "raidSignups" then
    self.activeTab = "guildEvents"
  elseif self.activeTab == "guildBank" then
    self.activeTab = "workOrderRep"
  end

  local accessTabs = {self.tabWelcome, self.tabMe, self.tabRoster, self.tabLeaderWeek, self.tabLeaderLife, self.tabAchievements, self.tabShinobiReputation, self.tabBadges, self.tabShoutouts, self.tabHistory, self.tabLiveHistory, self.tabGuildEvents, self.tabWorkOrderRep, self.tabOptions}
  if hasAccess then
    for _, tab in ipairs(accessTabs) do
      if tab then tab:Show() end
    end
  else
    for _, tab in ipairs(accessTabs) do
      if tab then tab:Hide() end
    end
  end

  if self.tabAdmin then
    if hasAccess and LeafVE:IsAdminRank() then
      self.tabAdmin:Show()
    else
      self.tabAdmin:Hide()
      -- Redirect away from admin tab if player lost access
      if self.activeTab == "admin" then
        self.activeTab = hasAccess and "me" or "join"
      end
    end
  end
  
  if self.tabJoin then
    if hasAccess then
      self.tabJoin:Hide()
    else
      self.tabJoin:Show()
    end
    UpdateLeafTabVisual(self.tabJoin, not hasAccess and self.activeTab == "join")
  end
  for _, tab in ipairs(accessTabs) do
    if tab then
      local isActive = false
      if tab == self.tabWelcome then isActive = (self.activeTab == "welcome")
      elseif tab == self.tabMe then isActive = (self.activeTab == "me")
      elseif tab == self.tabRoster then isActive = (self.activeTab == "roster")
      elseif tab == self.tabLeaderWeek then isActive = (self.activeTab == "leaderWeek")
      elseif tab == self.tabLeaderLife then isActive = (self.activeTab == "leaderLife")
    elseif tab == self.tabAchievements then isActive = (self.activeTab == "achievements")
    elseif tab == self.tabShinobiReputation then isActive = (self.activeTab == "shinobiReputation")
    elseif tab == self.tabBadges then isActive = (self.activeTab == "badges")
      elseif tab == self.tabShoutouts then isActive = (self.activeTab == "shoutouts")
      elseif tab == self.tabHistory then isActive = (self.activeTab == "history")
      elseif tab == self.tabLiveHistory then isActive = (self.activeTab == "liveHistory")
      elseif tab == self.tabGuildEvents then isActive = (self.activeTab == "guildEvents")
      elseif tab == self.tabWorkOrderRep then isActive = (self.activeTab == "workOrderRep")
      elseif tab == self.tabOptions then isActive = (self.activeTab == "options")
      end
      UpdateLeafTabVisual(tab, isActive)
    end
  end
  UpdateLeafTabVisual(self.tabAdmin, self.activeTab == "admin" and self.tabAdmin and self.tabAdmin:IsShown())
  self:RefreshGroupedNavigation(hasAccess)

  if self.card then
    if hasAccess and self.activeTab ~= "guildEvents" and self.activeTab ~= "workOrderRep" and self.activeTab ~= "workOrders" and self.activeTab ~= "shinobiDuties" and self.activeTab ~= "welcome" then
      self.card:Show()
    else
      self.card:Hide()
    end
  end

  local function ShowPanelWithTransition(panel)
    if not panel then return end
    if LEAFVE_UI_MODERN and LEAFVE_UI_MODERN.AnimateTabTransition then
      LEAFVE_UI_MODERN:AnimateTabTransition(panel)
    else
      panel:Show()
    end
  end
  
  if not hasAccess then
    if self.panels.join then
      ShowPanelWithTransition(self.panels.join)
    end
    return
  end
  
  -- Show active tab
  if self.activeTab == "me" and self.panels.me then
    ShowPanelWithTransition(self.panels.me)
    local me = ShortName(UnitName("player") or "")
    if not me or me == "" then return end
    
    local day = DayKey()
    local dayEntry = LeafVE_DB.global[day] and LeafVE_DB.global[day][me]
    local dayT = IsPointEntryInCurrentBucket(dayEntry) and dayEntry or {L = 0, G = 0, S = 0}
    
    if self.panels.me.todayStats then
      self.panels.me.todayStats:SetText(string.format(
        "Login: %d  |  Group: %d  |  Shoutouts: %d  |  |cFFFFD700Total: %d|r",
        dayT.L or 0, dayT.G or 0, dayT.S or 0, (dayT.L or 0) + (dayT.G or 0) + (dayT.S or 0)
      ))
    end
    
    -- Weekly: use only local aggregation (same as Today uses global[day][me] directly)
    local weekAgg = (AggForThisWeek())
    local weekT = weekAgg[me] or {L = 0, G = 0, S = 0}
    if self.panels.me.weekStats then
      self.panels.me.weekStats:SetText(string.format(
        "Login: %d  |  Group: %d  |  Shoutouts: %d  |  |cFFFFD700Total: %d|r",
        weekT.L or 0, weekT.G or 0, weekT.S or 0, (weekT.L or 0) + (weekT.G or 0) + (weekT.S or 0)
      ))
    end
    
    -- Reconcile season/all-time with aggregated daily totals so display never lags
    -- behind the authoritative per-day ledger.
    local globalSum = AggregateGlobalTotalsForPlayer(me)

    local seasonEntry = LeafVE_DB.season[me]
    local seasonBase = IsPointEntryInCurrentBucket(seasonEntry) and seasonEntry or {L = 0, G = 0, S = 0}
    local seasonT = {
      L = math.max(seasonBase.L or 0, globalSum.L or 0),
      G = math.max(seasonBase.G or 0, globalSum.G or 0),
      S = math.max(seasonBase.S or 0, globalSum.S or 0),
    }
    if not IsPointEntryInCurrentBucket(LeafVE_DB.season[me])
      or (LeafVE_DB.season[me].L or 0) < seasonT.L
      or (LeafVE_DB.season[me].G or 0) < seasonT.G
      or (LeafVE_DB.season[me].S or 0) < seasonT.S then
      LeafVE_DB.season[me] = {L = seasonT.L, G = seasonT.G, S = seasonT.S, _b = CurrentWipeVersion()}
    end
    if self.panels.me.seasonStats then
      self.panels.me.seasonStats:SetText(string.format(
        "Login: %d  |  Group: %d  |  Shoutouts: %d  |  |cFFFFD700Total: %d|r",
        seasonT.L or 0, seasonT.G or 0, seasonT.S or 0, (seasonT.L or 0) + (seasonT.G or 0) + (seasonT.S or 0)
      ))
    end
    
    local leaderboardAlltime = ResolveLifetimeEntryForDisplay(me)
    local bestAlltime = GetBestLifetimeEntry(me)
    local alltimeT = {
      L = math.max(leaderboardAlltime.L or 0, bestAlltime.L or 0, globalSum.L or 0),
      G = math.max(leaderboardAlltime.G or 0, bestAlltime.G or 0, globalSum.G or 0),
      S = math.max(leaderboardAlltime.S or 0, bestAlltime.S or 0, globalSum.S or 0),
    }
    if not IsPointEntryInCurrentBucket(LeafVE_DB.alltime[me])
      or (LeafVE_DB.alltime[me].L or 0) < alltimeT.L
      or (LeafVE_DB.alltime[me].G or 0) < alltimeT.G
      or (LeafVE_DB.alltime[me].S or 0) < alltimeT.S then
      LeafVE_DB.alltime[me] = {L = alltimeT.L, G = alltimeT.G, S = alltimeT.S, _b = CurrentWipeVersion()}
      StoreLifetimeSnapshot(me, alltimeT.L, alltimeT.G, alltimeT.S, me, true, true)
    end
    LeafVE:CacheBadgeProgress(me)
    if self.panels.me.alltimeStats then
      self.panels.me.alltimeStats:SetText(string.format(
        "Login: %d  |  Group: %d  |  Shoutouts: %d  |  |cFFFFD700Total: %d|r",
        alltimeT.L or 0, alltimeT.G or 0, alltimeT.S or 0, (alltimeT.L or 0) + (alltimeT.G or 0) + (alltimeT.S or 0)
      ))
    end
  
    -- Calculate Last Week's Top Shinobis
    if self.panels.me.lastWeekWinner then
      local previousWeekKey = PreviousWeekKey()
      local cachedWinner = LeafVE:GetCachedWeeklyWinnerSnapshot(previousWeekKey)
      if not cachedWinner then
        cachedWinner = LeafVE:SnapshotWeeklyLeaderboardWinner(previousWeekKey)
      end
      self.panels.me.lastWeekWinner:SetText(LeafVE:BuildWeeklyTopShinobisText(cachedWinner))
    end
    
    -- Calculate All-Time Leader (union of local alltime and synced lboard.alltime)
    if self.panels.me.alltimeLeader then
      local leader = nil
      local maxPoints = 0
      local wk = WeekKey()
      local syncedWeek = (type(LeafVE_DB.lboard.weekly[wk]) == "table") and LeafVE_DB.lboard.weekly[wk] or {}
      local localWeek = AggForThisWeek()
      local seen = {}
      for name, _ in pairs(LeafVE_DB.alltime) do seen[name] = true end
      for name, _ in pairs(LeafVE_DB.lboard.alltime) do seen[name] = true end
      for name, _ in pairs(localWeek) do seen[name] = true end
      for name, _ in pairs(syncedWeek) do seen[name] = true end
      for name, _ in pairs(seen) do
        local localPts  = LeafVE_DB.alltime[name]
        if not IsPointEntryInCurrentBucket(localPts) then
          localPts = nil
        end
        local syncedPts = LeafVE_DB.lboard.alltime[name]
        local lifeMeta = LeafVE_DB.lboard.updatedAt[name]
        local syncedIsAuthoritative = (type(lifeMeta) == "table" and lifeMeta.lifetimeAuthoritative == true)
        local pts = syncedIsAuthoritative and syncedPts or nil
        if not SamePlayerName(name, me) then
          localPts = nil
        end
        if LboardEntryTotal(localPts) > LboardEntryTotal(pts) then
          pts = localPts
        end
        local weekPts = syncedWeek[name] or localWeek[name]
        if LboardEntryTotal(weekPts) > LboardEntryTotal(pts) then
          pts = weekPts
        end
        local total = pts and ((pts.L or 0) + (pts.G or 0) + (pts.S or 0)) or 0
        if total > maxPoints then
          maxPoints = total
          leader = name
        end
      end
      if leader then
        local leaderClass = LeafVE:GetClassTagForPlayer(leader)
        self.panels.me.alltimeLeader:SetText(string.format("%s with |cFFFFD700%s points|r", LeafVE:BuildStyledPlayerName(leader, leaderClass), LeafVE:FormatPointAmount(maxPoints)))
      else
        self.panels.me.alltimeLeader:SetText("|cFF888888No data available|r")
      end
    end

    -- Refresh Season Rewards display
    if self.panels.me.seasonRewards then
      self.panels.me.seasonRewards:SetText("|cFFFFD700Temporarily Deactivated|r")
    end

    -- Calculate Week Countdown
    if self.panels.me.weekCountdown then
      local weekStart = WeekStartTS(Now())
      local weekEnd = weekStart + (7 * SECONDS_PER_DAY)
      local timeLeft = weekEnd - Now()
      
    if timeLeft > 0 then
      local days = math.floor(timeLeft / SECONDS_PER_DAY)
      local hours = math.floor((timeLeft - (days * SECONDS_PER_DAY)) / SECONDS_PER_HOUR)
      local minutes = math.floor((timeLeft - (days * SECONDS_PER_DAY) - (hours * SECONDS_PER_HOUR)) / 60)
      
      self.panels.me.weekCountdown:SetText(string.format("|cFFFFD700%dd %dh %dm|r", days, hours, minutes))
    else
      self.panels.me.weekCountdown:SetText("|cFFFF0000Resetting now!|r")
    end
   end

    if self.panels.me.messageOfDayText then
      self.panels.me.messageOfDayText:SetText(
        "|cFFBFE9C8\"" .. tostring(LeafVE:GetNarutoMessageOfTheDay(Now()) or "A true shinobi keeps moving for the people who believe in them.") .. "\"|r"
      )
    end

    -- Populate current weekly top 5 standings
    if self.panels.me.weekTopEntries then
      local wk = WeekKey()
      local syncedWeek = LeafVE_DB.lboard.weekly[wk]
      local localWeek = (AggForThisWeek())

      local weekLeaders = {}
      local memberSet = {}
      if LeafVE_DB.persistentRoster then
        for lowerName, info in pairs(LeafVE_DB.persistentRoster) do
          memberSet[lowerName] = info
        end
      end
      for lowerName, info in pairs(LeafVE.guildRosterCache) do
        memberSet[lowerName] = info
      end
      for _, guildInfo in pairs(memberSet) do
        local name = guildInfo.name
        local localPts = localWeek[name]
        local syncedPts = syncedWeek and syncedWeek[name]
        -- Synced data is ground truth; local aggregation is fallback only when synced is absent.
        local pts = syncedPts or localPts
        local total = pts and ((pts.L or 0) + (pts.G or 0) + (pts.S or 0)) or 0
        if total > 0 then
          table.insert(weekLeaders, {name = name, total = total})
        end
      end
      table.sort(weekLeaders, function(a, b)
        if a.total == b.total then return Lower(a.name) < Lower(b.name) end
        return a.total > b.total
      end)
      local medalProvider = LEAFVE_STYLE and LEAFVE_STYLE.GetMedalForRank
      local medal1 = medalProvider and LEAFVE_STYLE:GetMedalForRank(1) or nil
      local medal2 = medalProvider and LEAFVE_STYLE:GetMedalForRank(2) or nil
      local medal3 = medalProvider and LEAFVE_STYLE:GetMedalForRank(3) or nil
      local rankLabels = {
        (medal1 and (medal1 .. " ") or "") .. "|cFFFFD7001st|r",
        (medal2 and (medal2 .. " ") or "") .. "|cFFC0C0C02nd|r",
        (medal3 and (medal3 .. " ") or "") .. "|cFFCD7F323rd|r",
        "|cFFFFFFFF4th|r", "|cFFFFFFFF5th|r"
      }
      for i = 1, 5 do
        if self.panels.me.weekTopEntries[i] then
          if weekLeaders[i] then
            local leaderClass = LeafVE:GetClassTagForPlayer(weekLeaders[i].name)
            self.panels.me.weekTopEntries[i]:SetText(string.format("%s %s - |cFFFFD700%s pts|r", rankLabels[i], LeafVE:BuildStyledPlayerName(weekLeaders[i].name, leaderClass), LeafVE:FormatPointAmount(weekLeaders[i].total)))
          else
            self.panels.me.weekTopEntries[i]:SetText(string.format("%s |cFF888888------|r", rankLabels[i]))
          end
        end
      end
    end

  elseif self.activeTab == "shoutouts" and self.panels.shoutouts then
    ShowPanelWithTransition(self.panels.shoutouts)
    local me = ShortName(UnitName("player"))
    if me then
      local today = DayKey()
      local bucket = CurrentWipeVersion()
      if not LeafVE_DB.shoutouts[me] then LeafVE_DB.shoutouts[me] = {} end
      local count = 0
      for tname, timestamp in pairs(LeafVE_DB.shoutouts[me]) do
        local shoutTs = tonumber(timestamp) or 0
        if (bucket <= 0 or shoutTs >= bucket) and DayKeyFromTS(shoutTs) == today then
          count = count + 1
        end
      end
      local maxDaily = LeafVE:GetShoutoutDailyLimitForPlayer(me)
      local maxDailyLabel = LeafVE:GetShoutoutDailyLimitLabel(maxDaily)
      if self.panels.shoutouts.subtitleText then
        self.panels.shoutouts.subtitleText:SetText("|cFF888888Give recognition to guild members! You can give " .. maxDailyLabel .. " shoutout" .. (maxDaily ~= 1 and "s" or "") .. " per day.|r")
      end
      if self.panels.shoutouts.usageText then
        self.panels.shoutouts.usageText:SetText(LeafVE:GetShoutoutUsageStatusText(count, maxDaily))
      end
    end
    self:RefreshShoutoutsPanel()
    
  elseif self.activeTab == "leaderWeek" and self.panels.leaderWeek then
    ShowPanelWithTransition(self.panels.leaderWeek)
    self:RefreshLeaderboard("leaderWeek")
    
  elseif self.activeTab == "leaderLife" and self.panels.leaderLife then
    ShowPanelWithTransition(self.panels.leaderLife)
    self:RefreshLeaderboard("leaderLife")
    
  elseif self.activeTab == "roster" and self.panels.roster then
    ShowPanelWithTransition(self.panels.roster)
    self:RefreshRoster()
    
  elseif self.activeTab == "history" and self.panels.history then
    ShowPanelWithTransition(self.panels.history)
    self:RefreshHistory()
    
  elseif self.activeTab == "badges" and self.panels.badges then
    ShowPanelWithTransition(self.panels.badges)

    LeafVE:ScheduleDeferred("badges_panel_refresh", 0, function()
      if LeafVE and LeafVE.UI and LeafVE.UI.activeTab == "badges"
        and LeafVE.UI.panels and LeafVE.UI.panels.badges
        and LeafVE.UI.panels.badges:IsVisible() then
        LeafVE.UI:RefreshBadges()
      end
    end)

  elseif self.activeTab == "titles" and self.panels.titles then
    ShowPanelWithTransition(self.panels.titles)
    self:RefreshTitlesPanel()
    
  elseif self.activeTab == "achievements" and self.panels.achievements then
    ShowPanelWithTransition(self.panels.achievements)
    self:RefreshAchievementsLeaderboard()

  elseif self.activeTab == "shinobiReputation" and self.panels.shinobiReputation then
    ShowPanelWithTransition(self.panels.shinobiReputation)
    self:RefreshShinobiReputationLeaderboard()

  elseif self.activeTab == "options" and self.panels.options then
    ShowPanelWithTransition(self.panels.options)
    self:RefreshOptions()

  elseif self.activeTab == "admin" and self.panels.admin then
    if LeafVE:IsAdminRank() then
      ShowPanelWithTransition(self.panels.admin)
    else
      -- Redirect non-admins back to "me" tab
      self.activeTab = "me"
      if self.panels.me then ShowPanelWithTransition(self.panels.me) end
    end

  elseif self.activeTab == "liveHistory" and self.panels.liveHistory then
    ShowPanelWithTransition(self.panels.liveHistory)
    self:RefreshLiveHistory()

  elseif self.activeTab == "guildEvents" and self.panels.guildEvents then
    ShowPanelWithTransition(self.panels.guildEvents)
    if self.RefreshGuildEventsPanel then
      self:RefreshGuildEventsPanel()
    end

  elseif self.activeTab == "workOrders" and self.panels.workOrders then
    ShowPanelWithTransition(self.panels.workOrders)
    if self.RefreshWorkOrdersPanel then
      self:RefreshWorkOrdersPanel()
    end

  elseif self.activeTab == "shinobiDuties" and self.panels.shinobiDuties then
    ShowPanelWithTransition(self.panels.shinobiDuties)
    if self.RefreshShinobiDutiesPanel then
      self:RefreshShinobiDutiesPanel()
    end

  elseif self.activeTab == "workOrderRep" and self.panels.workOrderRep then
    ShowPanelWithTransition(self.panels.workOrderRep)
    if self.RefreshWorkOrderReputationPanel then
      self:RefreshWorkOrderReputationPanel()
    end

  elseif self.activeTab == "welcome" and self.panels.welcome then
    ShowPanelWithTransition(self.panels.welcome)
    self:RefreshWelcome()
  end
end

function LeafVE.UI:RefreshLiveHistory()
  EnsureDB()
  local p = self.panels.liveHistory
  if not p then return end
  local scrollChild = p.scrollChild
  if not scrollChild then return end

  -- Collect all entries from all players, merged
  local allEntries = {}
  for pName, entries in pairs(LeafVE_DB.pointHistory) do
    if type(entries) == "table" then
      for _, entry in ipairs(entries) do
        local merged = {}
        merged.playerName = pName
        merged.timestamp = entry.timestamp or 0
        merged.amount = entry.amount or 0
        merged.reason = entry.reason or ""
        merged.dateStr = entry.dateStr or ""
        table.insert(allEntries, merged)
      end
    end
  end

  -- Sort by timestamp descending (newest first)
  table.sort(allEntries, function(a, b) return a.timestamp > b.timestamp end)

  -- Cap at 500 entries
  local maxEntries = 500
  local count = table.getn(allEntries)
  if count > maxEntries then count = maxEntries end

  -- Clear existing rows
  if p.historyEntries then
    for _, row in ipairs(p.historyEntries) do
      row:Hide()
    end
  end
  p.historyEntries = {}

  local rowH = 18
  local yOff = -4
  local totalHeight = 0
  local altRow = false

  for i = 1, count do
    local entry = allEntries[i]
    local row = CreateFrame("Frame", nil, scrollChild)
    row:SetWidth(scrollChild:GetWidth() or 500)
    row:SetHeight(rowH)
    row:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", 0, yOff)

    -- Alternating row background
    altRow = not altRow
    if altRow then
      local bg = row:CreateTexture(nil, "BACKGROUND")
      bg:SetAllPoints(row)
      bg:SetTexture("Interface\\Tooltips\\UI-Tooltip-Background")
      bg:SetVertexColor(0.1, 0.1, 0.12, 0.5)
    end

    -- Date/time
    local dateFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    dateFS:SetPoint("LEFT", row, "LEFT", 4, 0)
    dateFS:SetWidth(90)
    dateFS:SetJustifyH("LEFT")
    dateFS:SetText("|cFF888888"..(entry.dateStr or "").."  |r")

    -- Player name
    local nameFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    nameFS:SetPoint("LEFT", row, "LEFT", 98, 0)
    nameFS:SetWidth(80)
    nameFS:SetJustifyH("LEFT")
    nameFS:SetText("|cFF00CCFF"..(entry.playerName or "").."  |r")

    -- Amount
    local amtFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    amtFS:SetPoint("LEFT", row, "LEFT", 182, 0)
    amtFS:SetWidth(55)
    amtFS:SetJustifyH("LEFT")
    local amtColor = (entry.amount and entry.amount > 0) and "|cFF2DD35C" or "|cFFFF4444"
    amtFS:SetText(amtColor.."+"..tostring(entry.amount or 0).." LP|r")

    -- Reason
    local reasonFS = row:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
    reasonFS:SetPoint("LEFT", row, "LEFT", 240, 0)
    reasonFS:SetWidth(230)
    reasonFS:SetJustifyH("LEFT")
    reasonFS:SetText(entry.reason or "")

    table.insert(p.historyEntries, row)
    yOff = yOff - rowH
    totalHeight = totalHeight + rowH
  end

  scrollChild:SetHeight(math.max(totalHeight + 8, 1))
  p.scrollFrame:SetVerticalScroll(0)
  if p.scrollBar then p.scrollBar:SetValue(0) end
end

function LeafVE.UI:RefreshWelcome()
  EnsureDB()
  local p = self.panels.welcome
  if not p then return end
  if self.SetWelcomeSection then
    self:SetWelcomeSection((LeafVE_DB.ui and LeafVE_DB.ui.welcomeSection) or p.activeWelcomeSection or "guide")
  end
  local opts = LeafVE_DB.options
  local soPts = (opts and opts.shoutoutPoints) or 10
  local soMax = LeafVE:GetShoutoutDailyLimitForPlayer(UnitName("player"))
  local soMaxLabel = LeafVE:GetShoutoutDailyLimitLabel(soMax)
  local dutyMin = LeafVE.shinobiDutyTierInfo and LeafVE.shinobiDutyTierInfo.D or { lpReward = 10, repReward = 22 }
  local dutyMax = LeafVE.shinobiDutyTierInfo and LeafVE.shinobiDutyTierInfo.S or { lpReward = 40, repReward = 100 }

  if p.welcomeWeekendLine then
    p.welcomeWeekendLine:SetText(string.format("|cFFFFD700Weekend Bonus|r - All Leaf Point gains are multiplied by %dx on Saturday and Sunday.", WEEKEND_POINT_MULTIPLIER))
  end
  if p.welcomeLoginLine then
    p.welcomeLoginLine:SetText("|cFFFFD700Daily Login|r - Checking in awards 20 LP and pushes your streak toward login badges like Dedicated, Truly Dedicated, and Daily Legend.")
  end
  if p.welcomeGroupLine then
    p.welcomeGroupLine:SetText(string.format("|cFFFFD700Group Time|r - Earn %d LP per online guildie every 60 minutes while grouped, up to %d LP per day. AFK and offline members do not count.", GROUP_POINTS, GROUP_POINTS_DAILY_CAP))
  end
  if p.welcomeQuestLine then
    p.welcomeQuestLine:SetText(string.format("|cFFFFD700Guild Quest Turn-Ins|r - Turning in quests while grouped with a guildmate awards %d LP each, with no daily cap.", QUEST_POINTS))
  end
  if p.welcomeInstanceLine then
    p.welcomeInstanceLine:SetText(string.format("|cFFFFD700Dungeons and Raids|r - %d LP per dungeon boss, %d per raid boss, %d extra per guildie on boss kills, plus %d / %d for dungeon and raid completion.", INSTANCE_BOSS_POINTS, RAID_BOSS_POINTS, BOSS_GUILDIE_BONUS_POINTS, INSTANCE_COMPLETION_POINTS, RAID_COMPLETION_POINTS))
  end
  if p.welcomeHKLine then
    p.welcomeHKLine:SetText("|cFFFFD700Shinobi Combat|r - Honorable kills earned while grouped with guildies award 0.5 LP each and feed the Shinobi Combatant badge path.")
  end
  if p.welcomeShoutoutLine then
    p.welcomeShoutoutLine:SetText(string.format("|cFFFFD700Shoutouts|r - Use |cFF00CCFF/so PlayerName [reason]|r to recognize a guildmate. Both the sender and receiver earn %d LP, and you currently have %s shoutouts per day.", soPts, soMaxLabel))
  end
  if p.welcomeWorkOrderLine then
    p.welcomeWorkOrderLine:SetText(string.format("|cFFFFD700Verified Work Orders|r - When a requester clicks Verify, the crafter earns %d LP and both shinobi gain work order reputation.", WORK_ORDER_FINAL_REWARD_POINTS))
  end
  if p.welcomeRepThresholdLine then
    p.welcomeRepThresholdLine:SetText(string.format("Current major reputation thresholds are |cFFFFD700%d|r, |cFFFFD700%d|r, |cFFFFD700%d|r, and |cFFFFD700%d|r rep.", WORK_ORDER_REPUTATION_BADGE_THRESHOLDS.trustedHand, WORK_ORDER_REPUTATION_BADGE_THRESHOLDS.villageArtisan, WORK_ORDER_REPUTATION_BADGE_THRESHOLDS.masterSupplier, WORK_ORDER_REPUTATION_BADGE_THRESHOLDS.leafLegend))
  end
  if p.welcomeDutyRewardLine then
    p.welcomeDutyRewardLine:SetText(string.format("Duty rewards currently range from |cFFFFD700%d LP / %d REP|r at D tier up to |cFFFFD700%d LP / %d REP|r at S tier.", dutyMin.lpReward or 10, dutyMin.repReward or 22, dutyMax.lpReward or 40, dutyMax.repReward or 100))
  end
  if p.RefreshGuideLayout then
    p.RefreshGuideLayout(true)
  end
  if self.RefreshAllianceWelcomePanel then
    self:RefreshAllianceWelcomePanel()
  end
end

