LeafVE_updateTimers = {
  groupCheck = 0,
  notification = 0,
  attendance = 0,
  badgeSync = 0,
  achievementLeaderboard = 0,
  wipeMarkerPoll = 0,
  bankWatcher = 0,
}

LeafVE_eventFrame:SetScript("OnEvent", function()
  local event = _G.event
  local arg1 = _G.arg1
  local arg2 = _G.arg2
  local arg3 = _G.arg3
  local arg4 = _G.arg4
  if event == "ADDON_LOADED" and arg1 == LeafVE.name then
    EnsureDB()
    
    -- Register addon message prefixes
    if RegisterAddonMessagePrefix then
      RegisterAddonMessagePrefix("LeafVE")
      RegisterAddonMessagePrefix("LeafVEAch")
      Print("Registered addon message prefixes")
    else
      Print("Warning: RegisterAddonMessagePrefix not available!")
    end
    
    LeafVE:CreateMinimapButton()
  Print("Addon loaded v"..LeafVE.version.."! Use /lve to open")
    return
  end
  if event == "ADDON_LOADED" and arg1 ~= LeafVE.name then
    if LeafVE and LeafVE.RegisterBadgeHyperlinkHandler then
      pcall(LeafVE.RegisterBadgeHyperlinkHandler, LeafVE)
    end
    if LeafVE and LeafVE.InstallChatAnnouncementSendHook then
      pcall(LeafVE.InstallChatAnnouncementSendHook, LeafVE)
    end
    if LeafVE and LeafVE.PatchAchievementsChatAnnouncements then
      pcall(LeafVE.PatchAchievementsChatAnnouncements, LeafVE)
    end
  end
  
  if event == "PLAYER_LOGIN" then
    Print("Loaded v"..LeafVE.version)
    Print("Auto-tracking: Login & Group points enabled!")
    EnsureDB()
    LeafVE:RefreshMinimapButtonAccess()
    LeafVE:InvalidateClientAchievementCatalog()
    LeafVE:ApplyGuildWipeMarkerIfNeeded()
    LeafVE:RecordActivity()
    -- One-time migration: purge old "Quest area trigger" history entries
    if not LeafVE_DB.migratedTriggerHistory then
      EnsureDB()
      for pName, entries in pairs(LeafVE_DB.pointHistory) do
        if type(entries) == "table" then
          local filtered = {}
          for _, entry in ipairs(entries) do
            local reason = entry.reason or ""
            local isTrigger = string.find(reason, "Quest area trigger") or string.find(reason, "trigger %d+")
            if not isTrigger then
              table.insert(filtered, entry)
            end
          end
          LeafVE_DB.pointHistory[pName] = filtered
        end
      end
      LeafVE_DB.migratedTriggerHistory = true
    end
    -- Apply a pending full data wipe (all points/badges/history) for offline members
    if ShouldApplyIncomingWipeVersion(LeafVE_GlobalDB.fullWipeVersion or 0) then
      LVE_ApplyFullWipeVersion(
        LeafVE_GlobalDB.fullWipeVersion or 0,
        "|cFFFFD700[LVL]|r Your Leaf Point data was reset by a guild admin. Welcome to the new season!"
      )
    end
    LeafVE:CheckDailyLogin()
    LeafVE:PurgeStaleWeeklyData()
    LeafVE:PurgeInvalidWorkOrders()
    LeafVE:PrimeHonorableKillTracker()
    if LeafVE.allianceEnabled == true then
      LeafVE:CacheLocalAllianceRoster()
    end
    local me = ShortName(UnitName("player"))
    local myAlltime = me and LeafVE_DB.alltime and LeafVE_DB.alltime[me]
    if myAlltime and IsPointEntryInCurrentBucket(myAlltime) then
      -- Seed self as authoritative before shared-cache merge so stale relays
      -- cannot overwrite this client's real lifetime snapshot on login.
      StoreLifetimeSnapshot(me, myAlltime.L or 0, myAlltime.G or 0, myAlltime.S or 0, me, true, true)
    end
    LeafVE:MergeSharedLeaderboardIntoLocal()
    -- Seed the quest log cache so we can diff on the first QUEST_LOG_UPDATE
    LeafVE:CacheQuestLog()
    -- Register badge hyperlink handler last so it wraps any other addon's hook
    LeafVE:RegisterBadgeHyperlinkHandler()
    LeafVE:InstallChatAnnouncementSendHook()
    LeafVE:PatchAchievementsChatAnnouncements()
    if LeafVE.allianceEnabled == true then
      LeafVE:InstallAllianceChatSupport()
    end
    LeafVE:ScheduleDeferred("player_login_badge_link_hook_1", 3, function()
      LeafVE:RegisterBadgeHyperlinkHandler()
    end)
    LeafVE:ScheduleDeferred("player_login_badge_link_hook_2", 9, function()
      LeafVE:RegisterBadgeHyperlinkHandler()
    end)
    LeafVE:ScheduleDeferred("player_login_chat_announce_hook_1", 3, function()
      LeafVE:InstallChatAnnouncementSendHook()
      LeafVE:PatchAchievementsChatAnnouncements()
    end)
    LeafVE:ScheduleDeferred("player_login_chat_announce_hook_2", 9, function()
      LeafVE:InstallChatAnnouncementSendHook()
      LeafVE:PatchAchievementsChatAnnouncements()
    end)

    LeafVE:ScheduleDeferred("player_login_sync_phase_1", 5, function()
      LeafVE:ApplyGuildWipeMarkerIfNeeded()
      if InGuild() then
        LeafVE.versionResponses = {}
        SendAddonMessage("LeafVE", "VERSIONREQ", "GUILD")
        LeafVE:BroadcastFullWipeVersion()
        LeafVE:BroadcastLeaderboardData()
      end
    end)
    if LeafVE.allianceEnabled == true then
      LeafVE:ScheduleDeferred("player_login_alliance_chat_hook_1", 4, function()
        LeafVE:InstallAllianceChatSupport()
      end)
      LeafVE:ScheduleDeferred("player_login_alliance_join", 6, function()
        LeafVE:MaybeAutoJoinAlliance(true)
      end)
      LeafVE:ScheduleDeferred("player_login_alliance_chat_hook_2", 8, function()
        LeafVE:InstallAllianceChatSupport()
      end)
      LeafVE:ScheduleDeferred("player_login_alliance_presence", 9, function()
        LeafVE:BroadcastAllianceRosterPresence(true)
      end)
      LeafVE:ScheduleDeferred("player_login_alliance_roster_cache", 9, function()
        LeafVE:CacheLocalAllianceRoster()
      end)
    end
    LeafVE:ScheduleDeferred("player_login_version_popup", 11, function()
      LeafVE:MaybeShowOutdatedVersionPopup(false)
    end)
    LeafVE:ScheduleDeferred("player_login_sync_phase_2", 7, function()
      if InGuild() then
    LeafVE:BroadcastMyAchievements()
    LeafVE:BroadcastBadges()
    LeafVE:BroadcastBadgeProgress()
    LeafVE:BroadcastMyEquippedTitle(true)
    LeafVE:BroadcastMyShinobiDutyRepBonus(true)
        local bme = ShortName(UnitName("player"))
        if bme and LeafVE_GlobalDB.playerNotes and LeafVE_GlobalDB.playerNotes[bme] then
          LeafVE:BroadcastPlayerNote(LeafVE_GlobalDB.playerNotes[bme])
        end
      end
    end)
    LeafVE:ScheduleDeferred("player_login_sync_phase_3", 10, function()
      -- Disabled to avoid city-wide gear snapshot bursts on login.
    end)
    LeafVE:ScheduleDeferred("player_login_sync_phase_4", 13, function()
      -- Disabled to avoid city-wide talent/spec bursts on login.
    end)
    LeafVE:ScheduleDeferred("player_login_sync_phase_5", 16, function()
      if InGuild() then
        LeafVE:RequestGuildEventSync(true)
      end
    end)
    LeafVE:ScheduleDeferred("player_login_sync_phase_6", 20, function()
      if InGuild() then
        LeafVE:RequestWorkOrderSync(true)
      end
    end)
    LeafVE:ScheduleDeferred("weekly_recap_popup", 24, function()
      LeafVE:MaybeShowWeeklyRecapPopup(false)
    end)
    LeafVE:ScheduleDeferred("login_briefing_popup", 15, function()
      if LeafVE and LeafVE.UI and LeafVE.UI.ShowLoginBriefingPopup then
        LeafVE.UI:ShowLoginBriefingPopup(false)
      end
    end)
    LeafVE:ScheduleDeferred("work_order_login_alert_1", 30, function()
      LeafVE:MaybeShowWorkOrderLoginAlert(false)
    end)
    LeafVE:ScheduleDeferred("work_order_login_alert_2", 40, function()
      LeafVE:MaybeShowWorkOrderLoginAlert(false)
    end)
    return
  end

  if event == "ACHIEVEMENT_EARNED" then
    LeafVE:InvalidateClientAchievementCatalog()

    LeafVE:ScheduleDeferred("achievement_earned_sync", 2, function()
      LeafVE:InvalidateClientAchievementCatalog()

      if InGuild() then
        LeafVE:BroadcastMyAchievements()
      end

      local me = ShortName(UnitName("player"))
      if LeafVE.UI and me and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == Lower(me) then
        LeafVE.UI:ShowPlayerCard(LeafVE.UI.cardCurrentPlayer)
      end

      if LeafVE.UI and LeafVE.UI.achPopup and LeafVE.UI.achPopup:IsShown() and LeafVE.UI.achPopup.playerName and me and Lower(LeafVE.UI.achPopup.playerName) == Lower(me) then
        LeafVE.UI:RefreshAchievementPopup(LeafVE.UI.achPopup.playerName)
      end

      if LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.achievements and LeafVE.UI.panels.achievements:IsVisible() then
        LeafVE.UI:RefreshAchievementsLeaderboard()
      end
    end)
    return
  end

  if event == "PLAYER_LOGOUT" then
    EnsureDB()
    LeafVE_DB.lastLogoutAt = Now()
    return
  end
  
  if event == "CHAT_MSG_ADDON" then
    LeafVE:OnAddonMessage(arg1, arg2, arg3, arg4)
    return
  end
  
  if event == "GUILD_ROSTER_UPDATE" then
    -- Invalidate the roster cache so the next GetGroupGuildies() call rebuilds it
    -- from the fresh server data (without triggering another GuildRoster() request).
    LeafVE.guildRosterCacheTime = 0
    LeafVE:RefreshMinimapButtonAccess()
    if LeafVE.allianceEnabled == true then
      LeafVE:CacheLocalAllianceRoster()
      LeafVE:ScheduleDeferred("alliance_roster_presence_sync", 1.5, function()
        LeafVE:BroadcastAllianceRosterPresence(false)
      end)
    end
    if LeafVE.UI and LeafVE.UI.frame and LeafVE.UI.frame:IsVisible() then
      if LeafVE:HasLeafAccess() then
        LeafVE.UI:Refresh()
      else
        LeafVE.UI.frame:Hide()
      end
    end
    LeafVE:ApplyGuildWipeMarkerIfNeeded()
    return
  end

  if event == "PARTY_MEMBERS_CHANGED" or event == "RAID_ROSTER_UPDATE" then
    LeafVE:OnGroupUpdate()
    return
  end

  if event == "ZONE_CHANGED_NEW_AREA" then
    LeafVE:RecordActivity()
    LeafVE:OnZoneChanged()
    return
  end

  if event == "QUEST_LOG_UPDATE" then
    -- Keep the cache fresh; turn-in detection is handled by QUEST_COMPLETE + QUEST_FINISHED.
    LeafVE:CacheQuestLog()
    return
  end

  if event == "QUEST_COMPLETE" then
    -- Dialog opened: player is about to turn in a quest. Capture the title now.
    LeafVE.pendingQuestTurnIn = GetTitleText and GetTitleText() or nil
    return
  end

  if event == "QUEST_FINISHED" then
    -- Dialog closed. If we captured a title from QUEST_COMPLETE, this is a real turn-in.
    if LeafVE.pendingQuestTurnIn and LeafVE.pendingQuestTurnIn ~= "" then
      LeafVE:OnQuestTurnedIn()
    end
    -- Always clear; covers both successful turn-ins and dialog cancellations.
    LeafVE.pendingQuestTurnIn = nil
    return
  end

  if event == "PLAYER_REGEN_DISABLED" then
    LeafVE.lastCombatAt = Now()
    LeafVE:RecordActivity()
    return
  end

  if event == "PLAYER_REGEN_ENABLED" or event == "PLAYER_TARGET_CHANGED"
     or event == "LOOT_OPENED" or event == "CHAT_MSG_SAY"
     or event == "CHAT_MSG_PARTY" or event == "CHAT_MSG_GUILD"
     or event == "CHAT_MSG_WHISPER" then
    LeafVE:RecordActivity()
    return
  end

  if event == "CHAT_MSG_COMBAT_HOSTILE_DEATH" then
    LeafVE:OnBossKillChat(arg1 or "")
    return
  end

  if event == "PLAYER_PVP_KILLS_CHANGED" or event == "CHAT_MSG_COMBAT_HONOR_GAIN" then
    LeafVE:HandleHonorableKillUpdate()
    return
  end

  if event == "COMBAT_LOG_EVENT_UNFILTERED" then
    local timestamp = _G.arg1
    local subEvent = _G.arg2
    local sourceGUID = _G.arg3
    local sourceName = _G.arg4
    local sourceFlags = _G.arg5
    local destGUID = _G.arg6
    local destName = _G.arg7
    local destFlags = _G.arg8
    LeafVE:OnBossKillCombatLog(timestamp, subEvent, sourceGUID, sourceName, sourceFlags, destGUID, destName, destFlags)
    return
  end

  if event == "UNIT_INVENTORY_CHANGED" then
    if arg1 == "player" then
      LeafVE:ScheduleMyGearBroadcast(false)
    end
    return
  end

  if event == "BAG_UPDATE" then
    return
  end

  if event == "PLAYER_MONEY" then
    return
  end

  if event == "CHARACTER_POINTS_CHANGED" then
    LeafVE:CaptureAndCacheMyTalents(true)
    LeafVE:BroadcastMyTalents(true)
    local me = ShortName(UnitName("player"))
    if me and LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == Lower(me) then
      LeafVE.UI:ShowPlayerCard(me)
      if LeafVE.UI.talentPopup and LeafVE.UI.talentPopup:IsVisible() then
        LeafVE.UI:RefreshTalentPopup(me, true)
      end
    end
    return
  end
end)

LeafVE_updateFrame = CreateFrame("Frame")
LeafVE_updateFrame:SetScript("OnUpdate", function(_, elapsed)
  elapsed = elapsed or _G.arg1 or 0
  LeafVE_updateTimers.groupCheck = LeafVE_updateTimers.groupCheck + elapsed
  LeafVE_updateTimers.notification = LeafVE_updateTimers.notification + elapsed
  LeafVE_updateTimers.attendance = LeafVE_updateTimers.attendance + elapsed
  LeafVE_updateTimers.badgeSync = LeafVE_updateTimers.badgeSync + elapsed
  LeafVE_updateTimers.achievementLeaderboard = LeafVE_updateTimers.achievementLeaderboard + elapsed
  LeafVE_updateTimers.wipeMarkerPoll = LeafVE_updateTimers.wipeMarkerPoll + elapsed
  LeafVE_updateTimers.bankWatcher = LeafVE_updateTimers.bankWatcher + elapsed

  if LeafVE_updateTimers.groupCheck >= 30 then
    LeafVE_updateTimers.groupCheck = 0
    LeafVE:OnGroupUpdate()
  end
  
  if LeafVE_updateTimers.notification >= 0.1 then
    LeafVE_updateTimers.notification = 0
    LeafVE:ProcessNotifications()
  end
  
  if LeafVE_updateTimers.attendance >= 300 then
    LeafVE_updateTimers.attendance = 0
    LeafVE:TrackAttendance()
  end
  
  -- Keep automatic leaderboard convergence, but do not rebroadcast
  -- unrelated badge/gear/talent data on the same 5-minute timer.
  if LeafVE_updateTimers.badgeSync >= 300 then
    LeafVE_updateTimers.badgeSync = 0
    if InGuild() then
      LeafVE:BroadcastLeaderboardData()
    end
  end

  -- Achievement leaderboard auto-refresh every 5 minutes
  if LeafVE_updateTimers.achievementLeaderboard >= 300 then
    LeafVE_updateTimers.achievementLeaderboard = 0
    -- Request a leaderboard resync from the guild (respects cooldown)
    if InGuild() then
      local now = Now()
      if (now - LeafVE.lastResyncRequestAt) >= LBOARD_RESYNC_COOLDOWN then
        LeafVE.lastResyncRequestAt = now
        LeafVE:SendResyncRequest()
      end
    end
    -- Refresh the achievement leaderboard panel if it is currently open
    if LeafVE.UI and LeafVE.UI.panels and
       LeafVE.UI.panels.achievements and LeafVE.UI.panels.achievements:IsVisible() then
      LeafVE.UI:RefreshAchievementsLeaderboard()
    end
  end

  -- Periodically poll the guild wipe marker so missed addon packets still
  -- converge to the latest wipe version while players remain online.
  if LeafVE_updateTimers.wipeMarkerPoll >= 60 then
    LeafVE_updateTimers.wipeMarkerPoll = 0
    LeafVE:PurgeStaleWeeklyData()
    if InGuild() then
      LeafVE:ApplyGuildWipeMarkerIfNeeded()
    end
  end

  if LeafVE.guildBankEnabled == true and LeafVE_updateTimers.bankWatcher >= 0.25 then
    LeafVE_updateTimers.bankWatcher = 0
    local me = ShortName(UnitName("player"))
    local bankVisible = me and LeafVE:IsGuildBankOwner(me) and LeafVE:IsGuildBankBankFrameVisible() or false
    local wasVisible = LeafVE.guildBankBankFrameWasVisible and true or false

    if bankVisible ~= wasVisible then
      LeafVE.guildBankBankFrameWasVisible = bankVisible
      LeafVE:ApplyGuildBankOwnerBankMode(bankVisible)
      if bankVisible then
        LeafVE:ScheduleGuildBankSnapshotUpdate(true, true, true)
      elseif LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
        LeafVE.UI:RefreshVisibleGuildBankUI(true)
      end
    end
  end

end)

